"use client"

import { useState, useCallback } from "react"
import { Button } from "@/components/ui/button"
import {
    Card,
    CardContent,
    CardDescription,
    CardFooter,
    CardHeader,
    CardTitle,
} from "@/components/ui/card"
import { Input } from "@/components/ui/input"
import { Label } from "@/components/ui/label"
import Link from "next/link"
import { useRouter } from "next/navigation"
import { api } from "@/lib/api"
import { Eye, EyeOff } from "lucide-react"

interface AuthUser {
    id: string;
    fullName: string;
    email: string;
    isSuperAdmin: boolean;
}

interface AuthResponse {
    user: AuthUser;
    requiresMfa?: boolean;
    tempToken?: string;
    tenants?: any[];
}

export default function LoginPage() {
    const router = useRouter()
    const [email, setEmail] = useState("")
    const [password, setPassword] = useState("")
    const [showPassword, setShowPassword] = useState(false)
    const [loading, setLoading] = useState(false)
    const [error, setError] = useState("")

    const [step, setStep] = useState<"identity" | "mfa">("identity")
    const [isAdmin, setIsAdmin] = useState(false)
    const [tempToken, setTempToken] = useState("")
    const [mfaCode, setMfaCode] = useState("")

    const completeLogin = useCallback((data: AuthResponse) => {
        // SEC-006: Sensitive tokens are now in HttpOnly cookies (nexus_token / nexus_refresh).
        // We only store the user profile for UI hydration.
        localStorage.setItem("k_user", JSON.stringify(data.user))

        const SAFE_FALLBACK = "/portal/dashboard"
        const returnTo = localStorage.getItem("return_to")
        localStorage.removeItem("return_to")

        if (data.user?.isSuperAdmin && (!data.tenants || data.tenants.length === 0)) {
            window.location.href = "/portal/admin/monitoring"
            return
        }

        const safeRedirect = (raw: string | null): string => {
            if (!raw) return SAFE_FALLBACK
            if (/^[a-zA-Z][a-zA-Z\d+\-.]*:/.test(raw)) return SAFE_FALLBACK
            if (raw.startsWith("//")) return SAFE_FALLBACK
            if (!raw.startsWith("/portal")) return SAFE_FALLBACK
            try {
                const parsed = new URL(raw, window.location.origin)
                if (parsed.origin !== window.location.origin) return SAFE_FALLBACK
                return parsed.pathname + parsed.search + parsed.hash
            } catch {
                return SAFE_FALLBACK
            }
        }

        window.location.href = safeRedirect(returnTo)
    }, []);

    const handleLogin = useCallback(async (e: React.FormEvent<HTMLFormElement>) => {
        e.preventDefault()
        setLoading(true)
        setError("")

        try {
            if (step === "identity") {
                let finalEmail = email.trim();
                let finalPassword = password.trim();

                // Double-check via DOM as second factor for autofill reliability
                if (typeof document !== 'undefined') {
                    const emailInput = document.getElementById('email') as HTMLInputElement;
                    const passInput = document.getElementById('password') as HTMLInputElement;
                    if (emailInput?.value) finalEmail = emailInput.value.trim();
                    if (passInput?.value) finalPassword = passInput.value.trim();
                }

                if (!finalEmail || !finalPassword) {
                    setError("Credentials required.");
                    setLoading(false);
                    return;
                }

                const endpoint = isAdmin ? "auth/login/admin" : "auth/login/web";
                const res = await api.post(endpoint, { email: finalEmail, password: finalPassword })

                if (res.data.requiresMfa) {
                    setTempToken(res.data.tempToken);
                    setStep("mfa");
                    setLoading(false);
                    return;
                }

                completeLogin(res.data as AuthResponse);
            } else {
                // MFA Step
                const res = await api.post("auth/mfa/verify-login", {
                    tempToken,
                    totpCode: mfaCode
                });
                completeLogin(res.data as AuthResponse);
            }
        } catch (err: any) {
            console.error(err);
            if (!err.response) {
                setError("Network Error: Unable to reach the server.");
            } else {
                setError(err.response?.data?.message || "Authentication Failed");
                // If MFA failed, don't reset step, just show error.
            }
        } finally {
            setLoading(false)
        }
    }, [step, email, password, isAdmin, tempToken, mfaCode, completeLogin]);

    const goBack = useCallback(() => {
        setStep("identity");
        setMfaCode("");
        setError("");
    }, []);

    const toggleAdmin = useCallback(() => {
        setIsAdmin(prev => !prev);
    }, []);

    const toggleShowPassword = useCallback(() => {
        setShowPassword(prev => !prev);
    }, []);

    return (
        <div className="flex items-center justify-center min-h-screen bg-slate-50 selection:bg-blue-500/10">
            <div className="absolute inset-0 bg-[radial-gradient(circle_at_50%_50%,rgba(59,130,246,0.03),transparent)] pointer-events-none" />

            <Card className="w-full max-w-md bg-white border-slate-200 shadow-2xl relative z-10 rounded-[2.5rem] p-4">
                <form onSubmit={handleLogin}>
                    <CardHeader className="space-y-1 pb-8">
                        <div className="flex justify-center mb-6">
                            <div className="p-3 rounded-2xl bg-blue-50 border border-blue-100">
                                <div className="w-12 h-12 bg-blue-600 rounded-xl flex items-center justify-center font-black text-white text-xl shadow-lg shadow-blue-500/20">
                                    K
                                </div>
                            </div>
                        </div>
                        <CardTitle className="text-3xl font-extrabold text-center text-slate-900 tracking-tight uppercase">
                            {isAdmin ? "Admin Login" : "Sign In"}
                        </CardTitle>
                        <CardDescription className="text-center text-slate-500 font-medium">
                            {isAdmin ? "Global Infrastructure Access" : "Welcome back. Enter your details to continue."}
                        </CardDescription>
                    </CardHeader>
                    <CardContent className="space-y-6">
                        {error && (
                            <div className="bg-rose-50 border border-rose-100 text-rose-600 px-4 py-3 rounded-2xl text-xs font-bold uppercase tracking-wider animate-in fade-in zoom-in-95" role="alert">
                                {error}
                            </div>
                        )}

                        {step === "identity" ? (
                            <>
                                <div className="space-y-2">
                                    <Label htmlFor="email" className="text-slate-500 font-bold text-[10px] uppercase tracking-widest ml-1">Email</Label>
                                    <Input
                                        id="email"
                                        type="email"
                                        name="email"
                                        autoComplete="username"
                                        placeholder="name@company.com"
                                        className="bg-slate-50 border-slate-200 text-slate-900 focus:ring-blue-500/20 focus:border-blue-500 placeholder:text-slate-400 h-12 rounded-xl font-medium px-4"
                                        value={email}
                                        onChange={(e) => setEmail(e.target.value)}
                                        required
                                    />
                                </div>
                                <div className="space-y-2">
                                    <div className="flex items-center justify-between ml-1">
                                        <Label htmlFor="password" className="text-slate-500 font-bold text-[10px] uppercase tracking-widest">Password</Label>
                                        <Link
                                            href="/forgot-password"
                                            className="text-[10px] font-black text-blue-600 hover:text-blue-700 cursor-pointer uppercase tracking-tighter transition-colors"
                                        >
                                            Recovery?
                                        </Link>
                                    </div>
                                    <div className="relative">
                                        <Input
                                            id="password"
                                            name="password"
                                            autoComplete="current-password"
                                            type={showPassword ? "text" : "password"}
                                            className="bg-slate-50 border-slate-200 text-slate-900 focus:ring-blue-500/20 focus:border-blue-500 h-12 rounded-xl px-4 pr-10"
                                            value={password}
                                            onChange={(e) => setPassword(e.target.value)}
                                            required
                                        />
                                        <button
                                            type="button"
                                            onClick={toggleShowPassword}
                                            className="absolute right-3 top-1/2 -translate-y-1/2 text-slate-400 hover:text-slate-600 transition-colors"
                                        >
                                            {showPassword ? <EyeOff size={16} /> : <Eye size={16} />}
                                        </button>
                                    </div>
                                </div>
                            </>
                        ) : (
                            <div className="space-y-4">
                                <div className="space-y-2">
                                    <Label htmlFor="mfaCode" className="text-slate-500 font-bold text-[10px] uppercase tracking-widest ml-1">Authenticator Code</Label>
                                    <Input
                                        id="mfaCode"
                                        placeholder="000000"
                                        className="bg-slate-50 border-slate-200 text-slate-900 text-center text-2xl tracking-[0.5em] focus:ring-blue-500/20 focus:border-blue-500 h-16 rounded-xl font-black"
                                        value={mfaCode}
                                        onChange={(e) => setMfaCode(e.target.value)}
                                        autoFocus
                                        required
                                    />
                                </div>
                                <div className="p-4 bg-blue-50 border border-blue-100 rounded-2xl">
                                    <p className="text-[10px] text-blue-600 font-bold leading-relaxed">
                                        RESCUE MODE: If you lost your device, enter one of your 8-digit recovery codes above to regain access.
                                    </p>
                                </div>
                                <button
                                    type="button"
                                    onClick={goBack}
                                    className="text-[10px] font-black text-slate-400 hover:text-slate-600 uppercase tracking-widest block w-full text-center transition-colors"
                                >
                                    &larr; Back to Login
                                </button>
                            </div>
                        )}
                    </CardContent>
                    <CardFooter className="flex flex-col gap-4 pb-8">
                        <Button className="w-full bg-blue-600 hover:bg-blue-700 text-white font-black h-12 rounded-xl transition-all shadow-lg shadow-blue-500/20 uppercase tracking-widest text-xs" disabled={loading}>
                            {loading ? "Verifying..." : (step === "identity" ? "Sign In" : "Unlock Identity")}
                        </Button>
                        <div className="text-[10px] text-center text-slate-400 font-bold uppercase tracking-tighter">
                            New here?{" "}
                            <Link href="/register" className="text-blue-600 hover:text-blue-700">
                                Create an account
                            </Link>
                        </div>
                        <div className="text-[10px] text-center text-slate-400 font-bold uppercase tracking-tighter">
                            <button
                                type="button"
                                onClick={toggleAdmin}
                                className="text-blue-600 hover:text-blue-700 underline underline-offset-4"
                            >
                                {isAdmin ? "Standard Login" : "Super Admin Mode"}
                            </button>
                        </div>
                    </CardFooter>
                </form>
            </Card>
        </div>
    )
}

'use client';

import { useState, useEffect } from 'react';
import Link from 'next/link';
import { useRouter } from 'next/navigation';
import { useForm } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import * as z from 'zod';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Card, CardContent, CardDescription, CardFooter, CardHeader, CardTitle } from '@/components/ui/card';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { Loader2, ArrowRight, ArrowLeft, CheckCircle2, Eye, EyeOff } from 'lucide-react';
import { Badge } from '@/components/ui/badge';
import { toast } from 'sonner';
import { api } from '@/lib/api';

// Validation Schemas
const userSchema = z.object({
    fullName: z.string().min(2, 'Full name is required'),
    email: z.string().email('Invalid email address'),
    password: z.string().min(8, 'Password must be at least 8 characters'),
    confirmPassword: z.string(),
}).refine((data) => data.password === data.confirmPassword, {
    message: "Passwords do not match",
    path: ["confirmPassword"],
});

const companySchema = z.object({
    tenantName: z.string().min(3, 'Company name is required'),
    companyType: z.string().min(1, 'Please select an industry'),
});

type UserFormData = z.infer<typeof userSchema>;
type CompanyFormData = z.infer<typeof companySchema>;

export default function RegisterPage() {
    const router = useRouter();
    const [step, setStep] = useState(1);
    const [isLoading, setIsLoading] = useState(false);
    const [userData, setUserData] = useState<UserFormData | null>(null);
    const [showPassword, setShowPassword] = useState(false);
    const [showConfirmPassword, setShowConfirmPassword] = useState(false);

    // PERF-002: Trap browser history payload states natively protecting the multi-step form data
    useEffect(() => {
        if (typeof window === 'undefined') return;
        const handlePopState = (e: PopStateEvent) => {
            if (step === 2) {
                // Intercept back button allowing user to return to Step 1 
                // natively without crashing out to login/index
                setStep(1);
            }
        };
        window.addEventListener('popstate', handlePopState);
        return () => window.removeEventListener('popstate', handlePopState);
    }, [step]);

    // Forms
    const {
        register: registerUser,
        handleSubmit: handleUserSubmit,
        setError,
        watch,
        formState: { errors: userErrors },
    } = useForm<UserFormData>({
        resolver: zodResolver(userSchema),
        mode: "onChange", // Enable live validation
    });

    const {
        register: registerCompany,
        handleSubmit: handleCompanySubmit,
        setValue: setCompanyValue,
        formState: { errors: companyErrors },
    } = useForm<CompanyFormData>({
        resolver: zodResolver(companySchema),
    });

    // Step 1: User Details
    const onUserStepSubmit = (data: UserFormData) => {
        setUserData(data);
        setStep(2);
        // Push fake state so hitting back browser-button triggers popstate trap
        if (typeof window !== 'undefined') {
            window.history.pushState({ wizardStep: 2 }, '', window.location.href);
        }
    };

    // Step 2: Company Details & Final Submission
    const onFinalSubmit = async (companyData: CompanyFormData) => {
        if (!userData) return;

        setIsLoading(true);
        try {
            // Exclude confirmPassword from the API payload
            const { confirmPassword, ...validUserData } = userData;

            const payload = {
                ...validUserData,
                ...companyData,
            };

            const response = await api.post('auth/register', payload);
            const { accessToken } = response.data;

            // Store both keys the same way login does ÔÇö TenantSelector reads k_identity first
            localStorage.setItem('k_token', accessToken);
            localStorage.setItem('k_identity', accessToken);
            localStorage.setItem('k_user', JSON.stringify(response.data.user));

            toast.success('Registration successful!', {
                description: 'Welcome to your new business account.',
            });

            // Redirect
            window.location.href = '/portal/dashboard';
        } catch (error: any) {
            console.error(error);
            if (error.response?.status === 409) {
                // Set specific error on the email field
                setError('email', {
                    type: 'manual',
                    message: 'This email is already registered. Please sign in.'
                });
                // Switch back to step 1 to show the error
                setStep(1);
            }

            toast.error('Registration failed', {
                description: error.response?.data?.message || error.message || 'Something went wrong. Please try again.',
            });
        } finally {
            setIsLoading(false);
        }
    };

    return (
        <div className="min-h-screen flex items-center justify-center bg-slate-50 selection:bg-blue-600/10 p-4 relative">
            <div className="absolute inset-0 bg-[radial-gradient(circle_at_50%_0%,rgba(37,99,235,0.05),transparent)] pointer-events-none" />
            <div className="w-full max-w-md space-y-8">
                <div className="text-center space-y-3 relative z-10">
                    <div className="flex justify-center mb-8">
                        <div className="p-4 rounded-3xl bg-white border border-slate-100 shadow-xl shadow-blue-500/5">
                            <div className="w-12 h-12 bg-blue-600 rounded-2xl flex items-center justify-center font-black text-white text-2xl shadow-lg shadow-blue-500/20">
                                K
                            </div>
                        </div>
                    </div>
                    <h1 className="text-4xl font-black tracking-tighter text-slate-900">Create Account</h1>
                    <p className="text-slate-500 font-medium">Set up your business workspace in minutes.</p>
                </div>

                <Card className="bg-white border-slate-200 shadow-2xl shadow-blue-500/5 relative z-10 rounded-[2.5rem] overflow-hidden">
                    <CardHeader className="p-8 pb-4">
                        <div className="flex items-center justify-between mb-2">
                            <CardTitle className="text-xl font-black uppercase tracking-tight text-slate-900">
                                {step === 1 ? 'Personal Profile' : 'Company Details'}
                            </CardTitle>
                            <Badge variant="outline" className="border-slate-100 text-slate-400 font-black text-[10px]">Step {step} of 2</Badge>
                        </div>
                        <CardDescription className="text-slate-500 font-medium">
                            {step === 1
                                ? 'Enter your credentials to create the primary admin profile.'
                                : 'Configure your company identity.'}
                        </CardDescription>
                    </CardHeader>

                    <CardContent className="p-8 pt-4">
                        {step === 1 ? (
                            <form id="user-form" onSubmit={handleUserSubmit(onUserStepSubmit)} className="space-y-5">
                                <div className="space-y-2">
                                    <Label htmlFor="fullName" className="text-[10px] font-black uppercase tracking-widest text-slate-400">Full Name</Label>
                                    <Input
                                        className="bg-slate-50 border-slate-100 text-slate-900 focus:ring-blue-600 focus:border-blue-600 placeholder:text-slate-300 h-12 rounded-xl font-medium"
                                        id="fullName"
                                        placeholder="Executive Director"
                                        {...registerUser('fullName')}
                                    />
                                    {userErrors.fullName && (
                                        <p className="text-xs text-rose-500 font-bold">{userErrors.fullName.message}</p>
                                    )}
                                </div>

                                <div className="space-y-2">
                                    <Label htmlFor="email" className="text-[10px] font-black uppercase tracking-widest text-slate-400">Work Email</Label>
                                    <Input
                                        className="bg-slate-50 border-slate-100 text-slate-900 focus:ring-blue-600 focus:border-blue-600 placeholder:text-slate-300 h-12 rounded-xl font-medium"
                                        id="email"
                                        type="email"
                                        placeholder="admin@company.com"
                                        {...registerUser('email')}
                                    />
                                    {userErrors.email && (
                                        <p className="text-xs text-rose-500 font-bold">{userErrors.email.message}</p>
                                    )}
                                </div>

                                <div className="space-y-2">
                                    <Label htmlFor="password" className="text-[10px] font-black uppercase tracking-widest text-slate-400">Password</Label>
                                    <div className="relative">
                                        <Input
                                            className="bg-slate-50 border-slate-100 text-slate-900 focus:ring-blue-600 focus:border-blue-600 placeholder:text-slate-300 h-12 rounded-xl font-medium pr-10"
                                            id="password"
                                            type={showPassword ? "text" : "password"}
                                            placeholder="Create a strong password"
                                            {...registerUser('password')}
                                        />
                                        <button
                                            type="button"
                                            onClick={() => setShowPassword(!showPassword)}
                                            className="absolute right-3 top-1/2 -translate-y-1/2 text-slate-400 hover:text-slate-600 transition-colors"
                                        >
                                            {showPassword ? <EyeOff size={16} /> : <Eye size={16} />}
                                        </button>
                                    </div>
                                    <div className="mt-3 space-y-2 bg-slate-50 p-3 rounded-xl border border-slate-100">
                                        <p className="text-[10px] font-black uppercase tracking-widest text-slate-400 mb-2">Password Requirements</p>
                                        <div className="grid grid-cols-1 gap-2">
                                            {[
                                                { label: "At least 8 characters", valid: (registerUser("password").onChange as any)?.target?.value?.length >= 8 || watch("password")?.length >= 8 },
                                                { label: "One uppercase letter", valid: /[A-Z]/.test(watch("password") || "") },
                                                { label: "One number", valid: /[0-9]/.test(watch("password") || "") },
                                                { label: "One special character", valid: /[^a-zA-Z0-9]/.test(watch("password") || "") },
                                            ].map((req, i) => (
                                                <div key={i} className="flex items-center gap-2">
                                                    <div className={`w-4 h-4 rounded-full flex items-center justify-center ${req.valid ? "bg-green-500 text-white" : "bg-slate-200 text-slate-400"}`}>
                                                        {req.valid && <CheckCircle2 className="w-2.5 h-2.5" />}
                                                    </div>
                                                    <span className={`text-[10px] font-bold uppercase tracking-tight ${req.valid ? "text-green-600" : "text-slate-400"}`}>{req.label}</span>
                                                </div>
                                            ))}
                                        </div>
                                    </div>
                                    {userErrors.password && (
                                        <p className="text-xs text-rose-500 font-bold mt-2">{userErrors.password.message}</p>
                                    )}
                                </div>

                                <div className="space-y-2">
                                    <Label htmlFor="confirmPassword" className="text-[10px] font-black uppercase tracking-widest text-slate-400">Confirm Password</Label>
                                    <div className="relative">
                                        <Input
                                            className="bg-slate-50 border-slate-100 text-slate-900 focus:ring-blue-600 focus:border-blue-600 placeholder:text-slate-300 h-12 rounded-xl font-medium pr-10"
                                            id="confirmPassword"
                                            type={showConfirmPassword ? "text" : "password"}
                                            placeholder="Re-enter your password"
                                            {...registerUser('confirmPassword')}
                                        />
                                        <button
                                            type="button"
                                            onClick={() => setShowConfirmPassword(!showConfirmPassword)}
                                            className="absolute right-3 top-1/2 -translate-y-1/2 text-slate-400 hover:text-slate-600 transition-colors"
                                        >
                                            {showConfirmPassword ? <EyeOff size={16} /> : <Eye size={16} />}
                                        </button>
                                    </div>
                                    {userErrors.confirmPassword && (
                                        <p className="text-xs text-rose-500 font-bold">{userErrors.confirmPassword.message}</p>
                                    )}
                                </div>
                            </form>
                        ) : (
                            <form id="company-form" onSubmit={handleCompanySubmit(onFinalSubmit)} className="space-y-5">
                                <div className="space-y-2">
                                    <Label htmlFor="tenantName" className="text-[10px] font-black uppercase tracking-widest text-slate-400">Company Name</Label>
                                    <Input
                                        className="bg-slate-50 border-slate-100 text-slate-900 focus:ring-blue-600 focus:border-blue-600 placeholder:text-slate-300 h-12 rounded-xl font-medium"
                                        id="tenantName"
                                        placeholder="Global Industries Corp"
                                        {...registerCompany('tenantName')}
                                    />
                                    {companyErrors.tenantName && (
                                        <p className="text-xs text-rose-500 font-bold">{companyErrors.tenantName.message}</p>
                                    )}
                                </div>

                                <div className="space-y-2">
                                    <Label htmlFor="companyType" className="text-[10px] font-black uppercase tracking-widest text-slate-400">Industry</Label>
                                    <Select onValueChange={(val) => setCompanyValue('companyType', val)}>
                                        <SelectTrigger className="h-12 bg-slate-50 border-slate-100 rounded-xl font-medium">
                                            <SelectValue placeholder="Select Industry" />
                                        </SelectTrigger>
                                        <SelectContent className="rounded-2xl border-slate-100 shadow-2xl">
                                            <SelectItem value="Manufacturing">Manufacturing</SelectItem>
                                            <SelectItem value="Retail">Retail</SelectItem>
                                            <SelectItem value="Wholesale">Wholesale</SelectItem>
                                            <SelectItem value="Healthcare">Healthcare</SelectItem>
                                            <SelectItem value="Education">Education</SelectItem>
                                            <SelectItem value="Construction">Construction</SelectItem>
                                            <SelectItem value="Logistics">Logistics</SelectItem>
                                            <SelectItem value="RealEstate">Real Estate</SelectItem>
                                            <SelectItem value="Service">Service</SelectItem>
                                            <SelectItem value="Gov">Government</SelectItem>
                                        </SelectContent>
                                    </Select>
                                    {companyErrors.companyType && (
                                        <p className="text-xs text-rose-500 font-bold">{companyErrors.companyType.message}</p>
                                    )}
                                </div>
                            </form>
                        )}
                    </CardContent>

                    <CardFooter className="p-8 pt-0 flex flex-col gap-4">
                        <div className="flex w-full gap-3">
                            {step === 2 && (
                                <Button variant="ghost" type="button" onClick={() => { setStep(1); if (typeof window !== 'undefined') window.history.back(); }} disabled={isLoading} className="text-slate-400 font-black uppercase tracking-widest text-[10px] hover:bg-slate-50 rounded-xl h-12">
                                    <ArrowLeft className="mr-2 h-4 w-4" /> Back
                                </Button>
                            )}
                            <Button type="submit" form={step === 1 ? "user-form" : "company-form"} disabled={isLoading} className="flex-1 bg-blue-600 hover:bg-blue-700 text-white font-black h-12 rounded-xl transition-all shadow-lg shadow-blue-500/20 uppercase tracking-widest text-[10px] active:scale-95">
                                {isLoading ? (
                                    <>
                                        <Loader2 className="mr-2 h-4 w-4 animate-spin" /> Creating Account...
                                    </>
                                ) : (
                                    <>
                                        {step === 1 ? "Continue" : "Create Account"}
                                        {step === 1 ? <ArrowRight className="ml-2 h-4 w-4" /> : <CheckCircle2 className="ml-2 h-4 w-4" />}
                                    </>
                                )}
                            </Button>
                        </div>
                        {step === 1 && (
                            <div className="text-center text-[10px] text-slate-400 font-black uppercase tracking-[0.2em]">
                                Already have an account? <Link href="/login" className="font-semibold text-blue-600 hover:text-blue-500 hover:underline">Sign In</Link>
                            </div>
                        )}
                    </CardFooter>
                </Card>
                <p className="text-center text-[9px] text-slate-400 font-black uppercase tracking-[0.4em] opacity-40">
                    Klypso v2.0
                </p>
            </div>
        </div>
    );
}

"use client"

import { useState, Suspense } from "react"
import { useSearchParams, useRouter } from "next/navigation"
import { Button } from "@/components/ui/button"
import {
    Card,
    CardContent,
    CardDescription,
    CardFooter,
    CardHeader,
    CardTitle,
} from "@/components/ui/card"
import { Input } from "@/components/ui/input"
import { Label } from "@/components/ui/label"
import { api } from "@/lib/api"
import { toast } from "sonner"
import { Eye, EyeOff, ShieldCheck } from "lucide-react"

function ResetPasswordForm() {
    const searchParams = useSearchParams()
    const router = useRouter()
    const token = searchParams.get("token")
    const [newPassword, setNewPassword] = useState("")
    const [confirmPassword, setConfirmPassword] = useState("")
    const [showPassword, setShowPassword] = useState(false)
    const [loading, setLoading] = useState(false)
    const [error, setError] = useState("")

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault()
        if (newPassword !== confirmPassword) {
            setError("Passwords do not match")
            return
        }
        if (newPassword.length < 6) {
            setError("Password must be at least 6 characters")
            return
        }

        setLoading(true)
        setError("")

        try {
            await api.post("auth/reset-password", { token, newPassword })
            toast.success("Password reset successful!")
            router.push("/login")
        } catch (err: any) {
            setError(err.response?.data?.message || "Invalid or expired token")
        } finally {
            setLoading(false)
        }
    }

    if (!token) {
        return (
            <div className="flex items-center justify-center min-h-screen bg-slate-50">
                <Card className="w-full max-w-md bg-white border-slate-200 shadow-2xl rounded-[2.5rem] p-4 text-center">
                    <CardHeader className="space-y-4">
                        <CardTitle className="text-3xl font-extrabold tracking-tight uppercase text-rose-600">Error</CardTitle>
                        <CardDescription className="text-slate-500 font-medium">
                            Invalid or missing recovery token.
                        </CardDescription>
                    </CardHeader>
                    <CardFooter>
                        <Button variant="outline" className="w-full h-12 rounded-xl" onClick={() => router.push("/login")}>
                            Back to Sign In
                        </Button>
                    </CardFooter>
                </Card>
            </div>
        )
    }

    return (
        <div className="flex items-center justify-center min-h-screen bg-slate-50 selection:bg-blue-500/10">
            <div className="absolute inset-0 bg-[radial-gradient(circle_at_50%_50%,rgba(59,130,246,0.03),transparent)] pointer-events-none" />

            <Card className="w-full max-w-md bg-white border-slate-200 shadow-2xl relative z-10 rounded-[2.5rem] p-4">
                <CardHeader className="space-y-1 pb-8 text-center">
                    <div className="flex justify-center mb-4">
                        <ShieldCheck className="text-blue-600" size={40} />
                    </div>
                    <CardTitle className="text-3xl font-extrabold tracking-tight uppercase">Set Password</CardTitle>
                    <CardDescription className="text-slate-500 font-medium">
                        Create a secure new password for your account.
                    </CardDescription>
                </CardHeader>
                <form onSubmit={handleSubmit}>
                    <CardContent className="space-y-6">
                        {error && (
                            <div className="bg-rose-50 border border-rose-100 text-rose-600 px-4 py-3 rounded-2xl text-xs font-bold uppercase tracking-wider" role="alert">
                                {error}
                            </div>
                        )}
                        <div className="space-y-2">
                            <Label className="text-slate-500 font-bold text-[10px] uppercase tracking-widest ml-1">New Password</Label>
                            <div className="relative">
                                <Input
                                    type={showPassword ? "text" : "password"}
                                    className="bg-slate-50 border-slate-200 text-slate-900 h-12 rounded-xl px-4 pr-10"
                                    value={newPassword}
                                    onChange={(e) => setNewPassword(e.target.value)}
                                    required
                                />
                                <button
                                    type="button"
                                    onClick={() => setShowPassword(!showPassword)}
                                    className="absolute right-3 top-1/2 -translate-y-1/2 text-slate-400 hover:text-slate-600"
                                >
                                    {showPassword ? <EyeOff size={16} /> : <Eye size={16} />}
                                </button>
                            </div>
                        </div>
                        <div className="space-y-2">
                            <Label className="text-slate-500 font-bold text-[10px] uppercase tracking-widest ml-1">Confirm Password</Label>
                            <Input
                                type="password"
                                className="bg-slate-50 border-slate-200 text-slate-900 h-12 rounded-xl px-4"
                                value={confirmPassword}
                                onChange={(e) => setConfirmPassword(e.target.value)}
                                required
                            />
                        </div>
                    </CardContent>
                    <CardFooter className="pb-8">
                        <Button className="w-full bg-blue-600 hover:bg-blue-700 text-white font-black h-12 rounded-xl shadow-lg shadow-blue-500/20 uppercase tracking-widest text-xs" disabled={loading}>
                            {loading ? "Updating..." : "Update Password"}
                        </Button>
                    </CardFooter>
                </form>
            </Card>
        </div>
    )
}

export default function ResetPasswordPage() {
    return (
        <Suspense fallback={<div>Loading...</div>}>
            <ResetPasswordForm />
        </Suspense>
    )
}

"use client";

import React, { useState, useEffect } from "react";
import {
    ShieldCheck,
    AlertTriangle,
    Lock,
    Unlock,
    FileText,
    BarChart3,
    Download,
    CheckCircle2,
    XCircle,
    HelpCircle,
    Clock,
    ArrowRightLeft,
    Search,
    Package
} from "lucide-react";
import { api } from "@/lib/api";
import { toast } from "sonner";

export default function AuditorDashboard() {
    const [data, setData] = useState<any>(null);
    const [loading, setLoading] = useState(true);
    const [month, setMonth] = useState(new Date().getMonth() + 1);
    const [year, setYear] = useState(new Date().getFullYear());
    const [reopenReason, setReopenReason] = useState("");
    const [isReopening, setIsReopening] = useState(false);

    const syncAuditorData = async (showLoading = false) => {
        try {
            if (showLoading) setLoading(true);
            const res = await api.get(`/accounting/auditor/dashboard?month=${month}&year=${year}`);
            setData(res.data);
        } catch (err) {
            console.error("Auditor Sync Failure:", err);
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        syncAuditorData(true);
        const interval = setInterval(() => syncAuditorData(false), 30000);
        return () => clearInterval(interval);
    }, [month, year]);

    const handleLock = async () => {
        try {
            await api.post("accounting/auditor/lock", { month, year });
            toast.success("Period locked successfully");
            syncAuditorData(true);
        } catch (err: any) {
            toast.error(err.response?.data?.message || "Failed to lock period");
        }
    };

    const handleUnlock = async () => {
        if (!reopenReason) {
            toast.error("Please provide a reason for reopening");
            return;
        }
        try {
            await api.post("accounting/auditor/unlock", { month, year, reason: reopenReason });
            toast.success("Period reopened");
            setIsReopening(false);
            setReopenReason("");
            syncAuditorData(true);
        } catch (err) {
            toast.error("Failed to reopen period");
        }
    };

    const handleCloseYear = async () => {
        if (!confirm(`Are you sure you want to CLOSE the Financial Year ${year}? This will zero out all Revenue/Expense accounts and move profit to Retained Earnings.`)) return;

        try {
            const res = await api.post("accounting/close-year", { year });
            toast.success(res.data.message);
            syncAuditorData(true);
        } catch (err: any) {
            toast.error(err.response?.data?.message || "Failed to close year");
        }
    };

    const handleTallyExport = async () => {
        try {
            toast.info(`Generating Tally Vouchers for ${new Date(0, month - 1).toLocaleString('default', { month: 'long' })} ${year}...`);
            const response = await api.get(`/accounting/export/tally?month=${month}&year=${year}`, {
                responseType: 'blob'
            });
            const url = window.URL.createObjectURL(new Blob([response.data]));
            const link = document.createElement('a');
            link.href = url;
            link.setAttribute('download', `Tally_Vouchers_${month}_${year}.xml`);
            document.body.appendChild(link);
            link.click();
            link.remove();
            toast.success("Vouchers exported successfully");
        } catch (err) {
            toast.error("Failed to generate Tally Export");
        }
    };

    const handleTallyMasters = async () => {
        try {
            toast.info("Generating Tally Masters (Ledgers + Items)...");
            const response = await api.get(`/accounting/export/masters`, {
                responseType: 'blob'
            });
            const url = window.URL.createObjectURL(new Blob([response.data]));
            const link = document.createElement('a');
            link.href = url;
            link.setAttribute('download', `Tally_Masters.xml`);
            document.body.appendChild(link);
            link.click();
            link.remove();
            toast.success("Masters exported successfully");
        } catch (err) {
            toast.error("Failed to generate Tally Masters");
        }
    };

    if (loading && !data) return <div className="p-8">Loading Auditor...</div>;

    return (
        <div className="p-4 md:p-8 pb-24 md:pb-20 space-y-6 md:space-y-8 bg-slate-50 text-slate-900 min-h-screen">
            {/* Header */}
            <div className="flex flex-col lg:flex-row lg:items-center justify-between gap-4">
                <div>
                    <h1 className="text-3xl font-black tracking-tight text-slate-900 flex items-center gap-2">
                        <ShieldCheck className="w-8 h-8 text-emerald-600" />
                        Klypso Auditor
                    </h1>
                    <p className="text-slate-500 font-medium mt-1">Review and close your monthly accounts.</p>
                </div>

                <div className="flex items-center gap-4 bg-white border border-slate-200 p-2 rounded-2xl shadow-sm">
                    <select
                        value={month}
                        onChange={(e) => setMonth(Number(e.target.value))}
                        className="bg-transparent border-none text-slate-900 focus:ring-0 cursor-pointer font-bold text-sm"
                    >
                        {[...Array(12)].map((_, i) => (
                            <option key={i + 1} value={i + 1} className="bg-white">{new Date(0, i).toLocaleString('default', { month: 'long' })}</option>
                        ))}
                    </select>
                    <select
                        value={year}
                        onChange={(e) => setYear(Number(e.target.value))}
                        className="bg-transparent border-none text-slate-900 focus:ring-0 cursor-pointer font-bold text-sm"
                    >
                        {[2024, 2025, 2026].map((y) => (
                            <option key={y} value={y} className="bg-zinc-900">{y}</option>
                        ))}
                    </select>
                    <button
                        onClick={() => syncAuditorData(true)}
                        className="p-2 hover:bg-zinc-800 rounded-lg transition-colors"
                    >
                        <Search className="w-4 h-4 text-zinc-400" />
                    </button>
                    <div className="flex items-center gap-2 px-3 py-1 bg-emerald-50 text-emerald-600 rounded-full text-[9px] font-black uppercase tracking-widest border border-emerald-100">
                        <ShieldCheck className="w-3 h-3 animate-pulse" /> Auto-Sync Active
                    </div>
                </div>
            </div>

            {/* Main Stats */}
            <div className="grid grid-cols-1 md:grid-cols-4 gap-6">
                <div className="bg-white border border-slate-200 p-6 rounded-[32px] shadow-sm relative overflow-hidden group">
                    <div className="absolute top-0 right-0 p-4 opacity-5 group-hover:opacity-10 transition-opacity">
                        <ShieldCheck className="w-16 h-16 text-slate-900" />
                    </div>
                    <p className="text-slate-500 text-[10px] font-black uppercase tracking-widest">Confidence Score</p>
                    <div className="mt-2 flex items-baseline gap-2">
                        <span className="text-4xl font-black text-slate-900 tracking-tighter">{data?.confidenceScore}%</span>
                        <span className={`text-[10px] font-bold px-2 py-0.5 rounded-lg ${data?.confidenceScore > 90 ? 'bg-emerald-50 text-emerald-600' : 'bg-amber-50 text-amber-600'}`}>
                            {data?.confidenceScore > 90 ? 'High' : 'Moderate'}
                        </span>
                    </div>
                    <div className="mt-4 w-full bg-slate-100 h-1.5 rounded-full overflow-hidden">
                        <div className="bg-emerald-500 h-full transition-all duration-1000" style={{ width: `${data?.confidenceScore}%` }}></div>
                    </div>
                </div>

                <div className="bg-white border border-slate-200 p-6 rounded-[32px] shadow-sm">
                    <p className="text-slate-500 text-[10px] font-black uppercase tracking-widest">Audit Status</p>
                    <div className="mt-2 flex items-center gap-2">
                        {data?.status === 'CLEAN' ? (
                            <CheckCircle2 className="w-6 h-6 text-emerald-600" />
                        ) : data?.status === 'BLOCKED' ? (
                            <XCircle className="w-6 h-6 text-red-600" />
                        ) : (
                            <AlertTriangle className="w-6 h-6 text-amber-600" />
                        )}
                        <span className="text-2xl font-black text-slate-900 tracking-tighter">{data?.status}</span>
                    </div>
                    <p className="text-[10px] text-slate-400 mt-2 font-bold italic">
                        {data?.status === 'CLEAN' ? 'Ready for statutory filing' : 'Corrections required before export'}
                    </p>
                </div>

                <div className="bg-white border border-slate-200 p-6 rounded-[32px] shadow-sm">
                    <p className="text-slate-500 text-[10px] font-black uppercase tracking-widest">Monthly Lock</p>
                    <div className="mt-2 flex items-center gap-3">
                        {data?.isLocked ? (
                            <Lock className="w-6 h-6 text-emerald-600" />
                        ) : (
                            <Unlock className="w-6 h-6 text-amber-500" />
                        )}
                        <span className="text-2xl font-black text-slate-900 tracking-tighter">{data?.isLocked ? 'Closed' : 'Open'}</span>
                    </div>
                    <p className="text-[10px] text-slate-400 mt-2 font-bold italic">
                        {data?.isLocked ? `Locked on ${new Date(data.lockDetails.lockedAt).toLocaleDateString()}` : 'Vouchers can still be edited'}
                    </p>
                </div>

                <div className="bg-white border border-slate-200 p-6 rounded-[32px] shadow-sm">
                    <p className="text-slate-500 text-[10px] font-black uppercase tracking-widest">Tax Coverage</p>
                    <div className="mt-2 flex items-baseline gap-2">
                        <span className="text-4xl font-black text-slate-900 tracking-tighter">{(data?.hsnCoverage || 0).toFixed(0)}%</span>
                        <FileText className="w-4 h-4 text-slate-400" />
                    </div>
                    <div className="mt-4 w-full bg-slate-100 h-1.5 rounded-full overflow-hidden">
                        <div className="bg-blue-600 h-full transition-all duration-1000" style={{ width: `${data?.hsnCoverage}%` }}></div>
                    </div>
                </div>
            </div>

            {/* Grid: Risk & Summary */}
            <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
                {/* Risk Flags */}
                <div className="bg-white border border-slate-200 rounded-[32px] p-8 shadow-sm">
                    <h2 className="text-xl font-black text-slate-900 mb-6 flex items-center gap-2 tracking-tight">
                        <AlertTriangle className="w-5 h-5 text-amber-600" />
                        Account Alerts & Blockers
                    </h2>
                    <div className="space-y-4">
                        {data?.riskFlags?.length === 0 && (
                            <div className="text-slate-400 font-bold italic py-12 text-center bg-slate-50 rounded-2xl border border-dashed border-slate-200">
                                No major flags detected for this period.
                            </div>
                        )}
                        {data?.riskFlags?.map((flag: any, i: number) => (
                            <div key={i} className={`p-5 rounded-2xl border-2 flex items-center justify-between transition-all hover:scale-[1.01] ${flag.severity === 'BLOCKER' ? 'bg-red-50 border-red-100 text-red-900' : 'bg-amber-50 border-amber-100 text-amber-900'}`}>
                                <div className="flex items-center gap-4">
                                    {flag.type === 'BACKDATED' && <Clock className="w-6 h-6 text-amber-600" />}
                                    {flag.type === 'HIGH_ROUNDOFF' && <BarChart3 className="w-6 h-6 text-amber-600" />}
                                    {flag.type === 'NEGATIVE_STOCK' && <Package className="w-6 h-6 text-red-600" />}
                                    {flag.type === 'UNLINKED_PAYMENTS' && <ArrowRightLeft className="w-6 h-6 text-amber-600" />}
                                    <div>
                                        <p className="font-black text-[11px] uppercase tracking-[0.1em]">{flag.type.replace('_', ' ')}</p>
                                        <p className="text-[10px] text-slate-500 font-bold mt-0.5">{flag.count} occurrences detected.</p>
                                    </div>
                                </div>
                                <span className={`text-[9px] font-black px-3 py-1 rounded-lg uppercase tracking-widest ${flag.severity === 'BLOCKER' ? 'bg-red-600 text-white' : 'bg-amber-500 text-white'}`}>
                                    {flag.severity}
                                </span>
                            </div>
                        ))}
                    </div>

                    <div className="mt-8 space-y-3">
                        {data?.errors.map((err: string, i: number) => (
                            <div key={i} className="text-sm text-red-400 flex gap-2">
                                <XCircle className="w-4 h-4 shrink-0 mt-0.5" />
                                {err}
                            </div>
                        ))}
                    </div>
                </div>

                {/* Financial Summary (Trial Balance Simulation) */}
                <div className="bg-white border border-slate-200 rounded-[32px] p-8 shadow-sm">
                    <h2 className="text-xl font-black text-slate-900 mb-6 flex items-center gap-2 tracking-tight">
                        <BarChart3 className="w-5 h-5 text-blue-600" />
                        Trial Balance Overview
                    </h2>
                    <div className="space-y-6">
                        <div className="grid grid-cols-2 gap-4">
                            <div className="p-5 bg-slate-50 rounded-2xl border border-slate-100">
                                <p className="text-[10px] text-slate-500 font-bold uppercase tracking-widest">Total Sales</p>
                                <p className="text-2xl font-black text-slate-900 tracking-tighter">Ôé╣{data?.summary.totalSales.toLocaleString()}</p>
                            </div>
                            <div className="p-5 bg-slate-50 rounded-2xl border border-slate-100">
                                <p className="text-[10px] text-slate-500 font-bold uppercase tracking-widest">Total GST Liability</p>
                                <p className="text-2xl font-black text-blue-600 tracking-tighter">Ôé╣{data?.summary.totalGST.toLocaleString()}</p>
                            </div>
                            <div className="p-5 bg-slate-50 rounded-2xl border border-slate-100">
                                <p className="text-[10px] text-slate-500 font-bold uppercase tracking-widest">Total Receipts</p>
                                <p className="text-2xl font-black text-emerald-600 tracking-tighter">Ôé╣{data?.summary.totalReceipts.toLocaleString()}</p>
                            </div>
                            <div className="p-5 bg-slate-50 rounded-2xl border border-slate-100">
                                <p className="text-[10px] text-slate-500 font-bold uppercase tracking-widest">Total Payments</p>
                                <p className="text-2xl font-black text-rose-600 tracking-tighter">Ôé╣{data?.summary.totalPayments.toLocaleString()}</p>
                            </div>
                        </div>

                        <div className="border-t border-slate-100 pt-6">
                            <div className="flex justify-between items-center mb-4">
                                <span className="text-slate-500 font-bold text-sm">Simulated Net Dr (Receivables)</span>
                                <span className="font-black text-slate-900 text-lg tracking-tight">Ôé╣{data?.summary.netBalanceDr.toLocaleString()}</span>
                            </div>
                            <div className="flex justify-between items-center mb-6">
                                <span className="text-slate-500 font-bold text-sm">Simulated Net Cr (Payables)</span>
                                <span className="font-black text-slate-900 text-lg tracking-tight">Ôé╣{data?.summary.netBalanceCr.toLocaleString()}</span>
                            </div>
                            <div className="bg-emerald-50 border border-emerald-100 p-5 rounded-2xl flex items-center justify-between">
                                <div className="flex items-center gap-3">
                                    <CheckCircle2 className="w-5 h-5 text-emerald-600" />
                                    <span className="font-black text-emerald-700 uppercase tracking-tight text-xs">Voucher Balancing</span>
                                </div>
                                <span className="text-xs font-black text-emerald-600 uppercase tracking-widest">Perfect (No mismatch)</span>
                            </div>
                        </div>
                    </div>
                </div>
            </div>

            {/* Action Bar */}
            <div className="fixed bottom-0 left-0 right-0 bg-white/90 backdrop-blur-xl border-t border-slate-200 p-4 flex flex-col sm:flex-row justify-between items-center gap-4 px-4 md:px-8 z-50">
                <div className="flex items-center gap-6">
                    <div className="flex items-center gap-2">
                        <div className={`w-3 h-3 rounded-full ${data?.isLocked ? 'bg-emerald-500 animate-pulse' : 'bg-amber-500'}`}></div>
                        <span className="text-[10px] font-black uppercase tracking-widest text-slate-500">{data?.isLocked ? 'Month Closed & Audited' : 'Month Open for Entries'}</span>
                    </div>
                </div>

                <div className="flex items-center gap-3">
                    {data?.isLocked ? (
                        <>
                            <button
                                onClick={() => setIsReopening(true)}
                                className="px-6 py-2.5 bg-zinc-800 hover:bg-zinc-700 text-white rounded-xl font-semibold flex items-center gap-2 transition-all border border-zinc-700"
                            >
                                <Unlock className="w-4 h-4" />
                                Reopen Month
                            </button>
                            <button
                                onClick={handleCloseYear}
                                className="px-6 py-2.5 bg-emerald-900/20 text-emerald-400 hover:bg-emerald-900/30 rounded-xl font-bold flex items-center gap-2 transition-all border border-emerald-900/30"
                            >
                                <ShieldCheck className="w-4 h-4" />
                                Close Year {year}
                            </button>
                            <button
                                onClick={handleTallyMasters}
                                className="px-6 py-2.5 bg-white/50 text-slate-600 hover:bg-white rounded-xl font-bold flex items-center gap-2 transition-all border border-slate-200"
                            >
                                <ArrowRightLeft className="w-4 h-4" />
                                Sync Masters
                            </button>
                            <button
                                onClick={handleTallyExport}
                                className="px-6 py-2.5 bg-white text-black hover:bg-zinc-200 rounded-xl font-bold flex items-center gap-2 transition-all shadow-lg shadow-white/5 border border-slate-200"
                            >
                                <Download className="w-4 h-4" />
                                Final Tally Export
                            </button>
                        </>
                    ) : (
                        <button
                            onClick={handleLock}
                            disabled={data?.status === 'BLOCKED'}
                            className={`px-10 py-3 rounded-2xl font-black flex items-center gap-2 transition-all shadow-xl text-xs uppercase tracking-widest ${data?.status === 'BLOCKED' ? 'bg-slate-100 text-slate-400 cursor-not-allowed mx-auto' : 'bg-emerald-600 hover:bg-emerald-500 text-white shadow-emerald-500/20'}`}
                        >
                            <Lock className="w-4 h-4" />
                            Close & Lock Month
                        </button>
                    )}
                </div>
            </div>

            {/* Reopen Dialog */}
            {isReopening && (
                <div className="fixed inset-0 bg-slate-900/50 backdrop-blur-xl flex items-center justify-center z-[100] p-4">
                    <div className="bg-white border border-slate-200 w-full max-w-md rounded-[32px] p-10 shadow-2xl">
                        <h3 className="text-2xl font-black text-slate-900 flex items-center gap-3 mb-2 tracking-tighter">
                            <Unlock className="w-6 h-6 text-amber-600" />
                            Reopen Closed Month
                        </h3>
                        <p className="text-slate-500 font-medium text-xs mb-8">Reopening a closed month will allow new entries to be made. Please provide a reason for reopening.</p>

                        <textarea
                            value={reopenReason}
                            onChange={(e) => setReopenReason(e.target.value)}
                            placeholder="Reason for reopening (e.g., Late GST invoice from supplier...)"
                            className="w-full bg-slate-50 border border-slate-200 rounded-2xl p-5 text-slate-900 focus:ring-2 focus:ring-amber-500/20 focus:border-amber-500 outline-none h-36 mb-8 text-sm font-semibold"
                        />

                        <div className="flex gap-4">
                            <button
                                onClick={() => setIsReopening(false)}
                                className="flex-1 px-4 py-3 border border-slate-200 hover:bg-slate-50 rounded-2xl font-bold text-slate-500 transition-all"
                            >
                                Cancel
                            </button>
                            <button
                                onClick={handleUnlock}
                                className="flex-2 px-8 py-3 bg-amber-600 hover:bg-amber-500 text-white font-black rounded-2xl transition-all shadow-lg shadow-amber-600/20 text-sm uppercase tracking-widest"
                            >
                                Confirm Reopen
                            </button>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
}

"use client";

import { useState, useEffect, useCallback } from "react";
import { api } from "@/lib/api";
import { toast } from "sonner";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogTrigger } from "@/components/ui/dialog";
import {
    Table,
    TableBody,
    TableCell,
    TableHead,
    TableHeader,
    TableRow,
} from "@/components/ui/table";
import { Badge } from "@/components/ui/badge";
import { Building2, Plus, PlayCircle, History } from "lucide-react";

interface DepreciationLog {
    id: string;
    amount: string;
    date: string;
    description: string;
}


interface FixedAsset {
    id: string;
    name: string;
    assetCode: string;
    purchaseDate: string;
    purchaseValue: string;
    salvageValue: string;
    usefulLife: number;
    accumulatedDepreciation: string;
    status: string;
    depreciationLogs?: DepreciationLog[];
}


export default function FixedAssetsPage() {
    const [assets, setAssets] = useState<FixedAsset[]>([]);
    const [loading, setLoading] = useState(true);
    const [fetchError, setFetchError] = useState<string | null>(null);
    const [dialogOpen, setDialogOpen] = useState(false);
    const [form, setForm] = useState({
        name: "",
        assetCode: "",
        purchaseDate: new Date().toISOString().split("T")[0],
        purchaseValue: "",
        salvageValue: "0",
        usefulLife: "60",
    });

    const fetchAssets = useCallback(async () => {
        try {
            setFetchError(null);
            const res = await api.get("accounting/fixed-assets");
            setAssets(Array.isArray(res.data) ? res.data : []);
        } catch (err: any) {
            const msg = err.response?.data?.message || "Failed to load fixed assets";
            setFetchError(msg);
            toast.error(msg);
        } finally {
            setLoading(false);
        }
    }, []);

    useEffect(() => {
        fetchAssets();
    }, [fetchAssets]);

    const handleAdd = async () => {
        if (!form.name || !form.assetCode || !form.purchaseValue) {
            toast.error("Name, asset code, and purchase value are required");
            return;
        }
        try {
            await api.post("accounting/fixed-assets", {
                ...form,
                purchaseValue: parseFloat(form.purchaseValue),
                salvageValue: parseFloat(form.salvageValue || "0"),
                usefulLife: parseInt(form.usefulLife),
                purchaseDate: new Date(form.purchaseDate).toISOString(),
                idempotencyKey: `FA-${form.assetCode}-${Date.now()}`,
            });

            toast.success("Fixed asset added");
            setDialogOpen(false);
            setForm({ name: "", assetCode: "", purchaseDate: new Date().toISOString().split("T")[0], purchaseValue: "", salvageValue: "0", usefulLife: "60" });
            fetchAssets();
        } catch (err: any) {
            toast.error(err.response?.data?.message || "Failed to add asset");
        }
    };

    const handleDepreciate = async (assetId: string, assetName: string) => {
        try {
            const res = await api.post(`accounting/fixed-assets/${assetId}/depreciate`);
            toast.success(`Depreciation of Ôé╣${res.data.monthlyDepreciation} posted for ${assetName}`);
            fetchAssets();
        } catch (err: any) {
            toast.error(err.response?.data?.message || "Depreciation failed");
        }
    };

    const bookValue = (asset: FixedAsset) =>
        (parseFloat(asset.purchaseValue) - parseFloat(asset.accumulatedDepreciation)).toFixed(2);

    const statusColor = (status: string) => {
        if (status === "Active") return "bg-emerald-100 text-emerald-700";
        if (status === "FullyDepreciated") return "bg-slate-100 text-slate-600";
        if (status === "Disposed") return "bg-red-100 text-red-700";
        return "bg-slate-100 text-slate-600";
    };

    return (
        <div className="space-y-8">
            <div className="flex items-center justify-between">
                <div>
                    <h1 className="text-2xl font-black tracking-tight text-slate-900">Fixed Assets</h1>
                    <p className="text-sm text-slate-500 mt-1">
                        Manage capital assets and run monthly depreciation schedules.
                    </p>
                </div>
                <Dialog open={dialogOpen} onOpenChange={setDialogOpen}>
                    <DialogTrigger asChild>
                        <Button className="bg-blue-600 hover:bg-blue-700 text-white font-bold rounded-2xl">
                            <Plus className="h-4 w-4 mr-2" />
                            Add Asset
                        </Button>
                    </DialogTrigger>
                    <DialogContent>
                        <DialogHeader>
                            <DialogTitle>Add Fixed Asset</DialogTitle>
                        </DialogHeader>
                        <div className="space-y-4 pt-2">
                            <div className="grid grid-cols-2 gap-4">
                                <div className="space-y-2">
                                    <Label>Asset Name</Label>
                                    <Input value={form.name} onChange={e => setForm(f => ({ ...f, name: e.target.value }))} placeholder="e.g. Lathe Machine" />
                                </div>
                                <div className="space-y-2">
                                    <Label>Asset Code</Label>
                                    <Input value={form.assetCode} onChange={e => setForm(f => ({ ...f, assetCode: e.target.value }))} placeholder="e.g. MACH-001" />
                                </div>
                            </div>
                            <div className="space-y-2">
                                <Label>Purchase Date</Label>
                                <Input type="date" value={form.purchaseDate} onChange={e => setForm(f => ({ ...f, purchaseDate: e.target.value }))} />
                            </div>
                            <div className="grid grid-cols-2 gap-4">
                                <div className="space-y-2">
                                    <Label>Purchase Value (Ôé╣)</Label>
                                    <Input type="number" value={form.purchaseValue || ""} onChange={e => {
                                        const val = e.target.value === "" ? 0 : parseFloat(e.target.value);
                                        setForm(f => ({ ...f, purchaseValue: isNaN(val) ? "0" : val.toString() }));
                                    }} placeholder="500000" />
                                </div>
                                <div className="space-y-2">
                                    <Label>Salvage Value (Ôé╣)</Label>
                                    <Input type="number" value={form.salvageValue} onChange={e => setForm(f => ({ ...f, salvageValue: e.target.value }))} placeholder="0" />
                                </div>
                            </div>
                            <div className="space-y-2">
                                <Label>Useful Life (months)</Label>
                                <Input type="number" value={form.usefulLife || ""} onChange={e => {
                                    const val = e.target.value === "" ? 0 : parseInt(e.target.value, 10);
                                    setForm(f => ({ ...f, usefulLife: isNaN(val) ? "0" : val.toString() }));
                                }} placeholder="60" />
                            </div>
                            <Button onClick={handleAdd} className="w-full bg-blue-600 hover:bg-blue-700 text-white font-bold rounded-xl">
                                Add Fixed Asset
                            </Button>
                        </div>
                    </DialogContent>
                </Dialog>
            </div>

            {loading ? (
                <div className="text-center py-16 text-slate-400">Loading assets...</div>
            ) : fetchError ? (
                <div className="text-center py-20 flex flex-col items-center gap-4">
                    <div className="p-5 bg-red-50 rounded-3xl">
                        <Building2 className="h-10 w-10 text-red-400" />
                    </div>
                    <div>
                        <p className="font-bold text-slate-700">Could not load fixed assets</p>
                        <p className="text-sm text-slate-400 mt-1">{fetchError}</p>
                        <button onClick={() => { setLoading(true); fetchAssets(); }} className="mt-4 text-sm text-blue-600 font-bold hover:underline">Try again</button>
                    </div>
                </div>
            ) : assets.length === 0 ? (
                <div className="text-center py-20 flex flex-col items-center gap-4">
                    <div className="p-5 bg-slate-100 rounded-3xl">
                        <Building2 className="h-10 w-10 text-slate-400" />
                    </div>
                    <div>
                        <p className="font-bold text-slate-700">No fixed assets yet</p>
                        <p className="text-sm text-slate-400 mt-1">Add machinery, vehicles, or equipment to track depreciation.</p>
                    </div>
                </div>
            ) : (
                <div className="bg-white rounded-3xl border border-slate-100 shadow-sm overflow-hidden">
                    <Table>
                        <TableHeader>
                            <TableRow className="bg-slate-50">
                                <TableHead className="font-black text-xs uppercase tracking-widest text-slate-500">Asset</TableHead>
                                <TableHead className="font-black text-xs uppercase tracking-widest text-slate-500">Code</TableHead>
                                <TableHead className="font-black text-xs uppercase tracking-widest text-slate-500 text-right">Cost</TableHead>
                                <TableHead className="font-black text-xs uppercase tracking-widest text-slate-500 text-right">Acc. Dep.</TableHead>
                                <TableHead className="font-black text-xs uppercase tracking-widest text-slate-500 text-right">Book Value</TableHead>
                                <TableHead className="font-black text-xs uppercase tracking-widest text-slate-500">Life (mo)</TableHead>
                                <TableHead className="font-black text-xs uppercase tracking-widest text-slate-500">Status</TableHead>
                                <TableHead className="font-black text-xs uppercase tracking-widest text-slate-500">Action</TableHead>
                            </TableRow>
                        </TableHeader>
                        <TableBody>
                            {assets.map((asset) => (
                                <TableRow key={asset.id} className="hover:bg-slate-50/50">
                                    <TableCell className="font-bold text-slate-900">{asset.name}</TableCell>
                                    <TableCell className="font-mono text-xs text-slate-500">{asset.assetCode}</TableCell>
                                    <TableCell className="text-right font-medium">Ôé╣{parseFloat(asset.purchaseValue).toLocaleString("en-IN")}</TableCell>
                                    <TableCell className="text-right text-slate-500">Ôé╣{parseFloat(asset.accumulatedDepreciation).toLocaleString("en-IN")}</TableCell>
                                    <TableCell className="text-right font-bold text-blue-600">Ôé╣{parseFloat(bookValue(asset)).toLocaleString("en-IN")}</TableCell>
                                    <TableCell className="text-slate-600">{asset.usefulLife}</TableCell>
                                    <TableCell>
                                        <span className={`px-2 py-1 rounded-full text-xs font-bold ${statusColor(asset.status)}`}>
                                            {asset.status}
                                        </span>
                                    </TableCell>
                                    <TableCell className="flex gap-2">
                                        {asset.status === "Active" && (
                                            <Button
                                                size="sm"
                                                variant="outline"
                                                onClick={() => handleDepreciate(asset.id, asset.name)}
                                                className="rounded-xl text-xs font-bold border-slate-200 hover:bg-blue-50 hover:border-blue-200 hover:text-blue-600"
                                            >
                                                <PlayCircle className="h-3 w-3 mr-1" />
                                                Depreciate
                                            </Button>
                                        )}
                                        <Dialog>
                                            <DialogTrigger asChild>
                                                <Button size="sm" variant="ghost" className="rounded-xl text-xs font-bold text-slate-500 hover:text-slate-900">
                                                    <History className="h-3 w-3 mr-1" />
                                                    History
                                                </Button>
                                            </DialogTrigger>
                                            <DialogContent className="max-w-md">
                                                <DialogHeader>
                                                    <DialogTitle>Depreciation History: {asset.name}</DialogTitle>
                                                </DialogHeader>
                                                <div className="space-y-4 pt-2">
                                                    {!asset.depreciationLogs || asset.depreciationLogs.length === 0 ? (
                                                        <p className="text-center py-8 text-slate-400 text-sm">No depreciation logs found.</p>
                                                    ) : (
                                                        <div className="space-y-3">
                                                            {asset.depreciationLogs.map((log) => (
                                                                <div key={log.id} className="flex justify-between items-center p-3 bg-slate-50 rounded-2xl border border-slate-100">
                                                                    <div>
                                                                        <p className="font-bold text-slate-900">Ôé╣{parseFloat(log.amount).toLocaleString("en-IN")}</p>
                                                                        <p className="text-[10px] text-slate-500">{new Date(log.date).toLocaleDateString()}</p>
                                                                    </div>
                                                                    <Badge variant="outline" className="text-[10px] font-bold border-slate-200">{log.description}</Badge>
                                                                </div>
                                                            ))}
                                                        </div>
                                                    )}
                                                </div>
                                            </DialogContent>
                                        </Dialog>
                                    </TableCell>

                                </TableRow>
                            ))}
                        </TableBody>
                    </Table>
                </div>
            )}
        </div>
    );
}

"use client";

import { useEffect, useState } from "react";
import { useRouter } from "next/navigation";
import { api } from "@/lib/api";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";
import {
    Table,
    TableBody,
    TableCell,
    TableHead,
    TableHeader,
    TableRow
} from "@/components/ui/table";
import { Plus, Wallet, ArrowUpRight, ArrowDownRight, Landmark, Receipt, Printer, Search, RefreshCw, ShoppingCart, MessageCircle, FileDown, Users, Activity, Ban } from "lucide-react";
import { toast } from "sonner";
import { Badge } from "@/components/ui/badge";
import { RecordPaymentModal } from "@/components/accounting/record-payment-modal";
import { CreateInvoiceDialog } from "@/components/accounting/create-invoice-dialog";
import { CreateAccountDialog } from "@/components/accounting/create-account-dialog";
import { CreateJournalEntryDialog } from "@/components/accounting/create-journal-entry-dialog";
import { CollaborationTimeline } from "@/components/system/collaboration-timeline";
import { ForecastingWidget } from "@/components/accounting/forecasting-widget";
import { useUX } from "@/components/providers/ux-provider";
import { FixedAssetTab } from "@/components/accounting/fixed-asset-tab";
import { AuditorDashboard } from "@/components/accounting/auditor-dashboard";
import { EmptyState } from "@/components/ui/empty-state";

export default function AccountingPage() {
    const { setUILocked, showConfirm } = useUX();
    const [accounts, setAccounts] = useState<any[]>([]);
    const [transactions, setTransactions] = useState<any[]>([]);
    const [invoices, setInvoices] = useState<any[]>([]);
    const [stats, setStats] = useState<any>({ receivable: 0, netProfit: 0, income: 0, expenses: 0, overdueAmount: 0, topDebtors: [] });
    const [invStats, setInvStats] = useState<any>({ lowStock: 0 });
    const [loading, setLoading] = useState(true);
    const [isSyncing, setIsSyncing] = useState(false);
    const [selectedInvoice, setSelectedInvoice] = useState<any>(null);
    const [showCreateInvoice, setShowCreateInvoice] = useState(false);
    const [searchQuery, setSearchQuery] = useState("");

    const [invoicePage, setInvoicePage] = useState(1);
    const [invoiceTotalPages, setInvoiceTotalPages] = useState(1);
    const [pendingDraft, setPendingDraft] = useState<any>(null);
    const [healthScore, setHealthScore] = useState<any>(null);
    const [leaderboard, setLeaderboard] = useState<any[]>([]);
    const [recoveryMemory, setRecoveryMemory] = useState<any[]>([]);
    const [showCreateAccount, setShowCreateAccount] = useState(false);
    const [showCreateJournalEntry, setShowCreateJournalEntry] = useState(false);
    const [lastSyncTime, setLastSyncTime] = useState<number>(Date.now());

    useEffect(() => {
        const draft = localStorage.getItem("invoice_draft");
        if (draft) {
            try {
                const parsed = JSON.parse(draft);
                if (parsed.items?.length > 0 && parsed.items[0].productId) {
                    setPendingDraft(parsed);
                }
            } catch (e) { }
        }
    }, [showCreateInvoice]);

    const syncLedgers = async (silent = false) => {
        try {
            if (!silent) setLoading(true);
            else setIsSyncing(true);

            const [accRes, txRes, invRes, statsRes, invStatsRes, healthRes, leaderRes, recoveryRes] = await Promise.all([
                api.get("accounting/accounts"),
                api.get("accounting/transactions"),
                api.get(`/accounting/invoices?page=${invoicePage}&limit=50`),
                api.get("accounting/stats"),
                api.get("inventory/stats"),
                api.get("accounting/health-score"),
                api.get("accounting/leaderboard"),
                api.get("accounting/recovery-memory")
            ]);
            setAccounts(accRes.data);
            setTransactions(txRes.data.data || txRes.data);
            setHealthScore(healthRes.data);
            setLeaderboard(leaderRes.data);
            setRecoveryMemory(recoveryRes.data);

            if (invRes.data.data) {
                setInvoices(invRes.data.data);
                setInvoiceTotalPages(invRes.data.meta.totalPages);
            } else {
                setInvoices(invRes.data);
            }

            setStats(statsRes.data);
            setInvStats(invStatsRes.data);
            setLastSyncTime(Date.now());
        } catch (err) {
            console.error("Ledger Sync Failure:", err);
            if (!silent) toast.error("Failed to load accounting data. Please refresh.");
        } finally {
            setLoading(false);
            setIsSyncing(false);
        }
    };

    const handleTallyMasters = async () => {
        try {
            toast.info("Generating Tally Ledger Masters...");
            const response = await api.get(`/accounting/export/masters`, {
                responseType: 'blob'
            });
            const url = window.URL.createObjectURL(new Blob([response.data]));
            const link = document.createElement('a');
            link.href = url;
            link.setAttribute('download', `Tally_Masters.xml`);
            document.body.appendChild(link);
            link.click();
            link.remove();
            toast.success("Ledger Masters generated successfully");
        } catch (err) {
            toast.error("Failed to generate Tally Masters");
        }
    };

    const handleCancelInvoice = (id: string) => {
        // UI-005: Stale State Protection
        if (Date.now() - lastSyncTime > 60000) {
            toast.warning("Accounting data might be stale. Syncing before action...", { icon: <RefreshCw className="h-4 w-4 animate-spin" /> });
            syncLedgers().then(() => proceedWithCancellation(id));
            return;
        }
        proceedWithCancellation(id);
    };

    const proceedWithCancellation = (id: string) => {
        showConfirm({
            title: "Cancel Invoice?",
            description: "Are you sure you want to cancel this invoice? This will reverse all ledger entries and stock movements. This action cannot be undone.",
            confirmText: "Yes, Cancel Invoice",
            variant: "destructive",
            onConfirm: async () => {
                try {
                    setUILocked(true);
                    await api.post(`/accounting/invoices/${id}/cancel`, { reason: "User cancelled from dashboard" });
                    toast.success("Invoice cancelled successfully");
                    syncLedgers();
                } catch (err: any) {
                    toast.error(err.response?.data?.message || "Cancellation failed");
                } finally {
                    setUILocked(false);
                }
            }
        });
    };

    const handleTallyExport = async () => {
        try {
            const month = new Date().getMonth() + 1;
            const year = new Date().getFullYear();

            // 1. Pre-flight Integrity Check
            toast.info("Validating financial data for Tally...");
            const valRes = await api.get(`/accounting/export/validate?month=${month}&year=${year}`);

            if (!valRes.data.isValid) {
                toast.error(`Export Blocked: ${valRes.data.errors[0]}`, {
                    description: `Found ${valRes.data.errors.length} integrity issues. Please fix before exporting.`,
                    duration: 5000
                });
                return;
            }

            // 2. Procced with Download
            const response = await api.get(`/accounting/export/tally?month=${month}&year=${year}`, {
                responseType: 'blob'
            });
            const url = window.URL.createObjectURL(new Blob([response.data]));
            const link = document.createElement('a');
            link.href = url;
            link.setAttribute('download', `Tally_Full_Sync_${month}_${year}.xml`);
            document.body.appendChild(link);
            link.click();
            link.remove();
            toast.success("Tally Full Sync generated successfully");
        } catch (err) {
            toast.error("Failed to generate Tally export");
        }
    };

    const filteredInvoices = invoices.filter((inv: any) => {
        const customerName = [inv.customer?.firstName, inv.customer?.lastName].filter(Boolean).join(" ").toLowerCase();
        return inv.invoiceNumber?.toLowerCase().includes(searchQuery.toLowerCase()) ||
            customerName.includes(searchQuery.toLowerCase());
    });

    useEffect(() => {
        syncLedgers();

        // CONTINUOUS BACKGROUND SYNC: 30s interval
        const interval = setInterval(() => syncLedgers(true), 30000);
        return () => clearInterval(interval);
    }, [invoicePage]);

    return (
        <div className="flex-1 space-y-6 md:space-y-8 pt-2 md:pt-6 px-4 md:px-8 w-full max-w-full overflow-hidden">
            <div className="flex flex-col xl:flex-row xl:items-center justify-between gap-4 xl:gap-0">
                <div>
                    <h2 className="text-4xl font-black tracking-tight text-slate-900 flex items-center">
                        <Landmark className="mr-4 h-9 w-9 text-amber-500 shadow-sm" />
                        Accounting
                    </h2>
                    <p className="text-slate-500 mt-2 font-medium">Manage invoices, accounts, transactions, and financial reports.</p>
                </div>
                <div className="flex flex-wrap items-center gap-3">
                    {pendingDraft && !showCreateInvoice && (
                        <Button
                            variant="outline"
                            className="bg-amber-50 border-amber-200 text-amber-600 hover:bg-amber-100 text-xs h-11 px-5 rounded-2xl animate-pulse font-black uppercase tracking-widest w-full sm:w-auto"
                            onClick={() => setShowCreateInvoice(true)}
                        >
                            <ShoppingCart className="mr-2 h-4 w-4" /> Resume Transaction
                        </Button>
                    )}
                    {isSyncing && (
                        <div className="flex items-center text-[10px] font-black text-slate-600 bg-slate-50 border border-slate-100 px-3 py-1.5 rounded-xl animate-pulse uppercase tracking-widest w-full sm:w-auto">
                            <RefreshCw className="h-3 w-3 mr-2 animate-spin text-blue-500" /> System Sync
                        </div>
                    )}
                    <div className="flex bg-slate-100 p-1 rounded-2xl border border-slate-200 shadow-inner w-full sm:w-auto">
                        <Button
                            variant="ghost"
                            className="text-slate-500 hover:text-slate-900 hover:bg-white hover:shadow-sm rounded-xl px-4 py-2 font-bold transition-all h-9 flex-1 sm:flex-none"
                            onClick={() => setShowCreateAccount(true)}
                        >
                            <RefreshCw className="mr-2 h-4 w-4 text-blue-500" /> All Accounts
                        </Button>
                        <Button
                            variant="ghost"
                            className="text-slate-500 hover:text-slate-900 hover:bg-white hover:shadow-sm rounded-xl px-4 py-2 font-bold transition-all h-9 flex-1 sm:flex-none"
                            onClick={() => setShowCreateJournalEntry(true)}
                        >
                            <Plus className="mr-2 h-4 w-4 text-emerald-500" /> Record Tx
                        </Button>
                    </div>
                    <Button className="rounded-2xl bg-amber-500 hover:bg-amber-600 font-bold px-8 shadow-lg shadow-amber-500/20 text-white h-11 w-full sm:w-auto" onClick={() => setShowCreateInvoice(true)}>
                        <Plus className="mr-2 h-4 w-4" /> New Invoice
                    </Button>
                </div>
            </div>

            <div className="grid gap-6 md:grid-cols-2 lg:grid-cols-4">
                <Card className="bg-white border-slate-200 shadow-sm hover:shadow-xl hover:shadow-emerald-500/5 transition-all rounded-3xl overflow-hidden border-b-4 border-b-emerald-500 border-none group">
                    <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
                        <CardTitle className="text-[10px] font-black uppercase tracking-[0.2em] text-slate-600">Total Income</CardTitle>
                        <div className="p-2.5 bg-emerald-50 rounded-2xl group-hover:scale-110 transition-transform">
                            <ArrowUpRight className="h-4 w-4 text-emerald-600" />
                        </div>
                    </CardHeader>
                    <CardContent>
                        <div className="text-3xl font-black text-slate-900 tracking-tighter">Ôé╣{Number(stats.income || 0).toLocaleString('en-IN', { minimumFractionDigits: 0 })}</div>
                        <p className="text-[10px] text-emerald-600 mt-2 font-black uppercase tracking-widest bg-emerald-50 w-fit px-2 py-0.5 rounded-lg">Accelerating</p>
                    </CardContent>
                </Card>
                <Card className="bg-white border-slate-200 shadow-sm hover:shadow-xl hover:shadow-amber-500/5 transition-all rounded-3xl overflow-hidden border-b-4 border-b-amber-500 border-none group">
                    <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
                        <CardTitle className="text-[10px] font-black uppercase tracking-[0.2em] text-slate-600">Total Receivables</CardTitle>
                        <div className="p-2.5 bg-amber-50 rounded-2xl group-hover:scale-110 transition-transform">
                            <Wallet className="h-4 w-4 text-amber-600" />
                        </div>
                    </CardHeader>
                    <CardContent>
                        <div className="text-3xl font-black text-amber-600 tracking-tighter">Ôé╣{Number(stats.receivable || 0).toLocaleString('en-IN', { minimumFractionDigits: 0 })}</div>
                        <p className="text-[10px] text-slate-600 mt-2 font-black uppercase tracking-widest">Pending Collection</p>
                    </CardContent>
                </Card>
                <Card className="bg-white border-slate-200 shadow-sm hover:shadow-xl hover:shadow-rose-500/5 transition-all rounded-3xl overflow-hidden border-b-4 border-b-rose-500 border-none group">
                    <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
                        <CardTitle className="text-[10px] font-black uppercase tracking-[0.2em] text-slate-600">Overdue Amount</CardTitle>
                        <div className="p-2.5 bg-rose-50 rounded-2xl group-hover:scale-110 transition-transform">
                            <ArrowDownRight className="h-4 w-4 text-rose-600" />
                        </div>
                    </CardHeader>
                    <CardContent>
                        <div className="text-3xl font-black text-rose-600 tracking-tighter">Ôé╣{Number(stats.overdueAmount || 0).toLocaleString('en-IN', { minimumFractionDigits: 0 })}</div>
                        <p className="text-[10px] text-rose-500 mt-2 font-black uppercase tracking-widest bg-rose-50 w-fit px-2 py-0.5 rounded-lg">Critical Alert</p>
                    </CardContent>
                </Card>
                <Card className="bg-white border-slate-200 shadow-sm hover:shadow-xl hover:shadow-blue-500/5 transition-all rounded-3xl overflow-hidden border-b-4 border-b-blue-500 border-none group">
                    <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
                        <CardTitle className="text-[10px] font-black uppercase tracking-[0.2em] text-slate-600">Indirect Tax</CardTitle>
                        <div className="p-2.5 bg-blue-50 rounded-2xl group-hover:scale-110 transition-transform">
                            <Receipt className="h-4 w-4 text-blue-600" />
                        </div>
                    </CardHeader>
                    <CardContent>
                        <div className="text-3xl font-black text-blue-600 tracking-tighter">Ôé╣{Number(stats.gstLiability || 0).toLocaleString('en-IN', { minimumFractionDigits: 0 })}</div>
                        <p className="text-[10px] text-slate-600 mt-2 font-black uppercase tracking-widest">GST Obligation</p>
                    </CardContent>
                </Card>
            </div>

            {/* Data Layer */}
            <div className="grid gap-6 lg:grid-cols-3">
                <div className="lg:col-span-2">
                    <ForecastingWidget />
                </div>
                <div className="lg:col-span-1">
                    <CollaborationTimeline resourceType="Accounting" resourceId="Global" />
                </div>
            </div>

            {/* Top Debtors Section */}
            {stats.topDebtors && stats.topDebtors.length > 0 && (
                <div className="grid gap-6 md:grid-cols-2">
                    <Card className="bg-white border-slate-200 shadow-xl shadow-slate-200/40 rounded-[32px] overflow-hidden border-none group">
                        <CardHeader className="bg-slate-50/50 border-b border-slate-100 py-6 px-8">
                            <CardTitle className="text-slate-900 text-xl font-black tracking-tight">Top Overdue Customers</CardTitle>
                            <CardDescription className="text-slate-500 font-medium mt-1">Customers with outstanding payments requiring follow-up.</CardDescription>
                        </CardHeader>
                        <CardContent className="p-8">
                            <div className="space-y-6">
                                {stats.topDebtors.map((d: any, i: number) => (
                                    <div key={i} className="flex items-center justify-between border-b border-slate-50 pb-5 last:border-0 hover:translate-x-1 transition-transform">
                                        <div className="flex items-center gap-5">
                                            <div className="h-12 w-12 rounded-2xl bg-slate-900 flex items-center justify-center text-xs font-black text-white shadow-lg shadow-slate-900/10">
                                                {String(i + 1).padStart(2, '0')}
                                            </div>
                                            <div>
                                                <span className="text-slate-900 font-black tracking-tight text-lg leading-tight block">{d.name}</span>
                                                <span className="text-[10px] text-slate-600 font-black uppercase tracking-widest">Active Debtor</span>
                                            </div>
                                        </div>
                                        <div className="text-right">
                                            <span className="text-rose-600 font-black text-xl italic tracking-tighter block">Ôé╣{d.amount.toLocaleString('en-IN')}</span>
                                            <Badge variant="secondary" className="bg-rose-50 text-rose-500 font-black text-[9px] border-none uppercase tracking-widest px-2 py-0.5 mt-1">Aging: {d.aging || 30}+ Days</Badge>
                                        </div>
                                    </div>
                                ))}
                            </div>
                        </CardContent>
                    </Card>
                </div>
            )}

            <Tabs defaultValue="invoices" className="space-y-6">
                <TabsList className="bg-slate-100 border-slate-200 overflow-x-auto flex justify-start w-full scrollbar-hide h-auto p-1.5 rounded-2xl snap-x">
                    <TabsTrigger value="invoices" className="snap-start data-[state=active]:bg-white data-[state=active]:text-amber-600 data-[state=active]:shadow-sm rounded-xl px-6 py-2.5 font-bold transition-all whitespace-nowrap">Invoices</TabsTrigger>
                    <TabsTrigger value="accounts" className="snap-start data-[state=active]:bg-white data-[state=active]:text-amber-600 data-[state=active]:shadow-sm rounded-xl px-6 py-2.5 font-bold transition-all whitespace-nowrap">Accounts</TabsTrigger>
                    <TabsTrigger value="transactions" className="snap-start data-[state=active]:bg-white data-[state=active]:text-amber-600 data-[state=active]:shadow-sm rounded-xl px-6 py-2.5 font-bold transition-all whitespace-nowrap">Transactions</TabsTrigger>
                    <TabsTrigger value="assets" className="snap-start data-[state=active]:bg-white data-[state=active]:text-amber-600 data-[state=active]:shadow-sm rounded-xl px-6 py-2.5 font-bold transition-all whitespace-nowrap">Fixed Assets</TabsTrigger>
                    <TabsTrigger value="auditor" className="snap-start data-[state=active]:bg-white data-[state=active]:text-amber-600 data-[state=active]:shadow-sm rounded-xl px-6 py-2.5 font-bold transition-all whitespace-nowrap">Auditor</TabsTrigger>
                    <TabsTrigger value="health" className="snap-start data-[state=active]:bg-white data-[state=active]:text-amber-600 data-[state=active]:shadow-sm rounded-xl px-6 py-2.5 font-bold transition-all whitespace-nowrap">Store Health</TabsTrigger>
                </TabsList>

                <TabsContent value="invoices" className="space-y-4">
                    <Card className="bg-white border-slate-200 shadow-xl shadow-slate-200/40 rounded-3xl overflow-hidden">
                        <CardHeader className="border-b border-slate-100 bg-slate-50/50 py-6">
                            <div className="flex flex-col lg:flex-row lg:items-center justify-between gap-6">
                                <div>
                                    <CardTitle className="text-slate-900 text-xl font-black">Sales Invoices</CardTitle>
                                    <CardDescription className="text-slate-500 font-medium">Track and manage customer invoices and payments.</CardDescription>
                                </div>
                                <div className="relative w-full md:w-96">
                                    <Search className="absolute left-4 top-3.5 h-4 w-4 text-slate-600" />
                                    <input
                                        placeholder="Search by invoice number or customer name..."
                                        className="w-full pl-12 h-11 bg-white border border-slate-200 rounded-2xl text-slate-900 text-sm font-semibold focus:outline-none focus:ring-2 focus:ring-amber-500/20 shadow-inner"
                                        value={searchQuery}
                                        onChange={(e) => setSearchQuery(e.target.value)}
                                    />
                                </div>
                            </div>
                        </CardHeader>
                        <CardContent className="p-0">
                            <Table>
                                <TableHeader>
                                    <TableRow className="border-slate-100 hover:bg-transparent bg-slate-50/20">
                                        <TableHead className="text-slate-600 font-bold uppercase text-[10px] tracking-widest pl-6">Invoice #</TableHead>
                                        <TableHead className="text-slate-600 font-bold uppercase text-[10px] tracking-widest">Customer</TableHead>
                                        <TableHead className="text-slate-600 font-bold uppercase text-[10px] tracking-widest">Date</TableHead>
                                        <TableHead className="text-slate-600 font-bold uppercase text-[10px] tracking-widest">Amount</TableHead>
                                        <TableHead className="text-slate-600 font-bold uppercase text-[10px] tracking-widest">Status</TableHead>
                                        <TableHead className="text-slate-600 font-bold uppercase text-[10px] tracking-widest text-right pr-6">Actions</TableHead>
                                    </TableRow>
                                </TableHeader>
                                <TableBody>
                                    {filteredInvoices.map((inv) => (
                                        <TableRow key={inv.id} className="border-slate-100 hover:bg-slate-50 transition-all group">
                                            <TableCell className="font-mono text-slate-600 text-xs pl-6 font-bold">#{inv.invoiceNumber}</TableCell>
                                            <TableCell className="font-black text-slate-800 tracking-tight">{[inv.customer?.firstName, inv.customer?.lastName].filter(Boolean).join(" ")}</TableCell>
                                            <TableCell className="text-slate-500 text-sm font-semibold">{new Date(inv.issueDate).toLocaleDateString()}</TableCell>
                                            <TableCell className="font-black text-slate-900">Ôé╣{Number(inv.totalAmount).toLocaleString('en-IN', { minimumFractionDigits: 2 })}</TableCell>
                                            <TableCell>
                                                <Badge variant={inv.status === 'Paid' ? 'default' : 'outline'} className={inv.status === 'Paid' ? "bg-emerald-100 text-emerald-700 border-none font-bold shadow-sm" : "border-slate-200 text-slate-500 font-bold"}>
                                                    {inv.status.toUpperCase()}
                                                </Badge>
                                            </TableCell>
                                            <TableCell className="text-right pr-6">
                                                <div className="flex items-center justify-end gap-2">
                                                    <Button
                                                        variant="ghost"
                                                        size="icon"
                                                        className="h-9 w-9 text-slate-600 hover:text-slate-900 hover:bg-slate-100 rounded-xl transition-all"
                                                        onClick={() => window.open(`/invoice/${inv.id}`, '_blank')}
                                                        title="Print Invoice"
                                                    >
                                                        <Printer className="h-4 w-4" />
                                                    </Button>
                                                    <Button
                                                        variant="ghost"
                                                        size="icon"
                                                        className="h-9 w-9 text-emerald-500 hover:text-emerald-700 hover:bg-emerald-50 rounded-xl transition-all"
                                                        onClick={() => {
                                                            const phone = inv.customer?.phone?.replace(/[^0-9]/g, '') || "";
                                                            const text = `Invoice #${inv.invoiceNumber} for Ôé╣${Number(inv.totalAmount).toLocaleString('en-IN')}. View here: ${window.location.origin}/invoice/${inv.id}`;
                                                            window.open(`https://wa.me/${phone}?text=${encodeURIComponent(text)}`, '_blank');
                                                        }}
                                                        title="Share on WhatsApp"
                                                    >
                                                        <MessageCircle className="h-4 w-4" />
                                                    </Button>
                                                    {inv.status !== 'Paid' && inv.status !== 'Cancelled' && (
                                                        <Button
                                                            variant="default"
                                                            size="sm"
                                                            onClick={() => setSelectedInvoice(inv)}
                                                            className="bg-amber-600 hover:bg-amber-700 text-white font-bold rounded-xl h-8 px-4 shadow-md shadow-amber-600/20"
                                                        >
                                                            Tag Payment
                                                        </Button>
                                                    )}
                                                    {inv.status !== 'Cancelled' && (
                                                        <Button
                                                            variant="ghost"
                                                            size="icon"
                                                            className="h-9 w-9 text-rose-500 hover:text-rose-700 hover:bg-rose-50 rounded-xl transition-all"
                                                            onClick={() => handleCancelInvoice(inv.id)}
                                                            title="Cancel Invoice"
                                                        >
                                                            <Ban className="h-4 w-4" />
                                                        </Button>
                                                    )}
                                                </div>
                                            </TableCell>
                                        </TableRow>
                                    ))}
                                    {filteredInvoices.length === 0 && !loading && (
                                        <TableRow>
                                            <TableCell colSpan={6} className="py-12 px-6">
                                                <EmptyState 
                                                    icon={Receipt}
                                                    title="No Invoices Found"
                                                    description="You haven't issued any tax invoices yet. Start by creating your first compliant invoice."
                                                    actionText="Issue New Invoice"
                                                    onAction={() => setShowCreateInvoice(true)}
                                                />
                                            </TableCell>
                                        </TableRow>
                                    )}
                                </TableBody>
                            </Table>
                            <div className="flex justify-between items-center p-4 border-t border-slate-100 bg-slate-50/50">
                                <Button variant="outline" size="sm" onClick={() => setInvoicePage(p => Math.max(1, p - 1))} disabled={invoicePage === 1} className="text-slate-500 border-slate-200 hover:bg-white">Previous</Button>
                                <span className="text-xs text-slate-500 font-medium tracking-tight">Page {invoicePage} of {invoiceTotalPages}</span>
                                <Button variant="outline" size="sm" onClick={() => setInvoicePage(p => Math.min(invoiceTotalPages, p + 1))} disabled={invoicePage === invoiceTotalPages} className="text-slate-500 border-slate-200 hover:bg-white">Next</Button>
                            </div>
                        </CardContent>
                    </Card>
                </TabsContent>

                <TabsContent value="accounts" className="space-y-4">
                    <Card className="bg-white border-slate-200 shadow-xl shadow-slate-200/40 rounded-3xl overflow-hidden border-none">
                        <CardHeader className="bg-slate-50 border-b border-slate-100 py-8 px-8">
                            <div className="flex items-center justify-between">
                                <div>
                                    <CardTitle className="text-slate-900 text-xl font-black">Chart of Accounts</CardTitle>
                                    <CardDescription className="text-slate-500 font-medium">All company accounts and current balances.</CardDescription>
                                </div>
                                <Button onClick={() => setShowCreateAccount(true)} className="bg-amber-500 hover:bg-amber-600 font-bold shadow-lg shadow-amber-500/20 text-white">
                                    <Plus className="mr-2 h-4 w-4" /> Add Account
                                </Button>
                            </div>
                        </CardHeader>
                        <CardContent className="p-0 overflow-x-auto max-w-[100vw] sm:max-w-none">
                            <Table className="min-w-[700px]">
                                <TableHeader className="bg-slate-50/50">
                                    <TableRow className="border-slate-100 hover:bg-transparent">
                                        <TableHead className="text-slate-600 font-bold uppercase text-[10px] tracking-widest pl-8">Code</TableHead>
                                        <TableHead className="text-slate-600 font-bold uppercase text-[10px] tracking-widest">Account Name</TableHead>
                                        <TableHead className="text-slate-600 font-bold uppercase text-[10px] tracking-widest">Type</TableHead>
                                        <TableHead className="text-slate-600 font-bold uppercase text-[10px] tracking-widest text-right pr-8">Balance</TableHead>
                                    </TableRow>
                                </TableHeader>
                                <TableBody>
                                    {accounts.map((acc) => (
                                        <TableRow key={acc.id} className="border-slate-100 hover:bg-slate-50/50 transition-all group">
                                            <TableCell className="pl-8 font-mono text-sm text-slate-600 font-semibold">{acc.code}</TableCell>
                                            <TableCell className="font-semibold text-slate-900">{acc.name}</TableCell>
                                            <TableCell>
                                                <Badge variant="secondary" className="bg-slate-100 text-slate-600 font-semibold text-xs rounded-lg border-none">{acc.type}</Badge>
                                            </TableCell>
                                            <TableCell className="text-right pr-8 font-black text-slate-900 text-lg">
                                                Ôé╣{Number(acc.balance).toLocaleString('en-IN', { minimumFractionDigits: 0 })}
                                            </TableCell>
                                        </TableRow>
                                    ))}
                                    {accounts.length === 0 && (
                                        <TableRow>
                                            <TableCell colSpan={4} className="text-center py-20 text-slate-400 font-medium italic">No accounts found.</TableCell>
                                        </TableRow>
                                    )}
                                </TableBody>
                            </Table>
                        </CardContent>
                    </Card>
                </TabsContent>

                <TabsContent value="transactions" className="space-y-4">
                    <Card className="bg-white border-slate-200 shadow-xl shadow-slate-200/40 rounded-3xl overflow-hidden border-none">
                        <CardHeader className="bg-slate-50 border-b border-slate-100 py-8 px-8">
                            <div className="flex items-center justify-between">
                                <div>
                                    <CardTitle className="text-slate-900 text-xl font-black">Transaction Journal</CardTitle>
                                    <CardDescription className="text-slate-500 font-medium">Complete record of all financial transactions.</CardDescription>
                                </div>
                                <Button onClick={() => setShowCreateJournalEntry(true)} className="bg-amber-500 hover:bg-amber-600 font-bold shadow-lg shadow-amber-500/20 text-white">
                                    <Plus className="mr-2 h-4 w-4" /> New Journal Entry
                                </Button>
                            </div>
                        </CardHeader>
                        <CardContent className="p-0 overflow-x-auto max-w-[100vw] sm:max-w-none">
                            <Table className="min-w-[600px]">
                                <TableHeader className="bg-slate-50/50">
                                    <TableRow className="border-slate-100 hover:bg-transparent">
                                        <TableHead className="text-slate-600 font-bold uppercase text-[10px] tracking-widest pl-8">Date</TableHead>
                                        <TableHead className="text-slate-600 font-bold uppercase text-[10px] tracking-widest">Account / Party</TableHead>
                                        <TableHead className="text-slate-600 font-bold uppercase text-[10px] tracking-widest">Type</TableHead>
                                        <TableHead className="text-slate-600 font-bold uppercase text-[10px] tracking-widest text-right pr-8">Amount</TableHead>
                                    </TableRow>
                                </TableHeader>
                                <TableBody>
                                    {transactions.map((tx) => (
                                        <TableRow key={tx.id} className="border-slate-100 hover:bg-slate-50/50 transition-all group">
                                            <TableCell className="pl-8 font-black text-[10px] text-slate-600 tracking-widest">{new Date(tx.date).toLocaleDateString()}</TableCell>
                                            <TableCell className="font-black text-slate-900 tracking-tight">{tx.account?.name}</TableCell>
                                            <TableCell className="text-slate-500 font-bold text-xs italic">"{tx.description}"</TableCell>
                                            <TableCell className={`text-right pr-8 font-black text-lg ${tx.type === 'Credit' ? "text-emerald-600" : "text-rose-600"}`}>
                                                {tx.type === 'Credit' ? 'Ôû▓' : 'Ôû╝'} Ôé╣{Number(tx.amount).toLocaleString('en-IN', { minimumFractionDigits: 0 })}
                                            </TableCell>
                                        </TableRow>
                                    ))}
                                    {transactions.length === 0 && (
                                        <TableRow>
                                            <TableCell colSpan={4} className="text-center py-20 text-slate-400 font-medium italic">No transactions recorded yet.</TableCell>
                                        </TableRow>
                                    )}
                                </TableBody>
                            </Table>
                        </CardContent>
                    </Card>
                </TabsContent>

                <TabsContent value="assets">
                    <FixedAssetTab />
                </TabsContent>
                <TabsContent value="auditor">
                    <AuditorDashboard />
                </TabsContent>
                <TabsContent value="health" className="space-y-4">
                    <Card className="bg-white border-slate-200 shadow-xl shadow-slate-200/40 rounded-3xl overflow-hidden border-none">
                        <CardHeader className="bg-slate-50 border-b border-slate-100 py-8 px-8">
                            <CardTitle className="text-slate-900 text-xl font-black">Store Health Profile</CardTitle>
                            <CardDescription className="text-slate-500 font-bold uppercase text-[10px] tracking-widest mt-1">Financial health and payment discipline overview</CardDescription>
                        </CardHeader>
                        <CardContent className="p-8">
                            {healthScore && (
                                <div className="space-y-12">
                                    <div className="grid gap-6 md:grid-cols-3">
                                        <div className="p-8 rounded-[32px] bg-slate-900 border border-slate-800 flex flex-col items-center justify-center text-center shadow-2xl relative overflow-hidden group">
                                            <div className="absolute inset-0 bg-blue-600/5 group-hover:bg-blue-600/10 transition-colors" />
                                            <p className="text-[10px] text-slate-600 mb-4 uppercase font-black tracking-[0.2em] relative z-10">Accuracy Rating</p>
                                            <div className="relative z-10">
                                                <span className={`text-6xl font-black tracking-tighter ${healthScore.status === 'RED' ? 'text-rose-500' : healthScore.status === 'YELLOW' ? 'text-amber-500' : 'text-blue-500'}`}>
                                                    {100 - healthScore.riskScore}%
                                                </span>
                                            </div>
                                            <Badge className={`mt-6 rounded-xl font-black text-[10px] uppercase tracking-widest px-4 py-1.5 border-none relative z-10 ${healthScore.status === 'RED' ? 'bg-rose-500/20 text-rose-400' : healthScore.status === 'YELLOW' ? 'bg-amber-500/20 text-amber-500' : 'bg-blue-500/20 text-blue-400'}`}>
                                                {healthScore.status} STATUS
                                            </Badge>
                                        </div>
                                        <div className="p-8 rounded-[32px] bg-white border border-slate-100 shadow-sm flex flex-col justify-center">
                                            <p className="text-[10px] text-slate-600 mb-2 uppercase font-black tracking-widest">Entry Delay</p>
                                            <p className="text-4xl font-black text-slate-900 tracking-tighter">{healthScore.metrics.avgEntryLag} <span className="text-xs font-bold text-slate-400">MINS</span></p>
                                            <div className="h-1.5 w-full bg-slate-100 rounded-full mt-4 overflow-hidden">
                                                <div className="h-full bg-blue-600 w-[40%]" />
                                            </div>
                                        </div>
                                        <div className="p-8 rounded-[32px] bg-white border border-slate-100 shadow-sm flex flex-col justify-center">
                                            <p className="text-[10px] text-slate-600 mb-2 uppercase font-black tracking-widest">Fulfillment Ratio</p>
                                            <p className="text-4xl font-black text-slate-900 tracking-tighter">{healthScore.metrics.taggingRatio}</p>
                                            <div className="h-1.5 w-full bg-slate-100 rounded-full mt-4 overflow-hidden">
                                                <div className="h-full bg-emerald-500 w-[85%]" />
                                            </div>
                                        </div>
                                    </div>

                                    <div className="space-y-6">
                                        <h4 className="text-[10px] font-black text-slate-600 uppercase tracking-[0.2em] flex items-center gap-4">
                                            Health Alerts
                                            <div className="h-px flex-1 bg-slate-100" />
                                        </h4>
                                        {healthScore.signals.length > 0 ? (
                                            <div className="grid gap-3">
                                                {healthScore.signals.map((s: string, i: number) => (
                                                    <div key={i} className="flex items-center gap-4 p-5 rounded-2xl bg-slate-50/50 border border-slate-100 group hover:border-blue-500/20 transition-all">
                                                        <div className="h-2 w-2 rounded-full bg-blue-600 animate-pulse" />
                                                        <span className="text-xs text-slate-600 font-bold uppercase tracking-tight">{s}</span>
                                                    </div>
                                                ))}
                                            </div>
                                        ) : (
                                            <div className="text-center py-16 bg-slate-50 rounded-[32px] border border-dashed border-slate-200">
                                                <p className="text-blue-600 font-black text-sm uppercase tracking-widest">All Good!</p>
                                                <p className="text-[10px] text-slate-400 font-bold mt-2 uppercase">No issues found in the current period</p>
                                            </div>
                                        )}
                                    </div>

                                    <div className="grid gap-8 md:grid-cols-2">
                                        <Card className="bg-white border-slate-200 shadow-xl shadow-slate-200/40 rounded-[32px] overflow-hidden border-none">
                                            <CardHeader className="bg-slate-50 border-b border-slate-100 py-6 px-8">
                                                <CardTitle className="text-slate-900 text-lg font-black tracking-tight flex items-center gap-3">
                                                    <div className="p-2 bg-blue-50 rounded-xl">
                                                        <Users className="h-5 w-5 text-blue-600" />
                                                    </div>
                                                    Staff Efficiency Index
                                                </CardTitle>
                                            </CardHeader>
                                            <CardContent className="p-8">
                                                <div className="space-y-6">
                                                    {leaderboard.map((u, i) => (
                                                        <div key={i} className="flex items-center justify-between border-b border-slate-50 pb-4 last:border-0 hover:translate-x-1 transition-transform">
                                                            <div className="flex items-center gap-4">
                                                                <div className="h-10 w-10 rounded-xl bg-slate-100 flex items-center justify-center font-black text-slate-500 text-xs">{(i + 1).toString().padStart(2, '0')}</div>
                                                                <span className="text-slate-900 font-black tracking-tight">{u.name}</span>
                                                            </div>
                                                            <div className="text-right">
                                                                <p className="text-sm text-slate-900 font-black">{u.invoices} SALES</p>
                                                                <p className="text-[10px] text-slate-600 font-black uppercase tracking-widest">{u.avgLag}M LAG</p>
                                                            </div>
                                                        </div>
                                                    ))}
                                                </div>
                                            </CardContent>
                                        </Card>

                                        <Card className="bg-white border-slate-200 shadow-xl shadow-slate-200/40 rounded-[32px] overflow-hidden border-none">
                                            <CardHeader className="bg-slate-50 border-b border-slate-100 py-6 px-8">
                                                <CardTitle className="text-slate-900 text-lg font-black tracking-tight flex items-center gap-3">
                                                    <div className="p-2 bg-amber-50 rounded-xl">
                                                        <Activity className="h-5 w-5 text-amber-600" />
                                                    </div>
                                                    Inactive Customers
                                                </CardTitle>
                                            </CardHeader>
                                            <CardContent className="p-8">
                                                <div className="space-y-6">
                                                    {recoveryMemory && (recoveryMemory as any).opportunities?.map((c: any, i: number) => (
                                                        <div key={i} className="flex items-center justify-between p-5 rounded-2xl bg-slate-50/50 border border-slate-100 transition-all hover:bg-white hover:shadow-lg hover:shadow-blue-500/5 group">
                                                            <div>
                                                                <p className="text-slate-900 font-black tracking-tight">{c.name}</p>
                                                                <p className="text-[10px] text-slate-600 font-black uppercase tracking-widest mt-1">{c.daysSilent} DAYS SINCE LAST ORDER</p>
                                                            </div>
                                                            <Button
                                                                variant="default"
                                                                size="sm"
                                                                className="bg-slate-900 hover:bg-blue-600 text-white font-black text-[9px] h-9 rounded-xl border-none shadow-lg shadow-slate-900/10 px-4 uppercase tracking-[0.2em] transition-all"
                                                                onClick={() => window.open(`https://wa.me/${c.phone?.replace(/[^0-9]/g, '')}?text=Hi ${c.name}, hope you are doing well!`, '_blank')}
                                                            >
                                                                Reconnect
                                                            </Button>
                                                        </div>
                                                    ))}
                                                    {(!recoveryMemory || ((recoveryMemory as any).opportunities?.length === 0)) && (
                                                        <div className="text-center py-16 bg-slate-50/50 rounded-3xl border border-dashed border-slate-200">
                                                            <p className="text-[10px] text-slate-400 font-black uppercase tracking-widest">All caught up</p>
                                                        </div>
                                                    )}
                                                </div>
                                            </CardContent>
                                        </Card>
                                    </div>
                                </div>
                            )}
                        </CardContent>
                    </Card>
                </TabsContent>
            </Tabs>

            <RecordPaymentModal
                invoice={selectedInvoice}
                isOpen={!!selectedInvoice}
                onClose={() => setSelectedInvoice(null)}
                onSuccess={syncLedgers}
            />

            <CreateInvoiceDialog
                isOpen={showCreateInvoice}
                onClose={() => setShowCreateInvoice(false)}
                onSuccess={syncLedgers}
            />

            <CreateAccountDialog
                open={showCreateAccount}
                onOpenChange={setShowCreateAccount}
                onSuccess={syncLedgers}
            />

            <CreateJournalEntryDialog
                open={showCreateJournalEntry}
                onOpenChange={setShowCreateJournalEntry}
                onSuccess={syncLedgers}
                accounts={accounts}
            />
        </div >

    );
}

"use client";

import React, { useState, useEffect } from "react";
import { api } from "@/lib/api";
import { toast } from "sonner";
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";
import { LoadingSpinner } from "@/components/ui/loading-spinner";
import { Badge } from "@/components/ui/badge";
import {
    Table, TableBody, TableCell, TableHead, TableHeader, TableRow,
} from "@/components/ui/table";
import { BarChart2, CheckCircle2, AlertCircle, TrendingUp, TrendingDown } from "lucide-react";

export default function ReportsPage() {
    const [trialBalance, setTrialBalance] = useState<any>(null);
    const [profitLoss, setProfitLoss] = useState<any>(null);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        const load = async () => {
            try {
                setLoading(true);
                const [tbRes, plRes] = await Promise.all([
                    api.get("/accounting/reports/trial-balance"),
                    api.get("/accounting/reports/profit-loss"),
                ]);
                setTrialBalance(tbRes.data);
                setProfitLoss(plRes.data);
            } catch (err) {
                toast.error("Failed to load financial reports");
            } finally {
                setLoading(false);
            }
        };
        load();
    }, []);

    const fmtINR = (val: any) =>
        Number(val).toLocaleString("en-IN", { style: "currency", currency: "INR", maximumFractionDigits: 2 });

    if (loading) return <LoadingSpinner className="h-full" text="Loading financial reports..." />;

    return (
        <div className="flex-1 space-y-6 md:space-y-8 pt-2 md:pt-6 px-4 md:px-8 w-full max-w-full overflow-hidden">
            <div>
                <h2 className="text-4xl font-black tracking-tight text-slate-900 flex items-center">
                    <BarChart2 className="mr-4 h-9 w-9 text-violet-600" />
                    Financial Reports
                </h2>
                <p className="text-slate-500 mt-2 font-medium">Core accounting reports for compliance and period-end review.</p>
            </div>

            <Tabs defaultValue="trial-balance" className="space-y-6">
                <TabsList className="bg-slate-100 p-1.5 rounded-2xl h-auto">
                    <TabsTrigger value="trial-balance" className="data-[state=active]:bg-white data-[state=active]:text-violet-600 data-[state=active]:shadow-sm rounded-xl px-6 py-2.5 font-bold">
                        Trial Balance
                    </TabsTrigger>
                    <TabsTrigger value="profit-loss" className="data-[state=active]:bg-white data-[state=active]:text-violet-600 data-[state=active]:shadow-sm rounded-xl px-6 py-2.5 font-bold">
                        Profit & Loss
                    </TabsTrigger>
                </TabsList>

                {/* --- TRIAL BALANCE --- */}
                <TabsContent value="trial-balance">
                    <Card className="rounded-3xl border-none shadow-xl shadow-slate-200/40">
                        <CardHeader className="bg-slate-50 border-b border-slate-100 py-6 px-6">
                            <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4">
                                <div>
                                    <CardTitle className="text-xl font-black text-slate-900">Trial Balance</CardTitle>
                                    <CardDescription className="text-[10px] uppercase tracking-widest font-bold text-slate-500 mt-1">
                                        All accounts as of today
                                    </CardDescription>
                                </div>
                                {trialBalance && (
                                    <div className={`flex items-center gap-2 px-4 py-2 rounded-2xl text-sm font-bold ${trialBalance.balanced ? "bg-emerald-50 text-emerald-700" : "bg-red-50 text-red-700"}`}>
                                        {trialBalance.balanced ? (
                                            <><CheckCircle2 className="h-4 w-4" /> Balanced</>
                                        ) : (
                                            <><AlertCircle className="h-4 w-4" /> Out of Balance</>
                                        )}
                                    </div>
                                )}
                            </div>
                        </CardHeader>
                        <CardContent className="p-0 overflow-x-auto max-w-[100vw]">
                            <Table className="min-w-[600px]">
                                <TableHeader className="bg-slate-50/50">
                                    <TableRow className="border-slate-100 hover:bg-transparent">
                                        <TableHead className="pl-8 text-[10px] font-black uppercase tracking-widest text-slate-500">Account Name</TableHead>
                                        <TableHead className="text-[10px] font-black uppercase tracking-widest text-slate-500">Type</TableHead>
                                        <TableHead className="text-right text-[10px] font-black uppercase tracking-widest text-slate-500">Debit (Dr)</TableHead>
                                        <TableHead className="text-right pr-8 text-[10px] font-black uppercase tracking-widest text-slate-500">Credit (Cr)</TableHead>
                                    </TableRow>
                                </TableHeader>
                                <TableBody>
                                    {(trialBalance?.accounts || []).map((acct: any) => (
                                        <TableRow key={acct.id} className="border-slate-100 hover:bg-slate-50/50">
                                            <TableCell className="pl-8 font-bold text-slate-900 truncate max-w-[200px]" title={acct.name}>{acct.name}</TableCell>
                                            <TableCell>
                                                <Badge variant="secondary" className="bg-slate-100 text-slate-500 text-[9px] font-black uppercase rounded-md border-none tracking-tighter">
                                                    {acct.type}
                                                </Badge>
                                            </TableCell>
                                            <TableCell className="text-right font-mono text-slate-700">
                                                {Number(acct.debit) > 0 ? fmtINR(acct.debit) : "-"}
                                            </TableCell>
                                            <TableCell className="text-right pr-8 font-mono text-slate-700">
                                                {Number(acct.credit) > 0 ? fmtINR(acct.credit) : "-"}
                                            </TableCell>
                                        </TableRow>
                                    ))}
                                </TableBody>
                            </Table>
                            {/* Totals Row */}
                            {trialBalance && (
                                <div className="border-t-2 border-slate-900 py-4 px-8 flex justify-end gap-16 bg-slate-50">
                                    <div className="text-right">
                                        <div className="text-[10px] font-black uppercase tracking-widest text-slate-400 mb-1">Total Dr</div>
                                        <div className="font-mono font-black text-slate-900 text-lg">{fmtINR(trialBalance.totalDebit)}</div>
                                    </div>
                                    <div className="text-right">
                                        <div className="text-[10px] font-black uppercase tracking-widest text-slate-400 mb-1">Total Cr</div>
                                        <div className="font-mono font-black text-slate-900 text-lg">{fmtINR(trialBalance.totalCredit)}</div>
                                    </div>
                                </div>
                            )}
                        </CardContent>
                    </Card>
                </TabsContent>

                {/* --- PROFIT & LOSS --- */}
                <TabsContent value="profit-loss">
                    <div className="grid lg:grid-cols-3 gap-6 mb-8">
                        <Card className={`rounded-3xl border-none shadow-xl col-span-1 overflow-hidden ${profitLoss?.isProfitable ? "bg-emerald-600" : "bg-red-600"} text-white`}>
                            <CardContent className="p-8 flex flex-col gap-2 h-full justify-center">
                                <div className="text-[10px] font-black uppercase tracking-widest text-white/70">Net Profit / (Loss)</div>
                                <div className="text-4xl font-black tracking-tighter">
                                    {fmtINR(profitLoss?.netProfit || 0)}
                                </div>
                                <div className="flex items-center gap-2 text-sm font-bold text-white/80 mt-2">
                                    {profitLoss?.isProfitable ? <TrendingUp className="h-4 w-4" /> : <TrendingDown className="h-4 w-4" />}
                                    {profitLoss?.isProfitable ? "Profitable Period" : "Loss Period"}
                                </div>
                            </CardContent>
                        </Card>

                        <Card className="rounded-3xl border-none shadow-xl lg:col-span-2 overflow-hidden">
                            <CardContent className="p-0">
                                {/* Revenue Section */}
                                <div className="p-6 border-b border-slate-100">
                                    <div className="text-[10px] font-black uppercase tracking-widest text-slate-400 mb-4">Income / Revenue</div>
                                    {(profitLoss?.revenue || []).map((a: any) => (
                                        <div key={a.id} className="flex justify-between items-center py-2">
                                            <span className="font-medium text-slate-700">{a.name}</span>
                                            <span className="font-mono font-bold text-emerald-700">{fmtINR(a.balance)}</span>
                                        </div>
                                    ))}
                                    <div className="flex justify-between items-center pt-4 mt-2 border-t border-dashed border-slate-200">
                                        <span className="font-black text-slate-900 text-sm uppercase tracking-wider">Total Revenue</span>
                                        <span className="font-mono font-black text-emerald-700 text-lg">{fmtINR(profitLoss?.totalRevenue || 0)}</span>
                                    </div>
                                </div>

                                {/* Expense Section */}
                                <div className="p-6">
                                    <div className="text-[10px] font-black uppercase tracking-widest text-slate-400 mb-4">Expenses</div>
                                    {(profitLoss?.expenses || []).map((a: any) => (
                                        <div key={a.id} className="flex justify-between items-center py-2">
                                            <span className="font-medium text-slate-700">{a.name}</span>
                                            <span className="font-mono font-bold text-red-700">{fmtINR(a.balance)}</span>
                                        </div>
                                    ))}
                                    <div className="flex justify-between items-center pt-4 mt-2 border-t border-dashed border-slate-200">
                                        <span className="font-black text-slate-900 text-sm uppercase tracking-wider">Total Expenses</span>
                                        <span className="font-mono font-black text-red-700 text-lg">{fmtINR(profitLoss?.totalExpense || 0)}</span>
                                    </div>
                                </div>
                            </CardContent>
                        </Card>
                    </div>
                </TabsContent>
            </Tabs>
        </div>
    );
}

"use client";

import { useEffect, useState } from "react";
import { useParams, useRouter } from "next/navigation";
import { api } from "@/lib/api";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card";
import {
    ChevronLeft,
    Download,
    Trash2,
    Globe,
    Github,
    Package,
    History,
    ShieldAlert,
    Verified,
    ExternalLink
} from "lucide-react";
import { toast } from "sonner";
import { Badge } from "@/components/ui/badge";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";

export default function AppDetailPage() {
    const params = useParams();
    const router = useRouter();
    const appName = params.name as string;
    const [app, setApp] = useState<any>(null);
    const [loading, setLoading] = useState(true);

    const syncAppData = async (showLoading = false) => {
        try {
            if (showLoading) setLoading(true);
            const res = await api.get("/system/apps");
            const found = res.data.find((a: any) => a.name === appName);
            setApp(found);
        } catch (err) {
            console.error("Manifest Sync Failure:", err);
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        syncAppData(true);
        const interval = setInterval(() => syncAppData(false), 30000);
        return () => clearInterval(interval);
    }, [appName]);

    const handleInstall = async () => {
        try {
            await api.post(`/system/apps/${appName}/install`);
            toast.success(`${app.label} activated successfully`);
            syncAppData(true);
        } catch (err) {
            toast.error("Installation failed");
        }
    };

    const handleUninstall = async () => {
        try {
            await api.post(`/system/apps/${appName}/uninstall`);
            toast.success(`${app.label} removed successfully`);
            syncAppData(true);
        } catch (err) {
            toast.error("Removal error");
        }
    };

    if (loading) return <div className="p-8 text-slate-400 font-black uppercase tracking-widest italic animate-pulse">Loading Details...</div>;
    if (!app) return <div className="p-8 text-slate-900 bg-slate-50 min-h-screen font-black uppercase tracking-widest uppercase italic">Module [${appName}] not found in Klypso Store.</div>;

    return (
        <div className="flex-1 space-y-8 md:space-y-10 p-4 md:p-10 pt-4 md:pt-8 bg-slate-50/30 min-h-screen">
            <Button
                variant="ghost"
                onClick={() => router.back()}
                className="text-slate-500 hover:text-slate-900 font-bold hover:bg-slate-100/50 rounded-xl"
            >
                <ChevronLeft className="mr-2 h-4 w-4" /> Back to Marketplace
            </Button>

            <div className="flex flex-col xl:flex-row gap-12">
                <div className="flex-1 space-y-10">
                    <div className="flex flex-col lg:flex-row items-start justify-between gap-8 md:gap-0">
                        <div className="flex flex-col sm:flex-row gap-6 sm:gap-8 items-start sm:items-center">
                            <div className="h-24 w-24 sm:h-28 sm:w-28 shrink-0 rounded-[32px] bg-gradient-to-br from-blue-600 to-indigo-700 flex items-center justify-center border-none shadow-2xl shadow-blue-500/30">
                                <Package className="h-12 w-12 text-white" />
                            </div>
                            <div className="space-y-3">
                                <div className="flex items-center gap-3">
                                    <h1 className="text-5xl font-black text-slate-900 tracking-tighter">{app.label}</h1>
                                    <Verified className="h-6 w-6 text-blue-500" />
                                </div>
                                <div className="flex items-center gap-4">
                                    <Badge variant="outline" className="text-blue-600 border-blue-200 bg-blue-50 font-black px-3 py-0.5 rounded-lg text-[10px]">
                                        v{app.version}
                                    </Badge>
                                    <span className="text-slate-400 font-black uppercase text-[10px] tracking-widest">{app.category}</span>
                                    <span className="text-slate-200">|</span>
                                    <span className="text-slate-400 font-black uppercase text-[10px] tracking-widest">Authored by <span className="text-slate-600 underline decoration-slate-200">{app.author || 'Klypso Core'}</span></span>
                                </div>
                            </div>
                        </div>
                        <div className="flex flex-col sm:flex-row gap-4 w-full lg:w-auto">
                            {app.installed ? (
                                <>
                                    <Button variant="outline" className="border-rose-200 text-rose-500 hover:bg-rose-50 rounded-2xl px-6 font-bold transition-all" onClick={handleUninstall}>
                                        <Trash2 className="mr-2 h-4 w-4" /> Remove
                                    </Button>
                                    <Button className="bg-slate-900 hover:bg-blue-600 rounded-2xl px-10 text-white font-black shadow-xl shadow-slate-900/10 transition-all active:scale-95" onClick={() => router.push(`/apps/${app.name}`)}>
                                        Launch Module
                                    </Button>
                                </>
                            ) : (
                                <Button className="bg-blue-600 hover:bg-blue-700 rounded-2xl px-12 text-white font-black shadow-xl shadow-blue-500/20 h-14 transition-all active:scale-95" onClick={handleInstall}>
                                    <Download className="mr-2 h-4 w-4" /> Activate Module
                                </Button>
                            )}
                        </div>
                    </div>

                    <Tabs defaultValue="overview" className="w-full">
                        <TabsList className="bg-slate-100/80 border border-slate-200 p-1.5 rounded-2xl h-auto flex flex-wrap max-w-full">
                            <TabsTrigger value="overview" className="data-[state=active]:bg-white data-[state=active]:text-blue-600 data-[state=active]:shadow-sm rounded-xl px-10 py-3 font-bold transition-all">Overview</TabsTrigger>
                            <TabsTrigger value="technical" className="data-[state=active]:bg-white data-[state=active]:text-blue-600 data-[state=active]:shadow-sm rounded-xl px-10 py-3 font-bold transition-all">Architecture</TabsTrigger>
                            <TabsTrigger value="history" className="data-[state=active]:bg-white data-[state=active]:text-blue-600 data-[state=active]:shadow-sm rounded-xl px-10 py-3 font-bold transition-all">Changelog</TabsTrigger>
                        </TabsList>
                        <TabsContent value="overview" className="mt-10 space-y-10">
                            <p className="text-slate-600 leading-relaxed text-xl font-medium max-w-3xl">
                                {app.description || "No extended details found for this module."}
                            </p>
                            <div className="grid grid-cols-2 md:grid-cols-3 gap-6">
                                <div className="p-8 rounded-[32px] bg-white border border-slate-100 shadow-xl shadow-slate-200/40 space-y-3">
                                    <div className="text-[10px] text-slate-400 uppercase tracking-widest font-black">Response Time</div>
                                    <div className="text-3xl font-black text-slate-900 tracking-tighter">0.4<span className="text-sm font-bold ml-1 text-slate-300">MS</span></div>
                                </div>
                                <div className="p-8 rounded-[32px] bg-white border border-slate-100 shadow-xl shadow-slate-200/40 space-y-3">
                                    <div className="text-[10px] text-slate-400 uppercase tracking-widest font-black">Data Reliability</div>
                                    <div className="text-3xl font-black text-slate-900 tracking-tighter">100<span className="text-sm font-bold ml-1 text-slate-300">%</span></div>
                                </div>
                                <div className="p-8 rounded-[32px] bg-white border border-slate-100 shadow-xl shadow-slate-200/40 space-y-3">
                                    <div className="text-[10px] text-slate-400 uppercase tracking-widest font-black">Security Grade</div>
                                    <div className="text-3xl font-black text-emerald-600 tracking-tighter">A+</div>
                                </div>
                            </div>
                        </TabsContent>
                        <TabsContent value="technical" className="mt-10">
                            <Card className="bg-white border-none shadow-2xl shadow-slate-200/40 rounded-[32px] overflow-hidden">
                                <CardHeader className="bg-slate-50/50 border-b border-slate-100 py-6 px-10">
                                    <CardTitle className="text-slate-900 text-base font-black uppercase tracking-widest">System Dependencies</CardTitle>
                                </CardHeader>
                                <CardContent className="space-y-4 p-10">
                                    {app.dependencies ? app.dependencies.split(',').map((dep: string) => (
                                        <div key={dep} className="flex items-center justify-between p-5 rounded-2xl bg-slate-50 border border-slate-100 hover:border-blue-100 transition-all group">
                                            <span className="text-sm text-slate-900 font-black tracking-tight flex items-center">
                                                <div className="w-2 h-2 rounded-full bg-blue-500 mr-4 group-hover:scale-125 transition-all" />
                                                {dep}
                                            </span>
                                            <Badge className="bg-blue-50 text-blue-600 border-none px-3 font-black text-[9px] rounded-lg">CORE_NODE</Badge>
                                        </div>
                                    )) : <p className="text-slate-400 italic font-bold">No external dependencies required.</p>}
                                </CardContent>
                            </Card>
                        </TabsContent>
                    </Tabs>
                </div>

                <div className="w-full lg:w-96 space-y-8">
                    <Card className="bg-white border-none shadow-2xl shadow-slate-200/40 rounded-[32px] overflow-hidden">
                        <CardHeader className="bg-slate-50/50 border-b border-slate-100 py-6">
                            <CardTitle className="text-slate-900 text-[10px] font-black uppercase tracking-[0.2em] text-center">Module Info</CardTitle>
                        </CardHeader>
                        <CardContent className="space-y-6 pt-8 pb-8">
                            <div className="flex items-center gap-4 group">
                                <div className="p-3 bg-slate-50 rounded-xl group-hover:bg-blue-50 transition-colors">
                                    <Globe className="h-5 w-5 text-slate-400 group-hover:text-blue-600 transition-colors" />
                                </div>
                                <a href={app.website} target="_blank" className="text-sm font-black text-slate-600 hover:text-blue-600 flex items-center transition-colors">
                                    Official Repository <ExternalLink className="ml-2 h-3 w-3" />
                                </a>
                            </div>
                            <div className="flex items-center gap-4 group">
                                <div className="p-3 bg-slate-50 rounded-xl">
                                    <Github className="h-5 w-5 text-slate-400" />
                                </div>
                                <span className="text-sm font-black text-slate-400 uppercase tracking-widest">SOURCE_RESTRICTED</span>
                            </div>
                            <div className="flex items-center gap-4 group">
                                <div className="p-3 bg-amber-50 rounded-xl">
                                    <ShieldAlert className="h-5 w-5 text-amber-600" />
                                </div>
                                <span className="text-sm font-black text-amber-600 uppercase tracking-widest">SANDBOX_RUNTIME</span>
                            </div>
                        </CardContent>
                    </Card>

                    <Card className="bg-white border-none shadow-2xl shadow-slate-200/40 rounded-[32px] overflow-hidden">
                        <CardHeader className="bg-slate-50/50 border-b border-slate-100 py-6">
                            <CardTitle className="text-slate-900 text-[10px] font-black uppercase tracking-[0.2em] text-center">Sync Status</CardTitle>
