                    </Card>
                </div>
            </div>
        </div>
    );
}

"use client";

import { useEffect, useState, useCallback } from "react";
import { api } from "@/lib/api";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card";
import { LayoutGrid, Download, Trash2, ExternalLink, ShieldCheck, CheckCircle, Package, Zap, Smartphone, QrCode } from "lucide-react";
import { toast } from "sonner";
import { Badge } from "@/components/ui/badge";
import Link from "next/link";
import { useUX } from "@/components/providers/ux-provider";

interface SystemApp {
    id: string;
    name: string;
    label: string;
    description: string;
    version: string;
    author: string;
    category: string;
    installed: boolean;
}

export default function AppsMarketplace() {
    const { showConfirm } = useUX();
    const [apps, setApps] = useState<SystemApp[]>([]);
    const [loading, setLoading] = useState(true);

    const syncAppData = useCallback(async (showLoading = false) => {
        try {
            if (showLoading) setLoading(true);
            const res = await api.get("system/apps");
            setApps(res.data);
        } catch (err) {
            console.error("App Sync Failure:", err);
            toast.error("Failed to load apps. Please refresh.");
        } finally {
            setLoading(false);
        }
    }, []);

    useEffect(() => {
        syncAppData(true);
        const interval = setInterval(() => syncAppData(false), 30000);
        return () => clearInterval(interval);
    }, [syncAppData]);

    const handleUninstall = useCallback((name: string) => {
        showConfirm({
            title: "Remove Module?",
            description: `This will remove the [${name}] module from your system. Any data specific to this module might become inaccessible.`,
            confirmText: "Uninstall",
            variant: "destructive",
            onConfirm: async () => {
                try {
                    await api.post(`/system/apps/${name}/uninstall`);
                    toast.success(`Module [${name}] removed successfully`);
                    syncAppData(true);
                    window.dispatchEvent(new CustomEvent('system-apps-updated'));
                } catch (err) {
                    toast.error("Failed to remove module");
                }
            }
        });
    }, [showConfirm, syncAppData]);

    const handleInstall = useCallback(async (name: string) => {
        try {
            await api.post(`/system/apps/${name}/install`);
            toast.success(`Module [${name}] installed successfully`);
            syncAppData(true);
            window.dispatchEvent(new CustomEvent('system-apps-updated'));
        } catch (err) {
            toast.error("Installation failed");
        }
    }, [syncAppData]);

    return (
        <div className="flex-1 space-y-6 md:space-y-8 pt-2 md:pt-6 px-4 md:px-8">
            <div className="flex flex-col lg:flex-row lg:items-center justify-between gap-4 lg:gap-0">
                <div>
                    <h2 className="text-4xl font-black tracking-tight text-slate-900 flex items-center">
                        <LayoutGrid className="mr-4 h-9 w-9 text-blue-600 shadow-sm" />
                        Apps & Modules
                    </h2>
                    <p className="text-slate-500 mt-2 font-medium">Install and manage add-on modules for your business.</p>
                </div>
                <Button className="rounded-2xl bg-white border border-slate-200 text-slate-600 shadow-sm font-bold h-11 px-5" variant="outline">
                    <ShieldCheck className="mr-2 h-4 w-4 text-emerald-600" /> System Verified
                </Button>
            </div>

            <div className="grid gap-8 lg:grid-cols-2">
                <Card className="bg-white border-slate-200 shadow-xl shadow-slate-200/40 rounded-3xl overflow-hidden border-none border-t-4 border-t-emerald-500">
                    <CardHeader className="bg-emerald-50/50 border-b border-emerald-100 py-6">
                        <CardTitle className="text-slate-900 flex items-center gap-3 font-black text-xl">
                            <Smartphone className="h-5 w-5 text-emerald-600" />
                            Nexus Mobile Gateway
                        </CardTitle>
                        <CardDescription className="text-slate-500 font-bold uppercase text-[10px] tracking-widest mt-1">Direct Enterprise Rollout ÔÇó Build 1.0.0 (Hardened)</CardDescription>
                    </CardHeader>
                    <CardContent className="pt-8 flex flex-col md:flex-row gap-8">
                        <div className="flex-1 space-y-4">
                            <p className="text-slate-600 font-medium leading-relaxed">
                                Access your ERP from the shop floor with the native Android application.
                                Securely anchored to your enterprise identity.
                            </p>
                            <div className="flex gap-4">
                                <Button
                                    className="bg-emerald-600 hover:bg-emerald-700 text-white font-black rounded-2xl h-12 px-6 shadow-lg shadow-emerald-500/20"
                                    onClick={() => {
                                        toast.success("Initializing Secure Download...");
                                        window.open("/nexus-gateway-v1.apk", "_blank");
                                    }}
                                >
                                    <Download className="mr-2 h-5 w-5" /> Download APK
                                </Button>
                            </div>
                        </div>
                        <div className="hidden md:flex flex-col items-center justify-center p-4 bg-slate-50 rounded-2xl border border-slate-100">
                            <QrCode className="h-24 w-24 text-slate-300 mb-2" />
                            <span className="text-[10px] font-black text-slate-400 uppercase tracking-tighter">Scan to Install</span>
                        </div>
                    </CardContent>
                </Card>

                <Card className="bg-white border-slate-200 shadow-xl shadow-slate-200/40 rounded-3xl overflow-hidden border-none border-t-4 border-t-blue-500">
                    <CardHeader className="bg-slate-50 border-b border-slate-100 py-6">
                        <CardTitle className="text-slate-900 flex items-center gap-3 font-black text-xl">
                            <Zap className="h-5 w-5 text-blue-600" />
                            Business Blueprints
                        </CardTitle>
                        <CardDescription className="text-slate-500 font-bold uppercase text-[10px] tracking-widest mt-1">Install pre-configured business setups in a single click</CardDescription>
                    </CardHeader>
                    <CardContent className="flex flex-wrap gap-4 pt-8">
                        {["Manufacturing", "Retail", "Wholesale", "Services"].map(type => (
                            <Button
                                key={type}
                                className="bg-white border-slate-200 text-slate-700 hover:bg-slate-50 hover:border-blue-500/50 rounded-2xl h-12 px-6 font-bold shadow-sm transition-all"
                                variant="outline"
                                onClick={async () => {
                                    try {
                                        await api.post("system/apps/preset", { type });
                                        toast.success(`${type} blueprint sequence initiated`);
                                        syncAppData(true);
                                        window.dispatchEvent(new CustomEvent('system-apps-updated'));
                                    } catch (err) {
                                        toast.error("Blueprint installation failed");
                                    }
                                }}
                            >
                                {type} Profile
                            </Button>
                        ))}
                    </CardContent>
                </Card>
            </div>

            <div className="grid gap-8 md:grid-cols-2 lg:grid-cols-3">
                {apps.map((app) => (
                    <Card key={app.id} className="bg-white border-slate-200 shadow-lg shadow-slate-200/40 rounded-3xl group overflow-hidden flex flex-col hover:shadow-2xl hover:shadow-blue-500/5 transition-all outline outline-0 hover:outline-2 hover:outline-blue-500/20">
                        <div className={`h-2.5 w-full transition-colors ${app.installed ? 'bg-emerald-500' : 'bg-slate-100'}`} />
                        <CardHeader className="flex-1 px-8 pt-8">
                            <div className="flex justify-between items-start mb-6">
                                <Badge variant="secondary" className="bg-slate-100 text-slate-500 font-black text-[9px] rounded-lg border-none uppercase tracking-widest">{app.category}</Badge>
                                {app.installed && <div className="bg-emerald-50 p-1.5 rounded-full"><CheckCircle className="h-4 w-4 text-emerald-600" /></div>}
                            </div>
                            <Link href={`/apps/market/${app.name}`}>
                                <CardTitle className="text-xl font-black text-slate-900 group-hover:text-blue-600 transition-colors flex items-center cursor-pointer tracking-tight">
                                    <Package className="mr-3 h-6 w-6 text-blue-500/50" />
                                    {app.label}
                                </CardTitle>
                            </Link>
                            <CardDescription className="text-slate-500 mt-4 text-sm leading-relaxed font-medium">
                                {app.description}
                            </CardDescription>
                        </CardHeader>
                        <CardContent className="px-8 pb-8 pt-0">
                            <div className="flex items-center justify-between text-[10px] text-slate-400 font-black uppercase tracking-tighter mb-6 bg-slate-50 p-2 rounded-xl">
                                <span>BUILD_{app.version}</span>
                                <span>CREATED BY {app.author.toUpperCase()}</span>
                            </div>
                            <div className="flex gap-3 w-full">
                                {app.installed ? (
                                    <Button
                                        variant="ghost"
                                        size="sm"
                                        className="flex-1 bg-rose-50 text-rose-600 hover:bg-rose-100 font-black rounded-2xl h-11"
                                        onClick={() => handleUninstall(app.name)}
                                    >
                                        <Trash2 className="h-4 w-4 mr-2" /> Remove Module
                                    </Button>
                                ) : (
                                    <Button
                                        size="sm"
                                        className="flex-1 bg-blue-600 hover:bg-blue-700 text-white font-black rounded-2xl h-11 shadow-lg shadow-blue-500/20"
                                        onClick={() => handleInstall(app.name)}
                                    >
                                        <Download className="h-4 w-4 mr-2" /> Install Module
                                    </Button>
                                )}
                                <Link href={`/apps/market/${app.name}`}>
                                    <Button variant="ghost" size="icon" className="h-11 w-11 bg-slate-50 border border-slate-100 text-slate-400 rounded-2xl hover:bg-white hover:border-slate-300">
                                        <ExternalLink className="h-4 w-4" />
                                    </Button>
                                </Link>
                            </div>
                        </CardContent>
                    </Card>
                ))}

                {apps.length === 0 && !loading && (
                    <div className="col-span-full py-32 flex flex-col items-center justify-center border-2 border-dashed border-slate-200 rounded-3xl bg-slate-50/50">
                        <Package className="h-20 w-20 text-slate-200 mb-6" />
                        <h3 className="text-xl font-black text-slate-400 uppercase tracking-widest">No Apps Installed</h3>
                        <p className="text-slate-400 mt-2 font-bold">No apps or modules are currently installed.</p>
                    </div>
                )}
            </div>
        </div>
    );
}

"use client";

import { useEffect, useState } from "react";
import { useParams, useRouter } from "next/navigation";
import { api } from "@/lib/api";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card";
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from "@/components/ui/table";
import { ArrowLeft, User, Phone, Mail, Building, FileText, Wallet } from "lucide-react";
import { Loader2 } from "lucide-react";
import { Badge } from "@/components/ui/badge";

export default function CustomerDetailPage() {
    const params = useParams();
    const router = useRouter();
    const [customer, setCustomer] = useState<any>(null);
    const [ledger, setLedger] = useState<any[]>([]);
    const [loading, setLoading] = useState(true);

    const syncRelationDetail = async (showLoading = false) => {
        if (!params.id) return;
        try {
            if (showLoading) setLoading(true);
            const custRes = await api.get("/crm/customers");
            const found = custRes.data.find((c: any) => c.id === params.id);
            setCustomer(found);

            const ledgerRes = await api.get(`/accounting/ledger/${params.id}`);
            setLedger(ledgerRes.data);
        } catch (err) {
            console.error("Relation Sync Failure:", err);
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        syncRelationDetail(true);
        const interval = setInterval(() => syncRelationDetail(false), 30000);
        return () => clearInterval(interval);
    }, [params.id]);

    if (loading) {
        return <div className="flex items-center justify-center h-full bg-slate-50 text-slate-900"><Loader2 className="animate-spin h-8 w-8 mr-2 text-blue-600" /> Initializing Node Pulse...</div>;
    }

    if (!customer) {
        return <div className="text-slate-900 p-8 h-screen bg-slate-50 font-black uppercase tracking-widest flex items-center justify-center">Strategic Relation Not Found.</div>;
    }

    const currentBalance = ledger.length > 0 ? ledger[ledger.length - 1].balance : 0;

    return (
        <div className="flex-1 space-y-6 md:space-y-8 pt-2 md:pt-6 px-4 md:px-8 bg-slate-50 min-h-screen w-full max-w-full overflow-hidden">
            <div className="flex flex-col lg:flex-row md:items-center gap-4">
                <Button variant="ghost" className="text-slate-500 hover:text-slate-900 hover:bg-white rounded-xl font-bold md:h-10 px-0 md:px-4 w-fit" onClick={() => router.back()}>
                    <ArrowLeft className="mr-2 h-4 w-4" /> Back to Store
                </Button>
                <div>
                    <h2 className="text-3xl font-black tracking-tight text-slate-900 tracking-tighter">{customer.firstName} {customer.lastName}</h2>
                    <p className="text-slate-500 font-medium text-sm">{customer.company || "Independent Client"}</p>
                </div>
                <div className="md:ml-auto w-full md:w-auto">
                    <Card className="bg-white border-slate-200 shadow-xl shadow-slate-200/40 rounded-[32px] overflow-hidden border-none border-b-4 border-b-amber-500">
                        <CardContent className="p-6 flex items-center space-x-6">
                            <div className="p-3 bg-amber-50 rounded-2xl">
                                <Wallet className="h-8 w-8 text-amber-600" />
                            </div>
                            <div>
                                <p className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em]">Net Balance</p>
                                <div className={`text-3xl font-black tracking-tighter ${currentBalance > 0 ? "text-rose-600" : "text-emerald-600"}`}>
                                    Ôé╣{currentBalance.toLocaleString('en-IN', { minimumFractionDigits: 0 })}
                                </div>
                            </div>
                        </CardContent>
                    </Card>
                </div>
            </div>

            <div className="grid gap-8 md:grid-cols-3">
                <Card className="bg-white border-slate-200 shadow-xl shadow-slate-200/40 rounded-[32px] md:col-span-1 h-fit border-none">
                    <CardHeader className="bg-slate-50/50 border-b border-slate-100 py-6 px-8">
                        <CardTitle className="text-slate-900 text-lg font-black tracking-tight">Relation Metadata</CardTitle>
                    </CardHeader>
                    <CardContent className="p-8 space-y-5">
                        <div className="flex items-center text-slate-600 font-bold text-sm">
                            <Mail className="h-4 w-4 mr-4 text-blue-500" /> {customer.email || "No email provided"}
                        </div>
                        <div className="flex items-center text-slate-600 font-bold text-sm">
                            <Phone className="h-4 w-4 mr-4 text-slate-400" /> {customer.phone || "No phone number"}
                        </div>
                        <div className="flex items-center text-slate-600 font-bold text-sm">
                            <Building className="h-4 w-4 mr-4 text-slate-400" /> {customer.company || "Retail Consumer"}
                        </div>
                        <div className="pt-6 border-t border-slate-50">
                            <div className="flex justify-between items-center mb-3">
                                <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Status</span>
                                <Badge variant="outline" className="text-emerald-600 border-emerald-100 bg-emerald-50 font-black text-[9px] uppercase tracking-widest px-2.5 py-0.5">{customer.status}</Badge>
                            </div>
                            <div className="flex justify-between items-center">
                                <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Created On</span>
                                <span className="text-xs text-slate-900 font-black">{new Date(customer.createdAt).toLocaleDateString()}</span>
                            </div>
                        </div>
                    </CardContent>
                </Card>

                <Card className="bg-white border-slate-200 shadow-xl shadow-slate-200/40 rounded-[32px] md:col-span-2 border-none overflow-hidden print:col-span-3 print:border-none print:shadow-none print:bg-white print:text-black">
                    <CardHeader className="bg-slate-50/50 border-b border-slate-100 p-8 flex flex-row items-center justify-between print:border-b print:border-black">
                        <div>
                            <CardTitle className="text-slate-900 text-xl font-black tracking-tight print:text-black">Audit Statement</CardTitle>
                            <CardDescription className="text-slate-500 font-medium print:text-zinc-600">Transaction history for: {customer.firstName} {customer.lastName}</CardDescription>
                        </div>
                        <Button variant="outline" className="rounded-2xl border-slate-200 text-slate-600 font-bold h-11 px-6 print:hidden shadow-sm" onClick={() => window.print()}>
                            <FileText className="mr-2 h-4 w-4" /> Export Record
                        </Button>
                    </CardHeader>
                    <CardContent className="p-0 print:p-0 print:pt-4 overflow-x-auto max-w-[100vw]">
                        <Table className="min-w-[700px]">
                            <TableHeader className="bg-slate-50/30">
                                <TableRow className="border-slate-100 hover:bg-transparent print:border-black">
                                    <TableHead className="text-slate-500 font-black text-[10px] uppercase tracking-[0.2em] pl-8 py-5">Date</TableHead>
                                    <TableHead className="text-slate-500 font-black text-[10px] uppercase tracking-[0.2em]">Particulars</TableHead>
                                    <TableHead className="text-slate-500 font-black text-[10px] uppercase tracking-[0.2em]">Reference</TableHead>
                                    <TableHead className="text-right text-slate-500 font-black text-[10px] uppercase tracking-[0.2em]">Debit (Ôû▓)</TableHead>
                                    <TableHead className="text-right text-slate-500 font-black text-[10px] uppercase tracking-[0.2em]">Credit (Ôû╝)</TableHead>
                                    <TableHead className="text-right text-slate-500 font-black text-[10px] uppercase tracking-[0.2em] pr-8">Balance</TableHead>
                                </TableRow>
                            </TableHeader>
                            <TableBody>
                                {/* Opening Balance Simulation */}
                                <TableRow className="border-slate-50 hover:bg-transparent print:border-zinc-200">
                                    <TableCell className="pl-8 text-slate-400 text-[10px] font-black tracking-widest">INIT</TableCell>
                                    <TableCell className="text-slate-400 font-bold italic text-sm">Opening Balance</TableCell>
                                    <TableCell></TableCell>
                                    <TableCell></TableCell>
                                    <TableCell></TableCell>
                                    <TableCell className="text-right pr-8 font-black text-slate-900">Ôé╣0.00</TableCell>
                                </TableRow>

                                {ledger.map((entry: any) => (
                                    <TableRow key={`${entry.type}-${entry.id}`} className="border-slate-50 hover:bg-slate-50/50 print:border-zinc-200 print:text-black group">
                                        <TableCell className="pl-8 text-slate-900 text-xs font-black tracking-tighter print:text-black">{new Date(entry.title || entry.date).toLocaleDateString()}</TableCell>
                                        <TableCell>
                                            <span className={`text-[10px] font-black uppercase tracking-widest px-2 py-0.5 rounded-lg ${entry.type === 'INVOICE' ? "bg-blue-50 text-blue-600 print:text-black" : "bg-emerald-50 text-emerald-600 print:text-black"}`}>
                                                {entry.type === 'INVOICE' ? 'Sales Invoice' : 'Payment Received'}
                                            </span>
                                        </TableCell>
                                        <TableCell className="text-slate-500 text-[10px] font-black tracking-widest uppercase opacity-60 font-mono">{entry.ref}</TableCell>
                                        <TableCell className="text-right text-rose-600 font-black text-sm">
                                            {Number(entry.debit) > 0 ? `Ôé╣${Number(entry.debit).toLocaleString('en-IN')}` : ''}
                                        </TableCell>
                                        <TableCell className="text-right text-emerald-600 font-black text-sm">
                                            {Number(entry.credit) > 0 ? `Ôé╣${Number(entry.credit).toLocaleString('en-IN')}` : ''}
                                        </TableCell>
                                        <TableCell className="text-right pr-8 font-black text-slate-900">
                                            Ôé╣{Number(entry.balance).toLocaleString('en-IN')}
                                            <span className="text-[9px] ml-1 text-slate-400 font-normal uppercase tracking-widest">{entry.balance >= 0 ? "Dr" : "Cr"}</span>
                                        </TableCell>
                                    </TableRow>
                                ))}
                            </TableBody>
                        </Table>

                        <div className="p-10 border-t border-slate-100 text-center text-[10px] text-slate-400 font-black uppercase tracking-[0.3em] print:block hidden">
                            <p>Computer generated statement ÔÇó No signature required</p>
                            <p className="mt-2 text-slate-500">Generated at: {new Date().toLocaleString()}</p>
                        </div>
                    </CardContent>
                </Card>
            </div>
        </div>
    );
}

"use client";

