import { format } from "date-fns";
import { Badge } from "@/components/ui/badge";

export default function DebitNotesPage() {
    const [notes, setNotes] = useState<any[]>([]);
    const [loading, setLoading] = useState(true);
    const [searchTerm, setSearchTerm] = useState("");

    const fetchNotes = async () => {
        setLoading(true);
        try {
            const res = await api.get("/accounting/debit-notes");
            setNotes(res.data);
        } catch (err) {
            console.error("Failed to fetch debit notes", err);
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        fetchNotes();
    }, []);

    const filteredNotes = notes.filter(n =>
        n.noteNumber.toLowerCase().includes(searchTerm.toLowerCase()) ||
        n.supplier?.name.toLowerCase().includes(searchTerm.toLowerCase())
    );

    return (
        <div className="p-6 space-y-6 bg-slate-50/50 min-h-screen">
            <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
                <div>
                    <h1 className="text-3xl font-black text-slate-900 tracking-tight flex items-center gap-3">
                        <Truck className="w-8 h-8 text-indigo-600" />
                        Debit Notes
                    </h1>
                    <p className="text-slate-500 font-medium">Manage purchase returns and supplier debits</p>
                </div>
                <div className="flex gap-2">
                    <Button variant="outline" onClick={fetchNotes} disabled={loading}>
                        <RefreshCw className={`w-4 h-4 mr-2 ${loading ? 'animate-spin' : ''}`} />
                        Refresh
                    </Button>
                    <Button className="bg-indigo-600 hover:bg-indigo-700 text-white font-bold rounded-xl shadow-lg shadow-indigo-200">
                        <Plus className="w-4 h-4 mr-2" />
                        Issue Debit Note
                    </Button>
                </div>
            </div>

            <Card className="border-none shadow-xl shadow-slate-200/50 rounded-3xl overflow-hidden">
                <CardHeader className="bg-white border-b border-slate-100 p-6">
                    <div className="flex flex-col md:flex-row md:items-center gap-4 justify-between">
                        <div className="relative flex-1 max-w-md">
                            <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400" />
                            <Input
                                placeholder="Search by number or supplier..."
                                className="pl-10 bg-slate-50 border-slate-200 rounded-xl"
                                value={searchTerm}
                                onChange={(e) => setSearchTerm(e.target.value)}
                            />
                        </div>
                        <div className="flex gap-2">
                            <Button variant="ghost" size="sm" className="text-slate-500 font-bold uppercase text-[10px] tracking-widest">
                                <Filter className="w-3 h-3 mr-2" />
                                Filter
                            </Button>
                        </div>
                    </div>
                </CardHeader>
                <CardContent className="p-0">
                    <Table>
                        <TableHeader className="bg-slate-50/50">
                            <TableRow className="hover:bg-transparent">
                                <TableHead className="font-bold text-slate-500 uppercase text-[10px] tracking-widest pl-6">Note #</TableHead>
                                <TableHead className="font-bold text-slate-500 uppercase text-[10px] tracking-widest">Supplier</TableHead>
                                <TableHead className="font-bold text-slate-500 uppercase text-[10px] tracking-widest">Date</TableHead>
                                <TableHead className="font-bold text-slate-500 uppercase text-[10px] tracking-widest">PO Ref</TableHead>
                                <TableHead className="font-bold text-slate-500 uppercase text-[10px] tracking-widest text-right pr-6">Amount</TableHead>
                            </TableRow>
                        </TableHeader>
                        <TableBody>
                            {loading ? (
                                <TableRow>
                                    <TableCell colSpan={5} className="h-32 text-center text-slate-400 font-medium">Loading debit notes...</TableCell>
                                </TableRow>
                            ) : filteredNotes.length === 0 ? (
                                <TableRow>
                                    <TableCell colSpan={5} className="h-48 text-center">
                                        <div className="flex flex-col items-center gap-2">
                                            <div className="p-4 bg-slate-100 rounded-full">
                                                <FileText className="w-8 h-8 text-slate-300" />
                                            </div>
                                            <p className="text-slate-400 font-bold">No debit notes found</p>
                                        </div>
                                    </TableCell>
                                </TableRow>
                            ) : filteredNotes.map((note) => (
                                <TableRow key={note.id} className="hover:bg-indigo-50/30 transition-colors group cursor-pointer">
                                    <TableCell className="pl-6 py-4">
                                        <div className="font-bold text-slate-900 group-hover:text-indigo-600 transition-colors">
                                            {note.noteNumber}
                                        </div>
                                    </TableCell>
                                    <TableCell>
                                        <div className="font-bold text-slate-700">{note.supplier?.name}</div>
                                        <div className="text-[10px] text-slate-400 font-bold uppercase">{note.supplier?.category || "General"}</div>
                                    </TableCell>
                                    <TableCell className="text-slate-500 font-medium">
                                        {format(new Date(note.date), "dd MMM yyyy")}
                                    </TableCell>
                                    <TableCell>
                                        <Badge variant="outline" className="rounded-lg font-mono text-[10px]">
                                            {note.purchaseOrder?.orderNumber || "Direct Debit"}
                                        </Badge>
                                    </TableCell>
                                    <TableCell className="text-right pr-6 font-black text-blue-600 tabular-nums">
                                        Ôé╣{Number(note.totalAmount).toLocaleString('en-IN', { minimumFractionDigits: 2 })}
                                    </TableCell>
                                </TableRow>
                            ))}
                        </TableBody>
                    </Table>
                </CardContent>
            </Card>
        </div>
    );
}

"use client";

import React, { useState, useEffect } from "react";
import {
    ArrowLeftRight,
    TrendingDown,
    TrendingUp,
    PackageSearch,
    AlertCircle,
    Truck,
    CheckCircle2
} from "lucide-react";
import { api } from "@/lib/api";
import { toast } from "sonner";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card";
import { Label } from "@/components/ui/label";
import { Input } from "@/components/ui/input";
import {
    Select,
    SelectContent,
    SelectItem,
    SelectTrigger,
    SelectValue,
} from "@/components/ui/select";
import { LoadingSpinner } from "@/components/ui/loading-spinner";

export default function StockMovementsPage() {
    const [loading, setLoading] = useState(true);
    const [submitting, setSubmitting] = useState(false);
    const [products, setProducts] = useState<any[]>([]);
    const [warehouses, setWarehouses] = useState<any[]>([]);

    // Form State
    const [movementType, setMovementType] = useState<"TRANSFER" | "IN" | "OUT">("TRANSFER");
    const [productId, setProductId] = useState("");
    const [quantity, setQuantity] = useState("");
    const [fromWarehouse, setFromWarehouse] = useState("");
    const [toWarehouse, setToWarehouse] = useState("");
    const [notes, setNotes] = useState("");

    const loadData = async () => {
        try {
            setLoading(true);
            const [prodRes, whRes] = await Promise.all([
                api.get("/inventory/products?limit=1000"), // Minimal pagination for now
                api.get("/inventory/warehouses"),
            ]);
            setProducts(prodRes.data.data || []);
            setWarehouses(whRes.data || []);
        } catch (err) {
            toast.error("Failed to load inventory data");
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        loadData();
    }, []);

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!productId || !quantity || Number(quantity) <= 0) {
            toast.error("Please select a product and enter a valid quantity.");
            return;
        }

        try {
            setSubmitting(true);
            if (movementType === "TRANSFER") {
                if (!fromWarehouse || !toWarehouse || fromWarehouse === toWarehouse) {
                    toast.error("Please select different source and destination warehouses.");
                    return;
                }
                await api.post("/inventory/transfers", {
                    productId,
                    fromWarehouseId: fromWarehouse,
                    toWarehouseId: toWarehouse,
                    quantity: Number(quantity),
                    notes
                });
            } else {
                if (!toWarehouse) {
                    toast.error("Please select a warehouse.");
                    return;
                }
                await api.post("/inventory/movements", {
                    productId,
                    warehouseId: toWarehouse,
                    quantity: Number(quantity),
                    type: movementType,
                    notes
                });
            }

            toast.success("Stock movement recorded successfully");
            // Reset form
            setQuantity("");
            setNotes("");
            loadData(); // Refresh stock caches
        } catch (err: any) {
            toast.error(err.response?.data?.message || "Failed to log movement");
        } finally {
            setSubmitting(false);
        }
    };

    if (loading) return <LoadingSpinner className="h-full" text="Loading inventory data..." />;

    return (
        <div className="flex-1 space-y-6 md:space-y-8 pt-2 md:pt-6 px-4 md:px-8 w-full max-w-full overflow-hidden">
            <div>
                <h2 className="text-4xl font-black tracking-tight text-slate-900 flex items-center">
                    <ArrowLeftRight className="mr-4 h-9 w-9 text-blue-600 shadow-sm" />
                    Stock Movements
                </h2>
                <p className="text-slate-500 mt-2 font-medium">Log manual stock adjustments and inter-warehouse transfers.</p>
            </div>

            <div className="grid lg:grid-cols-3 gap-8">
                {/* Form Column */}
                <Card className="lg:col-span-2 border-slate-200 shadow-xl shadow-slate-200/40 rounded-3xl overflow-hidden border-none bg-white">
                    <CardHeader className="bg-slate-50/50 border-b border-slate-100 py-6 px-6 md:px-8">
                        <CardTitle className="text-xl font-black text-slate-900">Record Movement</CardTitle>
                        <CardDescription className="font-bold uppercase tracking-widest text-[10px] text-slate-500 mt-1">
                            Select movement type and details
                        </CardDescription>
                    </CardHeader>
                    <CardContent className="p-6 md:p-8">
                        <form onSubmit={handleSubmit} className="space-y-8">
                            {/* Type Selection */}
                            <div className="grid grid-cols-3 gap-4">
                                <button
                                    type="button"
                                    onClick={() => setMovementType("TRANSFER")}
                                    className={`flex flex-col items-center justify-center p-4 rounded-2xl border-2 transition-all ${movementType === "TRANSFER"
                                        ? "border-blue-600 bg-blue-50/50 text-blue-700 shadow-inner"
                                        : "border-slate-100 hover:border-slate-300 text-slate-500 bg-white"
                                        }`}
                                >
                                    <Truck className="h-6 w-6 mb-2" />
                                    <span className="font-bold text-xs uppercase tracking-wider">Transfer</span>
                                </button>
                                <button
                                    type="button"
                                    onClick={() => setMovementType("IN")}
                                    className={`flex flex-col items-center justify-center p-4 rounded-2xl border-2 transition-all ${movementType === "IN"
                                        ? "border-emerald-600 bg-emerald-50/50 text-emerald-700 shadow-inner"
                                        : "border-slate-100 hover:border-slate-300 text-slate-500 bg-white"
                                        }`}
                                >
                                    <TrendingUp className="h-6 w-6 mb-2" />
                                    <span className="font-bold text-xs uppercase tracking-wider">Stock In</span>
                                </button>
                                <button
                                    type="button"
                                    onClick={() => setMovementType("OUT")}
                                    className={`flex flex-col items-center justify-center p-4 rounded-2xl border-2 transition-all ${movementType === "OUT"
                                        ? "border-red-600 bg-red-50/50 text-red-700 shadow-inner"
                                        : "border-slate-100 hover:border-slate-300 text-slate-500 bg-white"
                                        }`}
                                >
                                    <TrendingDown className="h-6 w-6 mb-2" />
                                    <span className="font-bold text-xs uppercase tracking-wider">Stock Out</span>
                                </button>
                            </div>

                            {/* Product Selection */}
                            <div className="space-y-4">
                                <div className="space-y-2">
                                    <Label className="text-xs font-bold uppercase tracking-widest text-slate-500">Product</Label>
                                    <Select value={productId} onValueChange={setProductId}>
                                        <SelectTrigger className="h-12 rounded-xl border-slate-200 bg-slate-50 shadow-inner font-medium text-slate-900 border-2">
                                            <SelectValue placeholder="Select a product" />
                                        </SelectTrigger>
                                        <SelectContent>
                                            {products.map((p) => (
                                                <SelectItem key={p.id} value={p.id} className="font-medium">
                                                    {p.name} <span className="text-slate-400 font-mono ml-2 text-xs">{p.sku}</span>
                                                </SelectItem>
                                            ))}
                                        </SelectContent>
                                    </Select>
                                </div>

                                <div className="grid md:grid-cols-2 gap-4">
                                    {movementType === "TRANSFER" && (
                                        <div className="space-y-2">
                                            <Label className="text-xs font-bold uppercase tracking-widest text-slate-500">Source Warehouse</Label>
                                            <Select value={fromWarehouse} onValueChange={setFromWarehouse}>
                                                <SelectTrigger className="h-12 rounded-xl border-slate-200 bg-slate-50 shadow-inner font-medium text-slate-900 border-2">
                                                    <SelectValue placeholder="Select source" />
                                                </SelectTrigger>
                                                <SelectContent>
                                                    {warehouses.map((w) => (
                                                        <SelectItem key={w.id} value={w.id} className="font-medium">
                                                            {w.name}
                                                        </SelectItem>
                                                    ))}
                                                </SelectContent>
                                            </Select>
                                        </div>
                                    )}

                                    <div className="space-y-2">
                                        <Label className="text-xs font-bold uppercase tracking-widest text-slate-500">
                                            {movementType === "TRANSFER" ? "Destination Warehouse" : "Warehouse"}
                                        </Label>
                                        <Select value={toWarehouse} onValueChange={setToWarehouse}>
                                            <SelectTrigger className="h-12 rounded-xl border-slate-200 bg-slate-50 shadow-inner font-medium text-slate-900 border-2">
                                                <SelectValue placeholder="Select destination" />
                                            </SelectTrigger>
                                            <SelectContent>
                                                {warehouses.map((w) => (
                                                    <SelectItem key={w.id} value={w.id} className="font-medium">
                                                        {w.name}
                                                    </SelectItem>
                                                ))}
                                            </SelectContent>
                                        </Select>
                                    </div>
                                </div>

                                <div className="grid md:grid-cols-2 gap-4">
                                    <div className="space-y-2">
                                        <Label className="text-xs font-bold uppercase tracking-widest text-slate-500">Quantity</Label>
                                        <Input
                                            type="number"
                                            min="0.01"
                                            step="0.01"
                                            placeholder="0.00"
                                            className="h-12 rounded-xl border-slate-200 bg-slate-50 shadow-inner font-mono text-lg text-slate-900 border-2"
                                            value={quantity}
                                            onChange={(e) => setQuantity(e.target.value)}
                                        />
                                    </div>
                                    <div className="space-y-2">
                                        <Label className="text-xs font-bold uppercase tracking-widest text-slate-500">Notes / Reference</Label>
                                        <Input
                                            placeholder="Optional remarks"
                                            className="h-12 rounded-xl border-slate-200 bg-slate-50 shadow-inner font-medium text-slate-900 border-2"
                                            value={notes}
                                            onChange={(e) => setNotes(e.target.value)}
                                        />
                                    </div>
                                </div>
                            </div>

                            <Button
                                type="submit"
                                disabled={submitting}
                                className="w-full h-12 rounded-xl bg-blue-600 hover:bg-blue-700 text-white font-bold tracking-wide shadow-lg shadow-blue-500/30"
                            >
                                {submitting ? (
                                    <LoadingSpinner text="Processing..." />
                                ) : (
                                    <>
                                        <CheckCircle2 className="mr-2 h-5 w-5" /> Execute Movement
                                    </>
                                )}
                            </Button>
                        </form>
                    </CardContent>
                </Card>

                {/* Info Column */}
                <div className="space-y-6">
                    <Card className="bg-slate-900 text-white rounded-3xl border-none shadow-xl shadow-slate-900/10 overflow-hidden relative">
                        <div className="absolute top-0 right-0 p-6 opacity-10">
                            <PackageSearch className="h-32 w-32" />
                        </div>
                        <CardHeader className="relative z-10 pb-2">
                            <CardTitle className="text-xl font-black text-white">Stock Availability</CardTitle>
                        </CardHeader>
                        <CardContent className="relative z-10 text-slate-400 font-medium">
                            <p className="text-sm">
                                Select a product to view its current stock availability across all your registered warehouses.
                            </p>
                            {productId && (
                                <div className="mt-6 space-y-4">
                                    {warehouses.map(w => {
                                        // Find stock for selected product in this warehouse
                                        const stockLoc = w.stocks?.find((s: any) => s.productId === productId);
                                        const qty = stockLoc ? Number(stockLoc.quantity) : 0;
                                        if (qty <= 0) return null;

                                        return (
                                            <div key={w.id} className="bg-slate-800/50 p-4 rounded-2xl flex justify-between items-center border border-slate-700/50">
                                                <span className="font-bold text-slate-100 text-sm">{w.name}</span>
                                                <span className="font-mono text-emerald-400 font-bold">{qty}</span>
                                            </div>
                                        );
                                    })}
                                    {!warehouses.some(w => w.stocks?.find((s: any) => s.productId === productId && Number(s.quantity) > 0)) && (
                                        <div className="text-xs font-bold text-rose-400 uppercase tracking-widest bg-rose-500/10 p-4 rounded-xl text-center">
                                            No stock available in any warehouse
                                        </div>
                                    )}
                                </div>
                            )}
                        </CardContent>
                    </Card>

                    <div className="bg-amber-50 rounded-3xl p-6 border-2 border-amber-200 flex items-start gap-4">
                        <AlertCircle className="h-6 w-6 text-amber-600 shrink-0 mt-0.5" />
                        <div className="text-amber-900 text-sm font-medium">
                            <strong className="block text-amber-950 font-black mb-1">Financial Impact</strong>
                            Transfers between warehouses do not affect the general ledger. Manual Stock In/Out adjustments <b>automatically post</b> to the Inventory Adjustment account for audit compliance.
                        </div>
                    </div>
                </div>
            </div>
        </div>
    );
}

"use client";

import { useEffect, useState } from "react";
import { api } from "@/lib/api";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card";
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogDescription } from "@/components/ui/dialog";
import { Package, Plus, Search, Filter, TrendingDown, Layers, Boxes, Sparkles, Brain, Clock, AlertCircle, Upload, Edit3, CheckCircle2, Info, ChevronRight, Tags, Scale } from "lucide-react";
import { OpeningBalanceDialog } from "@/components/accounting/opening-balance-dialog";
import { Input } from "@/components/ui/input";
import { NumericInput } from "@/components/ui/numeric-input";
import { Label } from "@/components/ui/label";
import {
    Table,
    TableBody,
    TableCell,
    TableHead,
    TableHeader,
    TableRow,
} from "@/components/ui/table";
import { toast } from "sonner";
import { Badge } from "@/components/ui/badge";
import { useUX } from "@/components/providers/ux-provider";
import { useUnsavedChanges } from "@/hooks/use-unsaved-changes";

export default function InventoryPage() {
    const { showConfirm, setUILocked } = useUX();
    const [products, setProducts] = useState<any[]>([]);
    const [stats, setStats] = useState<any>({ totalProducts: 0, lowStock: 0, totalValue: 0 });
    const [forecast, setForecast] = useState<any>(null);
    const [loading, setLoading] = useState(true);
    const [isSubmitting, setIsSubmitting] = useState(false);
    const [showForm, setShowForm] = useState(false);
    const [editingProduct, setEditingProduct] = useState<any>(null);
    const [searchQuery, setSearchQuery] = useState("");
    const [obProduct, setObProduct] = useState<any>(null);
    const [mounted, setMounted] = useState(false);
    const [fetchError, setFetchError] = useState<string | null>(null);
    const [formData, setFormData] = useState({
        name: "",
        sku: "",
        stock: 0,
        price: 0,
        costPrice: 0,
        category: "",
        tags: "",
        brand: "",
        manufacturer: "",
        minStockLevel: 0,
        hsnCode: "",
        gstRate: 0,
        description: "",
        barcode: "",
        isService: false
    });

    useUnsavedChanges(showForm || formData.name !== "" || formData.sku !== "");

    const [page, setPage] = useState(1);
    const [totalPages, setTotalPages] = useState(1);

    const syncInventory = async (showLoading = false) => {
        try {
            if (showLoading) setLoading(true);
            setFetchError(null);
            const [prodRes, statsRes, aiRes] = await Promise.all([
                api.get(`/inventory/products?page=${page}&limit=50`),
                api.get("inventory/stats"),
                api.get("system/ai/inventory-forecast")
            ]);

            if (prodRes.data?.data) {
                setProducts(prodRes.data.data);
                setTotalPages(prodRes.data.meta?.totalPages || 1);
            } else {
                setProducts(Array.isArray(prodRes.data) ? prodRes.data : []);
            }

            setStats(statsRes.data || { totalProducts: 0, lowStock: 0, totalValue: 0 });
            setForecast(aiRes.data || null);
        } catch (err: any) {
            console.error("Inventory Sync Failure:", err);
            const msg = err.isWakeup ? err.message : "Inventory update interrupted";
            setFetchError(msg);
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        setMounted(true);
        syncInventory(true);

        // CONTINUOUS BACKGROUND SYNC: 30s interval
        const interval = setInterval(() => syncInventory(false), 30000);
        return () => clearInterval(interval);
    }, [page]);

    if (!mounted) return null;

    const handleCreate = async (e: React.FormEvent) => {
        e.preventDefault();
        try {
            setIsSubmitting(true);
            setUILocked(true);
            const finalSku = formData.sku.trim() || `PRD-${Date.now().toString().slice(-6)}`;

            const payload = {
                ...formData,
                sku: finalSku,
                stock: Number(formData.stock),
                price: Number(formData.price),
                costPrice: Number(formData.costPrice),
                gstRate: Number(formData.gstRate),
                minStockLevel: Number(formData.minStockLevel)
            };

            await api.post("inventory/products", payload);

            setShowForm(false);
            setFormData({
                name: "", sku: "", stock: 0, price: 0, costPrice: 0, category: "",
                tags: "", brand: "", manufacturer: "", minStockLevel: 0, hsnCode: "", gstRate: 0,
                description: "", barcode: "", isService: false
            });
            toast.success("Product details updated");
            syncInventory(false);
        } catch (err: any) {
            toast.error(err.response?.data?.message || "Creation failed");
        } finally {
            setIsSubmitting(false);
            setUILocked(false);
        }
    };

    const handleUpdate = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!editingProduct) return;
        try {
            setIsSubmitting(true);
            setUILocked(true);

            const payload = {
                ...formData,
                stock: Number(formData.stock),
                price: Number(formData.price),
                costPrice: Number(formData.costPrice),
                gstRate: Number(formData.gstRate),
                minStockLevel: Number(formData.minStockLevel)
            };

            await api.patch(`/inventory/products/${editingProduct.id}`, payload);

            setEditingProduct(null);
            setFormData({
                name: "", sku: "", stock: 0, price: 0, costPrice: 0, category: "",
                tags: "", brand: "", manufacturer: "", minStockLevel: 0, hsnCode: "", gstRate: 0,
                description: "", barcode: "", isService: false
            });
            toast.success("Product updated");
            syncInventory(false);
        } catch (err: any) {
            toast.error(err.response?.data?.message || "Update failed");
        } finally {
            setIsSubmitting(false);
            setUILocked(false);
        }
    };

    const startEdit = (p: any) => {
        setEditingProduct(p);
        setFormData({
            name: p.name || "",
            sku: p.sku || "",
            stock: Number(p.stock) || 0,
            price: Number(p.price) || 0,
            costPrice: Number(p.costPrice) || 0,
            category: p.category || "",
            tags: p.tags || "",
            brand: p.brand || "",
            manufacturer: p.manufacturer || "",
            minStockLevel: Number(p.minStockLevel) || 0,
            hsnCode: p.hsnCode || "",
            gstRate: Number(p.gstRate) || 0,
            description: p.description || "",
            barcode: p.barcode || "",
            isService: p.isService || false
        });
        setShowForm(false); // Close add form if open
    };

    const handleDelete = (id: string) => {
        showConfirm({
            title: "Delete Product?",
            description: "This will permanently delete the product. This action cannot be undone.",
            confirmText: "Delete",
            variant: "destructive",
            onConfirm: async () => {
                try {
                    setUILocked(true);
                    await api.delete(`/inventory/products/${id}`);
                    toast.success("Product deleted successfully");
                    syncInventory(false);
                } catch (err) {
                    toast.error("Failed to delete product");
                } finally {
                    setUILocked(false);
                }
            }
        });
    };

    const filteredProducts = (products || []).filter(p =>
        p.name?.toLowerCase().includes(searchQuery.toLowerCase()) ||
        p.sku?.toLowerCase().includes(searchQuery.toLowerCase()) ||
        (p.category && p.category.toLowerCase().includes(searchQuery.toLowerCase())) ||
        (p.tags && p.tags.toLowerCase().includes(searchQuery.toLowerCase())) ||
        (p.brand && p.brand.toLowerCase().includes(searchQuery.toLowerCase()))
    );

    const handleImport = async (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (!file) return;

        const reader = new FileReader();
        reader.onload = async (event) => {
            const csv = event.target?.result as string;
            try {
                if (typeof csv !== 'string') return;
                const loadingToast = toast.loading("Processing bulk import...");
                const res = await api.post("inventory/import", { csv });
                toast.dismiss(loadingToast);
                toast.success(`Processed: ${res.data.imported} products imported`);
                if (res.data.failed > 0) {
                    toast.warning(`${res.data.failed} rows failed. Check console.`);
                    console.warn(res.data.errors);
                }
                syncInventory(false);
            } catch (err) {
                toast.dismiss();
                toast.error("Import failed");
            }
        };
        reader.readAsText(file);
    };

    return (
        <div className="flex-1 space-y-6 md:space-y-8 pt-2 md:pt-6 px-4 md:px-8 w-full max-w-full overflow-hidden">
            <div className="flex flex-col lg:flex-row lg:items-center justify-between gap-4 lg:gap-0">
                <div>
                    <h2 className="text-4xl font-black tracking-tight text-slate-900 flex items-center">
                        <Boxes className="mr-4 h-9 w-9 text-blue-600 shadow-sm shrink-0" />
                        <span className="truncate">Products & Inventory</span>
                    </h2>
                    <p className="text-slate-500 mt-2 font-medium truncate">Manage your products, stock levels, and warehouse items.</p>
                </div>
                <div className="flex flex-wrap gap-3 w-full lg:w-auto mt-2 lg:mt-0">
                    <div className="relative flex-1 sm:flex-none">
                        <Input type="file" accept=".csv" onChange={handleImport} className="absolute inset-0 opacity-0 cursor-pointer w-full h-full" />
