"use client";

import { useEffect, useState } from "react";
import { Navbar } from "@/components/layout/navbar";
import { Sidebar } from "@/components/layout/sidebar";
import AuthGuard from "@/components/auth/auth-guard";
import { CommandPalette } from "@/components/layout/command-palette";
import { jwtDecode } from "jwt-decode";
import { Loader2 } from "lucide-react";
import { DraftRecovery } from "@/components/auth/draft-recovery";

const DashboardLayout = ({
    children
}: {
    children: React.ReactNode;
}) => {
    const [isIdentityState, setIsIdentityState] = useState<boolean | null>(null);

    useEffect(() => {
        try {
            const token = localStorage.getItem("k_token");
            if (token) {
                const decoded: any = jwtDecode(token);
                setIsIdentityState(decoded.type === 'identity');
            } else {
                setIsIdentityState(false);
            }
        } catch {
            setIsIdentityState(false);
        }
    }, []);

    // Prevent hydration flashes
    if (isIdentityState === null) {
        return (
            <div className="flex bg-slate-50 h-screen w-screen items-center justify-center">
                <Loader2 className="w-8 h-8 text-blue-600 animate-spin" />
            </div>
        );
    }

    if (isIdentityState) {
        return (
            <AuthGuard>
                {children}
            </AuthGuard>
        );
    }

    return (
        <AuthGuard>
            <div className="h-screen bg-white text-slate-900 overflow-hidden relative">
                <CommandPalette />
                <div className="hidden h-full md:flex md:w-72 md:flex-col md:fixed md:inset-y-0 z-[80] border-r border-slate-100 bg-slate-50/50">
                    <Sidebar />
                </div>
                <div className="md:pl-72 h-full flex flex-col overflow-hidden">
                    <Navbar />
                    <DraftRecovery />
                    <main className="flex-1 overflow-y-auto scrollbar-hide">
                        <div className="max-w-[1700px] mx-auto min-h-full p-4 sm:p-6 md:p-8 lg:p-12">
                            {children}
                        </div>
                    </main>
                </div>
            </div>
        </AuthGuard>
    );
}

export default DashboardLayout;

"use client";

import { useState, useEffect } from "react";
import {
    Cpu,
    Plus,
    Settings,
    Activity,
    AlertTriangle,
    CheckCircle2,
    Clock,
    Wrench,
    Search,
    Filter
} from "lucide-react";
import { toast } from "sonner";
import { api } from "@/lib/api";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card";
import { Input } from "@/components/ui/input";
import {
    Dialog,
    DialogContent,
    DialogHeader,
    DialogTitle,
    DialogDescription,
    DialogTrigger,
    DialogFooter,
} from "@/components/ui/dialog";
import {
    Select,
    SelectContent,
    SelectItem,
    SelectTrigger,
    SelectValue,
} from "@/components/ui/select";
import { Badge } from "@/components/ui/badge";
import { Progress } from "@/components/ui/progress";

interface Machine {
    id: string;
    name: string;
    code: string;
    type: string;
    status: "Idle" | "Running" | "Maintenance" | "Offline";
    hourlyRate: number;
    lastMaintenance: string | null;
    health?: number; // Calculated on frontend for "wow" factor
}

export default function MachinesPage() {
    const [machines, setMachines] = useState<Machine[]>([]);
    const [loading, setLoading] = useState(true);
    const [search, setSearch] = useState("");
    const [isAddOpen, setIsAddOpen] = useState(false);
    const [newMachine, setNewMachine] = useState({
        name: "",
        code: "",
        type: "",
        hourlyRate: 0,
        status: "Idle"
    });

    useEffect(() => {
        fetchMachines();
    }, []);

    const fetchMachines = async () => {
        try {
            const res = await api.get("/manufacturing/machines");
            // Add mock health data for visual appeal
            const enriched = res.data.map((m: Machine) => ({
                ...m,
                health: Math.floor(Math.random() * 20) + 80 // 80-100%
            }));
            setMachines(enriched);
        } catch (error) {
            toast.error("Failed to load machines");
        } finally {
            setLoading(false);
        }
    };

    const handleCreate = async () => {
        try {
            if (!newMachine.name || !newMachine.code) {
                toast.error("Name and Code are required");
                return;
            }
            await api.post("/manufacturing/machines", newMachine);
            toast.success("Machine registered successfully");
            setIsAddOpen(false);
            fetchMachines();
            setNewMachine({ name: "", code: "", type: "", hourlyRate: 0, status: "Idle" });
        } catch (error) {
            toast.error("Registration failed");
        }
    };

    const getStatusColor = (status: string) => {
        switch (status) {
            case "Running": return "bg-emerald-500/10 text-emerald-500 border-emerald-500/20";
            case "Idle": return "bg-blue-500/10 text-blue-500 border-blue-500/20";
            case "Maintenance": return "bg-amber-500/10 text-amber-500 border-amber-500/20";
            default: return "bg-slate-500/10 text-slate-500 border-slate-500/20";
        }
    };

    const filtered = machines.filter(m =>
        m.name.toLowerCase().includes(search.toLowerCase()) ||
        m.code.toLowerCase().includes(search.toLowerCase())
    );

    return (
        <div className="p-6 space-y-6 max-w-7xl mx-auto">
            <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
                <div>
                    <h1 className="text-3xl font-bold tracking-tight bg-gradient-to-r from-white to-slate-400 bg-clip-text text-transparent">
                        Smart Factory Floor
                    </h1>
                    <p className="text-slate-400 mt-1">Manage and monitor manufacturing assets in real-time.</p>
                </div>

                <div className="flex items-center gap-2">
                    <div className="relative w-64">
                        <Search className="absolute left-2.5 top-2.5 h-4 w-4 text-slate-500" />
                        <Input
                            placeholder="Search assets..."
                            className="pl-9 bg-slate-900/50 border-slate-800"
                            value={search}
                            onChange={(e) => setSearch(e.target.value)}
                        />
                    </div>

                    <Dialog open={isAddOpen} onOpenChange={setIsAddOpen}>
                        <DialogTrigger asChild>
                            <Button className="bg-blue-600 hover:bg-blue-500 transition-all shadow-lg shadow-blue-500/20">
                                <Plus className="w-4 h-4 mr-2" />
                                Add Machine
                            </Button>
                        </DialogTrigger>
                        <DialogContent className="bg-slate-950 border-slate-800 text-white">
                            <DialogHeader>
                                <DialogTitle>Register New Asset</DialogTitle>
                                <DialogDescription>Add a machine to the factory floor tracking system.</DialogDescription>
                            </DialogHeader>
                            <div className="space-y-4 py-4">
                                <div className="grid grid-cols-2 gap-4">
                                    <div className="space-y-2">
                                        <label className="text-sm font-medium">Machine Name</label>
                                        <Input
                                            placeholder="CNC Milling X1"
                                            className="bg-slate-900 border-slate-800"
                                            value={newMachine.name}
                                            onChange={e => setNewMachine({ ...newMachine, name: e.target.value })}
                                        />
                                    </div>
                                    <div className="space-y-2">
                                        <label className="text-sm font-medium">Unique Code</label>
                                        <Input
                                            placeholder="MAC-001"
                                            className="bg-slate-900 border-slate-800"
                                            value={newMachine.code}
                                            onChange={e => setNewMachine({ ...newMachine, code: e.target.value })}
                                        />
                                    </div>
                                </div>
                                <div className="space-y-2">
                                    <label className="text-sm font-medium">Asset Type</label>
                                    <Input
                                        placeholder="Subtractive Manufacturing"
                                        className="bg-slate-900 border-slate-800"
                                        value={newMachine.type}
                                        onChange={e => setNewMachine({ ...newMachine, type: e.target.value })}
                                    />
                                </div>
                                <div className="space-y-2">
                                    <label className="text-sm font-medium">Hourly Rate (Ôé╣)</label>
                                    <Input
                                        type="number"
                                        placeholder="1200.00"
                                        className="bg-slate-900 border-slate-800"
                                        value={newMachine.hourlyRate}
                                        onChange={e => setNewMachine({ ...newMachine, hourlyRate: parseFloat(e.target.value) })}
                                    />
                                    <p className="text-[10px] text-slate-500">Used for precise COGS & Overhead calculations.</p>
                                </div>
                            </div>
                            <DialogFooter>
                                <Button variant="ghost" onClick={() => setIsAddOpen(false)}>Cancel</Button>
                                <Button onClick={handleCreate} className="bg-blue-600 hover:bg-blue-500">Register Asset</Button>
                            </DialogFooter>
                        </DialogContent>
                    </Dialog>
                </div>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                {loading ? (
                    [1, 2, 3].map(i => <div key={i} className="h-48 rounded-xl bg-slate-900/50 animate-pulse border border-slate-800" />)
                ) : filtered.length === 0 ? (
                    <div className="col-span-full py-20 text-center border-2 border-dashed border-slate-800 rounded-3xl">
                        <Cpu className="w-12 h-12 mx-auto text-slate-700 mb-4" />
                        <h3 className="text-lg font-medium text-slate-400">No assets found</h3>
                        <p className="text-slate-500">Click Add Machine to register your first manufacturing asset.</p>
                    </div>
                ) : (
                    filtered.map((m) => (
                        <Card key={m.id} className="bg-slate-900/40 border-slate-800 hover:border-slate-700 transition-all group overflow-hidden relative">
                            <div className="absolute top-0 right-0 p-4 opacity-10 group-hover:opacity-20 transition-opacity">
                                <Cpu className="w-16 h-16" />
                            </div>
                            <CardHeader className="pb-2">
                                <div className="flex justify-between items-start">
                                    <div>
                                        <Badge variant="outline" className={getStatusColor(m.status)}>
                                            {m.status === "Running" && <Activity className="w-3 h-3 mr-1 animate-pulse" />}
                                            {m.status}
                                        </Badge>
                                        <CardTitle className="text-xl mt-3">{m.name}</CardTitle>
                                        <CardDescription>{m.code} ÔÇó {m.type}</CardDescription>
                                    </div>
                                    <Button variant="ghost" size="icon" className="text-slate-500 hover:text-white">
                                        <Settings className="w-4 h-4" />
                                    </Button>
                                </div>
                            </CardHeader>
                            <CardContent className="space-y-4">
                                <div className="grid grid-cols-2 gap-4 text-sm mt-2">
                                    <div className="space-y-1">
                                        <p className="text-slate-500 flex items-center"><Clock className="w-3 h-3 mr-1" /> Rate/Hr</p>
                                        <p className="font-semibold text-slate-200">Ôé╣{m.hourlyRate.toFixed(2)}</p>
                                    </div>
                                    <div className="space-y-1">
                                        <p className="text-slate-500 flex items-center"><Wrench className="w-3 h-3 mr-1" /> Last Maint.</p>
                                        <p className="font-semibold text-slate-200">
                                            {m.lastMaintenance ? new Date(m.lastMaintenance).toLocaleDateString() : 'Never'}
                                        </p>
                                    </div>
                                </div>

                                <div className="space-y-2 mt-2">
                                    <div className="flex justify-between text-xs">
                                        <span className="text-slate-400">Asset Health</span>
                                        <span className={m.health && m.health < 85 ? "text-amber-400" : "text-emerald-400"}>
                                            {m.health}%
                                        </span>
                                    </div>
                                    <Progress value={m.health} className="h-1.5 bg-slate-800" />
                                </div>

                                <div className="flex gap-2 pt-2">
                                    <Button variant="outline" className="flex-1 bg-slate-900/50 border-slate-800 hover:bg-slate-800 text-xs h-8">
                                        Diagnostics
                                    </Button>
                                    <Button variant="outline" className="flex-1 bg-slate-900/50 border-slate-800 hover:bg-slate-800 text-xs h-8">
                                        History
                                    </Button>
                                </div>
                            </CardContent>
                        </Card>
                    ))
                )}
            </div>
        </div>
    );
}

"use client";

import React, { useState, useEffect } from "react";
import {
    Factory,
    Plus,
    Search,
    Calendar,
    Clock,
    CheckCircle2,
    AlertCircle,
    Boxes,
    ArrowRight,
    TrendingUp,
    BadgeCheck
} from "lucide-react";
import { api } from "@/lib/api";
import { toast } from "sonner";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card";
import { Input } from "@/components/ui/input";
import {
    Table,
    TableBody,
    TableCell,
    TableHead,
    TableHeader,
    TableRow
} from "@/components/ui/table";
import { LoadingSpinner } from "@/components/ui/loading-spinner";
import { CreateWorkOrderDialog } from "@/components/manufacturing/create-work-order-dialog";
import { CompleteWorkOrderDialog } from "@/components/manufacturing/complete-work-order-dialog";

export default function WorkOrdersPage() {
    const [workOrders, setWorkOrders] = useState<any[]>([]);
    const [loading, setLoading] = useState(true);
    const [searchQuery, setSearchQuery] = useState("");

    const syncExecutionQueues = async (showLoading = false) => {
        try {
            if (showLoading) setLoading(true);
            const res = await api.get("manufacturing/work-orders");
            setWorkOrders(res.data);
        } catch (err) {
            console.error("Execution Queue Sync Failure:", err);
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        syncExecutionQueues(true);
        const interval = setInterval(() => syncExecutionQueues(false), 30000);
        return () => clearInterval(interval);
    }, []);

    useEffect(() => {
        syncExecutionQueues(true);
        const interval = setInterval(() => syncExecutionQueues(false), 30000);
        return () => clearInterval(interval);
    }, []);

    const getStatusBadge = (status: string) => {
        switch (status) {
            case 'Completed':
                return <Badge className="bg-emerald-50 text-emerald-600 border-none font-black text-[10px] uppercase tracking-tighter rounded-lg">Completed</Badge>;
            case 'InProgress':
                return <Badge className="bg-blue-50 text-blue-600 border-none font-black text-[10px] uppercase tracking-tighter rounded-lg animate-pulse">In Production</Badge>;
            case 'Planned':
                return <Badge className="bg-slate-100 text-slate-500 border-none font-black text-[10px] uppercase tracking-tighter rounded-lg">Planned</Badge>;
            default:
                return <Badge variant="outline" className="text-[10px] uppercase tracking-tighter rounded-lg">{status}</Badge>;
        }
    };

    const filteredOrders = workOrders.filter(wo =>
        wo.orderNumber.toLowerCase().includes(searchQuery.toLowerCase()) ||
        wo.bom?.product?.name.toLowerCase().includes(searchQuery.toLowerCase())
    );

    if (loading) return <LoadingSpinner className="h-full" text="Loading work orders..." />;

    return (
        <div className="flex-1 space-y-6 md:space-y-8 pt-2 md:pt-6 px-4 md:px-8 w-full max-w-full overflow-hidden">
            <div className="flex flex-col lg:flex-row lg:items-center justify-between gap-4 lg:gap-0">
                <div>
                    <h2 className="text-4xl font-black tracking-tight text-slate-900 flex items-center">
                        <Factory className="mr-4 h-9 w-9 text-emerald-600 shadow-sm" />
                        Work Orders
                    </h2>
                    <p className="text-slate-500 mt-2 font-medium">Create and track work orders for your production runs.</p>
                </div>
                <CreateWorkOrderDialog refreshData={() => syncExecutionQueues(false)}>
                    <Button className="rounded-2xl bg-emerald-600 hover:bg-emerald-700 font-bold px-8 shadow-lg shadow-emerald-500/20 text-white h-11">
                        <Plus className="mr-2 h-4 w-4" /> New Work Order
                    </Button>
                </CreateWorkOrderDialog>
            </div>

            <div className="grid gap-6 md:grid-cols-3">
                <Card className="bg-white border-slate-200 shadow-sm rounded-3xl overflow-hidden border-b-4 border-b-emerald-500">
                    <CardHeader className="pb-2">
                        <CardTitle className="text-[10px] font-black text-slate-400 uppercase tracking-widest text-center">Active Orders</CardTitle>
                    </CardHeader>
                    <CardContent className="text-center">
                        <div className="text-3xl font-black text-slate-900 tracking-tighter">
                            {workOrders.filter(wo => wo.status !== 'Completed').length}
                        </div>
                    </CardContent>
                </Card>
                <Card className="bg-white border-slate-200 shadow-sm rounded-3xl overflow-hidden border-b-4 border-b-blue-500">
                    <CardHeader className="pb-2">
                        <CardTitle className="text-[10px] font-black text-slate-400 uppercase tracking-widest text-center">Completed Today</CardTitle>
                    </CardHeader>
                    <CardContent className="text-center">
                        <div className="text-3xl font-black text-slate-900 tracking-tighter">
                            {workOrders.filter(wo => wo.status === 'Completed').length}
                        </div>
                    </CardContent>
                </Card>
                <Card className="bg-white border-slate-200 shadow-sm rounded-3xl overflow-hidden border-b-4 border-b-amber-500">
                    <CardHeader className="pb-2">
                        <CardTitle className="text-[10px] font-black text-slate-400 uppercase tracking-widest text-center">Avg. Efficiency</CardTitle>
                    </CardHeader>
                    <CardContent className="text-center">
                        <div className="text-3xl font-black text-slate-900 tracking-tighter">98.2%</div>
                    </CardContent>
                </Card>
            </div>

            <Card className="bg-white border-slate-200 shadow-xl shadow-slate-200/40 rounded-3xl overflow-hidden border-none">
                <CardHeader className="bg-slate-50 border-b border-slate-100 py-6 md:py-8 px-4 md:px-6">
                    <div className="flex flex-col lg:flex-row lg:items-center justify-between gap-4 lg:gap-0">
                        <div>
                            <CardTitle className="text-slate-900 text-xl font-black">Work Orders</CardTitle>
                            <CardDescription className="text-slate-500 font-bold uppercase text-[10px] tracking-widest mt-1">History of all production runs</CardDescription>
                        </div>
                        <div className="relative w-full md:w-96">
                            <Search className="absolute left-4 top-3.5 h-4 w-4 text-slate-400" />
                            <Input
                                placeholder="Search by Order ID or Product..."
                                className="pl-12 bg-white border-slate-200 text-slate-900 rounded-2xl h-12 shadow-inner font-semibold focus:ring-blue-500/20"
                                value={searchQuery}
                                onChange={(e) => setSearchQuery(e.target.value)}
                            />
                        </div>
                    </div>
                </CardHeader>
                <CardContent className="p-0">
                    <Table>
                        <TableHeader className="bg-slate-50/50">
                            <TableRow className="border-slate-100 hover:bg-transparent">
                                <TableHead className="text-slate-500 font-bold uppercase text-[10px] tracking-widest pl-8">Order ID</TableHead>
                                <TableHead className="text-slate-500 font-bold uppercase text-[10px] tracking-widest">Finished Product</TableHead>
                                <TableHead className="text-slate-500 font-bold uppercase text-[10px] tracking-widest">Quantity</TableHead>
                                <TableHead className="text-slate-500 font-bold uppercase text-[10px] tracking-widest">Status</TableHead>
                                <TableHead className="text-slate-500 font-bold uppercase text-[10px] tracking-widest">Timeline</TableHead>
                                <TableHead className="text-slate-500 font-bold uppercase text-[10px] tracking-widest text-right pr-8">Actions</TableHead>
                            </TableRow>
                        </TableHeader>
                        <TableBody>
                            {filteredOrders.map((wo) => (
                                <TableRow key={wo.id} className="border-slate-100 hover:bg-slate-50/50 transition-all group">
                                    <TableCell className="pl-8">
                                        <div className="font-black text-blue-600 tracking-widest text-[11px]">WO-{wo.orderNumber}</div>
                                        <div className="text-[9px] text-slate-400 font-bold uppercase mt-0.5">PRIORITY: {wo.priority.toUpperCase()}</div>
                                    </TableCell>
                                    <TableCell>
                                        <div className="flex items-center gap-3">
                                            <div className="h-8 w-8 rounded-lg bg-slate-100 flex items-center justify-center text-slate-400">
                                                <Boxes className="h-4 w-4" />
                                            </div>
                                            <div className="font-bold text-slate-900 text-sm">{wo.bom?.product?.name}</div>
                                        </div>
                                    </TableCell>
                                    <TableCell>
                                        <div className="font-black text-slate-900">x{wo.quantity}</div>
                                        <div className="text-[9px] text-slate-400 font-bold uppercase">Planned Units</div>
                                    </TableCell>
                                    <TableCell>
                                        {getStatusBadge(wo.status)}
                                    </TableCell>
                                    <TableCell>
                                        <div className="flex items-center text-[10px] text-slate-500 font-bold">
                                            <Calendar className="h-3 w-3 mr-2" />
                                            {wo.startDate ? new Date(wo.startDate).toLocaleDateString() : 'N/A'}
                                        </div>
                                        <div className="flex items-center text-[9px] text-slate-400 font-medium mt-1 uppercase tracking-tighter">
                                            <Clock className="h-3 w-3 mr-1" /> Estimated 4h 30m
                                        </div>
                                    </TableCell>
                                    <TableCell className="text-right pr-8">
                                        {wo.status !== 'Completed' ? (
                                            <CompleteWorkOrderDialog workOrder={wo} refreshData={() => syncExecutionQueues(true)}>
                                                <Button
                                                    className="bg-slate-900 hover:bg-emerald-600 text-white font-bold h-9 rounded-xl px-5 text-[10px] uppercase tracking-widest shadow-lg shadow-slate-900/10"
                                                >
                                                    Mark Complete
                                                </Button>
                                            </CompleteWorkOrderDialog>
                                        ) : (
                                            <div className="flex items-center justify-end text-emerald-600">
                                                <BadgeCheck className="h-5 w-5" />
                                            </div>
                                        )}
                                    </TableCell>
                                </TableRow>
                            ))}
                            {filteredOrders.length === 0 && (
                                <TableRow>
                                    <TableCell colSpan={6} className="h-48 text-center text-slate-400 font-bold italic bg-slate-50/10 uppercase tracking-widest text-[10px]">
                                        No Production Orders found.
                                    </TableCell>
                                </TableRow>
                            )}
                        </TableBody>
                    </Table>
                </CardContent>
            </Card>
        </div>
    );
}

"use client";

import React, { useState, useEffect } from "react";
import { useRouter } from "next/navigation";
import {
    Factory,
    Package,
    Settings,
    CheckCircle2,
    AlertCircle,
    Play,
    Plus,
    ArrowRight,
    TrendingUp,
    Boxes,
    Cpu
} from "lucide-react";
import { api } from "@/lib/api";
import { toast } from "react-hot-toast";
import { cn } from "@/lib/utils";
import { Badge } from "@/components/ui/badge";
import { Card } from "@/components/ui/card";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import {
    Dialog,
    DialogContent,
    DialogHeader,
    DialogTitle,
    DialogFooter,
} from "@/components/ui/dialog";
import {
    Select,
    SelectContent,
    SelectItem,
    SelectTrigger,
    SelectValue,
} from "@/components/ui/select";

export default function ManufacturingDashboard() {
    const [boms, setBoms] = useState<any[]>([]);
    const [workOrders, setWorkOrders] = useState<any[]>([]);
    const [loading, setLoading] = useState(true);
    const router = useRouter();

    const [showCompleteModal, setShowCompleteModal] = useState(false);
    const [selectedWO, setSelectedWO] = useState<any>(null);
    const [warehouses, setWarehouses] = useState<any[]>([]);
    const [machines, setMachines] = useState<any[]>([]);
    const [completionData, setCompletionData] = useState({
        producedQty: 0,
        scrapQty: 0,
        warehouseId: "",
        machineId: "",
        machineTimeHours: 0,
        operatorName: "",
        idempotencyKey: "",
    });

    const syncManufacturingData = async (showLoading = false) => {
        try {
            if (showLoading) setLoading(true);
            const [b, w, wh, m] = await Promise.all([
                api.get("manufacturing/boms"),
                api.get("manufacturing/work-orders"),
                api.get("inventory/warehouses"),
                api.get("manufacturing/machines"),
            ]);
            setBoms(b.data);
            setWorkOrders(w.data);
            setWarehouses(wh.data || []);
            setMachines(m.data || []);
        } catch (err) {
            console.error("Manufacturing Sync Failure:", err);
        } finally {
            setLoading(false);
        }
    };

    const handleOpenComplete = (wo: any) => {
        setSelectedWO(wo);
        setCompletionData({
            producedQty: wo.quantity,
            scrapQty: 0,
            warehouseId: "",
            machineId: "",
            machineTimeHours: 0,
            operatorName: "",
            idempotencyKey: `wo-comp-${wo.id}-${Date.now()}`,
        });
        setShowCompleteModal(true);
    };

    const submitCompletion = async () => {
        if (!completionData.warehouseId) {
            toast.error("Please select a target warehouse");
            return;
        }
        try {
            await api.post(`/manufacturing/work-orders/${selectedWO.id}/complete`, {
                producedQuantity: Number(completionData.producedQty),
                scrapQuantity: Number(completionData.scrapQty),
                machineId: completionData.machineId,
                machineTimeHours: Number(completionData.machineTimeHours),
                operatorName: completionData.operatorName,
                warehouseId: completionData.warehouseId,
                idempotencyKey: completionData.idempotencyKey,
            });
            toast.success("Production Completed! Inventory Updated.");
            setShowCompleteModal(false);
            syncManufacturingData();
        } catch (err: any) {
            toast.error(err.response?.data?.message || "Production failed. Check raw materials.");
        }
    };

    useEffect(() => {
        syncManufacturingData(true);

        // CONTINUOUS BACKGROUND SYNC: 30s interval
        const interval = setInterval(() => syncManufacturingData(false), 30000);
        return () => clearInterval(interval);
    }, []);

    if (loading) return (
        <div className="flex items-center justify-center min-h-[400px]">
            <div className="flex flex-col items-center gap-4">
                <div className="h-12 w-12 border-4 border-emerald-600 border-t-transparent rounded-full animate-spin" />
                <p className="text-slate-600 font-black text-[10px] uppercase tracking-widest">Loading Manufacturing Data...</p>
            </div>
        </div>
    );

    return (
        <div className="flex-1 space-y-6 md:space-y-8">
            {/* Header */}
            <div className="flex flex-col lg:flex-row lg:items-center justify-between gap-4 lg:gap-0">
                <div>
                    <h2 className="text-4xl font-black tracking-tight text-slate-900 flex items-center">
                        <Factory className="mr-4 h-9 w-9 text-emerald-600 shadow-sm" />
                        Manufacturing
                    </h2>
                    <p className="text-slate-500 mt-2 font-medium">Monitor and manage your production orders and materials.</p>
                </div>
                <div className="flex flex-wrap gap-3 w-full md:w-auto">
                    <button
                        onClick={() => router.push('/manufacturing/bom')}
                        className="flex-1 md:flex-none justify-center px-6 py-2.5 bg-white border border-slate-200 rounded-2xl text-[10px] font-black uppercase tracking-widest hover:bg-slate-50 text-slate-600 transition-all flex items-center gap-2 shadow-sm whitespace-nowrap"
                    >
                        <Settings className="w-4 h-4" />
                        Bill of Materials
                    </button>
                    <button
                        onClick={() => router.push('/manufacturing/machines')}
                        className="flex-1 md:flex-none justify-center px-6 py-2.5 bg-white border border-slate-200 rounded-2xl text-[10px] font-black uppercase tracking-widest hover:bg-slate-50 text-slate-600 transition-all flex items-center gap-2 shadow-sm whitespace-nowrap"
                    >
                        <Cpu className="w-4 h-4 shadow-sm" />
                        Machines
                    </button>
                    <button
                        onClick={() => router.push('/manufacturing/orders')}
                        className="flex-1 md:flex-none justify-center px-6 py-2.5 bg-emerald-600 text-white rounded-2xl text-[10px] font-black uppercase tracking-widest hover:bg-emerald-700 transition-all shadow-lg shadow-emerald-500/20 flex items-center gap-2 whitespace-nowrap"
                    >
                        <Plus className="w-4 h-4" />
                        New Work Order
                    </button>
                </div>
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">

                {/* WIP Work Orders */}
                <div className="lg:col-span-2 space-y-6">
                    <div className="flex items-center justify-between">
                        <h2 className="text-[10px] font-black text-slate-600 uppercase tracking-[0.2em] flex items-center gap-3">
                            <div className="h-2 w-2 rounded-full bg-emerald-500 animate-pulse" />
                            Active Work Orders
                        </h2>
                    </div>

                    <div className="space-y-4">
                        {workOrders.map((wo: any) => (
                            <div key={wo.id} className="bg-white border border-slate-200 p-8 rounded-[32px] hover:border-emerald-300 hover:shadow-2xl hover:shadow-emerald-500/5 transition-all group overflow-hidden relative border-none shadow-xl shadow-slate-200/40">
                                <div className="absolute top-0 right-0 w-48 h-48 bg-emerald-50 opacity-0 group-hover:opacity-100 blur-[80px] transition-all -z-0"></div>

                                <div className="flex flex-col sm:flex-row justify-between items-start relative z-10 gap-4 sm:gap-0">
                                    <div className="flex gap-4 sm:gap-8 items-start sm:items-center">
                                        <div className={cn(
                                            "w-12 h-12 sm:w-16 sm:h-16 rounded-2xl flex items-center justify-center transition-all shrink-0",
                                            wo.status === 'Completed' ? 'bg-emerald-50 text-emerald-600' : 'bg-slate-900 text-white shadow-xl shadow-slate-900/20'
                                        )}>
                                            {wo.status === 'Completed' ? <CheckCircle2 className="w-6 h-6 sm:w-8 sm:h-8" /> : <Boxes className="w-6 h-6 sm:w-8 sm:h-8" />}
                                        </div>
                                        <div>
                                            <span className="text-[10px] font-black text-slate-600 uppercase tracking-[0.3em] block mb-1">WO-{wo.orderNumber}</span>
                                            <h3 className="text-xl sm:text-2xl font-black text-slate-900 tracking-tight">{wo.bom?.product?.name}</h3>
                                            <div className="flex flex-wrap items-center gap-2 sm:gap-3 mt-2">
                                                <Badge variant="secondary" className="bg-slate-100 text-slate-500 font-black text-[9px] rounded-lg border-none uppercase">Level 1 Assembly</Badge>
                                                {wo.status !== 'Completed' && <span className="text-[9px] font-black text-amber-500 uppercase tracking-widest animate-pulse italic">In Production</span>}
                                            </div>
                                        </div>
                                    </div>

                                    <div className="text-left sm:text-right w-full sm:w-auto mt-2 sm:mt-0 ml-[4rem] sm:ml-0">
                                        <span className="text-3xl sm:text-4xl font-black text-slate-900 tracking-tighter">x{wo.quantity}</span>
                                        <p className="text-[10px] font-black text-slate-600 uppercase tracking-widest mt-1">Projected Output</p>
                                    </div>
                                </div>

                                <div className="mt-8 sm:mt-10 pt-6 sm:pt-8 border-t border-slate-100 flex flex-col sm:flex-row justify-between items-start sm:items-center relative z-10 gap-4 sm:gap-0">
                                    <div className="flex gap-3 sm:gap-5 items-center pl-[4rem] sm:pl-0">
                                        <div className="flex -space-x-3">
                                            {[1, 2, 3].map(i => (
                                                <div key={i} className="w-8 h-8 rounded-xl bg-slate-100 border-2 border-white shadow-sm flex items-center justify-center text-[10px] font-black text-slate-400">RC</div>
                                            ))}
                                        </div>
                                        <span className="text-[10px] font-black text-slate-600 uppercase tracking-widest">3 Materials Used</span>
                                    </div>

                                    {wo.status !== 'Completed' ? (
                                        <button
                                            onClick={() => handleOpenComplete(wo)}
                                            className="w-full sm:w-auto justify-center px-8 py-3 bg-slate-900 text-white rounded-2xl text-[10px] font-black uppercase tracking-[0.2em] hover:bg-emerald-600 transition-all flex items-center gap-3 shadow-xl shadow-slate-900/10 hover:shadow-emerald-500/20 active:scale-95"
                                        >
                                            Mark Complete
                                            <ArrowRight className="w-4 h-4" />
                                        </button>
                                    ) : (
                                        <div className="w-full sm:w-auto justify-center flex items-center gap-2 px-5 py-2.5 bg-emerald-50 text-emerald-600 rounded-2xl border border-emerald-100">
                                            <CheckCircle2 className="w-4 h-4" />
                                            <span className="text-[9px] font-black uppercase tracking-widest">Production Completed</span>
                                        </div>
                                    )}
                                </div>
                            </div>
                        ))}
                    </div>
                </div>

                {/* BOM Registry & Stats */}
                <div className="space-y-8">
                    <section className="space-y-4">
                        <h2 className="text-[10px] font-black text-slate-600 uppercase tracking-[0.2em]">Production Stats</h2>
                        <Card className="bg-white border-slate-200 shadow-xl shadow-slate-200/40 p-8 rounded-[40px] border-none group relative overflow-hidden">
                            <div className="absolute top-0 right-0 p-8 opacity-[0.03] group-hover:scale-110 transition-transform">
                                <TrendingUp className="h-24 w-24 text-blue-900" />
                            </div>
                            <div className="space-y-8 relative z-10">
                                <div>
                                    <p className="text-[10px] font-black text-slate-600 uppercase tracking-widest mb-2">Avg. Completion Time</p>
                                    <p className="text-4xl font-black text-slate-900 tracking-tighter">14.2<span className="text-sm font-bold ml-1 text-slate-400">MINS</span></p>
                                </div>
                                <div className="h-px bg-slate-100" />
                                <div>
                                    <p className="text-[10px] font-black text-slate-600 uppercase tracking-widest mb-2">Defect Rate</p>
                                    <p className="text-4xl font-black text-emerald-600 tracking-tighter">0.8<span className="text-sm font-bold ml-1">%</span></p>
                                </div>
                            </div>
                        </Card>
                    </section>

                    <section className="space-y-4">
                        <div className="flex items-center justify-between">
                            <h2 className="text-[10px] font-black text-slate-600 uppercase tracking-[0.2em]">Bill of Materials</h2>
                            <span className="text-[9px] font-black text-blue-600 bg-blue-50 px-2 py-0.5 rounded-lg">{boms.length} BOMs</span>
                        </div>
                        <div className="space-y-3">
                            {boms.map((bom: any) => (
                                <div key={bom.id} className="bg-white border border-slate-100 p-5 rounded-3xl flex justify-between items-center group hover:bg-slate-50 cursor-pointer transition-all hover:border-blue-200 hover:shadow-lg hover:shadow-blue-500/5 shadow-sm">
                                    <div className="flex gap-5 items-center">
                                        <div className="p-2.5 bg-slate-50 rounded-xl group-hover:bg-white group-hover:shadow-inner group-hover:scale-110 transition-all">
                                            <Package className="w-5 h-5 text-slate-400 group-hover:text-blue-600 transition-colors" />
                                        </div>
                                        <div>
                                            <p className="text-sm font-black text-slate-900 tracking-tight">{bom.name}</p>
                                            <p className="text-[10px] text-slate-600 font-bold uppercase tracking-widest mt-0.5">{bom.items?.length || 0} Components Required</p>
                                        </div>
                                    </div>
                                    <div className="h-8 w-8 rounded-full bg-slate-50 flex items-center justify-center opacity-0 group-hover:opacity-100 transition-all -translate-x-2 group-hover:translate-x-0">
                                        <ArrowRight className="w-4 h-4 text-slate-400" />
                                    </div>
                                </div>
                            ))}
                        </div>
                    </section>
                </div>

            </div>

            {/* Completion Modal */}
            <Dialog open={showCompleteModal} onOpenChange={setShowCompleteModal}>
                <DialogContent className="max-w-md bg-white border-none rounded-[32px] overflow-hidden p-0 shadow-2xl">
                    <div className="bg-emerald-600 p-8 text-white">
                        <DialogHeader>
                            <DialogTitle className="text-2xl font-black tracking-tight">Complete Production</DialogTitle>
                            <p className="text-emerald-100 font-bold uppercase text-[9px] tracking-widest mt-1 opacity-80">Finalizing WO-{selectedWO?.orderNumber}</p>
                        </DialogHeader>
                    </div>

                    <div className="p-8 space-y-6">
                        <div className="space-y-4">
                            <div className="grid grid-cols-2 gap-4">
                                <div className="space-y-2 text-slate-900">
                                    <Label className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Produced Quantity</Label>
                                    <Input
                                        type="number"
                                        value={completionData.producedQty}
                                        onChange={(e) => setCompletionData({ ...completionData, producedQty: Number(e.target.value) })}
                                        className="h-12 rounded-xl bg-slate-50 border-slate-100 font-black text-lg focus:ring-emerald-500/20"
                                    />
                                </div>
                                <div className="space-y-2">
                                    <Label className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Scrap / Rejects</Label>
                                    <Input
                                        type="number"
                                        value={completionData.scrapQty}
                                        onChange={(e) => setCompletionData({ ...completionData, scrapQty: Number(e.target.value) })}
                                        className="h-12 rounded-xl bg-slate-50 border-slate-100 font-black text-lg text-rose-600 focus:ring-rose-500/20"
                                    />
                                </div>
                            </div>

                            <div className="grid grid-cols-2 gap-4">
                                <div className="space-y-2">
                                    <Label className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Target Machine</Label>
                                    <Select value={completionData.machineId} onValueChange={(val) => setCompletionData({ ...completionData, machineId: val })}>
                                        <SelectTrigger className="h-12 rounded-xl bg-slate-50 border-slate-100 font-bold">
                                            <SelectValue placeholder="Select machine" />
                                        </SelectTrigger>
                                        <SelectContent>
                                            {machines.map((m: any) => (
                                                <SelectItem key={m.id} value={m.id} className="font-bold">{m.name} ({m.code})</SelectItem>
                                            ))}
                                        </SelectContent>
                                    </Select>
                                </div>
                                <div className="space-y-2">
                                    <Label className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Machine Hours</Label>
                                    <Input
                                        type="number"
                                        step="0.1"
                                        placeholder="0.0"
                                        value={completionData.machineTimeHours}
                                        onChange={(e) => setCompletionData({ ...completionData, machineTimeHours: Number(e.target.value) })}
                                        className="h-12 rounded-xl bg-slate-50 border-slate-100 font-black text-lg focus:ring-emerald-500/20"
                                    />
                                </div>
                            </div>

                            <div className="space-y-2">
                                <Label className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Operator Name</Label>
                                <Input
                                    placeholder="John Doe"
                                    value={completionData.operatorName}
                                    onChange={(e) => setCompletionData({ ...completionData, operatorName: e.target.value })}
                                    className="h-12 rounded-xl bg-slate-50 border-slate-100 font-bold focus:ring-emerald-500/20"
                                />
                            </div>

                            <div className="space-y-2">
                                <Label className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Target Warehouse</Label>
                                <Select value={completionData.warehouseId} onValueChange={(val) => setCompletionData({ ...completionData, warehouseId: val })}>
                                    <SelectTrigger className="h-12 rounded-xl bg-slate-50 border-slate-100 font-bold">
                                        <SelectValue placeholder="Select destination" />
                                    </SelectTrigger>
                                    <SelectContent>
                                        {warehouses.map((wh: any) => (
                                            <SelectItem key={wh.id} value={wh.id} className="font-bold">{wh.name}</SelectItem>
                                        ))}
                                    </SelectContent>
                                </Select>
                            </div>
                        </div>

                        <div className="bg-emerald-50 p-4 rounded-xl flex items-center gap-3">
                            <AlertCircle className="w-5 h-5 text-emerald-600 shrink-0" />
                            <p className="text-[10px] font-bold text-emerald-900 leading-relaxed uppercase tracking-tight">
                                Finalizing will consume raw materials and add finished goods to selected warehouse.
                            </p>
                        </div>
                    </div>

                    <DialogFooter className="p-8 pt-0 flex gap-3">
                        <button
                            onClick={() => setShowCompleteModal(false)}
                            className="flex-1 py-3 text-slate-400 font-black text-[10px] uppercase tracking-widest hover:text-slate-600 transition-all"
                        >
                            Abort
                        </button>
                        <button
                            onClick={submitCompletion}
                            className="flex-[2] py-4 bg-emerald-600 text-white rounded-2xl font-black text-[10px] uppercase tracking-widest hover:bg-emerald-700 transition-all shadow-lg shadow-emerald-500/20"
                        >
                            Confirm Production
                        </button>
                    </DialogFooter>
                </DialogContent>
            </Dialog>
        </div>
    );
}

"use client";

import { useState } from "react";
import { useRouter } from "next/navigation";
import { useForm } from "react-hook-form";
import { zodResolver } from "@hookform/resolvers/zod";
import * as z from "zod";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Card, CardContent, CardDescription, CardFooter, CardHeader, CardTitle } from "@/components/ui/card";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Loader2, CheckCircle2 } from "lucide-react";
import { toast } from "sonner";
import { api } from "@/lib/api";
import { useAuth } from "@/hooks/use-auth";

const onboardingSchema = z.object({
    industry: z.string().min(1, "Please select an industry"),
    businessType: z.string().min(1, "Please select a business type"),
    gstin: z.union([
        z.string().length(15, "GSTIN must be exactly 15 characters"),
        z.literal(""),
    ]).optional(),
});

type OnboardingFormData = z.infer<typeof onboardingSchema>;

export default function OnboardingPage() {
    const router = useRouter();
    const { user } = useAuth();
    const [isLoading, setIsLoading] = useState(false);

    const {
        register,
        handleSubmit,
        setValue,
        formState: { errors },
    } = useForm<OnboardingFormData>({
        resolver: zodResolver(onboardingSchema),
    });

    const onSubmit = async (data: OnboardingFormData) => {
        if (!user?.tenantId) {
            toast.error("Session error", {
                description: "Could not read your workspace. Please refresh the page.",
            });
            return;
        }

        setIsLoading(true);
        try {
            await api.post("auth/onboarding", {
                ...data,
                tenantId: user.tenantId,
            });

            // Refresh the token so it includes isOnboarded: true,
            // then go directly to the dashboard without forcing re-login.
            try {
                const { data: refreshData } = await api.post("auth/refresh", {}, { withCredentials: true });
                if (refreshData?.accessToken) {
                    localStorage.setItem("k_token", refreshData.accessToken);
                    if (refreshData.user) {
                        localStorage.setItem("k_user", JSON.stringify(refreshData.user));
                    }
                }
            } catch {
                // If refresh fails, clear the token and fall back to login
                localStorage.removeItem("k_token");
                localStorage.removeItem("k_user");
                toast.success("Onboarding complete!", {
                    description: "Please log in again to access your dashboard.",
                });
                router.push("/login");
                return;
            }

            toast.success("Onboarding complete!", {
                description: "Your workspace is ready.",
            });

            // Hard reload to flush all React state with the new isOnboarded token
            window.location.href = "/portal/dashboard";
        } catch (error: any) {
            toast.error("Onboarding failed", {
                description: error.response?.data?.message || "Something went wrong.",
            });
        } finally {
            setIsLoading(false);
        }
    };

    return (
        <div className="flex items-center justify-center min-h-[80vh]">
            <Card className="w-full max-w-lg rounded-[2.5rem] shadow-2xl shadow-blue-500/5 border-slate-200">
                <CardHeader className="p-8 pb-4">
                    <CardTitle className="text-2xl font-black uppercase tracking-tight text-slate-900">Finalize Setup</CardTitle>
                    <CardDescription className="text-slate-500 font-medium font-medium">Complete your company profile to activate your workspace.</CardDescription>
                </CardHeader>
                <CardContent className="p-8 pt-4">
                    <form id="onboarding-form" onSubmit={handleSubmit(onSubmit)} className="space-y-6">
                        <div className="space-y-2">
                            <Label className="text-[10px] font-black uppercase tracking-widest text-slate-400">Industry</Label>
                            <Select onValueChange={(val) => setValue("industry", val)}>
                                <SelectTrigger className="h-12 bg-slate-50 border-slate-100 rounded-xl font-medium">
                                    <SelectValue placeholder="Select Industry" />
                                </SelectTrigger>
                                <SelectContent className="rounded-2xl border-slate-100 shadow-2xl">
                                    <SelectItem value="Manufacturing">Manufacturing</SelectItem>
                                    <SelectItem value="Retail">Retail</SelectItem>
                                    <SelectItem value="Wholesale">Wholesale</SelectItem>
                                    <SelectItem value="Healthcare">Healthcare</SelectItem>
                                    <SelectItem value="Logistics">Logistics</SelectItem>
                                    <SelectItem value="Service">Service</SelectItem>
                                </SelectContent>
                            </Select>
                            {errors.industry && <p className="text-xs text-rose-500 font-bold">{errors.industry.message}</p>}
                        </div>

                        <div className="space-y-2">
                            <Label className="text-[10px] font-black uppercase tracking-widest text-slate-400">Business Type</Label>
                            <Select onValueChange={(val) => setValue("businessType", val)}>
                                <SelectTrigger className="h-12 bg-slate-50 border-slate-100 rounded-xl font-medium">
                                    <SelectValue placeholder="Select Type" />
                                </SelectTrigger>
                                <SelectContent className="rounded-2xl border-slate-100 shadow-2xl">
                                    <SelectItem value="Proprietorship">Proprietorship</SelectItem>
                                    <SelectItem value="Partnership">Partnership</SelectItem>
                                    <SelectItem value="Pvt Ltd">Private Limited</SelectItem>
                                    <SelectItem value="LLP">LLP</SelectItem>
                                </SelectContent>
                            </Select>
                            {errors.businessType && <p className="text-xs text-rose-500 font-bold">{errors.businessType.message}</p>}
                        </div>

                        <div className="space-y-2">
                            <Label className="text-[10px] font-black uppercase tracking-widest text-slate-400">GSTIN (Optional)</Label>
                            <Input
                                className="bg-slate-50 border-slate-100 text-slate-900 h-12 rounded-xl font-medium"
                                placeholder="27AAAAA0000A1Z5"
                                {...register("gstin")}
                            />
                            {errors.gstin && <p className="text-xs text-rose-500 font-bold">{errors.gstin.message}</p>}
                        </div>
                    </form>
                </CardContent>
                <CardFooter className="p-8 pt-0">
                    <Button
                        type="submit"
                        form="onboarding-form"
                        disabled={isLoading}
                        className="w-full bg-blue-600 hover:bg-blue-700 text-white font-black h-12 rounded-xl transition-all shadow-lg shadow-blue-500/20 uppercase tracking-widest text-[10px]"
                    >
                        {isLoading ? (
                            <>
                                <Loader2 className="mr-2 h-4 w-4 animate-spin" /> Finalizing...
                            </>
                        ) : (
                            <>
                                Complete Setup <CheckCircle2 className="ml-2 h-4 w-4" />
                            </>
                        )}
                    </Button>
                </CardFooter>
            </Card>
        </div>
    );
}

"use client";

import { useEffect, useState } from "react";
import { api } from "@/lib/api";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card";
import {
    ClipboardList,
    Plus,
    Calendar,
    CheckCircle2,
    Clock,
    LayoutGrid,
    ListTodo,
    Check,
    X,
    Trash2
} from "lucide-react";
import { Badge } from "@/components/ui/badge";
import { Progress } from "@/components/ui/progress";
import { toast } from "sonner";
import { Dialog, DialogContent, DialogHeader, DialogTitle } from "@/components/ui/dialog";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { LoadingSpinner } from "@/components/ui/loading-spinner";
import { cn } from "@/lib/utils";

export default function ProjectPage() {
    const [projects, setProjects] = useState<any[]>([]);
    const [stats, setStats] = useState<any>({ total: 0, active: 0, completed: 0 });
    const [loading, setLoading] = useState(true);
    const [showForm, setShowForm] = useState(false);

    // Task Management
    const [selectedProject, setSelectedProject] = useState<any>(null);
    const [projectTasks, setProjectTasks] = useState<any[]>([]);
    const [newTaskTitle, setNewTaskTitle] = useState("");

    const [formData, setFormData] = useState({ name: "", description: "", startDate: "", endDate: "", status: "Planning" });

    const syncProjectData = async (showLoading = false) => {
        try {
            if (showLoading) setLoading(true);
            const [projRes, statsRes] = await Promise.all([
                api.get("projects"),
                api.get("projects/stats")
            ]);
            setProjects(projRes.data);
            setStats(statsRes.data);
        } catch (err) {
            console.error("Projects load failed:", err);
            toast.error("Failed to load projects. Please refresh.");
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        syncProjectData(true);
        const interval = setInterval(() => syncProjectData(false), 30000);
        return () => clearInterval(interval);
    }, []);

    const fetchTasks = async (projectId: string) => {
        try {
            const res = await api.get(`/projects/tasks/all?projectId=${projectId}`);
            setProjectTasks(res.data);
        } catch (err) {
            toast.error("Failed to load tasks");
        }
    };

    const handleCreate = async (e: React.FormEvent) => {
        e.preventDefault();
        try {
            await api.post("projects", formData);
            setShowForm(false);
            setFormData({ name: "", description: "", startDate: "", endDate: "", status: "Planning" });
            toast.success("Project created successfully");
            syncProjectData(true);
        } catch (err) {
            toast.error("Project creation failed");
        }
    };

    const handleCreateTask = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!selectedProject || !newTaskTitle.trim()) return;

        try {
            await api.post("projects/tasks", {
                title: newTaskTitle,
                projectId: selectedProject.id,
                status: "Pending", // Default
                priority: "Medium"
            });
            setNewTaskTitle("");
            toast.success("Task added");
            fetchTasks(selectedProject.id);
            syncProjectData(true); // Refresh progress bars
        } catch (err) {
            toast.error("Task creation failed");
        }
    };

    const toggleTaskStatus = async (task: any) => {
        const newStatus = task.status === 'Completed' ? 'Pending' : 'Completed';
        try {
            // Optimistic update
            setProjectTasks(prev => prev.map(t => t.id === task.id ? { ...t, status: newStatus } : t));

            await api.patch(`/projects/tasks/${task.id}/status`, { status: newStatus });
            syncProjectData(true); // Refresh global progress
        } catch (err) {
            toast.error("Status update failed");
            fetchTasks(selectedProject.id); // Revert
        }
    };

    if (loading) return <LoadingSpinner className="h-full" text="Loading Projects..." />;

    return (
        <div className="flex-1 space-y-6 md:space-y-8 pt-2 md:pt-6 px-4 md:px-8 w-full max-w-full overflow-hidden">
            <div className="flex flex-col lg:flex-row lg:items-center justify-between gap-4 lg:gap-0">
                <div>
                    <h2 className="text-3xl md:text-4xl font-black tracking-tight text-slate-900 flex items-center">
                        <ClipboardList className="mr-4 h-8 w-8 md:h-9 md:w-9 text-blue-600 shadow-sm" />
                        Projects
                    </h2>
                    <p className="text-slate-500 mt-2 font-medium">Track and manage your projects, tasks, and team progress.</p>
                </div>
                <div className="flex w-full md:w-auto">
                    <Button className="w-full justify-center rounded-2xl bg-blue-600 hover:bg-blue-700 font-bold px-8 shadow-lg shadow-blue-500/20 text-white h-11 whitespace-nowrap" onClick={() => setShowForm(!showForm)}>
                        <Plus className="mr-2 h-4 w-4" /> New Project
                    </Button>
                </div>
            </div>

            <div className="grid gap-6 md:grid-cols-2 lg:grid-cols-4">
                <Card className="bg-white border-slate-200 shadow-sm rounded-3xl overflow-hidden border-b-4 border-b-blue-500">
                    <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
                        <CardTitle className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Total Projects</CardTitle>
                        <LayoutGrid className="h-4 w-4 text-blue-500" />
                    </CardHeader>
                    <CardContent>
                        <div className="text-3xl font-black text-slate-900 tracking-tighter">{stats.total}</div>
                        <p className="text-xs text-slate-500 font-bold mt-2 uppercase tracking-tighter">All projects</p>
                    </CardContent>
                </Card>
                <Card className="bg-white border-slate-200 shadow-sm rounded-3xl overflow-hidden border-b-4 border-b-emerald-500">
                    <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
                        <CardTitle className="text-[10px] font-black text-slate-400 uppercase tracking-widest">In Progress</CardTitle>
                        <Activity className="h-4 w-4 text-emerald-500" />
                    </CardHeader>
                    <CardContent>
                        <div className="text-3xl font-black text-emerald-600 tracking-tighter">{stats.active}</div>
                        <p className="text-xs text-slate-500 font-bold mt-2 uppercase tracking-tighter">Active now</p>
                    </CardContent>
                </Card>
                <Card className="bg-white border-slate-200 shadow-sm rounded-3xl overflow-hidden border-b-4 border-b-indigo-500">
                    <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
                        <CardTitle className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Completion Rate</CardTitle>
                        <CheckCircle2 className="h-4 w-4 text-indigo-500" />
                    </CardHeader>
                    <CardContent>
                        <div className="text-3xl font-black text-indigo-600 tracking-tighter">
                            {stats.total > 0 ? Math.round((stats.completed / stats.total) * 100) : 0}%
                        </div>
                        <p className="text-xs text-slate-500 font-bold mt-2 uppercase tracking-tighter">Overall progress</p>
                    </CardContent>
                </Card>
            </div>

            {showForm && (
                <Card className="bg-white border-slate-200 shadow-2xl rounded-3xl overflow-hidden border-none mb-8 animate-in fade-in slide-in-from-top-4">
                    <CardHeader className="bg-slate-50 border-b border-slate-100 py-6 px-4 md:px-8">
                        <CardTitle className="text-slate-900 font-black text-xl">New Project</CardTitle>
                        <CardDescription className="text-slate-500 font-bold uppercase text-[10px] tracking-widest mt-1">Fill in the details to create a new project</CardDescription>
                    </CardHeader>
                    <CardContent className="p-4 md:p-8">
                        <form onSubmit={handleCreate} className="grid grid-cols-1 md:grid-cols-2 gap-6">
                            <div className="md:col-span-2 space-y-2">
                                <Label className="text-slate-500 font-bold uppercase text-[10px] tracking-widest">Project Name</Label>
                                <Input className="bg-slate-50 border-slate-200 text-slate-900 rounded-xl h-11 focus:ring-blue-500/20 font-bold" value={formData.name} onChange={e => setFormData({ ...formData, name: e.target.value })} required />
                            </div>
                            <div className="md:col-span-2 space-y-2">
                                <Label className="text-slate-500 font-bold uppercase text-[10px] tracking-widest">Description</Label>
                                <Input className="bg-slate-50 border-slate-200 text-slate-900 rounded-xl h-11 focus:ring-blue-500/20 font-medium" value={formData.description} onChange={e => setFormData({ ...formData, description: e.target.value })} />
                            </div>
                            <div className="space-y-2">
                                <Label className="text-slate-500 font-bold uppercase text-[10px] tracking-widest">Start Date</Label>
                                <Input type="date" className="bg-slate-50 border-slate-200 text-slate-900 rounded-xl h-11 focus:ring-blue-500/20 font-bold" value={formData.startDate} onChange={e => setFormData({ ...formData, startDate: e.target.value })} />
                            </div>
                            <div className="space-y-2">
                                <Label className="text-slate-500 font-bold uppercase text-[10px] tracking-widest">End Date</Label>
                                <Input type="date" className="bg-slate-50 border-slate-200 text-slate-900 rounded-xl h-11 focus:ring-blue-500/20 font-bold" value={formData.endDate} onChange={e => setFormData({ ...formData, endDate: e.target.value })} />
                            </div>
                            <div className="md:col-span-2 flex justify-end gap-3 pt-4">
                                <Button type="button" variant="ghost" className="text-slate-400 font-bold" onClick={() => setShowForm(false)}>Cancel</Button>
                                <Button type="submit" className="bg-blue-600 hover:bg-blue-700 text-white font-black rounded-xl h-12 px-8">Create Project</Button>
                            </div>
                        </form>
                    </CardContent>
                </Card>
            )}

            <div className="grid gap-6 md:grid-cols-2 lg:grid-cols-3">
                {projects.map((project) => {
                    const progress = project.tasks?.length > 0
                        ? (project.tasks.filter((t: any) => t.status === 'Completed').length / project.tasks.length) * 100
                        : 0;

                    return (
                        <Card key={project.id} className="bg-white border-slate-200 shadow-xl shadow-slate-200/20 hover:shadow-2xl hover:shadow-blue-500/10 transition-all group overflow-hidden border-none">
                            <div className="h-1.5 w-full bg-gradient-to-r from-blue-600 to-indigo-600 overflow-hidden">
                                <div className="h-full bg-slate-900/10" style={{ width: `${100 - progress}%`, float: 'right' }} />
                            </div>
                            <CardHeader className="pb-4 bg-slate-50/50">
                                <div className="flex justify-between items-start mb-2">
                                    <Badge variant="secondary" className={`border-none font-black text-[9px] uppercase tracking-widest ${project.status === 'Completed' ? 'bg-emerald-50 text-emerald-600' :
                                        project.status === 'InProgress' ? 'bg-blue-50 text-blue-600' : 'bg-slate-100 text-slate-400'
                                        }`}>
                                        {project.status === 'InProgress' ? 'In Progress' : project.status}
                                    </Badge>
                                    <div className="text-[10px] text-slate-400 font-black tracking-widest">#{project.id.slice(0, 6).toUpperCase()}</div>
                                </div>
                                <CardTitle className="text-slate-900 text-xl font-black tracking-tight">{project.name}</CardTitle>
                                <CardDescription className="line-clamp-2 mt-1 font-medium text-slate-500">{project.description || "No description provided."}</CardDescription>
                            </CardHeader>
                            <CardContent className="space-y-6 pt-6">
                                <div className="space-y-2">
                                    <div className="flex justify-between text-[10px] font-black uppercase tracking-widest">
                                        <span className="text-slate-400">Progress</span>
                                        <span className="text-blue-600">{Math.round(progress)}%</span>
                                    </div>
                                    <Progress value={progress} className="h-2 bg-slate-100" indicatorClassName="bg-blue-600 shadow-[0_0_10px_rgba(37,99,235,0.4)]" />
                                </div>

                                <div className="grid grid-cols-2 gap-4 text-[10px] font-black uppercase tracking-widest text-slate-400 pt-4 border-t border-slate-100">
                                    <div className="flex items-center gap-2">
                                        <Calendar className="h-3.5 w-3.5 text-slate-300" />
                                        {project.startDate ? new Date(project.startDate).toLocaleDateString() : "TBD"}
                                    </div>
                                    <div className="flex items-center gap-2 justify-end">
                                        <Clock className="h-3.5 w-3.5 text-slate-300" />
                                        {project.endDate ? new Date(project.endDate).toLocaleDateString() : "No end date"}
                                    </div>
                                </div>

                                <div className="flex gap-3 pt-2">
                                    <Button variant="ghost" className="w-full text-slate-400 hover:text-slate-600 font-bold text-[10px] uppercase tracking-widest h-10 rounded-xl">
                                        Archive
                                    </Button>
                                    <Button
                                        className="w-full bg-slate-900 hover:bg-blue-600 text-white font-black text-[10px] uppercase tracking-widest h-10 rounded-xl shadow-lg shadow-slate-900/10 transition-all active:scale-95"
                                        onClick={() => {
                                            setSelectedProject(project);
                                            fetchTasks(project.id);
                                        }}
                                    >
                                        <ListTodo className="h-3.5 w-3.5 mr-2" />
                                        Tasks ({project.tasks?.length || 0})
                                    </Button>
                                </div>
                            </CardContent>
                        </Card>
                    );
                })}
                {projects.length === 0 && (
                    <div className="col-span-full py-32 text-center text-slate-400 font-black uppercase tracking-[0.2em] border-2 border-dashed border-slate-200 rounded-[32px] bg-slate-50/50">
                        No projects found.
                    </div>
                )}
            </div>

            <Dialog open={!!selectedProject} onOpenChange={(open) => !open && setSelectedProject(null)}>
                <DialogContent className="w-11/12 sm:min-w-fit sm:max-w-2xl bg-white border-none shadow-2xl rounded-[32px] overflow-hidden p-0 max-h-[90vh] flex flex-col">
                    <div className="bg-slate-900 p-6 md:p-10 pb-12 md:pb-16 flex-shrink-0">
                        <DialogTitle className="flex items-center gap-4 text-white text-2xl md:text-3xl font-black tracking-tight">
                            <div className="p-2 md:p-3 bg-blue-600 rounded-2xl shadow-lg shadow-blue-500/40">
                                <ListTodo className="h-5 w-5 md:h-6 md:w-6 text-white" />
                            </div>
                            Task Management
                        </DialogTitle>
                        <p className="text-slate-400 font-bold uppercase text-[10px] tracking-[0.2em] mt-4 md:mt-6 flex flex-wrap items-center gap-2">
                            Project: <span className="text-blue-400 break-words">{selectedProject?.name}</span>
                        </p>
                    </div>

                    <div className="p-6 md:p-10 -mt-10 bg-white rounded-t-[32px] space-y-6 md:space-y-8 flex-1 overflow-hidden flex flex-col">
                        <form onSubmit={handleCreateTask} className="flex flex-col lg:flex-row gap-3 flex-shrink-0">
                            <Input
                                placeholder="New task..."
                                className="bg-slate-50 border-slate-200 text-slate-900 rounded-2xl h-14 px-6 font-bold focus:ring-blue-500/20"
                                value={newTaskTitle}
                                onChange={(e) => setNewTaskTitle(e.target.value)}
                            />
                            <Button type="submit" className="bg-blue-600 hover:bg-blue-700 text-white font-black px-8 rounded-2xl h-14 shadow-lg shadow-blue-500/20 active:scale-95 transition-all w-full md:w-auto shrink-0">Add Task</Button>
                        </form>

                        <div className="flex-1 overflow-y-auto pr-2 md:pr-4 custom-scrollbar min-h-[300px]">
                            <div className="space-y-3">
                                {projectTasks.map((task) => (task && (
                                    <div key={task.id} className={cn(
                                        "group flex items-center justify-between p-5 rounded-[20px] border transition-all",
                                        task.status === 'Completed'
                                            ? "bg-slate-50/50 border-slate-100"
                                            : "bg-white border-slate-200 shadow-sm hover:border-blue-500/50 hover:shadow-lg hover:shadow-blue-500/5"
                                    )}>
                                        <div className="flex items-center gap-3 md:gap-4 flex-1 min-w-0 pr-4">
                                            <button
                                                type="button"
                                                onClick={() => toggleTaskStatus(task)}
                                                className={cn(
                                                    "h-6 w-6 md:h-7 md:w-7 rounded-lg md:rounded-xl border-2 flex shrink-0 items-center justify-center transition-all",
                                                    task.status === 'Completed'
                                                        ? "bg-blue-600 border-blue-600 shadow-lg shadow-blue-500/20"
                                                        : "border-slate-200 hover:border-blue-500"
                                                )}
                                            >
                                                {task.status === 'Completed' && <Check className="h-3 w-3 md:h-4 md:w-4 text-white" />}
                                            </button>
                                            <span className={cn(
                                                "text-sm font-black tracking-tight transition-colors truncate",
                                                task.status === 'Completed' ? "text-slate-400 line-through" : "text-slate-900"
                                            )} title={task.title}>
                                                {task.title}
                                            </span>
                                        </div>
                                        <Badge variant="secondary" className={cn(
                                            "text-[9px] font-black border-none px-2 md:px-3 py-1 rounded-lg uppercase tracking-widest shrink-0 whitespace-nowrap",
                                            task.priority === 'High' ? "bg-rose-50 text-rose-600" :
                                                task.priority === 'Medium' ? "bg-amber-50 text-amber-600" : "bg-slate-100 text-slate-400"
                                        )}>
                                            {task.priority || 'Normal'}
                                        </Badge>
                                    </div>
                                )))}
                                {projectTasks.length === 0 && (
                                    <div className="text-center py-20 text-slate-300 font-bold italic">
                                        No tasks found.
                                    </div>
                                )}
                            </div>
                        </div>
                    </div>
                </DialogContent>
            </Dialog>
        </div>
    );
}

function Activity(props: any) {
    return (
        <svg
            {...props}
            xmlns="http://www.w3.org/2000/svg"
            width="24"
            height="24"
            viewBox="0 0 24 24"
            fill="none"
            stroke="currentColor"
            strokeWidth="2"
            strokeLinecap="round"
            strokeLinejoin="round"
        >
            <path d="M22 12h-4l-3 9L9 3l-3 9H2" />
        </svg>
    )
}

"use client";

import { useEffect, useState } from "react";
import { api } from "@/lib/api";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";
import {
    Table,
    TableBody,
    TableCell,
    TableHead,
    TableHeader,
    TableRow
} from "@/components/ui/table";
import { Dialog, DialogContent, DialogDescription, DialogFooter, DialogHeader, DialogTitle } from "@/components/ui/dialog";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Plus, Truck, ShoppingBag, DollarSign, Package, CheckCircle2, XCircle, ShoppingCart, UserPlus, Scale } from "lucide-react";
import { toast } from "sonner";
import { Badge } from "@/components/ui/badge";
import { CreateSupplierDialog } from "@/components/purchases/create-supplier-dialog";
import { EditSupplierDialog } from "@/components/purchases/edit-supplier-dialog";
import { OpeningBalanceDialog } from "@/components/accounting/opening-balance-dialog";
import { Edit2 } from "lucide-react";
import { NumericInput } from "@/components/ui/numeric-input";
import { ConfirmationDialog } from "@/components/shared/ConfirmationDialog";

export default function PurchasesPage() {
    const [suppliers, setSuppliers] = useState<any[]>([]);
    const [products, setProducts] = useState<any[]>([]);
    const [purchaseOrders, setPurchaseOrders] = useState<any[]>([]);
    const [stats, setStats] = useState<any>({ totalSpent: 0, pendingPOs: 0 });
    const [loading, setLoading] = useState(true);
    const [showPODialog, setShowPODialog] = useState(false);
    const [isSubmitting, setIsSubmitting] = useState(false);
    const [isAddSupplierOpen, setIsAddSupplierOpen] = useState(false);
    const [editingSupplier, setEditingSupplier] = useState<any>(null);
    const [openingBalanceTarget, setOpeningBalanceTarget] = useState<any>(null);
    const [showConfirm, setShowConfirm] = useState(false);

    // Form state
    const [newPO, setNewPO] = useState({
        supplierId: "",
        productId: "",
        quantity: 1,
        unitPrice: 0,
        orderDate: new Date().toISOString().split('T')[0]
    });

    const syncProcurement = async (showLoading = false) => {
        try {
            if (showLoading) setLoading(true);
            const [suppRes, prodRes, poRes, statsRes] = await Promise.all([
                api.get("purchases/suppliers"),
                api.get("inventory/products"),
                api.get("purchases/orders"),
                api.get("purchases/stats")
            ]);
            const rawSuppliers = suppRes.data?.data ?? suppRes.data;
            setSuppliers(Array.isArray(rawSuppliers) ? rawSuppliers : []);
            // Products API returns paginated response { data: [], meta: {} }
            const rawProducts = prodRes.data?.data ?? prodRes.data;
            setProducts(Array.isArray(rawProducts) ? rawProducts : []);
            const rawOrders = poRes.data?.data ?? poRes.data;
            setPurchaseOrders(Array.isArray(rawOrders) ? rawOrders : []);
            setStats(statsRes.data || { totalSpent: 0, pendingPOs: 0 });
        } catch (err) {
            console.error("Procurement Sync Failure:", err);
            setSuppliers([]);
            setProducts([]);
            setPurchaseOrders([]);
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        syncProcurement(true);

        // CONTINUOUS BACKGROUND SYNC: 30s interval
        const interval = setInterval(() => syncProcurement(false), 30000);
        return () => clearInterval(interval);
    }, []);

    const handleConfirmSubmit = () => {
        if (!newPO.supplierId || !newPO.productId || newPO.quantity <= 0) {
            toast.error("Please fill in all required fields");
            return;
        }

        const orderTotal = newPO.quantity * newPO.unitPrice;
        if (orderTotal > 100000) {
            setShowConfirm(true);
        } else {
            createPO();
        }
    };

    const createPO = async () => {
        try {
            setIsSubmitting(true);
            const items = [{
                productId: newPO.productId,
                quantity: newPO.quantity,
                unitPrice: newPO.unitPrice
            }];

            await api.post("purchases/orders", {
                supplierId: newPO.supplierId,
                orderDate: new Date(newPO.orderDate),
                totalAmount: newPO.quantity * newPO.unitPrice,
                status: 'Ordered',
                items
            });

            toast.success("Purchase order created successfully");
            setShowPODialog(false);
            setNewPO({ ...newPO, productId: "", quantity: 1, unitPrice: 0 });
            syncProcurement(true);
        } catch (err) {
            toast.error("Failed to create purchase order");
        } finally {
            setIsSubmitting(false);
        }
    };

    const handleUpdateStatus = async (id: string, status: string) => {
        try {
            await api.patch(`/purchases/orders/${id}/status`, { status });
            toast.success(`Purchase order marked as ${status}`);
            syncProcurement(true);
        } catch (err) {
            toast.error("Failed to update purchase order");
        }
    };

    const getPOStatusBadge = (status: string) => {
        switch (status) {
            case 'Received': return <Badge className="bg-emerald-50 text-emerald-600 border-none font-black text-[10px] uppercase tracking-tighter rounded-lg px-3 py-1">Received</Badge>;
            case 'Ordered': return <Badge className="bg-blue-50 text-blue-600 border-none font-black text-[10px] uppercase tracking-tighter rounded-lg px-3 py-1">Ordered</Badge>;
            case 'Draft': return <Badge className="bg-slate-50 text-slate-500 border-none font-black text-[10px] uppercase tracking-tighter rounded-lg px-3 py-1">Draft</Badge>;
            case 'Cancelled': return <Badge className="bg-rose-50 text-rose-600 border-none font-black text-[10px] uppercase tracking-tighter rounded-lg px-3 py-1">Cancelled</Badge>;
            default: return <Badge variant="outline" className="bg-slate-100 text-slate-400 font-black text-[10px] uppercase tracking-tighter rounded-lg px-3 py-1">{status}</Badge>;
        }
    };

    return (
        <div className="flex-1 space-y-6 md:space-y-8 pt-2 md:pt-6 px-4 md:px-8 bg-slate-50/30 min-h-screen w-full max-w-full overflow-hidden">
            <CreateSupplierDialog
                open={isAddSupplierOpen}
                onOpenChange={setIsAddSupplierOpen}
                onSuccess={() => syncProcurement(false)}
            />
            <div className="flex flex-col lg:flex-row lg:items-center justify-between gap-4 lg:gap-0">
                <div>
                    <h2 className="text-3xl md:text-4xl font-black tracking-tight text-slate-900 flex items-center gap-3">
                        <ShoppingCart className="h-8 w-8 md:h-10 md:w-10 text-indigo-600" /> Purchases & Suppliers
                    </h2>
                    <p className="text-slate-500 mt-2 font-medium">Manage your supply chain and purchase orders.</p>
                </div>
                <div className="flex flex-wrap gap-3 w-full md:w-auto">
                    <Button
                        variant="outline"
                        onClick={() => setIsAddSupplierOpen(true)}
                        className="flex-1 sm:flex-none justify-center rounded-2xl border-slate-200 bg-white text-slate-600 font-bold h-12 px-6 shadow-sm hover:bg-slate-50 active:scale-95 transition-all flex items-center gap-2 whitespace-nowrap"
                    >
                        <UserPlus className="h-4 w-4" /> Add Supplier
                    </Button>
                    <Button
                        onClick={() => setShowPODialog(true)}
                        className="flex-1 sm:flex-none justify-center bg-indigo-600 hover:bg-indigo-700 text-white rounded-2xl px-6 md:px-8 h-12 font-black uppercase tracking-widest shadow-lg shadow-indigo-500/20 active:scale-95 transition-all whitespace-nowrap"
                    >
                        New Order
                    </Button>
                </div>
            </div>

            <div className="grid gap-6 md:grid-cols-3">
                <Card className="bg-white border-slate-200 shadow-sm rounded-3xl overflow-hidden border-b-4 border-b-emerald-500">
                    <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
                        <CardTitle className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Total Spent</CardTitle>
                        <DollarSign className="h-4 w-4 text-emerald-500" />
                    </CardHeader>
                    <CardContent>
                        <div className="text-3xl font-black text-slate-900 tracking-tighter">Ôé╣{Number(stats?.totalSpent || 0).toLocaleString('en-IN', { minimumFractionDigits: 0 })}</div>
                        <p className="text-xs text-slate-500 font-bold mt-2 uppercase tracking-tighter">Total purchase cost</p>
                    </CardContent>
                </Card>
                <Card className="bg-white border-slate-200 shadow-sm rounded-3xl overflow-hidden border-b-4 border-b-amber-500">
                    <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
                        <CardTitle className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Pending Orders</CardTitle>
                        <ShoppingBag className="h-4 w-4 text-amber-500" />
                    </CardHeader>
                    <CardContent>
                        <div className="text-3xl font-black text-amber-600 tracking-tighter">{stats?.pendingPOs || 0}</div>
                        <p className="text-xs text-slate-500 font-bold mt-2 uppercase tracking-tighter">Awaiting Fulfillment</p>
                    </CardContent>
                </Card>
                <Card className="bg-white border-slate-200 shadow-sm rounded-3xl overflow-hidden border-b-4 border-b-blue-500">
                    <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
                        <CardTitle className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Suppliers</CardTitle>
                        <Truck className="h-4 w-4 text-blue-500" />
                    </CardHeader>
                    <CardContent>
                        <div className="text-3xl font-black text-slate-900 tracking-tighter">{suppliers.length}</div>
                        <p className="text-xs text-slate-500 font-bold mt-2 uppercase tracking-tighter">Approved Suppliers</p>
                    </CardContent>
                </Card>
            </div>

            <Tabs defaultValue="orders" className="space-y-6 md:space-y-8">
                <TabsList className="bg-slate-100 border-slate-200 p-1.5 rounded-2xl h-auto w-full flex flex-wrap justify-start overflow-x-auto snap-x">
                    <TabsTrigger value="orders" className="flex-1 sm:flex-none data-[state=active]:bg-white data-[state=active]:text-blue-600 data-[state=active]:shadow-sm rounded-xl px-4 md:px-8 py-2.5 font-bold transition-all snap-start">Purchase Orders</TabsTrigger>
                    <TabsTrigger value="suppliers" className="flex-1 sm:flex-none data-[state=active]:bg-white data-[state=active]:text-blue-600 data-[state=active]:shadow-sm rounded-xl px-4 md:px-8 py-2.5 font-bold transition-all snap-start">Suppliers</TabsTrigger>
                </TabsList>

                <TabsContent value="orders">
                    <Card className="bg-white border-slate-200 shadow-xl shadow-slate-200/40 rounded-3xl overflow-hidden border-none text-slate-900">
                        <CardHeader className="bg-slate-50 border-b border-slate-100 py-6 px-4 md:px-8">
                            <CardTitle className="text-slate-900 text-xl font-black">Purchase Register</CardTitle>
                            <CardDescription className="text-slate-500 font-bold uppercase text-[10px] tracking-widest mt-1">All purchase orders and their status</CardDescription>
                        </CardHeader>
                        <CardContent className="p-0 overflow-x-auto max-w-[100vw] sm:max-w-none">
                            <Table className="min-w-[900px]">
                                <TableHeader className="bg-slate-50/50">
                                    <TableRow className="border-slate-100 hover:bg-transparent">
                                        <TableHead className="text-slate-500 font-bold uppercase text-[10px] tracking-widest pl-8">Order ID</TableHead>
                                        <TableHead className="text-slate-500 font-bold uppercase text-[10px] tracking-widest">Supplier</TableHead>
                                        <TableHead className="text-slate-500 font-bold uppercase text-[10px] tracking-widest">Order Date</TableHead>
                                        <TableHead className="text-slate-500 font-bold uppercase text-[10px] tracking-widest">Amount</TableHead>
                                        <TableHead className="text-slate-500 font-bold uppercase text-[10px] tracking-widest">Status</TableHead>
                                        <TableHead className="text-slate-500 font-bold uppercase text-[10px] tracking-widest text-right pr-8">Actions</TableHead>
                                    </TableRow>
                                </TableHeader>
                                <TableBody>
                                    {purchaseOrders.map((po) => (
                                        <TableRow key={po.id} className="border-slate-100 hover:bg-slate-50/50 transition-all group">
                                            <TableCell className="pl-8 font-black text-[10px] text-blue-600 tracking-widest bg-slate-50/30 w-32 uppercase tracking-tighter leading-none">
                                                {po.orderNumber.startsWith('PO-') ? po.orderNumber : `PO-${po.orderNumber.toUpperCase()}`}
                                            </TableCell>
                                            <TableCell className="font-black text-slate-900 tracking-tight">{po.supplier.name}</TableCell>
                                            <TableCell className="text-slate-500 font-bold text-xs">{new Date(po.orderDate).toLocaleDateString()}</TableCell>
                                            <TableCell className="font-black text-slate-900">Ôé╣{Number(po.totalAmount).toLocaleString('en-IN', { minimumFractionDigits: 0 })}</TableCell>
                                            <TableCell>{getPOStatusBadge(po.status)}</TableCell>
                                            <TableCell className="text-right pr-8">
                                                {po.status === 'Ordered' && (
                                                    <Button
                                                        size="sm"
                                                        onClick={() => handleUpdateStatus(po.id, 'Received')}
                                                        className="bg-emerald-600 hover:bg-emerald-700 text-white font-bold rounded-xl h-8 px-4 text-[11px] shadow-lg shadow-emerald-500/20"
                                                    >
                                                        <CheckCircle2 className="mr-1.5 h-3.5 w-3.5" /> Mark Received
                                                    </Button>
                                                )}
                                                {po.status === 'Received' && (
                                                    <span className="text-slate-400 text-[10px] font-black uppercase tracking-widest flex items-center justify-end">
                                                        <CheckCircle2 className="mr-1.5 h-4 w-4 text-emerald-500" /> Fulfilled
                                                    </span>
                                                )}
                                            </TableCell>
                                        </TableRow>
                                    ))}
                                    {purchaseOrders.length === 0 && (
                                        <TableRow>
                                            <TableCell colSpan={6} className="text-center py-20 text-slate-400 font-bold italic">
                                                <ShoppingBag className="mx-auto h-16 w-16 mb-4 opacity-10" />
                                                No purchase orders found.
                                            </TableCell>
                                        </TableRow>
                                    )}
                                </TableBody>
                            </Table>
                        </CardContent>
                    </Card>
                </TabsContent>

                <TabsContent value="suppliers">
                    <Card className="bg-white border-slate-200 shadow-xl shadow-slate-200/40 rounded-3xl overflow-hidden border-none text-slate-900">
                        <CardHeader className="bg-slate-50 border-b border-slate-100 py-6 px-8">
                            <CardTitle className="text-slate-900 text-xl font-black">Suppliers</CardTitle>
                            <CardDescription className="text-slate-500 font-bold uppercase text-[10px] tracking-widest mt-1">List of approved suppliers</CardDescription>
                        </CardHeader>
                        <CardContent className="p-8">
                            <div className="grid gap-6 md:grid-cols-2 lg:grid-cols-3">
                                {suppliers.map((s) => (
                                    <Card key={s.id} className="bg-slate-50/50 border-slate-100 hover:border-blue-500/50 hover:bg-white hover:shadow-xl hover:shadow-slate-200/50 transition-all group rounded-2xl overflow-hidden">
                                        <CardHeader>
                                            <div className="flex justify-between items-start mb-4">
                                                <div className="p-2 bg-white rounded-xl shadow-sm border border-slate-100 group-hover:border-blue-100 transition-all">
                                                    <Truck className="h-6 w-6 text-blue-600 transition-transform group-hover:rotate-12" />
                                                </div>
                                                <div className="flex gap-2">
                                                    <Button
                                                        variant="ghost"
                                                        size="icon"
                                                        onClick={() => setEditingSupplier(s)}
                                                        className="h-8 w-8 text-slate-400 hover:text-blue-600 hover:bg-blue-50 rounded-lg transition-all"
                                                    >
                                                        <Edit2 className="h-4 w-4" />
                                                    </Button>
                                                    <Badge variant="secondary" className="bg-slate-100 text-slate-500 font-black text-[9px] rounded-md border-none uppercase tracking-tighter self-start">{s.category}</Badge>
                                                </div>
                                            </div>
                                            <CardTitle className="text-lg font-black text-slate-900 tracking-tight">{s.name}</CardTitle>
                                            <CardDescription className="text-slate-500 font-bold text-xs">{s.email}</CardDescription>
                                        </CardHeader>
                                        <CardContent>
                                            <div className="flex flex-col gap-3">
                                                <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest bg-slate-100/50 p-3 rounded-xl italic">
                                                    <Package className="inline mr-1.5 h-3.5 w-3.5" /> {s.address || 'Global Operations'}
                                                </p>
                                                <Button
                                                    variant="outline"
                                                    size="sm"
                                                    onClick={() => setOpeningBalanceTarget({ id: s.id, name: s.name })}
                                                    className="w-full h-8 rounded-xl border-slate-200 text-slate-500 font-black text-[10px] uppercase tracking-widest hover:bg-blue-50 hover:text-blue-600 hover:border-blue-200 transition-all gap-2"
                                                >
                                                    <Scale className="h-3.5 w-3.5" /> Set Opening Balance
                                                </Button>
                                            </div>
                                        </CardContent>
                                    </Card>
                                ))}
                                {suppliers.length === 0 && (
                                    <div className="col-span-full text-center py-20 text-slate-400 font-bold italic">No suppliers added yet.</div>
                                )}
                            </div>
                        </CardContent>
                    </Card>
                </TabsContent>
            </Tabs>

            <EditSupplierDialog
                open={!!editingSupplier}
                onOpenChange={(open) => !open && setEditingSupplier(null)}
                supplier={editingSupplier}
                onSuccess={() => syncProcurement(false)}
            />

            {/* Purchase Order Creation Dialog */}
            <Dialog open={showPODialog} onOpenChange={setShowPODialog}>
                <DialogContent className="sm:max-w-[500px] rounded-3xl border-none shadow-2xl">
                    <DialogHeader>
                        <DialogTitle className="text-2xl font-black text-slate-900">New Purchase Order</DialogTitle>
                        <DialogDescription className="text-slate-500 font-medium">
                            Start a new order with a verified supplier.
                        </DialogDescription>
                    </DialogHeader>
                    <div className="grid gap-6 py-6">
                        <div className="grid gap-2">
                            <Label htmlFor="supplier" className="text-slate-700 font-black text-[10px] uppercase tracking-widest pl-1">
                                Supplier <span className="text-red-500">*</span>
                            </Label>
                            <select
                                id="supplier"
                                value={newPO.supplierId}
                                onChange={(e) => setNewPO({ ...newPO, supplierId: e.target.value })}
                                className="flex h-11 w-full rounded-2xl border border-slate-200 bg-white px-4 py-2 text-sm font-bold text-slate-900 focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-blue-600 transition-all"
                            >
                                <option value="">Select supplier...</option>
                                {Array.isArray(suppliers) && suppliers.map((s) => (
                                    <option key={s.id} value={s.id}>{s.name}</option>
                                ))}
                            </select>
                        </div>

                        <div className="grid grid-cols-2 gap-4">
                            <div className="grid gap-2">
                                <Label htmlFor="product" className="text-slate-700 font-black text-[10px] uppercase tracking-widest pl-1">
                                    Product <span className="text-red-500">*</span>
                                </Label>
                                <select
                                    id="product"
                                    value={newPO.productId}
                                    onChange={(e) => {
                                        const prod = products.find(p => p.id === e.target.value);
                                        setNewPO({ ...newPO, productId: e.target.value, unitPrice: prod?.costPrice || 0 });
                                    }}
                                    className="flex h-11 w-full rounded-2xl border border-slate-200 bg-white px-4 py-2 text-sm font-bold text-slate-900 focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-blue-600 transition-all"
                                >
                                    <option value="">Select product...</option>
                                    {Array.isArray(products) && products.map((p) => (
                                        <option key={p.id} value={p.id}>{p.name} ({p.sku})</option>
                                    ))}
                                </select>
                            </div>
                            <div className="grid gap-2">
                                <Label htmlFor="quantity" className="text-slate-700 font-black text-[10px] uppercase tracking-widest pl-1">
                                    Quantity <span className="text-red-500">*</span>
                                </Label>
                                <NumericInput
                                    id="quantity"
                                    value={newPO.quantity}
                                    onChange={(val) => setNewPO({ ...newPO, quantity: val })}
                                    className="h-11 rounded-2xl border-slate-200 font-bold px-4"
                                />
                            </div>
                        </div>

                        <div className="grid grid-cols-2 gap-4">
                            <div className="grid gap-2">
                                <Label htmlFor="unitPrice" className="text-slate-700 font-black text-[10px] uppercase tracking-widest pl-1">
                                    Unit Cost (Ôé╣)
                                </Label>
                                <NumericInput
                                    id="unitPrice"
                                    value={newPO.unitPrice}
                                    onChange={(val) => setNewPO({ ...newPO, unitPrice: val })}
                                    decimal
                                    className="h-11 rounded-2xl border-slate-200 font-bold px-4"
                                />
                            </div>
                            <div className="grid gap-2">
                                <Label htmlFor="orderDate" className="text-slate-700 font-black text-[10px] uppercase tracking-widest pl-1">
                                    Order Date
                                </Label>
                                <Input
                                    id="orderDate"
                                    type="date"
                                    value={newPO.orderDate}
                                    onChange={(e) => setNewPO({ ...newPO, orderDate: e.target.value })}
                                    className="h-11 rounded-2xl border-slate-200 font-bold px-4"
                                />
                            </div>
                        </div>

                        <div className="bg-blue-50/50 p-4 rounded-3xl border border-blue-100 mt-2">
                            <div className="flex justify-between items-center text-blue-900 font-black tracking-tight">
                                <span className="text-[10px] uppercase">Total Amount</span>
                                <span className="text-xl">Ôé╣{(newPO.quantity * newPO.unitPrice).toLocaleString('en-IN')}</span>
                            </div>
                        </div>
                    </div>
                    <DialogFooter className="gap-2">
                        <Button variant="ghost" className="rounded-2xl h-12" onClick={() => setShowPODialog(false)}>Cancel</Button>
                        <Button className="rounded-2xl h-12 bg-blue-600 font-bold px-8" onClick={handleConfirmSubmit} disabled={isSubmitting}>
                            {isSubmitting ? "Creating..." : "Create Purchase Order"}
                        </Button>
                    </DialogFooter>
                </DialogContent>
            </Dialog>

            <ConfirmationDialog
                isOpen={showConfirm}
                onClose={() => setShowConfirm(false)}
                onConfirm={createPO}
                title="Confirm Purchase"
                description={`You are creating a purchase order for Ôé╣${(newPO.quantity * newPO.unitPrice).toLocaleString('en-IN')}. Verify supplier and pricing before proceeding.`}
                confirmLabel="Yes, Create PO"
                cancelLabel="Review"
                variant="warning"
            />
            <OpeningBalanceDialog
                isOpen={!!openingBalanceTarget}
                onClose={() => setOpeningBalanceTarget(null)}
                supplierId={openingBalanceTarget?.id}
                targetName={openingBalanceTarget?.name || ""}
                onSuccess={() => syncProcurement(true)}
            />
        </div>
    );
}

"use client";

import React, { useState, useEffect } from "react";
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from "@/components/ui/table";
import { Receipt, Plus, Search, Filter, ArrowLeft, RefreshCw, FileText, CheckCircle2 } from "lucide-react";
import { api } from "@/lib/api";
import { format } from "date-fns";
import { Badge } from "@/components/ui/badge";

export default function CreditNotesPage() {
    const [notes, setNotes] = useState<any[]>([]);
    const [loading, setLoading] = useState(true);
    const [searchTerm, setSearchTerm] = useState("");

    const fetchNotes = async () => {
        setLoading(true);
        try {
            const res = await api.get("/accounting/credit-notes");
            setNotes(res.data);
        } catch (err) {
            console.error("Failed to fetch credit notes", err);
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        fetchNotes();
    }, []);

    const filteredNotes = notes.filter(n =>
        n.noteNumber.toLowerCase().includes(searchTerm.toLowerCase()) ||
        n.customer?.firstName.toLowerCase().includes(searchTerm.toLowerCase()) ||
        n.customer?.company?.toLowerCase().includes(searchTerm.toLowerCase())
    );

    return (
        <div className="p-6 space-y-6 bg-slate-50/50 min-h-screen">
            <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
                <div>
                    <h1 className="text-3xl font-black text-slate-900 tracking-tight flex items-center gap-3">
                        <Receipt className="w-8 h-8 text-blue-600" />
                        Credit Notes
                    </h1>
                    <p className="text-slate-500 font-medium">Manage sales returns and customer credits</p>
                </div>
                <div className="flex gap-2">
                    <Button variant="outline" onClick={fetchNotes} disabled={loading}>
                        <RefreshCw className={`w-4 h-4 mr-2 ${loading ? 'animate-spin' : ''}`} />
                        Refresh
                    </Button>
                    <Button className="bg-blue-600 hover:bg-blue-700 text-white font-bold rounded-xl shadow-lg shadow-blue-200">
                        <Plus className="w-4 h-4 mr-2" />
                        Issue Credit Note
                    </Button>
                </div>
            </div>

            <Card className="border-none shadow-xl shadow-slate-200/50 rounded-3xl overflow-hidden">
                <CardHeader className="bg-white border-b border-slate-100 p-6">
                    <div className="flex flex-col md:flex-row md:items-center gap-4 justify-between">
                        <div className="relative flex-1 max-w-md">
                            <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400" />
                            <Input
                                placeholder="Search by number or customer..."
                                className="pl-10 bg-slate-50 border-slate-200 rounded-xl"
                                value={searchTerm}
                                onChange={(e) => setSearchTerm(e.target.value)}
                            />
                        </div>
                        <div className="flex gap-2">
                            <Button variant="ghost" size="sm" className="text-slate-500 font-bold uppercase text-[10px] tracking-widest">
                                <Filter className="w-3 h-3 mr-2" />
                                Filter
                            </Button>
                        </div>
                    </div>
                </CardHeader>
                <CardContent className="p-0">
                    <Table>
                        <TableHeader className="bg-slate-50/50">
                            <TableRow className="hover:bg-transparent">
                                <TableHead className="font-bold text-slate-500 uppercase text-[10px] tracking-widest pl-6">Note #</TableHead>
                                <TableHead className="font-bold text-slate-500 uppercase text-[10px] tracking-widest">Customer</TableHead>
                                <TableHead className="font-bold text-slate-500 uppercase text-[10px] tracking-widest">Date</TableHead>
                                <TableHead className="font-bold text-slate-500 uppercase text-[10px] tracking-widest">Invoice Ref</TableHead>
                                <TableHead className="font-bold text-slate-500 uppercase text-[10px] tracking-widest text-right pr-6">Amount</TableHead>
                            </TableRow>
                        </TableHeader>
                        <TableBody>
                            {loading ? (
                                <TableRow>
                                    <TableCell colSpan={5} className="h-32 text-center text-slate-400 font-medium">Loading credit notes...</TableCell>
                                </TableRow>
                            ) : filteredNotes.length === 0 ? (
                                <TableRow>
                                    <TableCell colSpan={5} className="h-48 text-center">
                                        <div className="flex flex-col items-center gap-2">
                                            <div className="p-4 bg-slate-100 rounded-full">
                                                <FileText className="w-8 h-8 text-slate-300" />
                                            </div>
                                            <p className="text-slate-400 font-bold">No credit notes found</p>
                                        </div>
                                    </TableCell>
                                </TableRow>
                            ) : filteredNotes.map((note) => (
                                <TableRow key={note.id} className="hover:bg-blue-50/30 transition-colors group cursor-pointer">
                                    <TableCell className="pl-6 py-4">
                                        <div className="font-bold text-slate-900 group-hover:text-blue-600 transition-colors">
                                            {note.noteNumber}
                                        </div>
                                    </TableCell>
                                    <TableCell>
                                        <div className="font-bold text-slate-700">{note.customer?.firstName} {note.customer?.lastName}</div>
                                        <div className="text-[10px] text-slate-400 font-bold uppercase">{note.customer?.company || "Individual"}</div>
                                    </TableCell>
                                    <TableCell className="text-slate-500 font-medium">
                                        {format(new Date(note.date), "dd MMM yyyy")}
                                    </TableCell>
                                    <TableCell>
                                        <Badge variant="outline" className="rounded-lg font-mono text-[10px]">
                                            {note.invoice?.invoiceNumber || "Direct Credit"}
                                        </Badge>
                                    </TableCell>
                                    <TableCell className="text-right pr-6 font-black text-rose-600 tabular-nums">
                                        Ôé╣{Number(note.totalAmount).toLocaleString('en-IN', { minimumFractionDigits: 2 })}
                                    </TableCell>
                                </TableRow>
                            ))}
                        </TableBody>
                    </Table>
                </CardContent>
            </Card>
        </div>
    );
}

"use client";

import { useEffect, useState } from "react";
import { api } from "@/lib/api";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card";
import {
    Table,
    TableBody,
    TableCell,
    TableHead,
    TableHeader,
    TableRow
} from "@/components/ui/table";
import { Plus, ShoppingCart, TrendingUp, Package, Clock, Loader2, X } from "lucide-react";
import { toast } from "sonner";
import { Badge } from "@/components/ui/badge";
import { useUX } from "@/components/providers/ux-provider";
import { LoadingSpinner } from "@/components/ui/loading-spinner";
import { Dialog, DialogContent, DialogHeader, DialogTitle } from "@/components/ui/dialog";
import { ConfirmationDialog } from "@/components/shared/ConfirmationDialog";
import {
    Select,
    SelectContent,
    SelectItem,
    SelectTrigger,
    SelectValue,
} from "@/components/ui/select";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";

export default function SalesPage() {
    const { setUILocked } = useUX();
    const [orders, setOrders] = useState<any[]>([]);
    const [stats, setStats] = useState<any>({ totalRevenue: 0, orderCount: 0, pendingOrders: 0 });
    const [loading, setLoading] = useState(true);

    // New Order State
    const [showForm, setShowForm] = useState(false);
    const [isSubmitting, setIsSubmitting] = useState(false);
    const [products, setProducts] = useState<any[]>([]);
    const [customers, setCustomers] = useState<any[]>([]);
    const [orderData, setOrderData] = useState({ customerId: "", productId: "", quantity: 1 });
    const [showConfirm, setShowConfirm] = useState(false);

    const syncSalesData = async (showLoading = false) => {
        try {
            if (showLoading) setLoading(true);
            const [orderRes, statsRes, prodRes, custRes] = await Promise.all([
                api.get("sales/orders"),
                api.get("sales/stats"),
                api.get("inventory/products"),
                api.get("crm/customers")
            ]);
            setOrders(Array.isArray(orderRes.data) ? orderRes.data : (orderRes.data.data || []));
            setStats(statsRes.data);
            setProducts(Array.isArray(prodRes.data) ? prodRes.data : (prodRes.data.data || []));
            setCustomers(Array.isArray(custRes.data) ? custRes.data : (custRes.data.data || []));
        } catch (err) {
            console.error("Sales Sync Failure:", err);
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        syncSalesData(true);
        // CONTINUOUS BACKGROUND SYNC: 30s interval
        const interval = setInterval(() => syncSalesData(false), 30000);
        return () => clearInterval(interval);
    }, []);

    const handleConfirmSubmit = (e: React.FormEvent) => {
        e.preventDefault();
        if (!orderData.customerId || !orderData.productId) {
            toast.error("Please select customer and product");
            return;
        }

        const selectedProduct = (products || []).find(p => p.id === orderData.productId);
        const orderTotal = (selectedProduct ? Number(selectedProduct.price) : 0) * Number(orderData.quantity);

        if (orderTotal > 100000) {
            setShowConfirm(true);
        } else {
            submitOrder();
        }
    };

    const submitOrder = async () => {
        try {
            setIsSubmitting(true);
            setUILocked(true);
            const selectedProduct = (products || []).find(p => p.id === orderData.productId);

            await api.post("sales/orders", {
                customerId: orderData.customerId,
                items: [
                    {
                        productId: orderData.productId,
                        quantity: Number(orderData.quantity),
                        price: selectedProduct ? Number(selectedProduct.price) : 0
                    }
                ]
            });
            setShowForm(false);
            setOrderData({ customerId: "", productId: "", quantity: 1 });
            toast.success("Sales order processed successfully");
            syncSalesData();
        } catch (err: any) {
            toast.error(err.response?.data?.message || "Order processing failed");
        } finally {
            setIsSubmitting(false);
            setUILocked(false);
        }
    };

    const getStatusBadge = (status: string) => {
        switch (status) {
            case 'Paid': return <Badge className="bg-emerald-50 text-emerald-600 border-none font-black text-[10px] uppercase tracking-tighter rounded-full px-3 py-1">Paid</Badge>;
            case 'Shipped': return <Badge className="bg-blue-50 text-blue-600 border-none font-black text-[10px] uppercase tracking-tighter rounded-full px-3 py-1">Shipped</Badge>;
            case 'Pending': return <Badge className="bg-amber-50 text-amber-600 border-none font-black text-[10px] uppercase tracking-tighter rounded-full px-3 py-1">Pending</Badge>;
            case 'Cancelled': return <Badge className="bg-rose-50 text-rose-600 border-none font-black text-[10px] uppercase tracking-tighter rounded-full px-3 py-1">Cancelled</Badge>;
            default: return <Badge variant="secondary" className="bg-slate-100 text-slate-500 font-black text-[10px] uppercase tracking-tighter rounded-full px-3 py-1">{status}</Badge>;
        }
    };

    if (loading) return <LoadingSpinner className="h-full" text="Loading Sales Data..." />;

    return (
        <div className="flex-1 space-y-6 md:space-y-10 pt-2 md:pt-8 px-4 md:px-8 bg-slate-50/30 w-full max-w-full overflow-hidden">
            <div className="flex flex-col lg:flex-row lg:items-center justify-between gap-4 lg:gap-0">
                <div>
                    <h2 className="text-3xl md:text-4xl font-black tracking-tighter text-slate-900 flex items-center">
                        <div className="p-2 md:p-3 bg-blue-600 rounded-2xl shadow-lg shadow-blue-500/20 mr-4 md:mr-5 shrink-0">
                            <ShoppingCart className="h-6 w-6 md:h-7 md:w-7 text-white" />
                        </div>
                        <span className="truncate">Sales Orders</span>
                    </h2>
                    <p className="text-slate-600 mt-3 md:mt-2 font-black uppercase text-[10px] tracking-[0.2em] ml-0 md:ml-[68px]">All orders, revenue & customer transactions</p>
                </div>
                <div className="flex gap-4 w-full md:w-auto mt-2 lg:mt-0">
                    <Button
                        className="w-full md:w-auto rounded-2xl bg-slate-900 hover:bg-blue-600 font-black px-10 shadow-xl shadow-slate-900/10 text-white h-12 transition-all active:scale-95 border-none shrink-0"
                        onClick={() => setShowForm(true)}
                    >
                        <Plus className="mr-2 h-5 w-5" /> New Order
                    </Button>
                </div>
            </div>

            <div className="grid gap-4 sm:gap-6 md:grid-cols-2 lg:grid-cols-4 w-full">
                <Card className="bg-white border-none shadow-xl shadow-slate-200/40 rounded-[32px] overflow-hidden group hover:-translate-y-1 transition-all">
                    <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
                        <CardTitle className="text-[10px] font-black text-slate-600 uppercase tracking-widest">Total Revenue</CardTitle>
                        <div className="p-2.5 bg-emerald-50 rounded-2xl group-hover:scale-110 transition-transform">
                            <TrendingUp className="h-4 w-4 text-emerald-600" />
                        </div>
                    </CardHeader>
                    <CardContent>
                        <div className="text-4xl font-black text-slate-900 tracking-tighter italic">Ôé╣{Number(stats.totalRevenue).toLocaleString('en-IN', { minimumFractionDigits: 0 })}</div>
                        <div className="text-[10px] text-emerald-600 font-black mt-4 flex items-center bg-emerald-50 w-fit px-2 py-1 rounded-lg">
                            <TrendingUp className="h-3 w-3 mr-1.5" />
                            +12.4% vs Last Month
                        </div>
                    </CardContent>
                </Card>

                <Card className="bg-white border-none shadow-xl shadow-slate-200/40 rounded-[32px] overflow-hidden group hover:-translate-y-1 transition-all">
                    <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
                        <CardTitle className="text-[10px] font-black text-slate-600 uppercase tracking-widest">Total Orders</CardTitle>
                        <div className="p-2.5 bg-blue-50 rounded-2xl group-hover:scale-110 transition-transform">
                            <ShoppingCart className="h-4 w-4 text-blue-600" />
                        </div>
                    </CardHeader>
                    <CardContent>
                        <div className="text-4xl font-black text-slate-900 tracking-tighter italic">{stats.orderCount.toString().padStart(3, '0')}</div>
                        <p className="text-[10px] text-slate-400 font-black mt-4 uppercase tracking-widest">Completed Orders</p>
                    </CardContent>
                </Card>

                <Card className="bg-white border-none shadow-xl shadow-slate-200/40 rounded-[32px] overflow-hidden group hover:-translate-y-1 transition-all">
                    <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
                        <CardTitle className="text-[10px] font-black text-slate-600 uppercase tracking-widest">Pending Orders</CardTitle>
                        <div className="p-2.5 bg-amber-50 rounded-2xl group-hover:scale-110 transition-transform">
                            <Clock className="h-4 w-4 text-amber-600" />
                        </div>
                    </CardHeader>
                    <CardContent>
                        <div className="text-4xl font-black text-amber-600 tracking-tighter italic">{stats.pendingOrders.toString().padStart(2, '0')}</div>
                        <p className="text-[10px] text-amber-600/60 font-black mt-4 uppercase tracking-widest bg-amber-50 w-fit px-2 py-1 rounded-lg animate-pulse">Awaiting Confirmation</p>
                    </CardContent>
                </Card>

                <Card className="bg-white border-none shadow-xl shadow-slate-200/40 rounded-[32px] overflow-hidden group hover:-translate-y-1 transition-all">
                    <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
                        <CardTitle className="text-[10px] font-black text-slate-600 uppercase tracking-widest">Avg. Order Value</CardTitle>
                        <div className="p-2.5 bg-indigo-50 rounded-2xl group-hover:scale-110 transition-transform">
                            <Package className="h-4 w-4 text-indigo-600" />
                        </div>
                    </CardHeader>
                    <CardContent>
                        <div className="text-4xl font-black text-slate-900 tracking-tighter italic">
                            Ôé╣{stats.orderCount > 0 ? (stats.totalRevenue / stats.orderCount).toLocaleString('en-IN', { maximumFractionDigits: 0 }) : "0"}
                        </div>
                        <p className="text-[10px] text-slate-400 font-black mt-4 uppercase tracking-widest">Per Transaction Average</p>
                    </CardContent>
                </Card>
            </div>

            <Card className="bg-white border-none shadow-2xl shadow-slate-200/40 rounded-[40px] overflow-hidden">
                <CardHeader className="bg-slate-50/50 border-b border-slate-100 py-10 px-10">
                    <div className="flex flex-col lg:flex-row lg:items-center justify-between gap-4 lg:gap-0">
                        <div>
                            <CardTitle className="text-slate-900 text-2xl font-black tracking-tight">Sales Orders</CardTitle>
                            <CardDescription className="text-slate-600 font-black uppercase text-[10px] tracking-[0.2em] mt-2">All customer orders and invoices</CardDescription>
                        </div>
                        <Badge variant="outline" className="w-fit border-slate-200 bg-white text-slate-500 font-black px-4 py-1.5 rounded-xl uppercase tracking-widest text-[10px]">
                            Live Feed
                        </Badge>
                    </div>
                </CardHeader>
                <CardContent className="p-0 overflow-x-auto max-w-[100vw] sm:max-w-none">
                    <Table className="min-w-[900px]">
                        <TableHeader className="bg-slate-50/30">
                            <TableRow className="border-slate-100 hover:bg-transparent">
                                <TableHead className="text-slate-600 font-black uppercase text-[10px] tracking-[0.2em] pl-10 h-16">Order ID</TableHead>
                                <TableHead className="text-slate-600 font-black uppercase text-[10px] tracking-[0.2em]">Customer</TableHead>
                                <TableHead className="text-slate-600 font-black uppercase text-[10px] tracking-[0.2em]">Date</TableHead>
                                <TableHead className="text-slate-600 font-black uppercase text-[10px] tracking-[0.2em]">Amount</TableHead>
                                <TableHead className="text-slate-600 font-black uppercase text-[10px] tracking-[0.2em]">Status</TableHead>
                                <TableHead className="text-slate-600 font-black uppercase text-[10px] tracking-[0.2em] text-right pr-10">Actions</TableHead>
                            </TableRow>
                        </TableHeader>
                        <TableBody>
                            {orders.map((order) => (
                                <TableRow key={order.id} className="border-slate-50 hover:bg-blue-50/30 transition-all group">
                                    <TableCell className="pl-10 font-black text-[10px] text-blue-600 tracking-widest bg-slate-50/30 group-hover:bg-blue-50/30 transition-all">
                                        #{order.id.slice(0, 8).toUpperCase()}
                                    </TableCell>
                                    <TableCell>
                                        <div className="flex flex-col">
                                            <span className="font-black text-slate-900 tracking-tight leading-none mb-1 text-base truncate max-w-[200px]" title={order.customer ? `${order.customer.firstName} ${order.customer.lastName}` : "Direct Transaction"}>
                                                {order.customer ? `${order.customer.firstName} ${order.customer.lastName}` : "Direct Transaction"}
                                            </span>
                                            <span className="text-[10px] text-slate-400 font-bold uppercase tracking-widest">Customer</span>
                                        </div>
                                    </TableCell>
                                    <TableCell className="text-slate-500 font-black text-xs italic tracking-tighter">
                                        {new Date(order.createdAt).toLocaleDateString(undefined, { month: 'short', day: '2-digit', year: 'numeric' }).toUpperCase()}
                                    </TableCell>
                                    <TableCell>
                                        <span className="font-black text-slate-900 text-lg tabular-nums">
                                            Ôé╣{Number(order.total).toLocaleString('en-IN', { minimumFractionDigits: 0 })}
                                        </span>
                                    </TableCell>
                                    <TableCell>{getStatusBadge(order.status)}</TableCell>
                                    <TableCell className="text-right pr-10">
                                        <Button
                                            variant="outline"
                                            size="sm"
                                            className="h-10 px-6 font-black text-[10px] uppercase tracking-widest border-slate-200 text-slate-600 hover:text-blue-600 hover:border-blue-100 hover:bg-blue-50 rounded-2xl transition-all active:scale-95"
                                        >
                                            View Details
                                        </Button>
                                    </TableCell>
                                </TableRow>
                            ))}
                            {orders.length === 0 && (
                                <TableRow>
                                    <TableCell colSpan={6} className="text-center py-32 text-slate-300">
                                        <div className="flex flex-col items-center gap-6">
                                            <div className="w-24 h-24 rounded-full bg-slate-50 flex items-center justify-center border-4 border-dashed border-slate-100">
                                                <ShoppingCart className="h-10 w-10 opacity-20" />
                                            </div>
                                            <div>
                                                <p className="text-xl font-black text-slate-400 tracking-tight">No Orders Yet</p>
                                                <p className="text-[10px] font-black uppercase tracking-widest mt-1">Create your first order to get started</p>
                                            </div>
                                        </div>
                                    </TableCell>
                                </TableRow>
                            )}
                        </TableBody>
                    </Table>
                </CardContent>
            </Card>

            <Dialog open={showForm} onOpenChange={setShowForm}>
                <DialogContent className="w-11/12 sm:min-w-fit sm:max-w-lg bg-white border-none shadow-2xl rounded-[40px] overflow-hidden p-0">
                    <div className="bg-slate-900 p-10 pb-16">
                        <DialogTitle className="text-white font-black text-3xl tracking-tight">Create New Order</DialogTitle>
                        <p className="text-slate-400 font-black uppercase text-[10px] tracking-[0.2em] mt-3">Add a new customer order or invoice</p>
                    </div>
                    <form onSubmit={handleConfirmSubmit} className="p-10 -mt-8 bg-white rounded-t-[40px] space-y-8">
                        <div className="space-y-3">
                            <Label className="text-slate-600 font-black uppercase text-[10px] tracking-widest ml-1">Select Customer</Label>
                            <Select value={orderData.customerId} onValueChange={v => setOrderData({ ...orderData, customerId: v })}>
                                <SelectTrigger className="bg-slate-50 border-slate-100 text-slate-900 rounded-2xl h-14 px-5 font-bold focus:ring-blue-500/20 text-base">
                                    <SelectValue placeholder="Choose Customer" />
                                </SelectTrigger>
                                <SelectContent className="rounded-2xl border-slate-100 shadow-2xl p-2">
                                    {(customers || []).map(c => (
                                        <SelectItem key={c.id} value={c.id} className="rounded-xl py-3 font-black text-slate-700">
                                            {c.firstName} {c.lastName}
                                        </SelectItem>
                                    ))}
                                    {(!customers || customers.length === 0) && (
                                        <div className="p-4 text-center text-[10px] font-black text-slate-600 uppercase tracking-widest">No Customers Found</div>
                                    )}
                                </SelectContent>
                            </Select>
                        </div>
                        <div className="space-y-3">
                            <Label className="text-slate-600 font-black uppercase text-[10px] tracking-widest ml-1">Select Product</Label>
                            <Select value={orderData.productId} onValueChange={v => setOrderData({ ...orderData, productId: v })}>
                                <SelectTrigger className="bg-slate-50 border-slate-100 text-slate-900 rounded-2xl h-14 px-5 font-bold focus:ring-blue-500/20 text-base">
                                    <SelectValue placeholder="Choose Product" />
                                </SelectTrigger>
                                <SelectContent className="rounded-2xl border-slate-100 shadow-2xl p-2">
                                    {(products || []).map(p => (
                                        <SelectItem key={p.id} value={p.id} className="rounded-xl py-3 font-black text-slate-700">
                                            <div className="flex justify-between items-center w-full min-w-[300px]">
                                                <span>{p.name}</span>
                                                <span className="text-blue-500 bg-blue-50 px-2 py-0.5 rounded-lg text-[9px] ml-4">Ôé╣{p.price}</span>
                                            </div>
                                        </SelectItem>
                                    ))}
                                    {(!products || products.length === 0) && (
                                        <div className="p-4 text-center text-[10px] font-black text-slate-600 uppercase tracking-widest">No Products Found</div>
                                    )}
                                </SelectContent>
                            </Select>
                        </div>
                        <div className="space-y-3">
                            <Label className="text-slate-600 font-black uppercase text-[10px] tracking-widest ml-1">Quantity</Label>
                            <Input
                                type="number"
                                min="1"
                                className="bg-slate-50 border-slate-100 text-slate-900 rounded-2xl h-14 px-5 text-2xl font-black focus:ring-blue-500/20 tabular-nums"
                                value={orderData.quantity || ""}
                                onChange={e => {
                                    const val = e.target.value === "" ? 1 : parseInt(e.target.value, 10);
                                    setOrderData({ ...orderData, quantity: isNaN(val) ? 1 : Math.max(1, val) });
                                }}
                            />
                        </div>
                        <div className="flex gap-4 pt-6">
                            <Button type="button" variant="ghost" className="flex-1 h-14 text-slate-600 font-black rounded-2xl hover:bg-rose-50 hover:text-rose-600 transition-all" onClick={() => setShowForm(false)}>Cancel</Button>
                            <Button type="submit" disabled={isSubmitting} className="flex-[2] bg-blue-600 hover:bg-blue-700 text-white font-black rounded-2xl h-14 shadow-xl shadow-blue-500/20 transition-all active:scale-[0.98]">
                                {isSubmitting ? "Creating Order..." : "Create Order"}
                            </Button>
                        </div>
                    </form>
                </DialogContent>
            </Dialog>

            <ConfirmationDialog
                isOpen={showConfirm}
                onClose={() => setShowConfirm(false)}
                onConfirm={submitOrder}
                title="Large Order Alert"
                description="This order exceeds Ôé╣1,00,000. Please verify the customer and quantities before finalizing."
                confirmLabel="Confirm Order"
                cancelLabel="Review Changes"
                variant="warning"
            />
        </div>
    );
}

"use client";

import React, { useState, useEffect, useRef } from 'react';
import { Zap, Wifi, WifiOff } from 'lucide-react';
import { api } from '@/lib/api';
import { toast } from 'react-hot-toast';
import { BarcodeSearch } from '@/components/sales/rapid/BarcodeSearch';
import { CartTable } from '@/components/sales/rapid/CartTable';
import { CheckoutSidebar } from '@/components/sales/rapid/CheckoutSidebar';
import { ProductGrid } from '@/components/sales/rapid/ProductGrid';
import { ConfirmationDialog } from '@/components/shared/ConfirmationDialog';

const generateId = () => Math.random().toString(36).substring(2, 10) + Date.now().toString(36);

interface Item {
    productId: string;
    name: string;
    sku: string;
    price: number;
    quantity: number;
    gstRate: number;
}

export default function RapidBillingPage() {
    const [items, setItems] = useState<Item[]>([]);
    const [search, setSearch] = useState('');
    const [customerId, setCustomerId] = useState<string | null>(null);
    const [customerName, setCustomerName] = useState('Walk-in Customer');
    const [startTime, setStartTime] = useState<number | null>(null);
    const [elapsed, setElapsed] = useState(0);
    const [isOffline, setIsOffline] = useState(false);
    const [pendingSync, setPendingSync] = useState(0);
    const [paymentMode, setPaymentMode] = useState<'CASH' | 'UPI' | 'CREDIT'>('CASH');
    const [lastScanFailed, setLastScanFailed] = useState(false);
    const [customAmountPaid, setCustomAmountPaid] = useState<number>(0);
    const [userRole, setUserRole] = useState<string | null>(null);
    const [isSubmitting, setIsSubmitting] = useState(false);
    const [isSearching, setIsSearching] = useState(false);

    // Manual Search State
    const [manualSearch, setManualSearch] = useState('');
    const [searchResults, setSearchResults] = useState<any[]>([]);
    const [isManualSearching, setIsManualSearching] = useState(false);
    const [showConfirm, setShowConfirm] = useState(false);

    const searchRef = useRef<HTMLInputElement>(null!);
    const timerRef = useRef<NodeJS.Timeout | null>(null);

    useEffect(() => {
        searchRef.current?.focus();
        if (typeof navigator !== 'undefined') {
            setIsOffline(!navigator.onLine);
            window.addEventListener('online', () => setIsOffline(false));
            window.addEventListener('offline', () => setIsOffline(true));
        }

        const loadMetadata = () => {
            const queue = JSON.parse(localStorage.getItem('billing_queue') || '[]');
            setPendingSync(queue.length);
            const userData = localStorage.getItem('k_user');
            if (userData) {
                try {
                    const u = JSON.parse(userData);
                    setUserRole(u.role);
                } catch (e) { }
            }
        };
        loadMetadata();

        return () => {
            if (timerRef.current) clearInterval(timerRef.current);
        };
    }, []);

    useEffect(() => {
        if (items.length > 0 && !startTime) {
            setStartTime(Date.now());
            timerRef.current = setInterval(() => {
                setElapsed(prev => prev + 1);
            }, 1000);
        }
    }, [items, startTime]);

    const handleSearch = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!search || isSearching) return;

        let multiplier = 1;
        let finalCode = search.trim();

        if (search.includes('*')) {
            const parts = search.split('*');
            if (parts.length === 2 && !isNaN(parseFloat(parts[0]))) {
                multiplier = parseFloat(parts[0]);
                finalCode = parts[1].trim();
            }
        }

        if (!finalCode) return;

        setIsSearching(true);
        try {
            const res = await api.get(`/inventory/products/find-by-code?code=${finalCode}`);
            if (res.data) {
                addItem(res.data, multiplier);
                setLastScanFailed(false);
                if (multiplier > 1) toast.success(`Added ${multiplier} units!`);
            } else {
                setLastScanFailed(true);
                setTimeout(() => setLastScanFailed(false), 1000);
                toast.error("Product not found");
            }
        } catch (err) {
            toast.error("Connection issue");
        } finally {
            setIsSearching(false);
            setSearch('');
        }
    };

    // Manual Search Effect
    useEffect(() => {
        const timer = setTimeout(async () => {
            if (!manualSearch.trim()) {
                setSearchResults([]);
                return;
            }

            setIsManualSearching(true);
            try {
                // Determine if search is numeric (likely SKU/Barcode) or text (Name)
                const isNumeric = /^\d+$/.test(manualSearch);
                const endpoint = isNumeric
                    ? `/inventory/products/find-by-code?code=${manualSearch}`
                    : `/inventory/products?search=${manualSearch}&limit=5`;

                const res = await api.get(endpoint);

                if (isNumeric && res.data) {
                    setSearchResults([res.data]); // Single result for direct code match
                } else if (!isNumeric && res.data.data) {
                    setSearchResults(res.data.data); // List for text search
                } else {
                    setSearchResults([]);
                }
            } catch (err) {
                console.error("Search failed", err);
            } finally {
                setIsManualSearching(false);
            }
        }, 300); // 300ms debounce

        return () => clearTimeout(timer);
    }, [manualSearch]);

    const addItem = (product: any, quantity: number = 1) => {
        setItems(prev => {
            const existing = prev.find(i => i.productId === product.id);
            if (existing) {
                return prev.map(i => i.productId === product.id ? { ...i, quantity: i.quantity + quantity } : i);
            }
            return [...prev, {
                productId: product.id,
                name: product.name,
                sku: product.sku,
                price: parseFloat(product.price),
                quantity: quantity,
                gstRate: product.gstRate || 0
            }];
        });
        searchRef.current?.focus();
    };

    const updateQty = (id: string, delta: number) => {
        setItems(prev => prev.map(i =>
            i.productId === id ? { ...i, quantity: i.quantity + delta } : i
        ).filter(i => i.quantity > 0));
    };

    const removeItem = (id: string) => {
        setItems(prev => prev.filter(i => i.productId !== id));
    };

    const round2 = (val: number) => Math.round((val + Number.EPSILON) * 100) / 100;

    const subtotal = items.reduce((sum, i) => sum + (i.price * i.quantity), 0);
    const taxTotal = items.reduce((sum, i) => {
        const itemTaxable = i.price * i.quantity;
        const itemTax = (itemTaxable * (i.gstRate || 0)) / 100;
        return sum + itemTax;
    }, 0);
    const total = round2(subtotal + taxTotal);

    const handleCompletePress = () => {
        if (items.length === 0 || isSubmitting) return;

        // Show confirmation for large amounts
        if (total > 100000) {
            setShowConfirm(true);
        } else {
            completeInvoice();
        }
    };

    const completeInvoice = async () => {
        if (items.length === 0 || isSubmitting) return;

        setIsSubmitting(true);
        const idempotencyKey = `POS-${Date.now()}-${generateId()}`;
        const invoiceNumber = `INV-${Date.now()}-${generateId().substring(0, 4).toUpperCase()}`;

        const amountPaid = customAmountPaid > 0 ? customAmountPaid : (paymentMode === 'CREDIT' ? 0 : total);

        const invoiceData = {
            customerId: customerId || undefined,
            items: items.map(i => ({ productId: i.productId, quantity: i.quantity, price: i.price, gstRate: i.gstRate })),
            billingTimeSeconds: elapsed,
            paymentMode,
            amountPaid,
            idempotencyKey,
            issueDate: new Date().toISOString(),
            dueDate: new Date().toISOString(),
            invoiceNumber
        };

        if (isOffline) {
            const queue = JSON.parse(localStorage.getItem('billing_queue') || '[]');
            queue.push(invoiceData);
            localStorage.setItem('billing_queue', JSON.stringify(queue));
            setPendingSync(queue.length);
            toast.success("Saved Offline");
            reset();
            setIsSubmitting(false);
            return;
        }

        try {
            await api.post('accounting/invoices', invoiceData);
            toast.success(`Success!`);
            reset();
        } catch (err) {
            toast.error("Sync Error: Saved Locally");
            const queue = JSON.parse(localStorage.getItem('billing_queue') || '[]');
            queue.push(invoiceData);
            localStorage.setItem('billing_queue', JSON.stringify(queue));
            setPendingSync(queue.length);
            reset();
        } finally {
            setIsSubmitting(false);
        }
    };

    const syncQueue = async () => {
        if (isOffline || isSubmitting) return;
        const queue = JSON.parse(localStorage.getItem('billing_queue') || '[]');
        if (queue.length === 0) return;

        setIsSubmitting(true);
        try {
            const res = await api.post('accounting/invoices/bulk', queue);
            const successful = new Set(res.data.results.filter((r: any) => r.status === 'SUCCESS').map((r: any) => r.invoiceNumber));
            const alreadyDone = new Set(res.data.results.filter((r: any) => r.error === 'ALREADY_SYNCED').map((r: any) => r.invoiceNumber));

            const remaining = queue.filter((inv: any) => !successful.has(inv.invoiceNumber) && !alreadyDone.has(inv.invoiceNumber));
            localStorage.setItem('billing_queue', JSON.stringify(remaining));
            setPendingSync(remaining.length);
            if (successful.size > 0 || alreadyDone.size > 0) toast.success("Sync complete");
        } catch (err) {
            toast.error("Sync failed");
        } finally {
            setIsSubmitting(false);
        }
    };

    useEffect(() => {
        if (!isOffline && pendingSync > 0) syncQueue();
    }, [isOffline, pendingSync]);

    const reset = () => {
        setItems([]);
        setStartTime(null);
        setElapsed(0);
        setSearch('');
        setCustomAmountPaid(0);
        if (timerRef.current) clearInterval(timerRef.current);
    };

    useEffect(() => {
        const handleKeys = (e: KeyboardEvent) => {
            if (e.key === 'F1') { e.preventDefault(); handleCompletePress(); }
            if (e.key === 'F2') {
                e.preventDefault();
                const modes: any[] = ['CASH', 'UPI', 'CREDIT'];
                const next = modes[(modes.indexOf(paymentMode) + 1) % modes.length];
                setPaymentMode(next);
                toast(`Payment: ${next}`);
            }
            if (e.key === 'Escape') reset();
        };
        window.addEventListener('keydown', handleKeys);
        return () => window.removeEventListener('keydown', handleKeys);
    }, [items, isOffline, elapsed, paymentMode]);

    return (
        <div className="h-[calc(100vh-64px)] bg-slate-50 flex flex-col overflow-hidden font-sans antialiased text-slate-900">
            <header className="px-6 py-4 border-b border-slate-200 bg-white flex justify-between items-center shadow-sm relative z-20 shrink-0 h-16">
                <div className="flex items-center gap-3">
                    <div className="w-9 h-9 rounded-xl bg-blue-600 flex items-center justify-center shadow-lg shadow-blue-500/30">
                        <Zap className="w-5 h-5 text-white" />
                    </div>
                    <span className="text-xl font-black tracking-tighter uppercase">Rapid <span className="text-blue-600">Commerce</span></span>
                </div>

                <div className="flex gap-4 items-center bg-slate-50 px-4 py-2 rounded-full border border-slate-100">
                    {isOffline ? <WifiOff className="w-4 h-4 text-amber-500" /> : <Wifi className="w-4 h-4 text-emerald-500" />}
                    <span className="text-[10px] font-black uppercase tracking-widest">{isOffline ? 'Offline Mode' : 'Online System'}</span>
                </div>
            </header>

            <main className="flex-1 flex flex-col lg:flex-row overflow-hidden overflow-y-auto lg:overflow-hidden">
                <section className="flex-1 flex flex-col border-b lg:border-b-0 lg:border-r border-slate-200 bg-white relative">
                    <ProductGrid onProductClick={(product) => {
                        addItem(product);
                        toast.success(`Sent ${product.name} to cart`);
                    }} />
                </section>

                {/* Main POS Interface (Cart + Scanner) */}
                <section className="flex-1 flex flex-col h-full bg-slate-50 relative min-w-0 pb-20 lg:pb-0 border-r border-slate-200">

                    <BarcodeSearch
                        search={search}
                        setSearch={setSearch}
                        onSubmit={handleSearch}
                        isSearching={isSearching}
                        lastScanFailed={lastScanFailed}
                        inputRef={searchRef}
                    />
                    <CartTable
                        items={items}
                        updateQty={updateQty}
                        removeItem={removeItem}
                        setItems={setItems}
                    />
                </section>

                <CheckoutSidebar
                    customerName={customerName}
                    paymentMode={paymentMode}
                    setPaymentMode={setPaymentMode}
                    customAmountPaid={customAmountPaid}
                    setCustomAmountPaid={setCustomAmountPaid}
                    subtotal={subtotal}
                    taxTotal={taxTotal}
                    total={total}
                    itemsCount={items.length}
                    isSubmitting={isSubmitting}
                    completeInvoice={handleCompletePress}
                    userRole={userRole}
                />
            </main >

            <ConfirmationDialog
                isOpen={showConfirm}
                onClose={() => setShowConfirm(false)}
                onConfirm={completeInvoice}
                title="High Value Invoice"
                description={`You are about to generate an invoice for Ôé╣${total.toLocaleString('en-IN')}. Are you sure you want to proceed?`}
                confirmLabel="Yes, Generate"
                cancelLabel="Review"
                variant="warning"
            />
        </div >
    );
}

"use client";

import { useEffect, useState } from "react";
import { api } from "@/lib/api";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Settings, Shield, CreditCard, Bell, Globe, Zap } from "lucide-react";
import { toast } from "sonner";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";
import { Badge } from "@/components/ui/badge";
import { Users, UserPlus, Key, Trash2, ShieldAlert } from "lucide-react";
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogDescription, DialogFooter } from "@/components/ui/dialog";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { useAuth } from "@/hooks/use-auth";
import { ApiKeyManager } from "@/components/system/api-key-manager";
import { Role } from "@nexus/shared";

// Use shared Role enum instead of local string literals

export default function SettingsPage() {
    const [tenant, setTenant] = useState<any>(null);
    const [orgName, setOrgName] = useState('');
    const [loading, setLoading] = useState(true);
    const [billingInfo, setBillingInfo] = useState<any>(null);
    const [members, setMembers] = useState<any[]>([]);
    const [isAddUserOpen, setIsAddUserOpen] = useState(false);
    const [newUser, setNewUser] = useState({ fullName: '', email: '', role: Role.Biller });
    const [isResetOpen, setIsResetOpen] = useState(false);
    const [tempPassword, setTempPassword] = useState<string | null>(null);
    const [mounted, setMounted] = useState(false);
    const [error, setError] = useState<string | null>(null);
    const { user: currentUser } = useAuth();
    const isOwner = currentUser?.role === Role.Owner;

    const fetchSettings = async () => {
        setLoading(true);
        setError(null);
        try {
            const [profRes, billRes, usersRes] = await Promise.all([
                api.get("auth/profile"),
                api.get("system/billing/plan"),
                api.get("users")
            ]);
            setTenant(profRes.data?.tenant || null);
            setOrgName(profRes.data?.tenant?.name || '');
            setBillingInfo(billRes.data || null);
            setMembers(Array.isArray(usersRes.data) ? usersRes.data : []);
        } catch (err: any) {
            console.error(err);
            setError(err.isWakeup ? err.message : "Failed to load settings. Please refresh.");
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        setMounted(true);
        fetchSettings();
    }, []);

    if (!mounted) return null; // Prevent hydration mismatch

    const handleAddUser = async (e: React.FormEvent) => {
        e.preventDefault();
        try {
            await api.post("users", newUser);
            toast.success(`${newUser.fullName} added to the team`);
            setIsAddUserOpen(false);
            const res = await api.get("users");
            setMembers(Array.isArray(res.data) ? res.data : []);
        } catch (err) {
            toast.error("Failed to add user");
        }
    };

    const handleUpdateRole = async (userId: string, role: Role) => {
        try {
            await api.patch(`/users/${userId}/role`, { role });
            toast.success("Role updated successfully");
            const res = await api.get("users");
            setMembers(Array.isArray(res.data) ? res.data : []);
        } catch (err) {
            toast.error("Failed to update role");
        }
    };

    const handleResetPassword = async (userId: string) => {
        try {
            const res = await api.post(`/users/${userId}/reset-password`);
            setTempPassword(res.data.temporaryPassword);
            setIsResetOpen(true);
            toast.success("Temporary password generated");
        } catch (err) {
            toast.error("Failed to generate password");
        }
    };

    const handleRemoveUser = async (userId: string) => {
        if (!confirm("Are you sure you want to remove this user? This cannot be undone.")) return;
        try {
            await api.delete(`/users/${userId}`);
            toast.success("User removed from tenant");
            const res = await api.get("users");
            setMembers(Array.isArray(res.data) ? res.data : []);
        } catch (err) {
            toast.error("Failed to remove user");
        }
    };

    const handleUpdate = async (e: React.FormEvent) => {
        e.preventDefault();
        toast.success("Settings updated successfully");
    };

    const handleUpgrade = async (plan: string) => {
        try {
            await api.post("system/billing/upgrade", { plan });
            toast.success(`Successfully upgraded to ${plan} plan`);
            location.reload();
        } catch (err) {
            toast.error("Upgrade failed. Please try again.");
        }
    }

    return (
        <div className="flex-1 space-y-6 md:space-y-8 pt-2 md:pt-6">
            <div className="flex flex-col lg:flex-row lg:items-center justify-between gap-4 lg:gap-0">
                <div>
                    <h2 className="text-3xl md:text-4xl font-black tracking-tight text-slate-900 flex items-center">
                        <Settings className="mr-3 h-8 w-8 text-slate-400" />
                        Settings
                    </h2>
                    <p className="text-slate-500 font-medium mt-1">Manage your account, team, and billing preferences.</p>
                </div>
            </div>

            <Tabs defaultValue="general" className="space-y-6">
                <TabsList className="bg-slate-100 border border-slate-200 p-1.5 rounded-2xl h-auto w-full flex flex-wrap justify-start overflow-x-auto snap-x">
                    <TabsTrigger value="general" className="flex-1 sm:flex-none data-[state=active]:bg-white data-[state=active]:text-slate-900 data-[state=active]:shadow-sm rounded-xl px-4 md:px-6 py-2.5 font-bold transition-all snap-start">General</TabsTrigger>
                    <TabsTrigger value="team" className="flex-1 sm:flex-none data-[state=active]:bg-white data-[state=active]:text-slate-900 data-[state=active]:shadow-sm rounded-xl px-4 md:px-6 py-2.5 font-bold transition-all snap-start">Company Team</TabsTrigger>
                    <TabsTrigger value="security" className="flex-1 sm:flex-none data-[state=active]:bg-white data-[state=active]:text-slate-900 data-[state=active]:shadow-sm rounded-xl px-4 md:px-6 py-2.5 font-bold transition-all snap-start">Security</TabsTrigger>
                    <TabsTrigger value="billing" className="flex-1 sm:flex-none data-[state=active]:bg-white data-[state=active]:text-slate-900 data-[state=active]:shadow-sm rounded-xl px-4 md:px-6 py-2.5 font-bold transition-all snap-start">Billing</TabsTrigger>
                    <TabsTrigger value="notifications" className="flex-1 sm:flex-none data-[state=active]:bg-white data-[state=active]:text-slate-900 data-[state=active]:shadow-sm rounded-xl px-4 md:px-6 py-2.5 font-bold transition-all snap-start">Notifications</TabsTrigger>
                    <TabsTrigger value="connectivity" className="flex-1 sm:flex-none data-[state=active]:bg-white data-[state=active]:text-slate-900 data-[state=active]:shadow-sm rounded-xl px-4 md:px-6 py-2.5 font-bold transition-all snap-start">Connectivity</TabsTrigger>
                </TabsList>

                <TabsContent value="general">
                    <Card className="bg-white border-slate-200 shadow-sm max-w-2xl">
                        <CardHeader>
                            <CardTitle className="text-slate-900 font-black flex items-center">
                                <Globe className="mr-2 h-5 w-5 text-sky-600" />
                                Company Profile
                            </CardTitle>
                            <CardDescription className="text-slate-500">Update your company name and workspace details.</CardDescription>
                        </CardHeader>
                        <CardContent className="space-y-6">
                            <form onSubmit={handleUpdate} className="space-y-4">
                                <div className="grid gap-2">
                                    <Label htmlFor="name" className="text-slate-500 font-bold uppercase text-[10px] tracking-wider">Organization Name</Label>
                                    <Input
                                        id="name"
                                        value={orgName}
                                        onChange={e => setOrgName(e.target.value)}
                                        className="bg-slate-50 border-slate-200 text-slate-900 focus:ring-blue-500 h-10"
                                    />
                                </div>
                                <div className="grid gap-2">
                                    <Label htmlFor="slug" className="text-slate-500 font-bold uppercase text-[10px] tracking-wider">Workspace Identifier (Slug)</Label>
                                    <Input
                                        id="slug"
                                        defaultValue={tenant?.slug}
                                        disabled
                                        className="bg-slate-100 border-slate-200 text-slate-400 font-mono h-10"
                                    />
                                    <p className="text-[11px] text-slate-400 italic font-medium">This ID is fixed and cannot be changed.</p>
                                </div>
                                <div className="pt-4">
                                    <Button type="submit" className="bg-slate-900 hover:bg-slate-950 text-white font-bold h-11 px-8 rounded-xl">Save Changes</Button>
                                </div>
                            </form>
                        </CardContent>
                    </Card>
                </TabsContent>

                <TabsContent value="team">
                    <div className="space-y-4">
                        <div className="flex flex-col sm:flex-row justify-between sm:items-center gap-4 bg-white p-4 rounded-xl border border-slate-200">
                            <div>
                                <h3 className="font-black text-slate-900">Team Members</h3>
                                <p className="text-xs text-slate-500 font-medium">Manage employees and their access levels.</p>
                            </div>
                            <Button className="bg-slate-900 hover:bg-slate-950 font-bold gap-2 w-full sm:w-auto justify-center" onClick={() => setIsAddUserOpen(true)}>
                                <UserPlus className="h-4 w-4" />
                                Add Member
                            </Button>
                        </div>

                        <Card className="bg-white border-slate-200 shadow-sm">
                            <CardContent className="p-0">
                                {loading ? (
                                    <div className="p-8 flex flex-col items-center justify-center gap-4">
                                        <div className="h-8 w-8 border-4 border-blue-500/20 border-t-blue-600 rounded-full animate-spin" />
                                        <p className="text-[10px] text-slate-400 font-black uppercase tracking-widest">Loading team...</p>
                                    </div>
                                ) : error ? (
                                    <div className="p-12 text-center space-y-4">
                                        <div className="inline-flex h-12 w-12 items-center justify-center rounded-full bg-rose-50 text-rose-500">
                                            <ShieldAlert className="h-6 w-6" />
                                        </div>
                                        <div className="space-y-1">
                                            <h3 className="font-black text-slate-900 uppercase tracking-tight">Connection Error</h3>
                                            <p className="text-xs text-slate-500 font-medium">{error}</p>
                                        </div>
                                        <Button onClick={fetchSettings} variant="outline" className="font-bold border-slate-200">
                                            Try Again
                                        </Button>
                                    </div>
                                ) : members.length === 0 ? (
                                    <div className="p-12 text-center text-slate-400 font-medium text-sm">No team members found.</div>
                                ) : (
                                    <div className="divide-y divide-slate-100">
                                        {(members || []).map((member) => (
                                            <div key={member.id} className="p-4 flex flex-col sm:flex-row sm:items-center justify-between gap-4 group">
                                                <div className="flex items-center gap-3">
                                                    <div className="h-10 w-10 rounded-full bg-slate-100 flex items-center justify-center font-black text-slate-400">
                                                        {member.fullName ? member.fullName[0] : '?'}
                                                    </div>
                                                    <div>
                                                        <div className="text-sm font-bold text-slate-900">{member.fullName}</div>
                                                        <div className="text-[11px] text-slate-400 font-medium">{member.email}</div>
                                                    </div>
                                                </div>

                                                <div className="flex flex-wrap items-center gap-4">
                                                    <Badge className={`font-black ${member.role === Role.Owner ? 'bg-rose-50 text-rose-600 border-rose-100' :
                                                        member.role === Role.Manager ? 'bg-blue-50 text-blue-600 border-blue-100' :
                                                            'bg-slate-50 text-slate-500 border-slate-100'
                                                        }`}>
                                                        {member.role ? member.role.toUpperCase() : 'UNKNOWN'}
                                                    </Badge>

                                                    <div className="flex items-center gap-1 opacity-0 group-hover:opacity-100 transition-all">
                                                        {isOwner && member.email !== currentUser?.email && (
                                                            <>
                                                                <Select onValueChange={(val: any) => handleUpdateRole(member.id, val)}>
                                                                    <SelectTrigger className="w-[120px] h-8 text-xs font-bold border-slate-200">
                                                                        <SelectValue placeholder="Change Role" />
                                                                    </SelectTrigger>
                                                                    <SelectContent className="bg-white">
                                                                        {[Role.Owner, Role.Manager, Role.Biller, Role.Storekeeper, Role.Accountant, Role.CA].map(r => (
                                                                            <SelectItem key={r} value={r} className="text-xs font-bold">{r}</SelectItem>
                                                                        ))}
                                                                    </SelectContent>
                                                                </Select>
                                                                <Button
                                                                    variant="ghost"
                                                                    size="sm"
                                                                    className="h-8 w-8 p-0 text-slate-400 hover:text-amber-600 hover:bg-amber-50"
                                                                    title="Reset Password"
                                                                    onClick={() => handleResetPassword(member.id)}
                                                                >
                                                                    <Key className="h-4 w-4" />
                                                                </Button>
                                                                <Button
                                                                    variant="ghost"
                                                                    size="sm"
                                                                    className="h-8 w-8 p-0 text-slate-400 hover:text-rose-600 hover:bg-rose-50"
                                                                    title="Remove Member"
                                                                    onClick={() => handleRemoveUser(member.id)}
                                                                >
                                                                    <Trash2 className="h-4 w-4" />
                                                                </Button>
                                                            </>
                                                        )}
                                                    </div>
                                                </div>
                                            </div>
                                        ))}
                                    </div>
                                )}
                            </CardContent>
                        </Card>
                    </div>
                </TabsContent>

                <TabsContent value="security">
                    <Card className="bg-white border-slate-200 shadow-sm max-w-2xl">
                        <CardHeader>
                            <CardTitle className="text-slate-900 font-black flex items-center">
                                <Shield className="mr-2 h-5 w-5 text-emerald-600" />
                                Security
                            </CardTitle>
                            <CardDescription className="text-slate-500">Manage authentication methods and audit logging.</CardDescription>
                        </CardHeader>
                        <CardContent className="space-y-4">
                            <div className="p-4 rounded-xl border border-slate-100 bg-slate-50/50 flex items-center justify-between">
                                <div>
                                    <div className="text-sm font-bold text-slate-900 tracking-tight">Multi-Factor Authentication</div>
                                    <div className="text-xs text-slate-500">Add an extra layer of security to your account.</div>
                                </div>
                                <Button variant="outline" className="border-slate-200 text-slate-600 font-bold bg-white">Configure</Button>
                            </div>
                            <div className="p-4 rounded-xl border border-slate-100 bg-slate-50/50 flex items-center justify-between">
                                <div>
                                    <div className="text-sm font-bold text-slate-900 tracking-tight">Active Sessions</div>
                                    <div className="text-xs text-slate-500">Monitor and manage your active system sessions.</div>
                                </div>
                                <Button variant="outline" className="border-slate-200 text-slate-600 font-bold bg-white">View Active</Button>
                            </div>
                        </CardContent>
                    </Card>
                </TabsContent>

                <TabsContent value="billing">
                    <div className="grid gap-6 md:grid-cols-2">
                        <Card className="bg-white border-slate-200 shadow-sm">
                            <CardHeader>
                                <CardTitle className="text-slate-900 font-black flex items-center">
                                    <CreditCard className="mr-2 h-5 w-5 text-amber-600" />
                                    Active Plan
                                </CardTitle>
                                <CardDescription className="text-slate-500">Your current plan and usage limits.</CardDescription>
                            </CardHeader>
                            <CardContent className="space-y-6">
                                <div className="p-6 rounded-2xl bg-slate-900 border-b-4 border-indigo-500 shadow-xl overflow-hidden relative">
                                    <div className="absolute -right-8 -top-8 w-32 h-32 bg-indigo-500/10 rounded-full blur-3xl" />
                                    <Badge className="mb-2 bg-indigo-600 text-white font-black">{billingInfo?.plan}</Badge>
                                    <h3 className="text-2xl font-black text-white uppercase tracking-tighter">
                                        {billingInfo?.plan === 'Free' ? 'Free Plan' : 'Enterprise Plan'}
                                    </h3>
                                    <p className="text-slate-400 text-[10px] font-black uppercase tracking-widest mt-1 opacity-60">Status: Active</p>
                                </div>

                                <div className="space-y-4">
                                    <div className="flex justify-between items-center text-sm">
                                        <span className="text-slate-500 font-bold uppercase tracking-tight text-[11px]">User Seats</span>
                                        <span className="text-slate-900 font-black font-mono">{billingInfo?.quotas?.maxUsers}</span>
                                    </div>
                                    <div className="flex justify-between items-center text-sm">
                                        <span className="text-slate-500 font-bold uppercase tracking-tight text-[11px]">SKU Capacity</span>
                                        <span className="text-slate-900 font-black font-mono">{billingInfo?.quotas?.maxProducts.toLocaleString()}</span>
                                    </div>
                                    <div className="flex justify-between items-center text-sm">
                                        <span className="text-slate-500 font-bold uppercase tracking-tight text-[11px]">AI Engine</span>
                                        <Badge variant="outline" className={billingInfo?.quotas?.aiEnabled ? "border-emerald-500/20 text-emerald-600 font-black bg-emerald-50" : "border-slate-100 text-slate-400"}>
                                            {billingInfo?.quotas?.aiEnabled ? 'ENABLED' : 'DISABLED'}
                                        </Badge>
                                    </div>
                                </div>
                            </CardContent>
                        </Card>

                        <Card className="bg-white border-slate-200 shadow-sm">
                            <CardHeader>
                                <CardTitle className="text-slate-900 font-black flex items-center">
                                    <Zap className="mr-2 h-5 w-5 text-amber-600" />
                                    Upgrade Plan
                                </CardTitle>
                                <CardDescription className="text-slate-500">Unlock more features and higher limits.</CardDescription>
                            </CardHeader>
                            <CardContent className="space-y-4">
                                {['Pro', 'Enterprise'].map(tier => (
                                    <div key={tier} className="p-4 rounded-xl border border-slate-100 bg-slate-50/50 flex items-center justify-between hover:border-indigo-500 transition-all group cursor-pointer hover:bg-white">
                                        <div>
                                            <div className="text-sm font-black text-slate-900 tracking-tight">{tier} Configuration</div>
                                            <div className="text-[10px] text-slate-500 font-medium font-mono uppercase tracking-widest">More features & higher limits</div>
                                        </div>
                                        <Button
                                            variant="outline"
                                            className="border-slate-200 text-slate-900 font-bold hover:bg-slate-900 hover:text-white transition-all px-6"
                                            onClick={() => handleUpgrade(tier)}
                                            disabled={billingInfo?.plan === tier}
                                        >
                                            {billingInfo?.plan === tier ? 'Active' : 'Upgrade'}
                                        </Button>
                                    </div>
                                ))}
                            </CardContent>
                        </Card>
                    </div>
                </TabsContent>

                <TabsContent value="notifications">
                    <Card className="bg-white border-slate-200 shadow-sm max-w-2xl">
                        <CardHeader>
                            <CardTitle className="text-slate-900 font-black flex items-center">
                                <Bell className="mr-2 h-5 w-5 text-rose-600" />
                                Notifications
                            </CardTitle>
                            <CardDescription className="text-slate-500">Choose how you want to receive alerts and updates.</CardDescription>
                        </CardHeader>
                        <CardContent>
                            <p className="text-slate-400 text-sm italic font-medium">Notifications are currently turned off.</p>
                        </CardContent>
                    </Card>
                </TabsContent>

                <TabsContent value="connectivity">
                    <div className="max-w-4xl">
                        <ApiKeyManager />
                    </div>
                </TabsContent>
            </Tabs>

            {/* Add User Modal */}
            <Dialog open={isAddUserOpen} onOpenChange={setIsAddUserOpen}>
                <DialogContent className="w-11/12 sm:min-w-fit sm:max-w-md bg-white">
                    <DialogHeader>
                        <DialogTitle className="text-2xl font-black text-slate-900">Onboard New Team Member</DialogTitle>
                        <DialogDescription className="text-slate-500">Add an employee to your organization and assign their functional access role.</DialogDescription>
                    </DialogHeader>
                    <form onSubmit={handleAddUser} className="space-y-4 py-4">
                        <div className="space-y-2">
                            <Label className="text-[10px] font-black uppercase text-slate-400 tracking-wider">Full Name</Label>
                            <Input
                                placeholder="e.g. Anita Biller"
                                className="bg-slate-50 border-slate-200 h-11"
                                required
                                value={newUser.fullName}
                                onChange={e => setNewUser({ ...newUser, fullName: e.target.value })}
                            />
                        </div>
                        <div className="space-y-2">
                            <Label className="text-[10px] font-black uppercase text-slate-400 tracking-wider">Professional Email</Label>
                            <Input
                                type="email"
                                placeholder="name@woodcraft.com"
                                className="bg-slate-50 border-slate-200 h-11"
                                required
                                value={newUser.email}
                                onChange={e => setNewUser({ ...newUser, email: e.target.value })}
                            />
                        </div>
                        <div className="space-y-2">
                            <Label className="text-[10px] font-black uppercase text-slate-400 tracking-wider">Role</Label>
                            <Select value={newUser.role} onValueChange={(val: any) => setNewUser({ ...newUser, role: val })}>
                                <SelectTrigger className="bg-slate-50 border-slate-200 h-11 font-bold">
                                    <SelectValue />
                                </SelectTrigger>
                                <SelectContent className="bg-white">
                                    <SelectItem value={Role.Owner} className="font-bold">Owner (Full System Access)</SelectItem>
                                    <SelectItem value={Role.Manager} className="font-bold">Manager (Operational Admin)</SelectItem>
                                    <SelectItem value={Role.Biller} className="font-bold">Biller (Checkout & Sales)</SelectItem>
                                    <SelectItem value={Role.Storekeeper} className="font-bold">Storekeeper (Stock & Logistics)</SelectItem>
                                    <SelectItem value={Role.Accountant} className="font-bold">Accountant (Finance & Audit)</SelectItem>
                                </SelectContent>
                            </Select>
                        </div>
                        <DialogFooter className="pt-4">
                            <Button type="button" variant="ghost" className="font-bold" onClick={() => setIsAddUserOpen(false)}>Cancel</Button>
                            <Button type="submit" className="bg-slate-900 hover:bg-black font-black px-8">Add Member</Button>
                        </DialogFooter>
                    </form>
                </DialogContent>
            </Dialog>

            {/* Password Reset Modal */}
            <Dialog open={isResetOpen} onOpenChange={setIsResetOpen}>
                <DialogContent className="w-11/12 sm:min-w-fit sm:max-w-sm bg-white">
                    <DialogHeader>
                        <div className="h-12 w-12 rounded-full bg-amber-50 flex items-center justify-center mb-2 mx-auto">
                            <Key className="h-6 w-6 text-amber-600" />
                        </div>
                        <DialogTitle className="text-xl font-black text-slate-900 text-center">Temporary Password</DialogTitle>
                        <DialogDescription className="text-center text-slate-500">Share this temporary password with the employee. They should change it after logging in.</DialogDescription>
                    </DialogHeader>
                    <div className="py-6 flex flex-col items-center justify-center gap-4">
                        <div className="text-3xl font-black font-mono tracking-widest bg-slate-100 p-4 rounded-xl border-b-2 border-slate-200 w-full text-center text-slate-900">
                            {tempPassword}
                        </div>
                        <Button
                            className="w-full font-bold bg-slate-900"
                            onClick={async () => {
                                await navigator.clipboard.writeText(tempPassword || '');
                                toast.success("Key copied to clipboard");
                            }}
                        >
                            Copy to Clipboard
                        </Button>
                    </div>
                </DialogContent>
            </Dialog>
        </div>
    );
}

"use client";

import { useState } from "react";
import { api } from "@/lib/api";
import Link from "next/link";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Wand2, Plus, Trash2, Save, Layers, Database, PanelsTopLeft, GitBranch, ShieldCheck, Send } from "lucide-react";
import { toast } from "sonner";

export default function StudioPage() {
    const [appName, setAppName] = useState("custom_app");
    const [modelName, setModelName] = useState("");
    const [modelLabel, setModelLabel] = useState("");
    const [fields, setFields] = useState<any[]>([
        { name: "name", label: "Display Name", type: "Char", required: true }
    ]);

    const addField = () => {
        setFields([...fields, { name: "", label: "", type: "Char", required: false }]);
    };

    const updateField = (index: number, key: string, value: any) => {
        const newFields = [...fields];
        newFields[index][key] = value;
        setFields(newFields);
    };

    const removeField = (index: number) => {
        setFields(fields.filter((_, i) => i !== index));
    };

    const handleGenerate = async () => {
        try {
            if (!modelName || !modelLabel) {
                toast.error("Model technical name and label are required");
                return;
            }

            const payload = {
                appName,
                name: modelName,
                label: modelLabel,
                fields: fields
            };

            await api.post("system/studio/models", payload);
            toast.success(`Object [${modelLabel}] created in system!`);

            // Reset
            setModelName("");
            setModelLabel("");
            setFields([{ name: "name", label: "Display Name", type: "Char", required: true }]);
        } catch (err: any) {
            toast.error(err.response?.data?.message || "Creation failed");
        }
    };

    return (
        <div className="flex-1 space-y-6 md:space-y-8 p-4 md:p-8 pt-2 md:pt-6">
            <div className="flex flex-col lg:flex-row lg:items-center justify-between gap-4 lg:gap-0">
                <div>
                    <h2 className="text-3xl font-black tracking-tight text-slate-900 flex items-center">
                        <Wand2 className="mr-3 h-8 w-8 text-fuchsia-600" />
                        Klypso Logic Studio
                    </h2>
                    <p className="text-slate-500 mt-1 font-medium">Design custom business objects and automated workflows without code.</p>
                </div>
                <div className="flex flex-wrap w-full md:w-auto gap-2 bg-white p-1 rounded-xl border border-slate-200 shadow-sm">
                    <Button variant="ghost" className="flex-1 md:flex-none bg-fuchsia-50 text-fuchsia-700 font-bold rounded-lg px-6">
                        <Database className="mr-2 h-4 w-4" /> Object Builder
                    </Button>
                    <Link href="/studio/workflows" className="flex-1 md:flex-none">
                        <Button variant="ghost" className="w-full text-slate-500 hover:text-slate-900 hover:bg-slate-50 font-bold rounded-lg px-6">
                            <GitBranch className="mr-2 h-4 w-4" /> Workflows
                        </Button>
                    </Link>
                </div>
            </div>

            <div className="grid gap-8 lg:grid-cols-3">
                <Card className="bg-white border-slate-200 shadow-xl shadow-slate-200/40 rounded-3xl lg:col-span-1 overflow-hidden">
                    <CardHeader className="bg-slate-50 border-b border-slate-100">
                        <CardTitle className="text-slate-900 flex items-center font-black text-lg">
                            <PanelsTopLeft className="mr-2 h-4 w-4 text-fuchsia-600" />
                            App Settings
                        </CardTitle>
                        <CardDescription className="text-slate-500 font-bold uppercase text-[10px] tracking-widest">Select app and define object details.</CardDescription>
                    </CardHeader>
                    <CardContent className="space-y-4 pt-6">
                        <div className="space-y-2">
                            <Label className="text-slate-500 font-bold uppercase text-[10px] tracking-widest">App Name</Label>
                            <Input
                                value={appName}
                                onChange={(e) => setAppName(e.target.value)}
                                className="bg-slate-50 border-slate-200 text-slate-900 font-semibold"
                                placeholder="e.g. sales"
                            />
                        </div>
                        <div className="space-y-2">
                            <Label className="text-slate-500 font-bold uppercase text-[10px] tracking-widest">System Name (e.g. vehicle_log)</Label>
                            <Input
                                value={modelName}
                                onChange={(e) => setModelName(e.target.value)}
                                className="bg-slate-50 border-slate-200 text-slate-900 font-semibold"
                                placeholder="e.g. custom_vehicle"
                            />
                        </div>
                        <div className="space-y-2">
                            <Label className="text-slate-500 font-bold uppercase text-[10px] tracking-widest">Display Label</Label>
                            <Input
                                value={modelLabel}
                                onChange={(e) => setModelLabel(e.target.value)}
                                className="bg-slate-50 border-slate-200 text-slate-900 font-semibold"
                                placeholder="e.g. Company Vehicle"
                            />
                        </div>
                    </CardContent>
                </Card>

                <Card className="bg-white border-slate-200 shadow-xl shadow-slate-200/40 rounded-3xl lg:col-span-2 overflow-hidden">
                    <CardHeader className="flex flex-row items-center justify-between bg-slate-50 border-b border-slate-100">
                        <div>
                            <CardTitle className="text-slate-900 flex items-center font-black text-lg">
                                <Layers className="mr-2 h-4 w-4 text-fuchsia-600" />
                                Field Definitions
                            </CardTitle>
                            <CardDescription className="text-slate-500 font-bold uppercase text-[10px] tracking-widest">Define the fields for this object.</CardDescription>
                        </div>
                        <Button onClick={addField} variant="outline" className="border-fuchsia-200 text-fuchsia-600 bg-fuchsia-50 hover:bg-fuchsia-100 font-bold rounded-xl">
                            <Plus className="mr-2 h-4 w-4" /> Add Field
                        </Button>
                    </CardHeader>
                    <CardContent className="space-y-6 pt-6">
                        {fields.map((field, index) => (
                            <div key={index} className="flex flex-col sm:flex-row flex-wrap gap-4 items-start sm:items-end p-4 rounded-xl bg-slate-50/50 border border-slate-100 group relative transition-all hover:bg-white hover:shadow-md">
                                <div className="flex-1 w-full sm:w-auto space-y-2">
                                    <Label className="text-[10px] text-slate-400 font-black uppercase tracking-widest">System Name</Label>
                                    <Input
                                        value={field.name}
                                        onChange={(e) => updateField(index, 'name', e.target.value)}
                                        className="bg-white border-slate-200 text-slate-900 h-9 text-sm font-semibold"
                                    />
                                </div>
                                <div className="flex-1 w-full sm:w-auto space-y-2">
                                    <Label className="text-[10px] text-slate-400 font-black uppercase tracking-widest">Label</Label>
                                    <Input
                                        value={field.label}
                                        onChange={(e) => updateField(index, 'label', e.target.value)}
                                        className="bg-white border-slate-200 text-slate-900 h-9 text-sm font-semibold"
                                    />
                                </div>
                                <div className="w-full sm:w-[150px] space-y-2">
                                    <Label className="text-[10px] text-slate-400 font-black uppercase tracking-widest">Field Type</Label>
                                    <Select
                                        value={field.type}
                                        onValueChange={(val) => updateField(index, 'type', val)}
                                    >
                                        <SelectTrigger className="bg-white border-slate-200 text-slate-900 h-9 text-sm font-bold">
                                            <SelectValue />
                                        </SelectTrigger>
                                        <SelectContent className="bg-white border-slate-200 text-slate-900">
                                            <SelectItem value="Char">Char (Text)</SelectItem>
                                            <SelectItem value="Text">Text (Long)</SelectItem>
                                            <SelectItem value="Integer">Integer</SelectItem>
                                            <SelectItem value="Float">Float / Decimal</SelectItem>
                                            <SelectItem value="Boolean">Boolean</SelectItem>
                                            <SelectItem value="Date">Date</SelectItem>
                                            <SelectItem value="Many2One">Relation (Look-up)</SelectItem>
                                        </SelectContent>
                                    </Select>
                                </div>
                                <Button
                                    variant="ghost"
                                    size="icon"
                                    className="h-9 w-9 text-slate-400 hover:text-rose-600 hover:bg-rose-50 rounded-xl transition-all"
                                    onClick={() => removeField(index)}
                                >
                                    <Trash2 className="h-4 w-4" />
                                </Button>
                            </div>
                        ))}

                        <div className="pt-6 border-t border-slate-100 flex justify-end">
                            <Button
                                onClick={handleGenerate}
                                className="bg-fuchsia-600 hover:bg-fuchsia-700 text-white font-bold px-8 rounded-xl shadow-lg shadow-fuchsia-500/20 py-6"
                            >
                                <Database className="mr-2 h-5 w-5" /> Create Custom Object
                            </Button>
                        </div>
                    </CardContent>
                </Card>

                <Card className="bg-white border-slate-200 shadow-xl shadow-slate-200/40 rounded-3xl lg:col-span-1 overflow-hidden">
                    <CardHeader className="bg-slate-50 border-b border-slate-100">
                        <CardTitle className="text-slate-900 flex items-center font-black text-lg">
                            <ShieldCheck className="mr-2 h-4 w-4 text-emerald-500" />
                            Permissions
                        </CardTitle>
                        <CardDescription className="text-slate-500 font-bold uppercase text-[10px] tracking-widest">Grant permissions to system roles.</CardDescription>
                    </CardHeader>
                    <CardContent className="space-y-4 pt-6">
                        {["Admin", "Manager", "Employee", "Viewer"].map(role => (
                            <div key={role} className="flex items-center justify-between p-3 rounded-xl bg-slate-50 border border-slate-100">
                                <span className="text-xs text-slate-600 font-bold uppercase tracking-wide">{role}</span>
                                <div className="flex gap-1">
                                    <div className="h-6 w-6 rounded-lg bg-emerald-100 text-emerald-600 flex items-center justify-center text-[10px] font-black border border-emerald-200">R</div>
                                    <div className="h-6 w-6 rounded-lg bg-emerald-100 text-emerald-600 flex items-center justify-center text-[10px] font-black border border-emerald-200">W</div>
                                </div>
                            </div>
                        ))}
                    </CardContent>
                </Card>
            </div>
        </div>
    );
}

"use client";

import { useEffect, useState } from "react";
import { api } from "@/lib/api";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import {
    GitBranch,
    Plus,
    Save,
    ArrowRight,
    Zap,
    Play,
    CheckCircle2,
    Circle,
    Activity,
    Settings2,
    Trash2
} from "lucide-react";
import { toast } from "sonner";
import { Badge } from "@/components/ui/badge";

export default function WorkflowBuilder() {
    const [workflows, setWorkflows] = useState<any[]>([]);
    const [loading, setLoading] = useState(false);
    const [selectedWorkflow, setSelectedWorkflow] = useState<any>(null);
    const [modelName, setModelName] = useState("sale.order");
    const [workflowName, setWorkflowName] = useState("");

    const [nodes, setNodes] = useState<any[]>([]);
    const [transitions, setTransitions] = useState<any[]>([]);

    const syncWorkflows = async (showLoading = false) => {
        try {
            if (showLoading) setLoading(true);
            const res = await api.get(`/system/workflows/${modelName}`);
            setWorkflows(res.data);
        } catch (err) {
            console.error("Workflows Sync Failure:", err);
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        syncWorkflows(true);
        const interval = setInterval(() => syncWorkflows(false), 30000);
        return () => clearInterval(interval);
    }, [modelName]);

    const handleCreateWorkflow = async () => {
        try {
            if (!workflowName) return toast.error("Name required");
            const res = await api.post("system/workflows", { name: workflowName, modelName });
            toast.success("Workflow stream created");
            setWorkflowName("");
            syncWorkflows(true);
            setSelectedWorkflow(res.data);
        } catch (err) {
            toast.error("Initialization failed");
        }
    };

    const addNode = async () => {
        if (!selectedWorkflow) return;
        try {
            const res = await api.post(`/system/workflows/${selectedWorkflow.id}/nodes`, {
                name: "New State",
                type: "state",
                config: {}
            });
            setSelectedWorkflow({
                ...selectedWorkflow,
                nodes: [...(selectedWorkflow.nodes || []), res.data]
            });
            toast.success("State node added to graph");
        } catch (err) {
            toast.error("Node creation failed");
        }
    };

    return (
