"use client";

import { useState, useEffect, useCallback } from "react";
import { api } from "@/lib/api";
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import {
    ShieldCheck,
    ShieldAlert,
    Lock,
    Unlock,
    CheckCircle2,
    AlertTriangle,
    RefreshCw,
    FileSearch,
    ChevronRight
} from "lucide-react";
import { toast } from "sonner";
import { useUX } from "@/components/providers/ux-provider";

interface RiskFlag {
    type: string;
    severity: 'BLOCKER' | 'WARNING';
    count: number;
}

interface AuditorData {
    isLocked: boolean;
    confidenceScore: number;
    hsnCoverage: number;
    status: string;
    riskFlags: RiskFlag[];
    errors: string[];
}

export function AuditorDashboard() {
    const { setUILocked, showConfirm } = useUX();
    const [data, setData] = useState<AuditorData | null>(null);
    const [loading, setLoading] = useState(true);
    const [month, setMonth] = useState(new Date().getMonth() + 1);
    const [year, setYear] = useState(new Date().getFullYear());

    const months = [
        "January", "February", "March", "April", "May", "June",
        "July", "August", "September", "October", "November", "December"
    ];

    const years = Array.from({ length: 5 }, (_, i) => new Date().getFullYear() - i);

    const fetchDashboard = useCallback(async () => {
        try {
            setLoading(true);
            const res = await api.get(`/accounting/auditor/dashboard?month=${month}&year=${year}`);
            setData(res.data);
        } catch {
            toast.error("Failed to load auditor data");
        } finally {
            setLoading(false);
        }
    }, [month, year]);

    useEffect(() => {
        fetchDashboard();
    }, [fetchDashboard]);

    const toggleLock = useCallback(() => {
        const action = data?.isLocked ? 'UNLOCK' : 'LOCK';

        showConfirm({
            title: `${action} Period`,
            description: `Are you sure you want to ${action.toLowerCase()} the books for ${month}/${year}? ${action === 'LOCK' ? 'This will prevent further modifications.' : 'This will allow edits but mark the period as reopened.'}`,
            confirmText: action,
            onConfirm: async () => {
                try {
                    setUILocked(true);
                    const endpoint = action === 'LOCK' ? "/accounting/auditor/lock" : "/accounting/auditor/unlock";
                    await api.post(endpoint, {
                        month,
                        year,
                        reason: action === 'UNLOCK' ? 'Administrative Reopening' : undefined
                    });
                    toast.success(`Period ${action.toLowerCase()}ed successfully`);
                    fetchDashboard();
                } catch (err: any) {
                    toast.error(err.message || `Failed to ${action.toLowerCase()} period`);
                } finally {
                    setUILocked(false);
                }
            }
        });
    }, [data, month, year, showConfirm, setUILocked, fetchDashboard]);

    if (loading) return <div className="p-12 text-center font-bold text-slate-400">Auditing books...</div>;

    return (
        <div className="space-y-6">
            {/* Date Selectors */}
            <div className="flex flex-col md:flex-row gap-4 items-end mb-4 bg-white p-6 rounded-3xl border border-slate-100 shadow-sm">
                <div className="space-y-2 flex-grow">
                    <label className="text-[10px] font-black uppercase tracking-widest text-slate-400">Review Period</label>
                    <div className="flex gap-4">
                        <select
                            value={month}
                            onChange={(e) => setMonth(parseInt(e.target.value))}
                            className="bg-slate-50 border border-slate-200 rounded-xl px-4 py-2 font-bold text-slate-700 outline-none focus:ring-2 focus:ring-amber-500/20"
                        >
                            {months.map((m, i) => (
                                <option key={i} value={i + 1}>{m}</option>
                            ))}
                        </select>
                        <select
                            value={year}
                            onChange={(e) => setYear(parseInt(e.target.value))}
                            className="bg-slate-50 border border-slate-200 rounded-xl px-4 py-2 font-bold text-slate-700 outline-none focus:ring-2 focus:ring-amber-500/20"
                        >
                            {years.map(y => (
                                <option key={y} value={y}>{y}</option>
                            ))}
                        </select>
                    </div>
                </div>
                <Button
                    variant="outline"
                    onClick={fetchDashboard}
                    disabled={loading}
                    className="rounded-xl border-slate-200 font-bold gap-2"
                >
                    <RefreshCw className={`h-4 w-4 ${loading ? 'animate-spin' : ''}`} />
                    Refresh Audit
                </Button>
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
                {/* Verification Status */}
                <Card className="lg:col-span-2 bg-white border-slate-200 shadow-xl shadow-slate-200/40 rounded-3xl overflow-hidden border-none">
                    <CardHeader className={`${data?.isLocked ? 'bg-slate-900 text-white' : 'bg-amber-600 text-white'} p-8 transition-colors`}>
                        <div className="flex justify-between items-start">
                            <div className="space-y-1">
                                <CardTitle className="text-2xl font-black flex items-center gap-3">
                                    {data?.isLocked ? <Lock className="h-6 w-6" /> : <Unlock className="h-6 w-6" />}
                                    {data?.isLocked ? 'Books Locked' : 'Books Open'}
                                </CardTitle>
                                <CardDescription className="text-slate-100/70 font-bold">
                                    Period: {month}/{year} ÔÇó Security Mode: GST Compliant
                                </CardDescription>
                            </div>
                            <Button
                                onClick={toggleLock}
                                className={`${data?.isLocked ? 'bg-white/10 hover:bg-white/20' : 'bg-white text-amber-600 hover:bg-slate-50'} rounded-2xl font-black px-6`}
                            >
                                {data?.isLocked ? 'Unlock Books' : 'Lock & Reconcile'}
                            </Button>
                        </div>
                    </CardHeader>
                    <CardContent className="p-8 space-y-8">
                        <div className="grid grid-cols-2 md:grid-cols-4 gap-6">
                            {[
                                { label: 'Tally Readiness', val: `${data?.confidenceScore}%`, color: 'text-emerald-500', icon: ShieldCheck },
                                { label: 'HSN Coverage', val: `${data?.hsnCoverage}%`, color: 'text-blue-500', icon: FileSearch },
                                { label: 'Voucher Status', val: data?.status || 'PENDING', color: data?.status === 'CLEAN' ? 'text-emerald-500' : 'text-amber-500', icon: CheckCircle2 },
                                { label: 'Critical Risks', val: data?.riskFlags?.length || 0, color: (data?.riskFlags?.length ?? 0) > 0 ? 'text-rose-500' : 'text-slate-400', icon: ShieldAlert },
                            ].map((s, i) => (
                                <div key={i} className="space-y-1">
                                    <div className="flex items-center gap-2 text-[10px] font-black text-slate-400 uppercase tracking-widest">
                                        <s.icon className="h-3 w-3" /> {s.label}
                                    </div>
                                    <div className={`text-2xl font-black ${s.color}`}>{s.val}</div>
                                </div>
                            ))}
                        </div>

                        <div className="space-y-4">
                            <h3 className="text-sm font-black text-slate-900 uppercase tracking-tight flex items-center gap-2">
                                <AlertTriangle className="h-4 w-4 text-amber-500" /> Validation Messages
                            </h3>
                            <div className="space-y-3">
                                {data?.errors?.map((err, i) => (
                                    <div key={i} className="flex items-start gap-4 p-4 rounded-2xl bg-rose-50 border border-rose-100 text-rose-700 text-sm font-bold">
                                        <ShieldAlert className="h-5 w-5 mt-0.5" />
                                        {err}
                                    </div>
                                ))}
                                {data?.errors?.length === 0 && (
                                    <div className="flex items-start gap-4 p-6 rounded-3xl bg-emerald-50 border border-emerald-100 text-emerald-700 text-sm font-bold">
                                        <CheckCircle2 className="h-5 w-5 mt-0.5" />
                                        All vouchers are balanced and ready for Tally export. No drift detected.
                                    </div>
                                )}
                            </div>
                        </div>
                    </CardContent>
                </Card>

                {/* Audit Sidecard */}
                <Card className="bg-white border-slate-200 shadow-xl shadow-slate-200/40 rounded-3xl overflow-hidden border-none">
                    <CardHeader className="p-8 border-b border-slate-100">
                        <CardTitle className="text-xl font-black">Risk Parameters</CardTitle>
                        <CardDescription className="font-bold">Automated audit checkpoints</CardDescription>
                    </CardHeader>
                    <CardContent className="p-8 space-y-6">
                        {data?.riskFlags?.map((flag, i) => (
                            <div key={i} className="flex justify-between items-center group cursor-help">
                                <div className="flex items-center gap-3">
                                    <div className={`h-8 w-8 rounded-lg flex items-center justify-center ${flag.severity === 'BLOCKER' ? 'bg-rose-50 text-rose-500' : 'bg-amber-50 text-amber-500'}`}>
                                        <AlertTriangle className="h-4 w-4" />
                                    </div>
                                    <span className="text-sm font-bold text-slate-700 transition-colors group-hover:text-slate-900">{flag.type}</span>
                                </div>
                                <Badge variant="outline" className={`${flag.severity === 'BLOCKER' ? 'border-rose-200 text-rose-500 bg-rose-50' : 'border-amber-200 text-amber-500 bg-amber-50'} font-black text-[10px]`}>
                                    {flag.count} {flag.severity}
                                </Badge>
                            </div>
                        ))}
                        {!data?.riskFlags?.length && (
                            <div className="text-center py-12">
                                <ShieldCheck className="mx-auto h-12 w-12 text-emerald-100 mb-4" />
                                <p className="text-sm font-bold text-slate-400">Zero Critical Risks</p>
                            </div>
                        )}

                        <div className="pt-6 border-t border-slate-100">
                            <Button variant="ghost" className="w-full justify-between hover:bg-slate-50 rounded-2xl p-4 font-bold text-slate-600 transition-all group">
                                Download Audit Log
                                <ChevronRight className="h-4 w-4 transition-transform group-hover:translate-x-1" />
                            </Button>
                        </div>
                    </CardContent>
                </Card>
            </div>
        </div>
    );
}

"use client";

import { useState, useCallback } from "react";
import { Dialog, DialogContent, DialogDescription, DialogFooter, DialogHeader, DialogTitle } from "@/components/ui/dialog";
import { Button } from "@/components/ui/button";
import { Label } from "@/components/ui/label";
import { Input } from "@/components/ui/input";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { api } from "@/lib/api";
import { toast } from "sonner";

interface CreateAccountDialogProps {
    open: boolean;
    onOpenChange: (open: boolean) => void;
    onSuccess?: () => void;
}

type AccountType = "Asset" | "Liability" | "Equity" | "Revenue" | "Expense";

export function CreateAccountDialog({ open, onOpenChange, onSuccess }: CreateAccountDialogProps) {
    const [loading, setLoading] = useState(false);
    const [formData, setFormData] = useState({
        name: "",
        code: "",
        type: "Asset" as AccountType,
    });

    const handleSubmit = useCallback(async (e: React.FormEvent) => {
        e.preventDefault();

        const name = formData.name.trim();
        const code = formData.code.trim();

        if (!name || !code || !formData.type) {
            toast.error("Please fill in all required fields (no whitespace only)");
            return;
        }

        setLoading(true);
        try {
            await api.post("accounting/accounts", { ...formData, name, code });
            toast.success(`Account "${formData.name}" created successfully`);
            setFormData({ name: "", code: "", type: "Asset" });
            onOpenChange(false);
            onSuccess?.();
        } catch (error: any) {
            toast.error(error.response?.data?.message || "Failed to create account");
        } finally {
            setLoading(false);
        }
    }, [formData, onOpenChange, onSuccess]);

    return (
        <Dialog open={open} onOpenChange={onOpenChange}>
            <DialogContent className="w-11/12 sm:min-w-fit sm:max-w-[500px]">
                <DialogHeader>
                    <DialogTitle className="text-2xl font-bold">Create New Account</DialogTitle>
                    <DialogDescription>
                        Add a new account to organize your finances. Common examples: Petty Cash, Office Rent, Salary Expense, Sales Revenue.
                    </DialogDescription>
                </DialogHeader>
                <form onSubmit={handleSubmit}>
                    <div className="grid gap-6 py-4">
                        <div className="grid gap-2">
                            <Label htmlFor="name" className="font-semibold">
                                Account Name <span className="text-red-500">*</span>
                            </Label>
                            <Input
                                id="name"
                                placeholder="e.g., Petty Cash, Office Supplies"
                                value={formData.name}
                                onChange={(e) => setFormData({ ...formData, name: e.target.value })}
                                required
                                className="h-11"
                            />
                        </div>
                        <div className="grid gap-2">
                            <Label htmlFor="code" className="font-semibold">
                                Account Code <span className="text-red-500">*</span>
                            </Label>
                            <Input
                                id="code"
                                placeholder="e.g., 1003, 5104"
                                value={formData.code}
                                onChange={(e) => setFormData({ ...formData, code: e.target.value })}
                                required
                                className="h-11"
                            />
                            <p className="text-xs text-slate-500">
                                A unique code to identify this account
                            </p>
                        </div>
                        <div className="grid gap-2">
                            <Label htmlFor="type" className="font-semibold">
                                Account Type <span className="text-red-500">*</span>
                            </Label>
                            <Select
                                value={formData.type}
                                onValueChange={(value: AccountType) => setFormData({ ...formData, type: value })}
                            >
                                <SelectTrigger className="h-11">
                                    <SelectValue placeholder="Select account type" />
                                </SelectTrigger>
                                <SelectContent>
                                    <SelectItem value="Asset">Asset</SelectItem>
                                    <SelectItem value="Liability">Liability</SelectItem>
                                    <SelectItem value="Equity">Equity</SelectItem>
                                    <SelectItem value="Revenue">Revenue</SelectItem>
                                    <SelectItem value="Expense">Expense</SelectItem>
                                </SelectContent>
                            </Select>
                        </div>
                    </div>
                    <DialogFooter>
                        <Button
                            type="button"
                            variant="outline"
                            onClick={() => onOpenChange(false)}
                            disabled={loading}
                        >
                            Cancel
                        </Button>
                        <Button type="submit" disabled={loading} className="bg-amber-500 hover:bg-amber-600">
                            {loading ? "Creating..." : "Create Account"}
                        </Button>
                    </DialogFooter>
                </form>
            </DialogContent>
        </Dialog>
    );
}

"use client";

import { useState, useEffect, useCallback, useRef } from "react";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Dialog, DialogContent, DialogDescription, DialogFooter, DialogHeader, DialogTitle } from "@/components/ui/dialog";
import { Label } from "@/components/ui/label";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from "@/components/ui/table";
import { api } from "@/lib/api";
import { toast } from "sonner";
import { Loader2, Plus, Trash2 } from "lucide-react";
import { useUX } from "@/components/providers/ux-provider";

interface CreateInvoiceDialogProps {
    isOpen: boolean;
    onClose: () => void;
    onSuccess: () => void;
}

interface Customer {
    id: string;
    firstName: string;
    lastName: string;
    company: string;
    email: string;
}

interface Product {
    id: string;
    name: string;
    sku: string;
    price: string | number;
    gstRate?: number;
    hsnCode?: string;
    category?: string;
}

interface InvoiceItem {
    productId: string;
    quantity: number;
    price: number;
    gstRate: number;
    hsnCode: string;
    total: number;
}

export function CreateInvoiceDialog({ isOpen, onClose, onSuccess }: CreateInvoiceDialogProps) {
    const [customers, setCustomers] = useState<Customer[]>([]);
    const [products, setProducts] = useState<Product[]>([]);
    const [loading, setLoading] = useState(false);
    const { setUILocked, showConfirm } = useUX();

    // Form State
    const [customerId, setCustomerId] = useState("");
    const [dueDate, setDueDate] = useState("");
    const [invoiceDate, setInvoiceDate] = useState(new Date().toISOString().split('T')[0]);
    const [items, setItems] = useState<InvoiceItem[]>([]);
    const [isInitialLoad, setIsInitialLoad] = useState(true);
    const [productFilter, setProductFilter] = useState("");
    const searchRef = useRef<HTMLInputElement>(null);

    const handleAddItem = useCallback(() => {
        setItems(prev => [...prev, { productId: "", quantity: 1, price: 0, gstRate: 0, hsnCode: "", total: 0 }]);
    }, []);

    const executeSubmit = useCallback(async () => {
        setLoading(true);
        setUILocked(true);
        try {
            await api.post("accounting/invoices", {
                customerId,
                issueDate: invoiceDate,
                dueDate: dueDate || invoiceDate,
                items: items.map(i => ({
                    productId: i.productId,
                    quantity: Number(i.quantity),
                    price: Number(i.price)
                }))
            });

            toast.success("Invoice issued successfully");
            localStorage.removeItem("invoice_draft");
            setItems([{ productId: "", quantity: 1, price: 0, gstRate: 0, hsnCode: "", total: 0 }]);
            setCustomerId("");
            onSuccess();
            onClose();
        } catch (err: any) {
            toast.error(err.response?.data?.message || "Failed to issue invoice");
        } finally {
            setLoading(false);
            setUILocked(false);
        }
    }, [customerId, invoiceDate, dueDate, items, onSuccess, onClose, setUILocked]);

    const handleSubmit = useCallback(() => {
        if (loading) return;

        if (!customerId || !customerId.trim()) {
            toast.error("Please select a valid customer");
            return;
        }
        if (items.some(i => !i.productId)) {
            toast.error("Please select products for all lines");
            return;
        }

        const customerName = customers.find(c => c.id === customerId)?.company || "Selected Customer";

        const subtotalValue = items.reduce((sum, item) => sum + (item.price * item.quantity), 0);
        const totalTaxValue = items.reduce((sum, item) => sum + ((item.price * item.quantity) * (item.gstRate / 100)), 0);
        const grandTotalValue = subtotalValue + totalTaxValue;

        showConfirm({
            title: "Confirm Tax Invoice Posting",
            description: `You are about to post a compliant tax invoice for Ôé╣${grandTotalValue.toLocaleString('en-IN')} to ${customerName}. This action will affect your accounting ledgers and cannot be deleted once saved (only cancelled).`,
            confirmText: "Issue & Post",
            cancelText: "Review",
            onConfirm: async () => {
                await executeSubmit();
            }
        });
    }, [loading, customerId, items, customers, showConfirm, executeSubmit]);

    useEffect(() => {
        const handleKeyDown = (e: KeyboardEvent) => {
            if (!isOpen) return;
            if (e.key === "Escape" && isOpen && !loading) {
                onClose();
                return;
            }
            if (e.altKey && e.key === "n") {
                e.preventDefault();
                handleAddItem();
            }
            if (e.ctrlKey && e.key === "Enter") {
                e.preventDefault();
                handleSubmit();
            }
        };
        window.addEventListener("keydown", handleKeyDown);
        return () => window.removeEventListener("keydown", handleKeyDown);
    }, [isOpen, loading, onClose, handleAddItem, handleSubmit]);

    useEffect(() => {
        if (isOpen) {
            setTimeout(() => searchRef.current?.focus(), 150);
        }
    }, [isOpen]);

    // Draft Persistence Engine
    useEffect(() => {
        if (typeof window !== "undefined" && isOpen && isInitialLoad) {
            const draft = localStorage.getItem("invoice_draft");
            if (draft) {
                try {
                    const parsed = JSON.parse(draft);
                    setCustomerId(parsed.customerId || "");
                    setInvoiceDate(parsed.invoiceDate || new Date().toISOString().split('T')[0]);
                    setDueDate(parsed.dueDate || "");
                    setItems(parsed.items || [{ productId: "", quantity: 1, price: 0, gstRate: 0, hsnCode: "", total: 0 }]);
                } catch {
                    setItems([{ productId: "", quantity: 1, price: 0, gstRate: 0, hsnCode: "", total: 0 }]);
                }
            } else {
                setItems([{ productId: "", quantity: 1, price: 0, gstRate: 0, hsnCode: "", total: 0 }]);
            }
            setIsInitialLoad(false);
        }
    }, [isOpen, isInitialLoad]);

    useEffect(() => {
        if (!isInitialLoad && isOpen) {
            localStorage.setItem("invoice_draft", JSON.stringify({ customerId, invoiceDate, dueDate, items }));
        }
    }, [customerId, invoiceDate, dueDate, items, isOpen, isInitialLoad]);

    const fetchData = useCallback(async () => {
        try {
            const [custRes, prodRes] = await Promise.all([
                api.get("crm/customers"),
                api.get("inventory/products")
            ]);

            const rawCustomers = custRes.data?.data ?? custRes.data;
            const rawProducts = prodRes.data?.data ?? prodRes.data;
            setCustomers(Array.isArray(rawCustomers) ? rawCustomers : []);
            setProducts(Array.isArray(rawProducts) ? rawProducts : []);
        } catch {
            toast.error("Failed to load resources");
            setCustomers([]);
            setProducts([]);
        }
    }, []);

    useEffect(() => {
        if (isOpen) {
            fetchData();
        }
    }, [isOpen, fetchData]);

    const handleRemoveItem = (index: number) => {
        const newItems = [...items];
        newItems.splice(index, 1);
        setItems(newItems);
    };

    const handleProductChange = (index: number, productId: string) => {
        const product = products.find(p => p.id === productId);
        if (!product) return;

        const newItems = [...items];
        newItems[index] = {
            ...newItems[index],
            productId,
            price: Number(product.price),
            gstRate: Number(product.gstRate || 0),
            hsnCode: product.hsnCode || "",
            total: Number(product.price) * newItems[index].quantity
        };
        setItems(newItems);
    };

    const handleQuantityChange = (index: number, qty: number) => {
        const newItems = [...items];
        newItems[index].quantity = qty;
        newItems[index].total = newItems[index].price * qty;
        setItems(newItems);
    };

    const subtotal = items.reduce((sum, item) => sum + (item.price * item.quantity), 0);
    const totalTax = items.reduce((sum, item) => sum + ((item.price * item.quantity) * (item.gstRate / 100)), 0);
    const grandTotal = subtotal + totalTax;

    return (
        <Dialog open={isOpen} onOpenChange={onClose}>
            <DialogContent className="w-11/12 sm:min-w-fit sm:max-w-[800px] bg-[#09090b] text-white border-white/10 max-h-[90vh] overflow-y-auto">
                <DialogHeader>
                    <DialogTitle>Issue New Invoice</DialogTitle>
                    <DialogDescription className="text-zinc-400">Create a compliant tax invoice for your customer.</DialogDescription>
                </DialogHeader>

                <div className="grid grid-cols-2 gap-6 py-4">
                    <div className="space-y-2">
                        <Label>Customer</Label>
                        <Select value={customerId} onValueChange={setCustomerId}>
                            <SelectTrigger className="bg-white/5 border-white/10 text-white">
                                <SelectValue placeholder="Select Customer" />
                            </SelectTrigger>
                            <SelectContent className="bg-zinc-900 border-white/10 text-white">
                                {customers.map(c => (
                                    <SelectItem key={c.id} value={c.id}>{c.firstName} {c.lastName} ({c.company})</SelectItem>
                                ))}
                            </SelectContent>
                        </Select>
                        <Button
                            variant="link"
                            className="text-[10px] text-amber-500 h-auto p-0 hover:text-amber-400"
                            onClick={() => {
                                const walkIn = customers.find(c => c.email === 'walkin@system.local');
                                if (walkIn) setCustomerId(walkIn.id);
                            }}
                        >
                            Quick Counter Sale (Walk-In)
                        </Button>
                    </div>
                    <div className="grid grid-cols-2 gap-4">
                        <div className="space-y-2">
                            <Label>Invoice Date</Label>
                            <Input type="date" className="bg-white/5 border-white/10 text-white" value={invoiceDate} onChange={e => setInvoiceDate(e.target.value)} />
                        </div>
                        <div className="space-y-2">
                            <Label>Due Date</Label>
                            <Input type="date" className="bg-white/5 border-white/10 text-white" value={dueDate} onChange={e => setDueDate(e.target.value)} />
                        </div>
                    </div>
                </div>

                <div className="border rounded-md border-white/10 overflow-hidden">
                    <Table>
                        <TableHeader className="bg-white/5">
                            <TableRow className="border-white/5 hover:bg-transparent">
                                <TableHead className="text-zinc-400 w-[300px]">
                                    <div className="flex flex-col gap-1">
                                        <span>Item Details</span>
                                        <Input
                                            ref={searchRef}
                                            placeholder="Fuzzy search..."
                                            className="h-6 text-[10px] bg-white/5 border-white/10"
                                            value={productFilter}
                                            onChange={e => setProductFilter(e.target.value)}
                                        />
                                    </div>
                                </TableHead>
                                <TableHead className="text-zinc-400 w-[100px]">Qty</TableHead>
                                <TableHead className="text-zinc-400 text-right">Price</TableHead>
                                <TableHead className="text-zinc-400 text-right">Tax (%)</TableHead>
                                <TableHead className="text-zinc-400 text-right">Total</TableHead>
                                <TableHead className="w-[50px]"></TableHead>
                            </TableRow>
                        </TableHeader>
                        <TableBody>
                            {items.map((item, index) => (
                                <TableRow key={index} className="border-white/5 hover:bg-white/5">
                                    <TableCell>
                                        <Select value={item.productId} onValueChange={(val) => handleProductChange(index, val)}>
                                            <SelectTrigger className="h-8 bg-transparent border-transparent focus:bg-white/10 text-white">
                                                <SelectValue placeholder="Select Product" />
                                            </SelectTrigger>
                                            <SelectContent className="bg-zinc-900 border-white/10 text-white">
                                                {products
                                                    .filter(p =>
                                                        p.name.toLowerCase().includes(productFilter.toLowerCase()) ||
                                                        p.sku.toLowerCase().includes(productFilter.toLowerCase()) ||
                                                        (p.category && p.category.toLowerCase().includes(productFilter.toLowerCase()))
                                                    )
                                                    .map(p => (
                                                        <SelectItem key={p.id} value={p.id}>
                                                            <div className="flex flex-col">
                                                                <span className="font-medium">{p.name}</span>
                                                                <span className="text-[10px] opacity-50">{p.sku} | {p.category || 'General'}</span>
                                                            </div>
                                                        </SelectItem>
                                                    ))}
                                            </SelectContent>
                                        </Select>
                                        {item.hsnCode && <div className="text-[10px] text-zinc-500 px-3">HSN: {item.hsnCode}</div>}
                                    </TableCell>
                                    <TableCell>
                                        <Input
                                            type="number"
                                            min="0"
                                            className="h-8 bg-transparent border-white/10 text-white w-20"
                                            value={item.quantity || ""}
                                            onChange={(e) => {
                                                const val = e.target.value === "" ? 0 : parseFloat(e.target.value);
                                                handleQuantityChange(index, isNaN(val) ? 0 : val);
                                            }}
                                        />
                                    </TableCell>
                                    <TableCell className="text-right text-white font-mono">
                                        Ôé╣{item.price.toLocaleString('en-IN', { minimumFractionDigits: 2, maximumFractionDigits: 2 })}
                                    </TableCell>
                                    <TableCell className="text-right text-zinc-500 font-mono">
                                        {item.gstRate}%
                                    </TableCell>
                                    <TableCell className="text-right font-bold text-white font-mono truncate max-w-[120px]">
                                        Ôé╣{item.total.toLocaleString('en-IN', { minimumFractionDigits: 2, maximumFractionDigits: 2 })}
                                    </TableCell>
                                    <TableCell>
                                        <Button variant="ghost" size="icon" onClick={() => handleRemoveItem(index)} className="h-8 w-8 text-zinc-500 hover:text-rose-500">
                                            <Trash2 className="h-4 w-4" />
                                        </Button>
                                    </TableCell>
                                </TableRow>
                            ))}
                        </TableBody>
                    </Table>
                </div>

                <div className="sticky bottom-0 bg-[#09090b] pt-4 pb-2 border-t border-white/10 mt-4 z-20">
                    <div className="flex justify-between items-start">
                        <Button variant="outline" onClick={handleAddItem} className="border-dashed border-white/20 text-zinc-400 hover:text-white hover:bg-white/5">
                            <Plus className="mr-2 h-4 w-4" /> Add Line Item
                        </Button>

                        <div className="w-[200px] space-y-2 text-right">
                            <div className="flex justify-between text-sm text-zinc-400">
                                <span>Subtotal:</span>
                                <span>Ôé╣{subtotal.toLocaleString('en-IN', { minimumFractionDigits: 2 })}</span>
                            </div>
                            <div className="flex justify-between text-sm text-zinc-400">
                                <span>Total Tax:</span>
                                <span>Ôé╣{totalTax.toLocaleString('en-IN', { minimumFractionDigits: 2 })}</span>
                            </div>
                            <div className="flex justify-between text-lg font-bold text-white pt-2 border-t border-white/10">
                                <span>Total:</span>
                                <span>Ôé╣{grandTotal.toLocaleString('en-IN', { minimumFractionDigits: 2 })}</span>
                            </div>
                        </div>
                    </div>
                </div>

                <DialogFooter className="pt-6">
                    <Button variant="ghost" onClick={onClose} className="text-zinc-400 hover:text-white">Cancel</Button>
                    <Button onClick={handleSubmit} className="bg-amber-600 hover:bg-amber-700 text-white px-8" disabled={loading}>
                        {loading && <Loader2 className="mr-2 h-4 w-4 animate-spin" />}
                        Issue Tax Invoice
                    </Button>
                </DialogFooter>
            </DialogContent>
        </Dialog>
    );
}

"use client";

import { useState, useCallback } from "react";
import { Dialog, DialogContent, DialogDescription, DialogFooter, DialogHeader, DialogTitle } from "@/components/ui/dialog";
import { Button } from "@/components/ui/button";
import { Label } from "@/components/ui/label";
import { Input } from "@/components/ui/input";
import { Textarea } from "@/components/ui/textarea";
import { api } from "@/lib/api";
import { toast } from "sonner";
import { Plus, Trash2 } from "lucide-react";

interface Account {
    id: string;
    code: string;
    name: string;
}

interface CreateJournalEntryDialogProps {
    open: boolean;
    onOpenChange: (open: boolean) => void;
    onSuccess?: () => void;
    accounts: Account[];
}

interface JournalLine {
    accountId: string;
    type: "Debit" | "Credit";
    amount: string;
}

export function CreateJournalEntryDialog({ open, onOpenChange, onSuccess, accounts }: CreateJournalEntryDialogProps) {
    const [loading, setLoading] = useState(false);
    const [description, setDescription] = useState("");
    const [date, setDate] = useState(new Date().toISOString().split('T')[0]);
    const [lines, setLines] = useState<JournalLine[]>([
        { accountId: "", type: "Debit", amount: "" },
        { accountId: "", type: "Credit", amount: "" },
    ]);

    const addLine = useCallback(() => {
        setLines(prev => [...prev, { accountId: "", type: "Debit", amount: "" }]);
    }, []);

    const removeLine = useCallback((index: number) => {
        setLines(prev => {
            if (prev.length > 2) {
                return prev.filter((_, i) => i !== index);
            }
            return prev;
        });
    }, []);

    const updateLine = useCallback((index: number, field: keyof JournalLine, value: string) => {
        setLines(prev => {
            const newLines = [...prev];
            newLines[index] = { ...newLines[index], [field]: value } as JournalLine;
            return newLines;
        });
    }, []);

    const getTotalDebits = () => lines.filter(l => l.type === "Debit").reduce((sum, l) => sum + (parseFloat(l.amount) || 0), 0);
    const getTotalCredits = () => lines.filter(l => l.type === "Credit").reduce((sum, l) => sum + (parseFloat(l.amount) || 0), 0);
    const isBalanced = () => Math.abs(getTotalDebits() - getTotalCredits()) < 0.01;

    const handleSubmit = useCallback(async (e: React.FormEvent) => {
        e.preventDefault();

        // UI-001: Prevent double-execution during state-transition lag
        if (loading) return;

        if (!description) {
            toast.error("Please add a description");
            return;
        }

        if (lines.some(l => !l.accountId || !l.amount || parseFloat(l.amount) <= 0)) {
            toast.error("All lines must have an account and valid amount");
            return;
        }

        if (!isBalanced()) {
            toast.error("Debits and Credits must balance");
            return;
        }

        setLoading(true);
        try {
            // Create journal entry
            const journalData = {
                date,
                description,
                entries: lines.map(l => ({
                    accountId: l.accountId,
                    type: l.type,
                    amount: parseFloat(l.amount),
                    description
                }))
            };

            await api.post("accounting/journal-entries", journalData);
            toast.success("Journal entry created successfully");
            setDescription("");
            setDate(new Date().toISOString().split('T')[0]);
            setLines([
                { accountId: "", type: "Debit", amount: "" },
                { accountId: "", type: "Credit", amount: "" },
            ]);
            onOpenChange(false);
            onSuccess?.();
        } catch (error: any) {
            toast.error(error.response?.data?.message || "Failed to create journal entry");
        } finally {
            setLoading(false);
        }
    }, [loading, description, date, lines, onOpenChange, onSuccess]);

    return (
        <Dialog open={open} onOpenChange={onOpenChange}>
            <DialogContent className="w-11/12 sm:min-w-fit sm:max-w-[700px] max-h-[90vh] overflow-y-auto">
                <DialogHeader>
                    <DialogTitle className="text-2xl font-bold">Create Journal Entry</DialogTitle>
                    <DialogDescription>
                        Record a manual journal entry. Every debit must have an equal credit (double-entry bookkeeping). Use this for corrections, adjustments, or transactions not covered by invoices/payments.
                    </DialogDescription>
                </DialogHeader>
                <form onSubmit={handleSubmit}>
                    <div className="grid gap-6 py-4">
                        <div className="grid grid-cols-2 gap-4">
                            <div className="grid gap-2">
                                <Label htmlFor="date" className="font-semibold">
                                    Date <span className="text-red-500">*</span>
                                </Label>
                                <Input
                                    id="date"
                                    type="date"
                                    value={date}
                                    onChange={(e) => setDate(e.target.value)}
                                    required
                                    className="h-11"
                                />
                            </div>
                        </div>
                        <div className="grid gap-2">
                            <Label htmlFor="description" className="font-semibold">
                                Description <span className="text-red-500">*</span>
                            </Label>
                            <Textarea
                                id="description"
                                placeholder="e.g., Adjustment for inventory variance"
                                value={description}
                                onChange={(e) => setDescription(e.target.value)}
                                required
                                rows={2}
                            />
                        </div>

                        <div className="space-y-3">
                            <div className="flex items-center justify-between">
                                <Label className="font-semibold">Journal Lines</Label>
                                <Button type="button" size="sm" variant="outline" onClick={addLine}>
                                    <Plus className="h-3 w-3 mr-1" /> Add Line
                                </Button>
                            </div>

                            {lines.map((line, index) => (
                                <div key={index} className="grid grid-cols-12 gap-2 items-end bg-slate-50 p-3 rounded-lg">
                                    <div className="col-span-5">
                                        <Label className="text-xs">Account</Label>
                                        <select
                                            value={line.accountId}
                                            onChange={(e: React.ChangeEvent<HTMLSelectElement>) => updateLine(index, "accountId", e.target.value)}
                                            className="w-full h-9 px-3 border border-slate-200 rounded-md text-sm"
                                            required
                                        >
                                            <option value="">Select account...</option>
                                            {accounts.map((acc) => (
                                                <option key={acc.id} value={acc.id}>
                                                    {acc.code} - {acc.name}
                                                </option>
                                            ))}
                                        </select>
                                    </div>
                                    <div className="col-span-3">
                                        <Label className="text-xs">Type</Label>
                                        <select
                                            value={line.type}
                                            onChange={(e) => updateLine(index, "type", e.target.value as "Debit" | "Credit")}
                                            className="w-full h-9 px-3 border border-slate-200 rounded-md text-sm"
                                        >
                                            <option value="Debit">Debit</option>
                                            <option value="Credit">Credit</option>
                                        </select>
                                    </div>
                                    <div className="col-span-3">
                                        <Label className="text-xs">Amount</Label>
                                        <Input
                                            type="number"
                                            step="0.01"
                                            min="0"
                                            value={line.amount}
                                            onChange={(e) => updateLine(index, "amount", e.target.value)}
                                            placeholder="0.00"
                                            required
                                            className="h-9"
                                        />
                                    </div>
                                    <div className="col-span-1">
                                        {lines.length > 2 && (
                                            <Button
                                                type="button"
                                                size="icon"
                                                variant="ghost"
                                                onClick={() => removeLine(index)}
                                                className="h-9 w-9 text-red-500 hover:text-red-700 hover:bg-red-50"
                                            >
                                                <Trash2 className="h-4 w-4" />
                                            </Button>
                                        )}
                                    </div>
                                </div>
                            ))}

                            <div className="grid grid-cols-2 gap-4 p-3 bg-slate-900 text-white rounded-lg font-bold">
                                <div>
                                    <div className="text-xs opacity-70">Total Debits</div>
                                    <div className="text-lg">Ôé╣{getTotalDebits().toLocaleString('en-IN', { minimumFractionDigits: 2 })}</div>
                                </div>
                                <div>
                                    <div className="text-xs opacity-70">Total Credits</div>
                                    <div className="text-lg">Ôé╣{getTotalCredits().toLocaleString('en-IN', { minimumFractionDigits: 2 })}</div>
                                </div>
                            </div>

                            {!isBalanced() && getTotalDebits() > 0 && getTotalCredits() > 0 && (
                                <div className="text-sm text-red-600 bg-red-50 p-2 rounded">
                                    ÔÜá´©Å Entry is not balanced. Difference: Ôé╣{Math.abs(getTotalDebits() - getTotalCredits()).toFixed(2)}
                                </div>
                            )}
                        </div>
                    </div>
                    <DialogFooter>
                        <Button
                            type="button"
                            variant="outline"
                            onClick={() => onOpenChange(false)}
                            disabled={loading}
                        >
                            Cancel
                        </Button>
                        <Button type="submit" disabled={loading || !isBalanced()} className="bg-amber-500 hover:bg-amber-600">
                            {loading ? "Creating..." : "Create Entry"}
                        </Button>
                    </DialogFooter>
                </form>
            </DialogContent>
        </Dialog>
    );
}

"use client";

import { useState, useEffect, useCallback } from "react";
import { api } from "@/lib/api";
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from "@/components/ui/table";
import { Badge } from "@/components/ui/badge";
import { Plus, RefreshCw, Landmark } from "lucide-react";
import { toast } from "sonner";
import { useUX } from "@/components/providers/ux-provider";

interface Asset {
    id: string;
    name: string;
    assetCode: string;
    type: string;
    purchaseValue: string | number;
    accumulatedDepreciation: string | number;
    status: 'Active' | 'Disposed';
}

export function FixedAssetTab() {
    const { setUILocked } = useUX();
    const [assets, setAssets] = useState<Asset[]>([]);
    const [loading, setLoading] = useState(true);

    const fetchAssets = useCallback(async () => {
        try {
            setLoading(true);
            const res = await api.get("/accounting/fixed-assets");
            setAssets(res.data);
        } catch {
            toast.error("Failed to fetch assets");
        } finally {
            setLoading(false);
        }
    }, []);

    useEffect(() => {
        fetchAssets();
    }, [fetchAssets]);

    const runDepreciation = useCallback(async (assetId: string) => {
        try {
            setUILocked(true);
            await api.post(`/accounting/fixed-assets/${assetId}/depreciate`, {});
            toast.success("Depreciation processed successfully!");
            fetchAssets();
        } catch (err: any) {
            toast.error(err.message || "Depreciation failed");
        } finally {
            setUILocked(false);
        }
    }, [setUILocked, fetchAssets]);

    return (
        <Card className="bg-white border-slate-200 shadow-xl shadow-slate-200/40 rounded-3xl overflow-hidden">
            <CardHeader className="border-b border-slate-100 bg-slate-50/50 py-6">
                <div className="flex justify-between items-center">
                    <div>
                        <CardTitle className="text-slate-900 text-xl font-black">Fixed Asset Register</CardTitle>
                        <CardDescription className="text-slate-500 font-medium">Manage long-term assets and automated depreciation.</CardDescription>
                    </div>
                    <Button className="bg-amber-600 hover:bg-amber-700 text-white rounded-2xl font-bold gap-2">
                        <Plus className="h-4 w-4" />
                        Add Asset
                    </Button>
                </div>
            </CardHeader>
            <CardContent className="p-0">
                <Table>
                    <TableHeader className="bg-slate-50/50">
                        <TableRow className="hover:bg-transparent border-slate-100">
                            <TableHead className="font-bold text-slate-900 px-6 h-14">Asset</TableHead>
                            <TableHead className="font-bold text-slate-900 px-6 h-14">Type</TableHead>
                            <TableHead className="font-bold text-slate-900 px-6 h-14">Purchase Value</TableHead>
                            <TableHead className="font-bold text-slate-900 px-6 h-14">Accumulated Depr.</TableHead>
                            <TableHead className="font-bold text-slate-900 px-6 h-14">Net Value</TableHead>
                            <TableHead className="font-bold text-slate-900 px-6 h-14">Status</TableHead>
                            <TableHead className="text-right px-6 h-14">Actions</TableHead>
                        </TableRow>
                    </TableHeader>
                    <TableBody>
                        {assets.map((asset) => (
                            <TableRow key={asset.id} className="hover:bg-slate-50/50 border-slate-100 transition-colors">
                                <TableCell className="px-6 py-4">
                                    <div className="flex items-center gap-3">
                                        <div className="h-10 w-10 rounded-xl bg-amber-50 flex items-center justify-center text-amber-600 font-bold">
                                            <Landmark className="h-5 w-5" />
                                        </div>
                                        <div>
                                            <div className="font-black text-slate-900">{asset.name}</div>
                                            <div className="text-[10px] text-slate-500 font-bold uppercase tracking-widest">{asset.assetCode}</div>
                                        </div>
                                    </div>
                                </TableCell>
                                <TableCell className="px-6 py-4 font-bold text-slate-600">{asset.type}</TableCell>
                                <TableCell className="px-6 py-4 font-black text-slate-900">Ôé╣{Number(asset.purchaseValue).toLocaleString()}</TableCell>
                                <TableCell className="px-6 py-4 font-bold text-rose-500">-Ôé╣{Number(asset.accumulatedDepreciation).toLocaleString()}</TableCell>
                                <TableCell className="px-6 py-4 font-black text-emerald-600">Ôé╣{(Number(asset.purchaseValue) - Number(asset.accumulatedDepreciation)).toLocaleString()}</TableCell>
                                <TableCell className="px-6 py-4">
                                    <Badge className={
                                        asset.status === 'Active'
                                            ? "bg-emerald-50 text-emerald-600 border-none px-3 py-1 font-black text-[10px]"
                                            : "bg-amber-50 text-amber-600 border-none px-3 py-1 font-black text-[10px]"
                                    }>
                                        {asset.status.toUpperCase()}
                                    </Badge>
                                </TableCell>
                                <TableCell className="px-6 py-4 text-right">
                                    <Button
                                        variant="ghost"
                                        size="sm"
                                        className="text-amber-600 hover:text-amber-700 hover:bg-amber-50 font-bold gap-2"
                                        onClick={() => runDepreciation(asset.id)}
                                        disabled={asset.status !== 'Active'}
                                    >
                                        <RefreshCw className="h-4 w-4" />
                                        Depreciate
                                    </Button>
                                </TableCell>
                            </TableRow>
                        ))}
                        {assets.length === 0 && !loading && (
                            <TableRow>
                                <TableCell colSpan={7} className="h-32 text-center text-slate-400 font-bold">No assets found in register.</TableCell>
                            </TableRow>
                        )}
                    </TableBody>
                </Table>
            </CardContent>
        </Card>
    );
}

'use client';

import React, { useState, useEffect } from 'react';
import { Card, CardHeader, CardTitle, CardContent, CardDescription } from '@/components/ui/card';
import { Badge } from '@/components/ui/badge';
import { Progress } from '@/components/ui/progress';
import { TrendingUp, Calendar, AlertCircle, TrendingDown, Clock } from 'lucide-react';
import { api } from '@/lib/api';
import { motion } from 'framer-motion';

interface Projection {
    invoiceNumber: string;
    customerName: string;
    amount: number;
    expectedDate: string;
    probability: number;
}

interface ForecastData {
    projections: Projection[];
    totalExpected: number;
}

export function ForecastingWidget() {
    const [data, setData] = useState<ForecastData | null>(null);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        fetchForecast();
    }, []);

    const fetchForecast = async () => {
        try {
            const resp = await api.get('system/health/forecast');
            setData(resp.data);
        } catch (err) {
            console.error('Forecast failed', err);
        } finally {
            setLoading(false);
        }
    };

    if (loading) return <div className="h-[300px] flex items-center justify-center animate-pulse text-muted-foreground">Analyzing patterns...</div>;
    if (!data) return null;

    return (
        <Card className="border-amber-200/50 bg-amber-50/10 backdrop-blur-sm">
            <CardHeader className="pb-2">
                <div className="flex items-center justify-between">
                    <CardTitle className="text-xl font-black flex items-center gap-2">
                        <TrendingUp className="text-amber-500 w-6 h-6" />
                        Cashflow Forecast
                    </CardTitle>
                    <Badge variant="outline" className="bg-amber-100 text-amber-700 animate-pulse border-amber-200">
                        30-Day Forecast
                    </Badge>
                </div>
                <CardDescription className="font-medium">
                    Predictive settlement modeling based on historical customer behavior.
                </CardDescription>
            </CardHeader>
            <CardContent className="space-y-6">
                <div className="grid grid-cols-2 gap-4">
                    <div className="p-4 rounded-2xl bg-white border border-amber-100 shadow-sm">
                        <span className="text-xs font-bold text-slate-500 uppercase tracking-widest block mb-1">Expected Inflow</span>
                        <div className="text-2xl font-black text-slate-900">Ôé╣{data.totalExpected.toLocaleString()}</div>
                        <span className="text-[10px] text-green-600 font-bold flex items-center gap-1 mt-1">
                            +12% vs last period <TrendingUp className="w-3 h-3" />
                        </span>
                    </div>
                    <div className="p-4 rounded-2xl bg-white border border-amber-100 shadow-sm">
                        <span className="text-xs font-bold text-slate-500 uppercase tracking-widest block mb-1">Avg. Settlement</span>
                        <div className="text-2xl font-black text-slate-900">18.5 Days</div>
                        <span className="text-[10px] text-blue-600 font-bold flex items-center gap-1 mt-1">
                            Improved by 4.2 days <Clock className="w-3 h-3" />
                        </span>
                    </div>
                </div>

                <div className="space-y-3">
                    <h4 className="text-sm font-bold flex items-center gap-2">
                        <Calendar className="w-4 h-4 text-amber-500" /> High-Probability Settlements
                    </h4>
                    {data.projections.slice(0, 3).map((proj, idx) => (
                        <motion.div
                            key={idx}
                            initial={{ x: -20, opacity: 0 }}
                            animate={{ x: 0, opacity: 1 }}
                            transition={{ delay: idx * 0.1 }}
                            className="flex items-center justify-between p-3 bg-white/50 rounded-xl border border-slate-100"
                        >
                            <div className="flex-1">
                                <div className="text-sm font-bold">{proj.customerName}</div>
                                <div className="text-[10px] text-slate-500">Invoice #{proj.invoiceNumber} ÔÇó Expected {new Date(proj.expectedDate).toLocaleDateString()}</div>
                            </div>
                            <div className="text-right">
                                <div className="text-sm font-black text-slate-900">Ôé╣{proj.amount.toLocaleString()}</div>
                                <div className="flex items-center gap-2 mt-1">
                                    <Progress value={proj.probability} className="h-1 w-12 bg-slate-100" />
                                    <span className="text-[9px] font-black text-amber-600">{proj.probability}% Confidence</span>
                                </div>
                            </div>
                        </motion.div>
                    ))}
