"use client";

import React, { useState, useCallback, useEffect } from 'react';
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogFooter, DialogDescription } from "@/components/ui/dialog";
import { Button } from "@/components/ui/button";
import { Label } from "@/components/ui/label";
import { Input } from "@/components/ui/input";
import { NumericInput } from "@/components/ui/numeric-input";
import { api } from "@/lib/api";
import { toast } from "react-hot-toast";
import { Scale } from "lucide-react";

interface Warehouse {
    id: string;
    name: string;
}

interface OpeningBalanceDialogProps {
    isOpen: boolean;
    onClose: () => void;
    customerId?: string;
    supplierId?: string;
    productId?: string;
    targetName: string;
    onSuccess: () => void;
}

interface OpeningBalancePayload {
    date: string;
    description: string;
    amount?: number;
    quantity?: number;
    warehouseId?: string;
    unitCost?: number;
}

export function OpeningBalanceDialog({
    isOpen,
    onClose,
    customerId,
    supplierId,
    productId,
    targetName,
    onSuccess
}: OpeningBalanceDialogProps) {
    const [amount, setAmount] = useState<number>(0); // This will be 'quantity' for products
    const [unitCost, setUnitCost] = useState<number>(0);
    const [warehouseId, setWarehouseId] = useState<string>("");
    const [warehouses, setWarehouses] = useState<Warehouse[]>([]);
    const [date, setDate] = useState<string>(new Date().toISOString().split('T')[0]);
    const [description, setDescription] = useState<string>('Initial Opening Balance');
    const [isSubmitting, setIsSubmitting] = useState(false);

    useEffect(() => {
        if (isOpen && productId) {
            api.get('/inventory/warehouses').then(res => {
                const data = res.data;
                setWarehouses(data);
                if (data.length > 0) setWarehouseId(data[0].id);
            });
        }
    }, [isOpen, productId]);

    const handleSubmit = useCallback(async () => {
        if (amount <= 0) {
            toast.error(productId ? "Please enter valid quantity" : "Please enter a valid amount");
            return;
        }

        if (productId && !warehouseId) {
            toast.error("Please select a warehouse");
            return;
        }

        setIsSubmitting(true);
        try {
            let endpoint = "";
            const payload: OpeningBalancePayload = { date, description };

            if (customerId) {
                endpoint = `/accounting/customers/${customerId}/opening-balance`;
                payload.amount = amount;
            } else if (supplierId) {
                endpoint = `/accounting/suppliers/${supplierId}/opening-balance`;
                payload.amount = amount;
            } else if (productId) {
                endpoint = `/inventory/products/${productId}/opening-balance`;
                payload.quantity = amount;
                payload.warehouseId = warehouseId;
                payload.unitCost = unitCost;
            }

            await api.post(endpoint, payload);

            toast.success("Opening balance recorded");
            onSuccess();
            onClose();
        } catch (err: any) {
            toast.error(err.response?.data?.message || "Failed to record balance");
        } finally {
            setIsSubmitting(false);
        }
    }, [amount, date, description, customerId, supplierId, productId, warehouseId, unitCost, onSuccess, onClose]);

    return (
        <Dialog open={isOpen} onOpenChange={onClose}>
            <DialogContent className="sm:max-w-[425px]">
                <DialogHeader>
                    <div className="w-12 h-12 rounded-full bg-blue-50 flex items-center justify-center mb-4">
                        <Scale className="w-6 h-6 text-blue-600" />
                    </div>
                    <DialogTitle className="text-xl font-bold">Record Opening Balance</DialogTitle>
                    <DialogDescription>
                        Set the initial financial state for <span className="font-semibold text-slate-900">{targetName}</span>.
                        This will post a journal entry to Opening Balance Equity.
                    </DialogDescription>
                </DialogHeader>

                <div className="grid gap-6 py-4">
                    {productId && (
                        <div className="grid gap-2">
                            <Label className="font-bold text-slate-700 uppercase text-[10px] tracking-widest">Select Warehouse</Label>
                            <select
                                className="w-full h-11 px-3 bg-slate-50 border border-slate-200 rounded-xl font-bold text-sm focus:outline-none focus:ring-2 focus:ring-blue-500/20"
                                value={warehouseId}
                                onChange={(e) => setWarehouseId(e.target.value)}
                            >
                                <option value="">Select a warehouse...</option>
                                {warehouses.map(w => (
                                    <option key={w.id} value={w.id}>{w.name}</option>
                                ))}
                            </select>
                        </div>
                    )}

                    <div className="grid gap-2">
                        <Label htmlFor="amount" className="font-bold text-slate-700 uppercase text-[10px] tracking-widest">
                            {productId ? "Initial Quantity" : "Balance Amount (Ôé╣)"}
                        </Label>
                        <NumericInput
                            value={amount}
                            onChange={setAmount}
                            decimal={!productId}
                            placeholder="0.00"
                            className="text-lg font-bold h-12 bg-slate-50"
                        />
                    </div>

                    {productId && (
                        <div className="grid gap-2">
                            <Label className="font-bold text-slate-700 uppercase text-[10px] tracking-widest">Unit Cost (Ôé╣) per Item</Label>
                            <NumericInput
                                value={unitCost}
                                onChange={setUnitCost}
                                decimal
                                placeholder="0.00"
                                className="text-lg font-bold h-12 bg-slate-50"
                            />
                        </div>
                    )}

                    <div className="grid gap-2">
                        <Label htmlFor="date" className="font-bold text-slate-700 uppercase text-[10px] tracking-widest">Opening Date</Label>
                        <Input
                            id="date"
                            type="date"
                            value={date}
                            onChange={(e) => setDate(e.target.value)}
                            className="h-11 bg-slate-50"
                        />
                    </div>

                    <div className="grid gap-2">
                        <Label htmlFor="description" className="font-bold text-slate-700 uppercase text-[10px] tracking-widest">Description / Memo</Label>
                        <Input
                            id="description"
                            value={description}
                            onChange={(e) => setDescription(e.target.value)}
                            placeholder="e.g. Starting stock"
                            className="h-11 bg-slate-50"
                        />
                    </div>
                </div>

                <DialogFooter className="gap-2 sm:gap-0">
                    <Button variant="outline" onClick={onClose} disabled={isSubmitting}>
                        Cancel
                    </Button>
                    <Button
                        onClick={handleSubmit}
                        disabled={isSubmitting}
                        className="bg-blue-600 hover:bg-blue-700"
                    >
                        {isSubmitting ? "Recording..." : "Save Balance"}
                    </Button>
                </DialogFooter>
            </DialogContent>
        </Dialog>
    );
}

"use client";

import { useState, useCallback } from "react";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Dialog, DialogContent, DialogDescription, DialogFooter, DialogHeader, DialogTitle } from "@/components/ui/dialog";
import { Label } from "@/components/ui/label";
import { api } from "@/lib/api";
import { toast } from "sonner";
import { Loader2 } from "lucide-react";

interface Invoice {
    id: string;
    invoiceNumber: string;
    customerId: string;
    totalAmount: string | number;
    amountPaid: string | number;
}

interface RecordPaymentModalProps {
    invoice: Invoice | null;
    isOpen: boolean;
    onClose: () => void;
    onSuccess: () => void;
}

export function RecordPaymentModal({ invoice, isOpen, onClose, onSuccess }: RecordPaymentModalProps) {
    const [amount, setAmount] = useState<string>("");
    const [mode, setMode] = useState<string>("Bank");
    const [reference, setReference] = useState("");
    const [loading, setLoading] = useState(false);

    // Calc outstanding
    const outstanding = Number(invoice?.totalAmount || 0) - Number(invoice?.amountPaid || 0);

    const handleSubmit = useCallback(async (e: React.FormEvent) => {
        e.preventDefault();

        // UI-001: Prevent double-execution during state-transition lag
        if (loading || !invoice) return;

        if (!amount || Number(amount) <= 0) {
            toast.error("Please enter a valid amount");
            return;
        }
        if (Number(amount) > outstanding) {
            toast.error(`Amount exceeds outstanding balance of ${outstanding}`);
            return;
        }

        setLoading(true);
        try {
            await api.post("accounting/payments", {
                customerId: invoice.customerId,
                invoiceId: invoice.id,
                amount: Number(amount),
                mode,
                reference,
                date: new Date().toISOString()
            });
            toast.success("Payment recorded successfully");
            onSuccess();
            onClose();
        } catch (err: any) {
            toast.error(err.response?.data?.message || "Failed to record payment");
        } finally {
            setLoading(false);
        }
    }, [amount, mode, reference, loading, invoice, outstanding, onClose, onSuccess]);

    if (!invoice) return null;

    return (
        <Dialog open={isOpen} onOpenChange={onClose}>
            <DialogContent className="w-11/12 sm:min-w-fit sm:max-w-[425px] bg-[#09090b] text-white border-white/10">
                <DialogHeader>
                    <DialogTitle>Record Payment</DialogTitle>
                    <DialogDescription className="text-zinc-400">
                        Record a payment for Invoice #{invoice.invoiceNumber}
                    </DialogDescription>
                </DialogHeader>
                <form onSubmit={handleSubmit} className="space-y-4 py-4">
                    <div className="space-y-2">
                        <Label>Outstanding Balance</Label>
                        <div className="text-2xl font-bold text-white">
                            Ôé╣{outstanding.toLocaleString('en-IN', { minimumFractionDigits: 2 })}
                        </div>
                    </div>

                    <div className="grid grid-cols-2 gap-4">
                        <div className="space-y-2">
                            <Label htmlFor="amount">Payment Amount</Label>
                            <Input
                                id="amount"
                                type="number"
                                step="0.01"
                                value={amount}
                                onChange={(e) => setAmount(e.target.value)}
                                placeholder={outstanding.toString()}
                                className="bg-white/5 border-white/10 text-white"
                            />
                        </div>
                        <div className="space-y-2">
                            <Label htmlFor="mode">Mode</Label>
                            <Select value={mode} onValueChange={setMode}>
                                <SelectTrigger className="bg-white/5 border-white/10 text-white">
                                    <SelectValue placeholder="Select mode" />
                                </SelectTrigger>
                                <SelectContent className="bg-zinc-900 border-zinc-800 text-white">
                                    <SelectItem value="Cash">Cash</SelectItem>
                                    <SelectItem value="Bank">Bank Transfer</SelectItem>
                                    <SelectItem value="UPI">UPI</SelectItem>
                                    <SelectItem value="Cheque">Cheque</SelectItem>
                                </SelectContent>
                            </Select>
                        </div>
                    </div>

                    <div className="space-y-2">
                        <Label htmlFor="reference">Reference / Transaction ID</Label>
                        <Input
                            id="reference"
                            value={reference}
                            onChange={(e) => setReference(e.target.value)}
                            placeholder="e.g. UTR12345678"
                            className="bg-white/5 border-white/10 text-white"
                        />
                    </div>

                    <DialogFooter>
                        <Button type="button" variant="outline" onClick={onClose} className="border-white/10 text-white hover:bg-white/5">Cancel</Button>
                        <Button type="submit" disabled={loading} className="bg-amber-600 hover:bg-amber-700 text-white">
                            {loading && <Loader2 className="mr-2 h-4 w-4 animate-spin" />}
                            Confirm Payment
                        </Button>
                    </DialogFooter>
                </form>
            </DialogContent>
        </Dialog>
    );
}

"use client";

import React from 'react';
import { useAuth } from '@/hooks/use-auth';
import { Permission, RolePermissions } from '@/constants/permissions';

interface HasPermissionProps {
    permission: Permission;
    children: React.ReactNode;
    fallback?: React.ReactNode;
    disableOnly?: boolean;
}

export const HasPermission: React.FC<HasPermissionProps> = ({
    permission,
    children,
    fallback = null,
    disableOnly = false
}) => {
    const { user } = useAuth();
    const userRole = user?.role;

    const userPermissions = userRole ? (RolePermissions[userRole as any] || []) : [];
    const hasAccess = userPermissions.includes(permission);

    if (!hasAccess) {
        if (disableOnly && React.isValidElement(children)) {
            return React.cloneElement(children as React.ReactElement<any>, {
                disabled: true,
                title: "Insufficient permissions. Contact your Owner."
            });
        }
        return <>{fallback}</>;
    }

    return <>{children}</>;
};

