import React, { useState } from "react";
import {
    Dialog,
    DialogContent,
    DialogDescription,
    DialogHeader,
    DialogTitle,
    DialogTrigger,
    DialogFooter,
} from "@/components/ui/dialog";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { toast } from "sonner";
import { api } from "@/lib/api";
import { CheckCircle2, Factory, Cpu, User } from "lucide-react";
import { LoadingSpinner } from "@/components/ui/loading-spinner";
import {
    Select,
    SelectContent,
    SelectItem,
    SelectTrigger,
    SelectValue,
} from "@/components/ui/select";

export function CompleteWorkOrderDialog({
    workOrder,
    refreshData,
    children,
}: {
    workOrder: any;
    refreshData: () => void;
    children: React.ReactNode;
}) {
    const [open, setOpen] = useState(false);
    const [loading, setLoading] = useState(false);

    // Real-world defaults
    const [producedQuantity, setProducedQuantity] = useState(workOrder.quantity.toString());
    const [scrapQuantity, setScrapQuantity] = useState("0");
    const [machineId, setMachineId] = useState("");
    const [machineTimeHours, setMachineTimeHours] = useState("0");
    const [operatorName, setOperatorName] = useState("");
    const [machines, setMachines] = useState<any[]>([]);

    React.useEffect(() => {
        if (open) {
            api.get("manufacturing/machines").then(res => setMachines(res.data || [])).catch(() => { });
        }
    }, [open]);

    const handleComplete = async () => {
        try {
            setLoading(true);

            const prodQty = Number(producedQuantity);
            const scrQty = Number(scrapQuantity);

            if (isNaN(prodQty) || prodQty < 0) {
                toast.error("Invalid produced quantity.");
                return;
            }
            if (isNaN(scrQty) || scrQty < 0) {
                toast.error("Invalid scrap quantity.");
                return;
            }

            await api.post(`/manufacturing/work-orders/${workOrder.id}/complete`, {
                producedQuantity: prodQty,
                scrapQuantity: scrQty,
                machineId: machineId || undefined,
                machineTimeHours: Number(machineTimeHours),
                operatorName: operatorName
            });

            toast.success("Work order completed successfully.");
            setOpen(false);
            refreshData();
        } catch (err: any) {
            toast.error(err.response?.data?.message || "Failed to complete work order");
        } finally {
            setLoading(false);
        }
    };

    return (
        <Dialog open={open} onOpenChange={setOpen}>
            <DialogTrigger asChild>{children}</DialogTrigger>
            <DialogContent className="sm:max-w-[425px]">
                <DialogHeader>
                    <DialogTitle className="flex items-center gap-2">
                        <Factory className="h-5 w-5 text-emerald-600" />
                        Complete Work Order
                    </DialogTitle>
                    <DialogDescription>
                        Record the actual production yield for WO-{workOrder.orderNumber}.
                    </DialogDescription>
                </DialogHeader>

                <div className="grid gap-4 py-4">
                    <div className="bg-slate-50 p-3 rounded-lg border border-slate-100 mb-2">
                        <div className="text-xs font-bold text-slate-500 uppercase tracking-wider mb-1">Product Details</div>
                        <div className="font-medium text-slate-900">{workOrder.bom?.product?.name}</div>
                        <div className="text-xs text-slate-500 mt-1">Target Quantity: {workOrder.quantity} Units</div>
                    </div>

                    <div className="grid gap-2">
                        <Label htmlFor="producedQuantity" className="text-slate-700 font-bold">
                            Produced Quantity (Good Yield)
                        </Label>
                        <Input
                            id="producedQuantity"
                            type="number"
                            value={producedQuantity}
                            onChange={(e) => setProducedQuantity(e.target.value)}
                            min="0"
                            className="font-mono text-lg"
                        />
                        <p className="text-[10px] text-slate-500 mt-1">The actual amount of finished goods moving to inventory.</p>
                    </div>

                    <div className="grid gap-2">
                        <Label htmlFor="scrapQuantity" className="text-slate-700 font-bold">
                            Scrap Quantity (Defects / Waste)
                        </Label>
                        <Input
                            id="scrapQuantity"
                            type="number"
                            value={scrapQuantity}
                            onChange={(e) => setScrapQuantity(e.target.value)}
                            min="0"
                            className="font-mono text-lg text-red-600"
                        />
                        <p className="text-[10px] text-slate-500 mt-1">Materials consumed but did not result in finished goods.</p>
                    </div>

                    <div className="grid grid-cols-2 gap-3">
                        <div className="grid gap-2">
                            <Label className="text-slate-700 font-bold">Machine</Label>
                            <Select value={machineId} onValueChange={setMachineId}>
                                <SelectTrigger className="h-10">
                                    <SelectValue placeholder="Select machine" />
                                </SelectTrigger>
                                <SelectContent>
                                    {machines.map((m: any) => (
                                        <SelectItem key={m.id} value={m.id}>{m.name}</SelectItem>
                                    ))}
                                </SelectContent>
                            </Select>
                        </div>
                        <div className="grid gap-2">
                            <Label className="text-slate-700 font-bold text-xs uppercase">Run Time (Hrs)</Label>
                            <Input
                                type="number"
                                step="0.1"
                                value={machineTimeHours}
                                onChange={(e) => setMachineTimeHours(e.target.value)}
                            />
                        </div>
                    </div>

                    <div className="grid gap-2">
                        <Label className="text-slate-700 font-bold">Operator Name</Label>
                        <div className="relative">
                            <User className="absolute left-3 top-2.5 h-4 w-4 text-slate-400" />
                            <Input
                                className="pl-9"
                                placeholder="Employee Name"
                                value={operatorName}
                                onChange={e => setOperatorName(e.target.value)}
                            />
                        </div>
                    </div>
                </div>

                <DialogFooter>
                    <Button variant="outline" onClick={() => setOpen(false)} disabled={loading}>
                        Cancel
                    </Button>
                    <Button
                        onClick={handleComplete}
                        disabled={loading}
                        className="bg-emerald-600 hover:bg-emerald-700 font-bold"
                    >
                        {loading ? <LoadingSpinner text="Processing..." /> : (
                            <>
                                <CheckCircle2 className="mr-2 h-4 w-4" /> Finalize Production
                            </>
                        )}
                    </Button>
                </DialogFooter>
            </DialogContent>
        </Dialog>
    );
}

'use client';

import React, { useState, useEffect } from 'react';
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogTrigger } from '@/components/ui/dialog';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { NumericInput } from '@/components/ui/numeric-input';
import { Label } from '@/components/ui/label';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue, SelectGroup, SelectLabel } from '@/components/ui/select';
import { Plus, Trash2, Save, Loader2 } from 'lucide-react';
import { api } from '@/lib/api';
import { toast } from 'sonner';

interface Product {
    id: string;
    name: string;
    sku: string;
    unit: string;
    category?: string;
    costPrice?: number;
    stock?: number;
    tags?: string;
}

interface BOMItem {
    productId: string;
    quantity: number;
    unit: string;
}

interface CreateBOMDialogProps {
    refreshData: () => void;
    children: React.ReactNode;
}

export function CreateBOMDialog({ refreshData, children }: CreateBOMDialogProps) {
    const [open, setOpen] = useState(false);
    const [loading, setLoading] = useState(false);
    const [products, setProducts] = useState<Product[]>([]);

    // Form State
    const [name, setName] = useState('');
    const [selectedProduct, setSelectedProduct] = useState('');
    const [quantity, setQuantity] = useState(1);
    const [overheadRate, setOverheadRate] = useState(0);
    const [isOverheadFixed, setIsOverheadFixed] = useState(false);
    const [items, setItems] = useState<BOMItem[]>([]);

    useEffect(() => {
        if (open) {
            fetchProducts();
        }
    }, [open]);

    const fetchProducts = async () => {
        try {
            const res = await api.get('/inventory/products');
            // Handle both paginated ({ data: [...] }) and flat ([...]) responses
            const list = Array.isArray(res.data) ? res.data : (res.data?.data || []);
            setProducts(list);
        } catch (err) {
            console.error(err);
            toast.error("Failed to load products. Check console.");
        }
    };

    const addItem = () => {
        setItems([...items, { productId: '', quantity: 1, unit: 'pcs' }]);
    };

    const updateItem = (index: number, field: keyof BOMItem, value: any) => {
        const newItems = [...items];
        newItems[index] = { ...newItems[index], [field]: value };

        // Auto-set unit if product changes
        if (field === 'productId') {
            const product = products.find(p => p.id === value);
            if (product) {
                newItems[index].unit = product.unit || 'pcs';
            }
        }
        setItems(newItems);
    };

    const removeItem = (index: number) => {
        setItems(items.filter((_, i) => i !== index));
    };

    const handleSubmit = async () => {
        if (!name || !selectedProduct) {
            toast.error("Name and Finished Good are required");
            return;
        }
        if (items.length === 0) {
            toast.error("Add at least one raw material");
            return;
        }

        try {
            setLoading(true);
            await api.post('/manufacturing/boms', {
                name,
                productId: selectedProduct,
                quantity,
                overheadRate,
                isOverheadFixed,
                items
            });
            toast.success("BOM Created Successfully");
            setOpen(false);
            refreshData();
            // Reset form
            setName('');
            setSelectedProduct('');
            setItems([]);
        } catch (err) {
            console.error(err);
            toast.error("Failed to create BOM");
        } finally {
            setLoading(false);
        }
    };

    return (
        <Dialog open={open} onOpenChange={setOpen}>
            <DialogTrigger asChild>
                {children}
            </DialogTrigger>
            <DialogContent className="w-11/12 sm:min-w-fit sm:max-w-3xl max-h-[90vh] overflow-y-auto">
                <DialogHeader>
                    <DialogTitle>Create New Bill of Materials</DialogTitle>
                </DialogHeader>

                <div className="grid gap-6 py-4">
                    <div className="grid grid-cols-2 gap-4">
                        <div className="space-y-2">
                            <Label>BOM Name</Label>
