                            </p>
                        </div>
                    </div>

                    <div className="grid grid-cols-3 gap-4">
                        <div className="space-y-2">
                            <Label>Output Quantity</Label>
                            <NumericInput value={quantity} onChange={setQuantity} />
                        </div>
                        <div className="space-y-2">
                            <Label>Extra Cost % (Overhead)</Label>
                            <div className="flex gap-2">
                                <NumericInput decimal value={overheadRate} onChange={setOverheadRate} />
                                <Button
                                    variant="outline"
                                    className={`w-12 ${isOverheadFixed ? 'bg-primary text-primary-foreground' : ''}`}
                                    onClick={() => setIsOverheadFixed(!isOverheadFixed)}
                                >
                                    {isOverheadFixed ? '$' : '%'}
                                </Button>
                            </div>
                        </div>
                    </div>

                    <div className="border-t pt-4">
                        <div className="flex justify-between items-center mb-4">
                            <div>
                                <Label>Raw Materials / Components</Label>
                                <p className="text-[10px] text-muted-foreground">Add the items required to build 1 unit of the finished good.</p>
                            </div>
                            <Button size="sm" variant="outline" onClick={addItem}>
                                <Plus className="w-4 h-4 mr-1" /> Add Component
                            </Button>
                        </div>

                        <div className="space-y-3">
                            {items.map((item, index) => (
                                <div key={index} className="flex gap-3 items-end">
                                    <div className="flex-1 space-y-1">
                                        <Label className="text-xs text-muted-foreground">Component</Label>
                                        <Select value={item.productId} onValueChange={v => updateItem(index, 'productId', v)}>
                                            <SelectTrigger>
                                                <SelectValue placeholder="Select Material" />
                                            </SelectTrigger>
                                            <SelectContent>
                                                {Array.from(new Set(products.filter(p => !p.tags?.includes('FINISHED_GOOD')).map(p => p.category || 'Uncategorized'))).map(category => (
                                                    <SelectGroup key={category}>
                                                        <SelectLabel>{category}</SelectLabel>
                                                        {products.filter(p => !p.tags?.includes('FINISHED_GOOD') && (p.category || 'Uncategorized') === category).map(p => (
                                                            <SelectItem key={p.id} value={p.id}>{p.name} ({p.stock} avail)</SelectItem>
                                                        ))}
                                                    </SelectGroup>
                                                ))}
                                            </SelectContent>
                                        </Select>
                                    </div>
                                    <div className="w-24 space-y-1">
                                        <Label className="text-xs text-muted-foreground">Qty</Label>
                                        <NumericInput decimal value={item.quantity} onChange={v => updateItem(index, 'quantity', v)} />
                                    </div>
                                    <div className="w-20 space-y-1">
                                        <Label className="text-xs text-muted-foreground">Unit</Label>
                                        <Input value={item.unit} readOnly className="bg-muted" />
                                    </div>
                                    <Button size="icon" variant="ghost" className="text-destructive" onClick={() => removeItem(index)}>
                                        <Trash2 className="w-4 h-4" />
                                    </Button>
                                </div>
                            ))}
                            {items.length === 0 && (
                                <div className="text-center py-6 border-2 border-dashed rounded-lg text-muted-foreground text-sm">
                                    No items added. Click "Add Item" to start.
                                </div>
                            )}
                        </div>
                    </div>

                    <Button onClick={handleSubmit} disabled={loading} className="w-full mt-2">
                        {loading ? <Loader2 className="w-4 h-4 mr-2 animate-spin" /> : <Save className="w-4 h-4 mr-2" />}
                        Create BOM
                    </Button>
                </div>
            </DialogContent>
        </Dialog>
    );
}

'use client';

import React, { useState, useEffect } from 'react';
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogTrigger } from '@/components/ui/dialog';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { Save, Loader2, RefreshCw } from 'lucide-react';
import { api } from '@/lib/api';
import { toast } from 'sonner';

interface BOM {
    id: string;
    name: string;
    product: {
        name: string;
        sku: string;
    };
}

interface Shortage {
    productName: string;
    required: number;
    available: number;
    missing: number;
}

interface CreateWorkOrderDialogProps {
    refreshData: () => void;
    children: React.ReactNode;
}

export function CreateWorkOrderDialog({ refreshData, children }: CreateWorkOrderDialogProps) {
    const [open, setOpen] = useState(false);
    const [loading, setLoading] = useState(false);
    const [checking, setChecking] = useState(false);

    const [boms, setBoms] = useState<BOM[]>([]);
    const [selectedBomId, setSelectedBomId] = useState('');
    const [quantity, setQuantity] = useState(1);
    const [shortages, setShortages] = useState<Shortage[]>([]);

    useEffect(() => {
        if (open) {
            fetchBOMs();
        }
    }, [open]);

    useEffect(() => {
        if (selectedBomId && quantity > 0) {
            checkShortages();
        } else {
            setShortages([]);
        }
    }, [selectedBomId, quantity]);

    const fetchBOMs = async () => {
        try {
            const { data } = await api.get('/manufacturing/boms');
            setBoms(data);
        } catch (err) {
            toast.error("Failed to load BOMs");
        }
    };

    const checkShortages = async () => {
        if (!selectedBomId) return;
        setChecking(true);
        try {
            const { data } = await api.get(`/manufacturing/boms/${selectedBomId}/shortages?quantity=${quantity}`);
            setShortages(data);
        } catch (err) {
            console.error("Failed to check shortages");
        } finally {
            setChecking(false);
        }
    };

    const handleSubmit = async () => {
        if (!selectedBomId) {
            toast.error("Please select a BOM");
            return;
        }

        try {
            setLoading(true);
            await api.post('/manufacturing/work-orders', {
                bomId: selectedBomId,
                quantity
            });
            toast.success("Work Order Created Successfully");
            setOpen(false);
            refreshData();
            // Reset
            setSelectedBomId('');
            setQuantity(1);
            setShortages([]);
        } catch (err) {
            console.error(err);
            toast.error("Failed to create Work Order");
        } finally {
            setLoading(false);
        }
    };

    return (
        <Dialog open={open} onOpenChange={setOpen}>
            <DialogTrigger asChild>
                {children}
            </DialogTrigger>
            <DialogContent className="w-11/12 sm:min-w-fit sm:max-w-md">
                <DialogHeader>
                    <DialogTitle>Create Production Order</DialogTitle>
                </DialogHeader>

                <div className="grid gap-4 py-4">
                    <div className="space-y-2">
                        <Label>Product Recipe (BOM)</Label>
                        <Select value={selectedBomId} onValueChange={setSelectedBomId}>
                            <SelectTrigger>
                                <SelectValue placeholder="Select Product to Make" />
                            </SelectTrigger>
                            <SelectContent>
                                {boms.map(b => (
                                    <SelectItem key={b.id} value={b.id}>{b.name} ({b.product.name})</SelectItem>
                                ))}
                            </SelectContent>
                        </Select>
                    </div>

                    <div className="space-y-2">
                        <Label>Target Quantity</Label>
                        <Input type="number" min="1" value={quantity} onChange={e => setQuantity(Number(e.target.value))} />
                    </div>

                    {/* Shortage Preview */}
                    <div className={`rounded-lg p-3 text-sm ${shortages.length > 0 ? 'bg-red-50 text-red-800' : 'bg-green-50 text-green-800'}`}>
                        <div className="flex items-center gap-2 font-bold mb-2">
                            {checking ? <RefreshCw className="w-3 h-3 animate-spin" /> : null}
                            {shortages.length > 0 ? "Missing Materials" : "Materials Available"}
                        </div>
                        {shortages.length > 0 && (
                            <ul className="space-y-1">
                                {shortages.map((s, i) => (
                                    <li key={i} className="flex justify-between text-xs">
                                        <span>{s.productName}</span>
                                        <span className="font-mono">Missing: {s.missing}</span>
                                    </li>
                                ))}
                            </ul>
                        )}
                    </div>

                    <Button onClick={handleSubmit} disabled={loading} className="w-full mt-2">
                        {loading ? <Loader2 className="w-4 h-4 mr-2 animate-spin" /> : <Save className="w-4 h-4 mr-2" />}
                        Initialize Work Order
                    </Button>
                </div>
            </DialogContent>
        </Dialog>
    );
}

"use client";

import React, { createContext, useContext, useState, useEffect } from "react";
import {
    Dialog,
    DialogContent,
    DialogHeader,
    DialogTitle,
    DialogDescription,
    DialogFooter,
} from "@/components/ui/dialog";
import { Button } from "@/components/ui/button";
import { AlertCircle, LogOut } from "lucide-react";
import { useRouter, usePathname } from "next/navigation";
import { cn } from "@/lib/utils";

interface UXContextType {
    showConfirm: (options: ConfirmOptions) => void;
    triggerSessionExpiry: () => void;
    setUILocked: (locked: boolean) => void;
}

interface ConfirmOptions {
    title: string;
    description: string;
    confirmText?: string;
    cancelText?: string;
    variant?: "default" | "destructive";
    onConfirm: () => void;
}

const UXContext = createContext<UXContextType | undefined>(undefined);

export function UXProvider({ children }: { children: React.ReactNode }) {
    const router = useRouter();
    const [confirmOptions, setConfirmOptions] = useState<ConfirmOptions | null>(null);
    const [isSessionExpired, setIsSessionExpired] = useState(false);
    const [isUILocked, setIsUILocked] = useState(false);

    const showConfirm = (options: ConfirmOptions) => {
        setConfirmOptions(options);
    };

    const setUILocked = (locked: boolean) => {
        setIsUILocked(locked);
    };

    const triggerSessionExpiry = () => {
        setIsSessionExpired(true);
    };

    const handleConfirm = () => {
        if (confirmOptions) {
            confirmOptions.onConfirm();
            setConfirmOptions(null);
        }
    };

    const handleLoginRedirect = () => {
        setIsSessionExpired(false);
        // Save current path to restore state after login
        if (typeof window !== "undefined") {
            // Stripping the basePath if it exists to avoid double-prefixing on redirect
            const currentPath = window.location.pathname;
            const cleanPath = currentPath.startsWith('/portal')
                ? currentPath.replace('/portal', '')
                : currentPath;

            localStorage.setItem("return_to", cleanPath || "/");
            router.push("/login"); // router.push handles /portal automatically
        }
    };

    const pathname = usePathname();

    useEffect(() => {
        // Global listener for custom events if needed
        const handleSessionExpiry = () => {
            // Don't trigger if we are already on auth pages
            const authPages = ['/login', '/register', '/forgot-password', '/reset-password'];
            if (authPages.some(page => pathname?.includes(page))) {
                return;
            }
            setIsSessionExpired(true);
        };
        window.addEventListener("session-expired", handleSessionExpiry);
        return () => window.removeEventListener("session-expired", handleSessionExpiry);
    }, [pathname]);

    // UI-002: Improve Red-Text mandatory visual highlights directly upon broken Form saves
    useEffect(() => {
        const handleInvalidSubmits = (e: SubmitEvent) => {
            if (e.target instanceof HTMLFormElement) {
                e.target.classList.add('form-submitted');
            }
        };
        document.addEventListener('submit', handleInvalidSubmits, { capture: true });
        return () => document.removeEventListener('submit', handleInvalidSubmits, { capture: true });
    }, []);

    return (
        <UXContext.Provider value={{ showConfirm, triggerSessionExpiry, setUILocked }}>
            {children}

            {/* UI Lock Overlay */}
            {isUILocked && (
                <div className="fixed inset-0 z-[99999] bg-white/80 backdrop-blur-md flex items-center justify-center cursor-wait animate-in fade-in duration-300">
                    <div className="flex flex-col items-center gap-4">
                        <div className="h-12 w-12 border-4 border-blue-500/20 border-t-blue-600 rounded-full animate-spin" />
                        <div className="text-slate-900 font-bold text-[10px] tracking-widest uppercase animate-pulse">
                            Processing Request...
                        </div>
                    </div>
                </div>
            )}

            {/* Global Confirm Dialog */}
            <Dialog open={!!confirmOptions} onOpenChange={(open) => !open && setConfirmOptions(null)}>
                <DialogContent className="w-11/12 sm:min-w-fit bg-white border-slate-200 text-slate-900 rounded-[2rem] p-8 shadow-2xl">
                    <DialogHeader>
                        <DialogTitle className="flex items-center gap-2 text-xl font-black uppercase tracking-tight">
                            {confirmOptions?.variant === "destructive" && <AlertCircle className="h-5 w-5 text-rose-500" />}
                            {confirmOptions?.title || "Confirm Action"}
                        </DialogTitle>
                        <DialogDescription className="text-slate-500 font-medium">
                            {confirmOptions?.description}
                        </DialogDescription>
                    </DialogHeader>
                    <DialogFooter className="gap-3 sm:gap-2 mt-6">
                        <Button variant="ghost" className="font-bold text-slate-500 hover:text-slate-900 hover:bg-slate-50 rounded-xl" onClick={() => setConfirmOptions(null)}>
                            {confirmOptions?.cancelText || "Cancel"}
                        </Button>
                        <Button
                            variant={confirmOptions?.variant === "destructive" ? "destructive" : "default"}
                            className={cn(
                                "rounded-xl font-black uppercase tracking-wider text-[10px] h-11 px-6",
                                confirmOptions?.variant !== "destructive" ? "bg-blue-600 hover:bg-blue-700 shadow-lg shadow-blue-500/20" : ""
                            )}
                            onClick={handleConfirm}
                        >
                            {confirmOptions?.confirmText || "Execute"}
                        </Button>
                    </DialogFooter>
                </DialogContent>
            </Dialog>

            {/* Session Expired Modal */}
            <Dialog open={isSessionExpired} onOpenChange={() => { }}>
                <DialogContent className="bg-white border-slate-200 text-slate-900 sm:max-w-[400px] rounded-[2.5rem] p-8 shadow-2xl">
                    <DialogHeader className="items-center text-center">
                        <div className="h-16 w-16 rounded-3xl bg-rose-50 flex items-center justify-center mb-6">
                            <LogOut className="h-8 w-8 text-rose-500" />
                        </div>
                        <DialogTitle className="text-2xl font-black uppercase tracking-tight">Session Terminated</DialogTitle>
                        <DialogDescription className="text-slate-500 font-medium leading-relaxed">
                            Your security token has expired. For your safety, we've locked the session. Please re-authenticate to continue.
                        </DialogDescription>
                    </DialogHeader>
                    <DialogFooter className="mt-8">
                        <Button className="w-full bg-blue-600 hover:bg-blue-700 text-white font-black h-12 rounded-xl transition-all shadow-lg shadow-blue-500/20 uppercase tracking-widest text-[10px]" onClick={handleLoginRedirect}>
                            Return to Safe Login
                        </Button>
                    </DialogFooter>
                </DialogContent>
            </Dialog>
        </UXContext.Provider>
    );
}

export const useUX = () => {
    const context = useContext(UXContext);
    if (!context) throw new Error("useUX must be used within a UXProvider");
    return context;
};

"use client";

import { useState } from "react";
import { Dialog, DialogContent, DialogDescription, DialogFooter, DialogHeader, DialogTitle } from "@/components/ui/dialog";
import { Button } from "@/components/ui/button";
import { Label } from "@/components/ui/label";
import { Input } from "@/components/ui/input";
import { api } from "@/lib/api";
import { toast } from "sonner";
import { Loader2 } from "lucide-react";
import { useForm } from "react-hook-form";
import { zodResolver } from "@hookform/resolvers/zod";
import * as z from "zod";

const supplierSchema = z.object({
    name: z.string().min(1, "Supplier name is required"),
    email: z.string().email("Invalid email address"),
    phone: z.string().regex(/^\d{10}$/, "Phone number must be exactly 10 digits"),
    category: z.string().optional(),
    address: z.string().optional()
});

type SupplierFormData = z.infer<typeof supplierSchema>;

interface CreateSupplierDialogProps {
    open: boolean;
    onOpenChange: (open: boolean) => void;
    onSuccess?: () => void;
}

export function CreateSupplierDialog({ open, onOpenChange, onSuccess }: CreateSupplierDialogProps) {
    const [loading, setLoading] = useState(false);

    const { register, handleSubmit, reset, formState: { errors } } = useForm<SupplierFormData>({
        resolver: zodResolver(supplierSchema),
        defaultValues: {
            name: "",
            email: "",
            phone: "",
            category: "",
            address: ""
        }
    });

    const onSubmit = async (data: SupplierFormData) => {
        setLoading(true);
        try {
            await api.post("purchases/suppliers", data);
            toast.success("Supplier added successfully");
            reset();
            onOpenChange(false);
            onSuccess?.();
        } catch (error: any) {
            toast.error(error.response?.data?.message || "Failed to add supplier");
        } finally {
            setLoading(false);
        }
    };

    return (
        <Dialog open={open} onOpenChange={onOpenChange}>
            <DialogContent className="w-11/12 sm:min-w-fit sm:max-w-[425px] rounded-[32px] border-none shadow-2xl">
                <DialogHeader>
                    <DialogTitle className="text-2xl font-black tracking-tight text-slate-900">Add Supplier</DialogTitle>
                    <DialogDescription className="font-medium text-slate-500">
                        Register a new vendor or supplier for your procurement needs.
                    </DialogDescription>
                </DialogHeader>
                <form onSubmit={handleSubmit(onSubmit)} className="space-y-4 pt-4">
                    <div className="space-y-3">
                        <div className="grid gap-2">
                            <Label htmlFor="name" className="text-[10px] font-black uppercase tracking-widest text-slate-400 ml-1">
                                Supplier Name <span className="text-rose-500">*</span>
                            </Label>
                            <Input
                                id="name"
                                placeholder="Grand Logistics Ltd"
                                {...register("name")}
                                className="h-11 rounded-xl border-slate-100 bg-slate-50/50 focus:bg-white transition-all font-bold"
                            />
                            {errors.name && <p className="text-xs text-rose-500 font-semibold ml-1">{errors.name.message}</p>}
                        </div>
                        <div className="grid grid-cols-2 gap-3">
                            <div className="grid gap-2">
                                <Label htmlFor="email" className="text-[10px] font-black uppercase tracking-widest text-slate-400 ml-1">
                                    Email <span className="text-rose-500">*</span>
                                </Label>
                                <Input
                                    id="email"
                                    type="email"
                                    placeholder="vendor@example.com"
                                    {...register("email")}
                                    className="h-11 rounded-xl border-slate-100 bg-slate-50/50 focus:bg-white transition-all font-bold"
                                />
                                {errors.email && <p className="text-xs text-rose-500 font-semibold ml-1">{errors.email.message}</p>}
                            </div>
                            <div className="grid gap-2">
                                <Label htmlFor="phone" className="text-[10px] font-black uppercase tracking-widest text-slate-400 ml-1">
                                    Phone <span className="text-rose-500">*</span>
                                </Label>
                                <Input
                                    id="phone"
                                    placeholder="9876543210"
                                    {...register("phone")}
                                    className="h-11 rounded-xl border-slate-100 bg-slate-50/50 focus:bg-white transition-all font-bold"
                                />
                                {errors.phone && <p className="text-xs text-rose-500 font-semibold ml-1">{errors.phone.message}</p>}
                            </div>
                        </div>
                        <div className="grid gap-2">
                            <Label htmlFor="category" className="text-[10px] font-black uppercase tracking-widest text-slate-400 ml-1">
                                Category
                            </Label>
                            <Input
                                id="category"
                                placeholder="Raw Materials / Electronics"
                                {...register("category")}
                                className="h-11 rounded-xl border-slate-100 bg-slate-50/50 focus:bg-white transition-all font-bold"
                            />
                        </div>
                        <div className="grid gap-2">
                            <Label htmlFor="address" className="text-[10px] font-black uppercase tracking-widest text-slate-400 ml-1">
                                Address
                            </Label>
                            <Input
                                id="address"
                                placeholder="Full business address"
                                {...register("address")}
                                className="h-11 rounded-xl border-slate-100 bg-slate-50/50 focus:bg-white transition-all font-bold"
                            />
                        </div>
                    </div>
                    <DialogFooter className="pt-2">
                        <Button
                            type="button"
                            variant="ghost"
                            onClick={() => onOpenChange(false)}
                            className="rounded-xl font-bold h-11 px-6"
                        >
                            Cancel
                        </Button>
                        <Button
                            type="submit"
                            disabled={loading}
                            className="bg-indigo-600 hover:bg-indigo-700 text-white rounded-xl h-11 px-8 font-black uppercase tracking-widest shadow-lg shadow-indigo-500/20"
                        >
                            {loading ? <Loader2 className="h-4 w-4 animate-spin" /> : "Add Supplier"}
                        </Button>
                    </DialogFooter>
                </form>
            </DialogContent>
        </Dialog>
    );
}

"use client";

import { useState, useEffect } from "react";
import { Dialog, DialogContent, DialogDescription, DialogFooter, DialogHeader, DialogTitle } from "@/components/ui/dialog";
import { Button } from "@/components/ui/button";
import { Label } from "@/components/ui/label";
import { Input } from "@/components/ui/input";
import { api } from "@/lib/api";
import { toast } from "react-hot-toast";
import { Loader2 } from "lucide-react";

interface EditSupplierDialogProps {
    open: boolean;
    onOpenChange: (open: boolean) => void;
    supplier: any;
    onSuccess?: () => void;
}

export function EditSupplierDialog({ open, onOpenChange, supplier, onSuccess }: EditSupplierDialogProps) {
    const [loading, setLoading] = useState(false);
    const [formData, setFormData] = useState({
        name: "",
        email: "",
        phone: "",
        category: "",
        address: ""
    });

    useEffect(() => {
        if (supplier) {
            setFormData({
                name: supplier.name || "",
                email: supplier.email || "",
                phone: supplier.phone || "",
                category: supplier.category || "",
                address: supplier.address || ""
            });
        }
    }, [supplier, open]);

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();

        if (!formData.name) {
            toast.error("Supplier name is required");
            return;
        }

        setLoading(true);
        try {
            await api.patch(`purchases/suppliers/${supplier.id}`, formData);
            toast.success("Supplier updated successfully");
            onOpenChange(false);
            onSuccess?.();
        } catch (error: any) {
            toast.error(error.response?.data?.message || "Failed to update supplier");
        } finally {
            setLoading(false);
        }
    };

    return (
        <Dialog open={open} onOpenChange={onOpenChange}>
            <DialogContent className="w-11/12 sm:min-w-fit sm:max-w-[425px] rounded-[32px] border-none shadow-2xl">
                <DialogHeader>
                    <DialogTitle className="text-2xl font-black tracking-tight text-slate-900">Edit Supplier</DialogTitle>
                    <DialogDescription className="font-medium text-slate-500">
                        Update supplier information for {supplier?.name}.
                    </DialogDescription>
                </DialogHeader>
                <form onSubmit={handleSubmit} className="space-y-4 pt-4">
                    <div className="space-y-3">
                        <div className="grid gap-2">
