                            type="submit"
                            disabled={loading}
                            className="bg-indigo-600 hover:bg-indigo-700 text-white rounded-xl h-11 px-8 font-black uppercase tracking-widest shadow-lg shadow-indigo-500/20"
                        >
                            {loading ? <Loader2 className="h-4 w-4 animate-spin" /> : "Save Changes"}
                        </Button>
                    </DialogFooter>
                </form>
            </DialogContent>
        </Dialog>
    );
}

import React, { useState, useEffect } from 'react';
import { api } from '@/lib/api';
import { Package, Search } from 'lucide-react';

interface Product {
    id: string;
    name: string;
    sku: string;
    price: string | number;
    stock: string | number;
    category?: string;
    gstRate?: number;
}

interface ProductGridProps {
    onProductClick: (product: any) => void;
}

export function ProductGrid({ onProductClick }: ProductGridProps) {
    const [products, setProducts] = useState<Product[]>([]);
    const [loading, setLoading] = useState(true);
    const [searchTerm, setSearchTerm] = useState('');
    const [selectedCategory, setSelectedCategory] = useState<string>('All');

    useEffect(() => {
        const fetchProducts = async () => {
            try {
                const res = await api.get('/inventory/products?limit=100'); // Load top 100 for POS
                const list = Array.isArray(res.data) ? res.data : (res.data?.data || []);
                setProducts(list);
            } catch (err) {
                console.error("Failed to fetch products for POS:", err);
            } finally {
                setLoading(false);
            }
        };
        fetchProducts();
    }, []);

    const categories = ['All', ...Array.from(new Set(products.map(p => p.category || 'Uncategorized')))];

    const filteredProducts = products.filter(p => {
        const matchesSearch = p.name.toLowerCase().includes(searchTerm.toLowerCase()) || p.sku.toLowerCase().includes(searchTerm.toLowerCase());
        const matchesCategory = selectedCategory === 'All' || (p.category || 'Uncategorized') === selectedCategory;
        return matchesSearch && matchesCategory;
    });

    if (loading) {
        return <div className="flex-1 flex items-center justify-center text-slate-400">Loading catalog...</div>;
    }

    return (
        <div className="flex flex-col h-full bg-slate-50 border-r border-slate-200 w-full lg:w-[45%] shrink-0">
            <div className="p-4 bg-white border-b border-slate-200 space-y-3">
                <div className="relative">
                    <Search className="absolute left-3 top-2.5 h-4 w-4 text-slate-400" />
                    <input
                        type="text"
                        placeholder="Search product catalog..."
                        value={searchTerm}
                        onChange={(e) => setSearchTerm(e.target.value)}
                        className="w-full pl-9 pr-4 py-2 bg-slate-100 border-none rounded-xl text-sm focus:ring-2 focus:ring-blue-500 outline-none"
                    />
                </div>

                <div className="flex gap-2 overflow-x-auto pb-1 scrollbar-hide">
                    {categories.map(cat => (
                        <button
                            key={cat}
                            onClick={() => setSelectedCategory(cat)}
                            className={`px-3 py-1.5 rounded-lg text-xs font-bold whitespace-nowrap transition-colors ${selectedCategory === cat ? 'bg-slate-900 text-white shadow-md' : 'bg-slate-100 text-slate-600 hover:bg-slate-200'}`}
                        >
                            {cat}
                        </button>
                    ))}
                </div>
            </div>

            <div className="flex-1 overflow-y-auto p-4">
                <div className="grid grid-cols-2 sm:grid-cols-3 gap-3">
                    {filteredProducts.map(product => (
                        <button
                            key={product.id}
                            onClick={() => onProductClick(product)}
                            className="bg-white p-3 rounded-2xl border border-slate-200 shadow-sm hover:border-blue-500 hover:shadow-md transition-all text-left flex flex-col group active:scale-95"
                        >
                            <div className="w-10 h-10 rounded-xl bg-blue-50 flex items-center justify-center mb-3 group-hover:bg-blue-100 transition-colors">
                                <Package className="h-5 w-5 text-blue-600" />
                            </div>
                            <span className="font-bold text-slate-900 text-sm line-clamp-2 leading-tight mb-1">{product.name}</span>
                            <div className="mt-auto flex items-center justify-between w-full">
                                <span className="text-emerald-600 font-black text-sm">Ôé╣{parseFloat(product.price as string).toFixed(2)}</span>
                                <span className="text-[10px] text-slate-400 font-bold bg-slate-100 px-1.5 py-0.5 rounded-md">{Number(product.stock)} left</span>
                            </div>
                        </button>
                    ))}
                    {filteredProducts.length === 0 && (
                        <div className="col-span-full py-12 text-center text-slate-400">
                            No products found matching your search.
                        </div>
                    )}
                </div>
            </div>
        </div>
    );
}

'use client';

import React, { useState, useEffect } from 'react';
import { Card, CardHeader, CardTitle, CardContent, CardDescription } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Badge } from '@/components/ui/badge';
import { Key, Plus, Trash2, Eye, EyeOff, Copy, Check, ShieldCheck, ShieldAlert } from 'lucide-react';
import { api } from '@/lib/api';
import { toast } from 'sonner';
import { motion, AnimatePresence } from 'framer-motion';

interface ApiKey {
    id: string;
    name: string;
    prefix: string;
    scopes: string[];
    lastUsedAt: string | null;
    createdAt: string;
}

export function ApiKeyManager() {
    const [keys, setKeys] = useState<ApiKey[]>([]);
    const [newName, setNewName] = useState('');
    const [newKeySecret, setNewKeySecret] = useState<string | null>(null);
    const [loading, setLoading] = useState(true);
    const [copied, setCopied] = useState(false);

    useEffect(() => {
        fetchKeys();
    }, []);

    const fetchKeys = async () => {
        try {
            const resp = await api.get('system/api/keys');
            setKeys(resp.data);
        } catch (err) {
            toast.error('Failed to load API keys');
        } finally {
            setLoading(false);
        }
    };

    const generateKey = async () => {
        if (!newName.trim()) return toast.error('Key name is required');
        try {
            const resp = await api.post('system/api/keys', {
                name: newName,
                scopes: ['read:all', 'write:all'], // Default for now
            });
            setNewKeySecret(resp.data.key);
            setNewName('');
            fetchKeys();
            toast.success('API Key generated successfully');
        } catch (err) {
            toast.error('Failed to generate key');
        }
    };

    const revokeKey = async (id: string) => {
        if (!confirm('Are you sure? This will immediately break any external integrations using this key.')) return;
        try {
            await api.delete(`/system/api/keys/${id}`);
            fetchKeys();
            toast.success('Key revoked');
        } catch (err) {
            toast.error('Failed to revoke key');
        }
    };

    const copyToClipboard = () => {
        if (!newKeySecret) return;
        navigator.clipboard.writeText(newKeySecret);
        setCopied(true);
        setTimeout(() => setCopied(false), 2000);
    };

    return (
        <div className="space-y-6">
            <Card className="border-blue-200/50 bg-blue-50/5 backdrop-blur-sm">
                <CardHeader>
                    <div className="flex items-center justify-between">
                        <div>
                            <CardTitle className="text-xl font-black flex items-center gap-2">
                                <Key className="text-blue-500 w-6 h-6" />
                                Klypso: API Access
                            </CardTitle>
                            <CardDescription className="font-medium">
                                Generate secure credentials for external integrations and automations.
                            </CardDescription>
                        </div>
                        <ShieldCheck className="w-10 h-10 text-blue-500/20" />
                    </div>
                </CardHeader>
                <CardContent>
                    <div className="flex gap-4 items-end bg-white p-4 rounded-2xl border border-blue-100 shadow-sm">
                        <div className="flex-1 space-y-1.5">
                            <label className="text-xs font-black uppercase text-slate-500 tracking-widest pl-1">Key Description</label>
                            <Input
                                placeholder="e.g. WhatsApp Bot, Zapier Integration"
                                value={newName}
                                onChange={(e) => setNewName(e.target.value)}
                                className="border-none bg-slate-50 h-11 focus-visible:ring-blue-500/20 font-bold"
                            />
                        </div>
                        <Button onClick={generateKey} className="h-11 px-8 rounded-xl bg-blue-600 hover:bg-blue-700 shadow-lg shadow-blue-500/20">
                            <Plus className="w-4 h-4 mr-2" /> Create Secret
                        </Button>
                    </div>

                    <AnimatePresence>
                        {newKeySecret && (
                            <motion.div
                                initial={{ height: 0, opacity: 0 }}
                                animate={{ height: 'auto', opacity: 1 }}
                                exit={{ height: 0, opacity: 0 }}
                                className="mt-6 p-6 rounded-2xl bg-slate-900 text-white border-2 border-blue-500/50 shadow-2xl relative overflow-hidden"
                            >
                                <div className="absolute top-0 right-0 p-2">
                                    <Badge className="bg-blue-500 text-white font-black border-none px-3 py-1 animate-pulse">SECRET GENERATED</Badge>
                                </div>
                                <div className="flex items-center gap-3 mb-2 text-blue-400">
                                    <ShieldAlert className="w-5 h-5" />
                                    <span className="text-xs font-black uppercase tracking-widest">Copy this key now. It will never be shown again.</span>
                                </div>
                                <div className="flex gap-3 mt-4">
                                    <div className="flex-1 bg-white/10 p-4 rounded-xl font-mono text-lg break-all border border-white/5 select-all">
                                        {newKeySecret}
                                    </div>
                                    <Button onClick={copyToClipboard} size="icon" className="h-16 w-16 rounded-xl bg-white/20 hover:bg-white/30 text-white">
                                        {copied ? <Check className="w-6 h-6" /> : <Copy className="w-6 h-6" />}
                                    </Button>
                                </div>
                                <Button variant="ghost" className="mt-4 text-white/50 hover:text-white text-xs" onClick={() => setNewKeySecret(null)}>
                                    I have saved this key safely
                                </Button>
                            </motion.div>
                        )}
                    </AnimatePresence>
                </CardContent>
            </Card>

            <Card className="rounded-[32px] overflow-hidden border-none shadow-xl shadow-slate-200/40">
                <CardHeader className="bg-slate-50/50 border-b border-slate-100 px-8 py-6">
                    <CardTitle className="text-lg font-black tracking-tight">Active Credentials</CardTitle>
                </CardHeader>
                <CardContent className="p-0">
                    <div className="divide-y divide-slate-50">
                        {loading ? (
                            <div className="p-12 text-center animate-pulse text-slate-400 font-bold tracking-widest uppercase text-xs">Synchronizing Vault...</div>
                        ) : keys.length === 0 ? (
                            <div className="p-16 text-center text-slate-400 font-medium italic">No API keys active. Connectivity is offline.</div>
                        ) : (
                            keys.map((key) => (
                                <div key={key.id} className="p-6 px-8 flex items-center justify-between hover:bg-slate-50 transition-all group">
                                    <div className="flex items-center gap-6">
                                        <div className="p-3.5 bg-slate-900 rounded-2xl shadow-lg shadow-slate-900/10 group-hover:scale-110 transition-transform">
                                            <Key className="w-5 h-5 text-blue-400" />
                                        </div>
                                        <div>
                                            <h4 className="font-black text-slate-900 text-lg leading-tight">{key.name}</h4>
                                            <div className="flex items-center gap-3 mt-1.5">
                                                <code className="text-[10px] font-black bg-slate-200 text-slate-600 px-2 py-0.5 rounded uppercase tracking-widest">{key.prefix}.****</code>
                                                <span className="text-[10px] text-slate-500 font-bold uppercase tracking-widest">
                                                    {key.lastUsedAt ? `Last Used: ${new Date(key.lastUsedAt).toLocaleDateString()}` : 'Never Used'}
                                                </span>
                                            </div>
                                        </div>
                                    </div>
                                    <div className="flex items-center gap-4">
                                        <div className="flex gap-2">
                                            {key.scopes.map(s => (
                                                <Badge key={s} variant="secondary" className="bg-blue-50 text-blue-600 border-none font-bold text-[9px] uppercase tracking-widest">{s}</Badge>
                                            ))}
                                        </div>
                                        <Button
                                            variant="ghost"
                                            size="icon"
                                            onClick={() => revokeKey(key.id)}
                                            className="h-11 w-11 rounded-xl text-rose-300 hover:text-rose-600 hover:bg-rose-50 transition-all"
                                        >
                                            <Trash2 className="w-5 h-5" />
                                        </Button>
                                    </div>
                                </div>
                            ))
                        )}
                    </div>
                </CardContent>
            </Card>
        </div>
    );
}

"use client";

import React, { useState, useRef, useCallback } from "react";
import {
    Dialog,
    DialogContent,
    DialogDescription,
    DialogHeader,
    DialogTitle,
    DialogTrigger,
    DialogFooter,
} from "@/components/ui/dialog";
import { Button } from "@/components/ui/button";
import { toast } from "sonner";
import { api } from "@/lib/api";
import { UploadCloud, FileSpreadsheet, CheckCircle2, AlertCircle } from "lucide-react";
import { LoadingSpinner } from "@/components/ui/loading-spinner";

interface ImportResults {
    total: number;
    imported: number;
    failed: number;
    errors: string[];
}

interface BulkImportDialogProps {
    endpoint: string;
    title: string;
    description: string;
    onSuccess: () => void;
    children: React.ReactNode;
}

export function BulkImportDialog({
    endpoint,
    title,
    description,
    onSuccess,
    children,
}: BulkImportDialogProps) {
    const [open, setOpen] = useState(false);
    const [loading, setLoading] = useState(false);
    const [importResults, setImportResults] = useState<ImportResults | null>(null);
    const [file, setFile] = useState<File | null>(null);
    const [csvContent, setCsvContent] = useState<string>("");
    const fileInputRef = useRef<HTMLInputElement>(null);

    const handleFileChange = useCallback((e: React.ChangeEvent<HTMLInputElement>) => {
        const selected = e.target.files?.[0];
        if (!selected) return;

        if (selected.type !== "text/csv" && !selected.name.endsWith('.csv')) {
            toast.error("Please select a valid CSV file");
            return;
        }

        setFile(selected);
        setImportResults(null); // Clear previous results
        const reader = new FileReader();
        reader.onload = (event) => {
            const text = event.target?.result as string;
            setCsvContent(text);
        };
        reader.readAsText(selected);
    }, []);

    const handleImport = useCallback(async () => {
        if (!csvContent) {
            toast.error("Please select a file to import");
            return;
        }

        try {
            setLoading(true);
            setImportResults(null);

            const response = await api.post(endpoint, { csv: csvContent });
            const results = response.data as ImportResults;

            if (results.errors && results.errors.length > 0) {
                setImportResults(results);
                toast.warning(`Imported ${results.imported} rows, but ${results.failed} rows failed.`);
            } else {
                toast.success("Import successful");
                setOpen(false);
                setFile(null);
                setCsvContent("");
                onSuccess();
            }
        } catch (err: any) {
            const errorData = err.response?.data;
            if (errorData?.errors && Array.isArray(errorData.errors)) {
                setImportResults(errorData as ImportResults);
                toast.error(`Import failed with ${errorData.errors.length} errors.`);
            } else {
                toast.error(errorData?.message || errorData?.error || "Failed to import data");
            }
            console.error(err);
        } finally {
            setLoading(false);
        }
    }, [csvContent, endpoint, onSuccess]);

    const handleOpenChange = useCallback((val: boolean) => {
        setOpen(val);
        if (!val) {
            setFile(null);
            setCsvContent("");
        }
    }, []);

    return (
        <Dialog open={open} onOpenChange={handleOpenChange}>
            <DialogTrigger asChild>{children}</DialogTrigger>
            <DialogContent className="sm:max-w-[500px]">
                <DialogHeader>
                    <DialogTitle className="flex items-center gap-2">
                        <FileSpreadsheet className="h-5 w-5 text-blue-600" />
                        {title}
                    </DialogTitle>
                    <DialogDescription>
                        {description}
                    </DialogDescription>
                </DialogHeader>

                <div className="py-6 flex flex-col items-center justify-center">
                    <input
                        type="file"
                        accept=".csv"
                        className="hidden"
                        ref={fileInputRef}
                        onChange={handleFileChange}
                    />

                    <div
                        onClick={() => fileInputRef.current?.click()}
                        className={`w-full border-2 border-dashed rounded-2xl p-8 flex flex-col items-center justify-center transition-all cursor-pointer hover:bg-slate-50 ${file ? "border-blue-500 bg-blue-50/30" : "border-slate-200"
                            }`}
                    >
                        {file ? (
                            <>
                                <FileSpreadsheet className="h-12 w-12 text-blue-500 mb-4" />
                                <p className="text-sm font-bold text-slate-900">{file.name}</p>
                                <p className="text-xs text-slate-500 mt-1">{(file.size / 1024).toFixed(2)} KB</p>
                                <p className="text-[10px] text-blue-600 font-bold uppercase tracking-widest mt-4">Click to replace</p>
                            </>
                        ) : (
                            <>
                                <UploadCloud className="h-12 w-12 text-slate-400 mb-4 group-hover:text-blue-500 transition-colors" />
                                <p className="text-sm font-bold text-slate-700">Click to browse or drag and drop</p>
                                <p className="text-xs text-slate-500 mt-1">CSV files only</p>
                            </>
                        )}
                    </div>

                    {importResults && (
                        <div className="w-full mt-4 bg-slate-50 rounded-xl border border-slate-200 overflow-hidden">
                            <div className="p-3 border-b border-slate-200 bg-slate-100/50 flex justify-between items-center">
                                <span className="text-xs font-bold text-slate-700">Import Summary</span>
                                <div className="flex gap-2">
                                    <span className="text-[10px] bg-green-100 text-green-700 px-2 py-0.5 rounded-full font-bold">
                                        {importResults.imported} OK
                                    </span>
                                    <span className="text-[10px] bg-red-100 text-red-700 px-2 py-0.5 rounded-full font-bold">
                                        {importResults.failed} Failed
                                    </span>
                                </div>
                            </div>
                            <div className="max-h-[150px] overflow-y-auto p-3">
                                {importResults.errors.length > 0 ? (
                                    <div className="space-y-1.5">
                                        {importResults.errors.map((error, idx) => (
                                            <div key={idx} className="flex gap-2 text-[10px] items-start">
                                                <AlertCircle className="h-3 w-3 text-red-500 shrink-0 mt-0.5" />
                                                <span className="text-red-700 font-medium leading-tight">{error}</span>
                                            </div>
                                        ))}
                                    </div>
                                ) : (
                                    <p className="text-[10px] text-slate-500 italic">No errors reported.</p>
                                )}
                            </div>
                        </div>
                    )}

                    {!importResults && (
                        <div className="w-full mt-4 bg-amber-50 rounded-xl p-4 border border-amber-200 flex items-start gap-3">
                            <AlertCircle className="h-5 w-5 text-amber-600 shrink-0 mt-0.5" />
                            <div className="text-xs text-amber-900 font-medium">
                                Make sure your CSV headers exactly match the template format. Invalid rows will be skipped.
                            </div>
                        </div>
                    )}
                </div>

                <DialogFooter>
                    <Button variant="outline" onClick={() => setOpen(false)} disabled={loading}>
                        Cancel
                    </Button>
                    <Button
                        onClick={handleImport}
                        disabled={!file || loading}
                        className="bg-blue-600 hover:bg-blue-700 font-bold"
                    >
                        {loading ? <LoadingSpinner text="Importing..." /> : (
                            <>
                                <CheckCircle2 className="mr-2 h-4 w-4" /> Start Import
                            </>
                        )}
                    </Button>
                </DialogFooter>
            </DialogContent>
        </Dialog>
    );
}

"use client";

import { useEffect, useState, useCallback } from "react";
import { api } from "@/lib/api";
import {
    Table,
    TableBody,
    TableCell,
    TableHead,
    TableHeader,
    TableRow
} from "@/components/ui/table";
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Plus, Search, Filter, MoreHorizontal, Database, ArrowRightLeft } from "lucide-react";
import { Badge } from "@/components/ui/badge";
import { toast } from "sonner";

interface DynamicViewProps {
    modelName: string;
    appName: string;
}

interface SystemRecord {
    id: string;
    name?: string;
    label?: string;
    [key: string]: any;
}

export const DynamicView = ({ modelName, appName }: DynamicViewProps) => {
    const [records, setRecords] = useState<SystemRecord[]>([]);
    const [loading, setLoading] = useState(true);

    const syncNodeData = useCallback(async (showLoading = false) => {
        try {
            if (showLoading) setLoading(true);
            const recordsRes = await api.get(`/system/studio/records/${modelName}`);
            setRecords(recordsRes.data.data || recordsRes.data || []);
        } catch (err) {
            console.error("Node Data Sync Failure:", err);
        } finally {
            setLoading(false);
        }
    }, [modelName]);

    useEffect(() => {
        syncNodeData(true);
        const interval = setInterval(() => syncNodeData(false), 30000);
        return () => clearInterval(interval);
    }, [syncNodeData]);

    return (
        <div className="space-y-8">
            <div className="flex items-center justify-between">
                <div>
                    <h2 className="text-3xl font-bold tracking-tight text-white flex items-center">
                        <Database className="mr-3 h-8 w-8 text-indigo-400" />
                        {modelName.split('.').map((s: string) => s.charAt(0).toUpperCase() + s.slice(1)).join(' ')}
                    </h2>
                    <p className="text-zinc-500 mt-1">View and manage {modelName} records directly.</p>
                </div>
                <div className="flex items-center gap-2">
                    <Button variant="outline" className="border-white/10 bg-white/5 text-zinc-400">
                        <ArrowRightLeft className="mr-2 h-4 w-4" /> Import/Export
                    </Button>
                    <Button className="bg-indigo-600 hover:bg-indigo-700 rounded-full px-6">
                        <Plus className="mr-2 h-4 w-4" /> New Record
                    </Button>
                </div>
            </div>

            <Card className="bg-white/5 border-white/10 backdrop-blur-md overflow-hidden">
                <CardHeader className="bg-white/5 border-b border-white/5 flex flex-row items-center justify-between py-4">
                    <div className="flex items-center gap-4 flex-1 max-w-sm">
                        <div className="relative w-full">
                            <Search className="absolute left-3 top-2.5 h-4 w-4 text-zinc-500" />
                            <input
                                placeholder="Search records..."
                                className="w-full bg-zinc-900/50 border border-white/5 rounded-lg py-2 pl-10 pr-4 text-sm text-white focus:outline-none focus:ring-1 focus:ring-indigo-500 transition-all"
                            />
                        </div>
                        <Button variant="outline" size="icon" className="border-white/5 bg-white/5 text-zinc-500">
                            <Filter className="h-4 w-4" />
                        </Button>
                    </div>
                </CardHeader>
                <CardContent className="p-0">
                    <Table>
                        <TableHeader>
                            <TableRow className="border-white/5 hover:bg-transparent">
                                <TableHead className="text-zinc-500 w-[100px]">ID</TableHead>
                                <TableHead className="text-zinc-500">Display Name</TableHead>
                                <TableHead className="text-zinc-500 text-right">Actions</TableHead>
                            </TableRow>
                        </TableHeader>
                        <TableBody>
                            {records.map((record) => (
                                <TableRow key={record.id} className="border-white/5 hover:bg-white/5 transition-colors group">
                                    <TableCell className="font-mono text-[10px] text-zinc-600">
                                        {record.id.slice(0, 8)}...
                                    </TableCell>
                                    <TableCell className="font-medium text-white">
                                        {record.name || record.label || "Unnamed Record"}
                                    </TableCell>
                                    <TableCell className="text-right">
                                        <Button variant="ghost" size="icon" className="text-zinc-500 hover:text-white">
                                            <MoreHorizontal className="h-4 w-4" />
                                        </Button>
                                    </TableCell>
                                </TableRow>
                            ))}
                            {records.length === 0 && !loading && (
                                <TableRow>
                                    <TableCell colSpan={3} className="text-center py-32 text-zinc-600 italic">
                                        No records found.
                                    </TableCell>
                                </TableRow>
                            )}
                        </TableBody>
                    </Table>
                </CardContent>
            </Card>
        </div>
    );
};

"use client";

import { Input } from "@/components/ui/input";
import { cn } from "@/lib/utils";
import React from "react";

interface NumericInputProps extends Omit<React.InputHTMLAttributes<HTMLInputElement>, 'onChange' | 'value'> {
    value: number;
    onChange: (val: number) => void;
    allowNegative?: boolean;
    decimal?: boolean;
}

export function NumericInput({
    value,
    onChange,
    className,
    allowNegative = false,
    decimal = false,
    ...props
}: NumericInputProps) {
    const [displayValue, setDisplayValue] = React.useState<string>(value === 0 ? "" : value.toString());

    // Sync external value changes to display
    React.useEffect(() => {
        const numDisplay = Number(displayValue);
        if (numDisplay !== value || (value === 0 && displayValue === "0")) {
            // Only update display if the numeric value actually changed, 
            // to avoid resetting the cursor while user is typing "0." or "0.0"
            if (value === 0 && !displayValue) {
                setDisplayValue("");
            } else {
                setDisplayValue(value.toString());
            }
        }
    }, [value]);

    const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        let val = e.target.value;

        // 1. Strip non-numeric
        if (decimal) {
            val = val.replace(/[^0-9.-]/g, '');
        } else {
            val = val.replace(/[^0-9-]/g, '');
        }

        // 2. Prevent multiple decimals
        const parts = val.split('.');
        if (parts.length > 2) {
            val = parts[0] + '.' + parts.slice(1).join('');
        }

        // 3. Handle negative sign
        if (!allowNegative) {
            val = val.replace('-', '');
        }

        // 4. Smart leading zero handling: "001" -> "1", but "0." is fine
        if (val.length > 1 && val.startsWith('0') && val[1] !== '.') {
            val = val.replace(/^0+/, '');
            if (val === "" || val.startsWith('.')) val = '0' + val;
        }

        setDisplayValue(val);

        // Parse and notify
        const parsed = decimal ? parseFloat(val) : parseInt(val, 10);
        if (!isNaN(parsed)) {
            onChange(parsed);
        } else if (val === "" || val === "-") {
            onChange(0);
        }
    };

    const handleBlur = () => {
        // Cleanup formatting on blur
        if (displayValue === "" || displayValue === "-") {
            setDisplayValue("");
            onChange(0);
            return;
        }

        const parsed = decimal ? parseFloat(displayValue) : parseInt(displayValue, 10);
        if (isNaN(parsed)) {
            setDisplayValue("");
            onChange(0);
        } else {
            // Final sanitization: remove trailing dots or clean up ".5" -> "0.5"
            const finalStr = parsed.toString();
            setDisplayValue(finalStr);
            onChange(parsed);
        }
    };

    return (
        <Input
            {...props}
            type="text" // Use text for better control over leading zeros
            inputMode="decimal"
            className={cn("font-mono", className)}
            value={displayValue}
            onChange={handleChange}
            onBlur={handleBlur}
        />
    );
}
